<?php
/**
 * Commander Agent Panel API
 * Manages the 10 coding agents — status, dispatch, configuration
 * Auth: client_id 33 only (Commander)
 */
header('Content-Type: application/json; charset=utf-8');
header('Cache-Control: no-store, no-cache, must-revalidate, private');
header('Pragma: no-cache');
require_once dirname(__DIR__) . '/includes/path-guard.inc.php';

if (!function_exists('agent_panel_json')) {
    function agent_panel_json(array $data): void {
        echo json_encode($data, gositeme_json_public_encode_flags());
    }
}

session_start();
require_once __DIR__ . '/../includes/db-config.inc.php';

// Auth gate — Commander only
$db = getSharedDB();
$token = $_COOKIE['alfred_ide_token'] ?? $_SESSION['ide_session_token'] ?? '';
$authed = false;
if ($token) {
    $hash = hash('sha256', $token);
    $u = $db->prepare("SELECT client_id FROM alfred_ide_users WHERE session_token = ? AND token_expires > NOW() LIMIT 1");
    $u->execute([$hash]);
    $row = $u->fetch(PDO::FETCH_ASSOC);
    if ($row && (int)$row['client_id'] === 33) $authed = true;
}
if (!$authed) {
    http_response_code(403);
    agent_panel_json(['error' => 'Commander access only']);
    exit;
}

$action = $_GET['action'] ?? $_POST['action'] ?? 'status';

// ── Agent Registry ──────────────────────────────────────────────────
$agents = [
    [
        'id' => 'fortress',
        'name' => 'Fortress',
        'title' => 'Security & Encryption',
        'rank' => 'O-3 Major',
        'dept' => 'Security',
        'icon' => 'fa-shield-halved',
        'color' => '#ef4444',
        'desc' => 'Vault operations, GQES encryption, OWASP audits, credential rotation, CSP hardening',
        'domain_files' => ['scripts/vault-crypto.php', 'scripts/gqes-encrypt.php', '.htaccess', 'api/commander-vault.php'],
        'capabilities' => ['vault_ops', 'encryption', 'security_audit', 'key_rotation', 'csp_management'],
    ],
    [
        'id' => 'architect',
        'name' => 'Architect',
        'title' => 'Infrastructure & DevOps',
        'rank' => 'O-3 Major',
        'dept' => 'Infrastructure',
        'icon' => 'fa-server',
        'color' => '#3b82f6',
        'desc' => 'PM2 services, Apache config, database, Redis, DNS, backups, monitoring',
        'domain_files' => ['ecosystem.config.js', 'gohostme/bridge.sh', 'includes/db-config.inc.php'],
        'capabilities' => ['pm2_management', 'apache_config', 'database_ops', 'dns_management', 'monitoring'],
    ],
    [
        'id' => 'veil',
        'name' => 'Veil',
        'title' => 'Encrypted Communications',
        'rank' => 'O-4 Colonel',
        'dept' => 'Security',
        'icon' => 'fa-lock',
        'color' => '#8b5cf6',
        'desc' => 'Post-quantum messaging, Kyber-1024, E2E encryption, secure channels',
        'domain_files' => ['api/veil-protocol.php', 'api/veil-vault.php', 'api/veil-fortress.php', 'api/veil-status.php'],
        'capabilities' => ['pq_encryption', 'secure_messaging', 'key_exchange', 'channel_management'],
    ],
    [
        'id' => 'pulse',
        'name' => 'Pulse',
        'title' => 'Social Network',
        'rank' => 'O-2 Captain',
        'dept' => 'Communications',
        'icon' => 'fa-bolt',
        'color' => '#06b6d4',
        'desc' => 'Social feed, posts, follows, profiles, trending, notifications, badges',
        'domain_files' => ['pulse.php', 'assets/js/pulse-engine.js', 'api/pulse.php', 'api/pulse-groups.php'],
        'capabilities' => ['social_feed', 'profiles', 'engagement', 'notifications', 'groups'],
    ],
    [
        'id' => 'metadome',
        'name' => 'MetaDome',
        'title' => 'VR Worlds',
        'rank' => 'O-2 Captain',
        'dept' => 'Worlds',
        'icon' => 'fa-vr-cardboard',
        'color' => '#f97316',
        'desc' => '16 VR worlds, A-Frame, WebXR, passport system, 114k AI citizens',
        'domain_files' => ['passport.php', 'map.php', 'api/metaverse.php', 'universe.php'],
        'capabilities' => ['world_building', '3d_rendering', 'multiplayer', 'passport_system', 'vr_agents'],
    ],
    [
        'id' => 'garrison',
        'name' => 'Garrison',
        'title' => 'Military Governance',
        'rank' => 'O-4 Colonel',
        'dept' => 'Military Affairs',
        'icon' => 'fa-chess-rook',
        'color' => '#d4a017',
        'desc' => 'Ranks, promotions, field manual, service records, departments, justice',
        'domain_files' => ['docs/field-manual.php', 'service-record.php', 'api/rank-management.php'],
        'capabilities' => ['rank_management', 'promotions', 'governance', 'justice_system', 'department_ops'],
    ],
    [
        'id' => 'forge',
        'name' => 'Forge',
        'title' => 'Alfred IDE',
        'rank' => 'O-3 Major',
        'dept' => 'Engineering',
        'icon' => 'fa-code',
        'color' => '#10b981',
        'desc' => 'IDE platform, extensions, workspaces, auth, billing, developer portal',
        'domain_files' => ['alfred-ide.php', 'alfred-ide-auth.php', 'api/alfred-ide-session.php', 'api/alfred-ide-launch.php'],
        'capabilities' => ['ide_management', 'extension_dev', 'workspace_provisioning', 'ide_auth', 'billing'],
    ],
    [
        'id' => 'herald',
        'name' => 'Herald',
        'title' => 'Voice AI',
        'rank' => 'O-2 Captain',
        'dept' => 'Communications',
        'icon' => 'fa-microphone',
        'color' => '#ec4899',
        'desc' => 'STT/TTS pipeline, Whisper, Kokoro, VAPI, phone system, voice fleet',
        'domain_files' => ['voice.php', 'api/voice-manage.php', 'api/tts.php', 'api/stt.php'],
        'capabilities' => ['stt', 'tts', 'voice_agents', 'phone_system', 'voice_cloning'],
    ],
    [
        'id' => 'quartermaster',
        'name' => 'Quartermaster',
        'title' => 'Hosting & Billing',
        'rank' => 'O-2 Captain',
        'dept' => 'Finance & Supply',
        'icon' => 'fa-warehouse',
        'color' => '#f59e0b',
        'desc' => 'GoHostMe, WHMCS, DirectAdmin, domains, invoices, Stripe, SSO',
        'domain_files' => ['gohostme/server.js', 'gohostme/bridge.sh', 'gohostme/dashboard.php'],
        'capabilities' => ['hosting_provisioning', 'billing', 'domain_management', 'sso', 'customer_accounts'],
    ],
    [
        'id' => 'sentinel',
        'name' => 'Sentinel',
        'title' => 'AI Fleet Command',
        'rank' => 'O-4 Colonel',
        'dept' => 'AI Operations',
        'icon' => 'fa-robot',
        'color' => '#14b8a6',
        'desc' => '11.3M agent registry, multi-LLM orchestration, tool calling, department agents',
        'domain_files' => ['alfred-agent/src/agent.js', 'alfred-agent/src/tools.js', 'alfred-agent/src/providers.js'],
        'capabilities' => ['agent_deployment', 'llm_orchestration', 'tool_management', 'fleet_monitoring', 'department_agents'],
    ],
];

// ── Actions ──────────────────────────────────────────────────────────

switch ($action) {

    case 'status':
        // Get status of all agents — check their domain files exist + related services
        $pm2Raw = shell_exec("pm2 jlist 2>/dev/null");
        $pm2List = json_decode($pm2Raw, true) ?: [];
        $pm2Map = [];
        foreach ($pm2List as $p) {
            $pm2Map[$p['name']] = [
                'status' => $p['pm2_env']['status'] ?? 'unknown',
                'memory' => $p['monit']['memory'] ?? 0,
                'cpu' => $p['monit']['cpu'] ?? 0,
                'restarts' => $p['pm2_env']['restart_time'] ?? 0,
                'uptime' => $p['pm2_env']['pm_uptime'] ?? 0,
            ];
        }

        // Service mapping: which PM2 services belong to which agent
        $serviceMap = [
            'fortress' => ['vault-guardian', 'memory-failsafe'],
            'architect' => ['redis', 'meilisearch', 'headscale', 'sovereign-dns', 'hsd-node', 'vnc-websockify', 'system-optimizer-watchdog', 'pm2-logrotate', 'backup-scheduler'],
            'veil' => ['livekit'],
            'pulse' => ['agent-social-engine', 'social-outreach-engine', 'lavocat-quebec'],
            'metadome' => ['alfred-livestream'],
            'garrison' => ['agent-orchestrator'],
            'forge' => ['alfred-ide', 'gocodeme-middleware', 'coding-swarm', 'commander-terminal'],
            'herald' => ['ollama', 'alfred-soul'],
            'quartermaster' => ['gohostme', 'billing-cron', 'ticket-responder', 'alfred-email-watcher'],
            'sentinel' => ['alfred-agent', 'gocodeme-mcp', 'alfred-mcp', 'alfred-jobs', 'alfred-ws', 'alfred-discord', 'alfred-chat-bridge', 'alfred-heartbeat',
                'dept-agent-education', 'dept-agent-families', 'dept-agent-justice', 'dept-agent-legal',
                'dept-agent-nonprofit', 'dept-agent-police', 'dept-agent-productivity', 'dept-agent-realestate',
                'dept-agent-seniors', 'dept-agent-teachers', 'dept-agent-transport', 'dept-agent-university',
                'agent-content-engine', 'agent-ecosystem-engine', 'agent-events-engine', 'agent-expansion-engine',
                'agentpedia-scheduler', 'self-evolution-engine', 'crypto-trading-agent'],
        ];

        $webRoot = '/var/www/';
        $result = [];
        foreach ($agents as $a) {
            $filesOk = 0;
            $filesTotal = count($a['domain_files']);
            foreach ($a['domain_files'] as $f) {
                $path = (strpos($f, '/') === 0) ? $f : $webRoot . $f;
                if (file_exists($path)) $filesOk++;
            }

            $services = [];
            foreach ($serviceMap[$a['id']] ?? [] as $svc) {
                $services[$svc] = $pm2Map[$svc] ?? ['status' => 'not_found'];
            }

            // Check agent .md file exists
            $agentFile = '/home/gositeme/.github/agents/' . $a['id'] . '.agent.md';
            $agentFileOk = file_exists($agentFile);

            $result[] = [
                'id' => $a['id'],
                'name' => $a['name'],
                'title' => $a['title'],
                'rank' => $a['rank'],
                'dept' => $a['dept'],
                'icon' => $a['icon'],
                'color' => $a['color'],
                'desc' => $a['desc'],
                'capabilities' => $a['capabilities'],
                'agent_file' => $agentFileOk,
                'domain_files' => ['ok' => $filesOk, 'total' => $filesTotal],
                'services' => $services,
                'operational' => $agentFileOk && $filesOk > 0,
            ];
        }

        // Server vitals
        $mem = shell_exec('free -b 2>/dev/null');
        preg_match('/Mem:\s+(\d+)\s+(\d+)/', $mem, $m);
        $memPct = ($m[1] ?? 0) > 0 ? round(((int)$m[2]) / ((int)$m[1]) * 100) : 0;
        $load = sys_getloadavg();

        agent_panel_json([
            'ok' => true,
            'agents' => $result,
            'server' => [
                'memory_pct' => $memPct,
                'load' => round($load[0], 2),
                'pm2_online' => count(array_filter($pm2List, fn($p) => ($p['pm2_env']['status'] ?? '') === 'online')),
                'pm2_total' => count($pm2List),
            ],
            'timestamp' => date('c'),
        ]);
        break;

    case 'dispatch':
        // Record a dispatch order for an agent
        $agentId = $_POST['agent_id'] ?? '';
        $mission = trim($_POST['mission'] ?? '');
        $priority = $_POST['priority'] ?? 'normal';

        if (!$agentId || !$mission) {
            agent_panel_json(['error' => 'agent_id and mission required']);
            exit;
        }

        $validAgent = false;
        foreach ($agents as $a) {
            if ($a['id'] === $agentId) { $validAgent = true; break; }
        }
        if (!$validAgent) {
            agent_panel_json(['error' => 'Unknown agent: ' . htmlspecialchars($agentId)]);
            exit;
        }

        // Log dispatch to database
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_agent_dispatches (
            id INT AUTO_INCREMENT PRIMARY KEY,
            agent_id VARCHAR(32) NOT NULL,
            mission TEXT NOT NULL,
            priority ENUM('critical','high','normal','low') DEFAULT 'normal',
            status ENUM('pending','active','completed','failed') DEFAULT 'pending',
            dispatched_by INT DEFAULT 33,
            dispatched_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            completed_at DATETIME NULL,
            result TEXT NULL,
            INDEX idx_agent (agent_id),
            INDEX idx_status (status)
        )");

        $ins = $db->prepare("INSERT INTO alfred_agent_dispatches (agent_id, mission, priority) VALUES (?, ?, ?)");
        $ins->execute([$agentId, $mission, $priority]);
        $dispatchId = $db->lastInsertId();

        // Attempt live dispatch to agent harness
        $liveResult = null;
        $liveError = null;
        $executeNow = ($_POST['execute'] ?? '0') === '1';

        if ($executeNow) {
            // Mark as active
            $db->prepare("UPDATE alfred_agent_dispatches SET status = 'active' WHERE id = ?")->execute([$dispatchId]);

            // Build agent-specific prompt prefix
            $agentInfo = null;
            foreach ($agents as $a) { if ($a['id'] === $agentId) { $agentInfo = $a; break; } }
            $prefix = $agentInfo ? "[DISPATCH TO: {$agentInfo['name']} ({$agentInfo['title']}) — Priority: $priority]\n\n" : '';

            $payload = json_encode([
                'message' => $prefix . $mission,
                'sessionId' => 'dispatch-' . $dispatchId,
                'provider' => 'openai',
                'model' => 'gpt-4o-mini',
            ]);

            $ch = curl_init('http://127.0.0.1:3102/chat');
            curl_setopt_array($ch, [
                CURLOPT_POST => true,
                CURLOPT_POSTFIELDS => $payload,
                CURLOPT_HTTPHEADER => ['Content-Type: application/json'],
                CURLOPT_RETURNTRANSFER => true,
                CURLOPT_TIMEOUT => 60,
                CURLOPT_CONNECTTIMEOUT => 5,
            ]);
            $response = curl_exec($ch);
            $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);
            $curlErr = curl_error($ch);
            curl_close($ch);

            if ($curlErr) {
                $liveError = 'Harness connection failed: ' . $curlErr;
                $db->prepare("UPDATE alfred_agent_dispatches SET status = 'failed', result = ? WHERE id = ?")
                    ->execute([$liveError, $dispatchId]);
            } elseif ($httpCode === 200) {
                $decoded = json_decode($response, true);
                $liveResult = $decoded['response'] ?? $response;
                $db->prepare("UPDATE alfred_agent_dispatches SET status = 'completed', completed_at = NOW(), result = ? WHERE id = ?")
                    ->execute([mb_substr($liveResult, 0, 10000), $dispatchId]);
            } else {
                $liveError = "Harness returned HTTP $httpCode";
                $db->prepare("UPDATE alfred_agent_dispatches SET status = 'failed', result = ? WHERE id = ?")
                    ->execute([$liveError, $dispatchId]);
            }
        }

        $out = [
            'ok' => true,
            'dispatch_id' => $dispatchId,
            'agent_id' => $agentId,
            'mission' => $mission,
            'priority' => $priority,
        ];
        if ($executeNow) {
            $out['executed'] = true;
            if ($liveResult !== null) $out['response'] = $liveResult;
            if ($liveError !== null) $out['live_error'] = $liveError;
        }
        agent_panel_json($out);
        break;

    case 'missions':
        // Get recent dispatch history
        $agentFilter = $_GET['agent_id'] ?? '';
        $limit = min((int)($_GET['limit'] ?? 50), 200);

        $sql = "SELECT * FROM alfred_agent_dispatches";
        $params = [];
        if ($agentFilter) {
            $sql .= " WHERE agent_id = ?";
            $params[] = $agentFilter;
        }
        $sql .= " ORDER BY dispatched_at DESC LIMIT " . $limit;

        try {
            $stmt = $db->prepare($sql);
            $stmt->execute($params);
            $missions = $stmt->fetchAll(PDO::FETCH_ASSOC);
        } catch (PDOException $e) {
            $missions = [];
        }

        agent_panel_json(['ok' => true, 'missions' => $missions]);
        break;

    case 'update_mission':
        $missionId = (int)($_POST['mission_id'] ?? 0);
        $status = $_POST['status'] ?? '';
        $result = $_POST['result'] ?? '';

        if (!$missionId || !in_array($status, ['active','completed','failed'])) {
            agent_panel_json(['error' => 'mission_id and valid status required']);
            exit;
        }

        $upd = $db->prepare("UPDATE alfred_agent_dispatches SET status = ?, result = ?, completed_at = IF(? IN ('completed','failed'), NOW(), NULL) WHERE id = ?");
        $upd->execute([$status, $result, $status, $missionId]);

        agent_panel_json(['ok' => true, 'updated' => $missionId]);
        break;

    case 'profile':
        // Get detailed profile for a single agent
        $agentId = $_GET['agent_id'] ?? '';
        $agent = null;
        foreach ($agents as $a) {
            if ($a['id'] === $agentId) { $agent = $a; break; }
        }
        if (!$agent) {
            agent_panel_json(['error' => 'Unknown agent: ' . htmlspecialchars($agentId)]);
            exit;
        }

        $webRoot = '/var/www/';
        $agentFile = '/home/gositeme/.github/agents/' . $agent['id'] . '.agent.md';

        // Domain file details
        $fileDetails = [];
        foreach ($agent['domain_files'] as $f) {
            $path = (strpos($f, '/') === 0) ? $f : $webRoot . $f;
            $fileDetails[] = [
                'path' => $f,
                'exists' => file_exists($path),
                'size' => file_exists($path) ? filesize($path) : 0,
                'modified' => file_exists($path) ? date('c', filemtime($path)) : null,
            ];
        }

        // Agent file content (just the frontmatter summary)
        $agentContent = '';
        if (file_exists($agentFile)) {
            $raw = file_get_contents($agentFile);
            if (preg_match('/^---\n(.+?)\n---/s', $raw, $fm)) {
                $agentContent = $fm[1];
            }
        }

        // PM2 services for this agent
        $pm2Raw = shell_exec("pm2 jlist 2>/dev/null");
        $pm2List = json_decode($pm2Raw, true) ?: [];
        $svcMap = [
            'fortress' => ['vault-guardian', 'memory-failsafe'],
            'architect' => ['redis', 'meilisearch', 'headscale', 'sovereign-dns', 'hsd-node', 'vnc-websockify', 'system-optimizer-watchdog', 'pm2-logrotate', 'backup-scheduler'],
            'veil' => ['livekit'],
            'pulse' => ['agent-social-engine', 'social-outreach-engine', 'lavocat-quebec'],
            'metadome' => ['alfred-livestream'],
            'garrison' => ['agent-orchestrator'],
            'forge' => ['alfred-ide', 'gocodeme-middleware', 'coding-swarm', 'commander-terminal'],
            'herald' => ['ollama', 'alfred-soul'],
            'quartermaster' => ['gohostme', 'billing-cron', 'ticket-responder', 'alfred-email-watcher'],
            'sentinel' => ['alfred-agent', 'gocodeme-mcp', 'alfred-mcp', 'alfred-jobs', 'alfred-ws', 'alfred-discord', 'alfred-chat-bridge', 'alfred-heartbeat',
                'dept-agent-education', 'dept-agent-families', 'dept-agent-justice', 'dept-agent-legal',
                'dept-agent-nonprofit', 'dept-agent-police', 'dept-agent-productivity', 'dept-agent-realestate',
                'dept-agent-seniors', 'dept-agent-teachers', 'dept-agent-transport', 'dept-agent-university',
                'agent-content-engine', 'agent-ecosystem-engine', 'agent-events-engine', 'agent-expansion-engine',
                'agentpedia-scheduler', 'self-evolution-engine', 'crypto-trading-agent'],
        ];
        $myServices = $svcMap[$agent['id']] ?? [];
        $services = [];
        foreach ($pm2List as $p) {
            if (in_array($p['name'], $myServices)) {
                $services[$p['name']] = [
                    'status' => $p['pm2_env']['status'] ?? 'unknown',
                    'memory' => $p['monit']['memory'] ?? 0,
                    'cpu' => $p['monit']['cpu'] ?? 0,
                    'restarts' => $p['pm2_env']['restart_time'] ?? 0,
                    'uptime' => $p['pm2_env']['pm_uptime'] ?? 0,
                    'pid' => $p['pid'] ?? 0,
                ];
            }
        }

        // Recent missions for this agent
        try {
            $ms = $db->prepare("SELECT * FROM alfred_agent_dispatches WHERE agent_id = ? ORDER BY dispatched_at DESC LIMIT 20");
            $ms->execute([$agent['id']]);
            $missions = $ms->fetchAll(PDO::FETCH_ASSOC);
        } catch (PDOException $e) {
            $missions = [];
        }

        agent_panel_json([
            'ok' => true,
            'agent' => $agent,
            'agent_file' => file_exists($agentFile),
            'agent_frontmatter' => $agentContent,
            'domain_files' => $fileDetails,
            'services' => $services,
            'services_online' => count(array_filter($services, fn($s) => $s['status'] === 'online')),
            'services_total' => count($services),
            'missions' => $missions,
            'missions_pending' => count(array_filter($missions, fn($m) => $m['status'] === 'pending')),
            'missions_completed' => count(array_filter($missions, fn($m) => $m['status'] === 'completed')),
        ]);
        break;

    case 'fleet':
        // Fleet overview — high-level stats for all agents combined
        $pm2Raw = shell_exec("pm2 jlist 2>/dev/null");
        $pm2List = json_decode($pm2Raw, true) ?: [];
        $online = count(array_filter($pm2List, fn($p) => ($p['pm2_env']['status'] ?? '') === 'online'));
        $stopped = count(array_filter($pm2List, fn($p) => ($p['pm2_env']['status'] ?? '') === 'stopped'));
        $errored = count(array_filter($pm2List, fn($p) => ($p['pm2_env']['status'] ?? '') === 'errored'));
        $totalMem = array_sum(array_map(fn($p) => $p['monit']['memory'] ?? 0, $pm2List));

        // Mission stats
        try {
            $mStats = $db->query("SELECT
                COUNT(*) as total,
                SUM(status='pending') as pending,
                SUM(status='active') as active,
                SUM(status='completed') as completed,
                SUM(status='failed') as failed,
                SUM(priority='critical') as critical
            FROM alfred_agent_dispatches")->fetch(PDO::FETCH_ASSOC);
        } catch (PDOException $e) {
            $mStats = ['total'=>0,'pending'=>0,'active'=>0,'completed'=>0,'failed'=>0,'critical'=>0];
        }

        // Agent file health
        $agentFilesOk = 0;
        foreach ($agents as $a) {
            if (file_exists('/home/gositeme/.github/agents/' . $a['id'] . '.agent.md')) $agentFilesOk++;
        }

        // System
        $mem = shell_exec('free -b 2>/dev/null');
        preg_match('/Mem:\s+(\d+)\s+(\d+)/', $mem, $m);
        $load = sys_getloadavg();
        $disk = disk_free_space('/') ?: 0;
        $diskTotal = disk_total_space('/') ?: 1;

        agent_panel_json([
            'ok' => true,
            'fleet' => [
                'agents_total' => count($agents),
                'agents_configured' => $agentFilesOk,
                'pm2_online' => $online,
                'pm2_stopped' => $stopped,
                'pm2_errored' => $errored,
                'pm2_total' => count($pm2List),
                'pm2_memory_bytes' => $totalMem,
            ],
            'missions' => $mStats,
            'system' => [
                'load_1m' => round($load[0], 2),
                'load_5m' => round($load[1], 2),
                'load_15m' => round($load[2], 2),
                'memory_total' => (int)($m[1] ?? 0),
                'memory_used' => (int)($m[2] ?? 0),
                'disk_free' => $disk,
                'disk_total' => $diskTotal,
                'disk_pct' => round((1 - $disk/$diskTotal) * 100, 1),
            ],
            'timestamp' => date('c'),
        ]);
        break;

    case 'restart_service':
        // Restart a PM2 service that belongs to an agent
        $agentId = $_POST['agent_id'] ?? '';
        $serviceName = $_POST['service'] ?? '';

        if (!$agentId || !$serviceName) {
            agent_panel_json(['error' => 'agent_id and service required']);
            exit;
        }

        // Verify this service belongs to this agent
        $allSvcMap = [
            'fortress' => ['vault-guardian', 'memory-failsafe'],
            'architect' => ['redis', 'meilisearch', 'headscale', 'sovereign-dns', 'hsd-node', 'vnc-websockify', 'system-optimizer-watchdog', 'pm2-logrotate', 'backup-scheduler'],
            'veil' => ['livekit'],
            'pulse' => ['agent-social-engine', 'social-outreach-engine', 'lavocat-quebec'],
            'metadome' => ['alfred-livestream'],
            'garrison' => ['agent-orchestrator'],
            'forge' => ['alfred-ide', 'gocodeme-middleware', 'coding-swarm', 'commander-terminal'],
            'herald' => ['ollama', 'alfred-soul'],
            'quartermaster' => ['gohostme', 'billing-cron', 'ticket-responder', 'alfred-email-watcher'],
            'sentinel' => ['alfred-agent', 'gocodeme-mcp', 'alfred-mcp', 'alfred-jobs', 'alfred-ws', 'alfred-discord', 'alfred-chat-bridge', 'alfred-heartbeat',
                'dept-agent-education', 'dept-agent-families', 'dept-agent-justice', 'dept-agent-legal',
                'dept-agent-nonprofit', 'dept-agent-police', 'dept-agent-productivity', 'dept-agent-realestate',
                'dept-agent-seniors', 'dept-agent-teachers', 'dept-agent-transport', 'dept-agent-university',
