        $allowed = $allSvcMap[$agentId] ?? [];
        if (!in_array($serviceName, $allowed)) {
            agent_panel_json(['error' => 'Service ' . htmlspecialchars($serviceName) . ' does not belong to agent ' . htmlspecialchars($agentId)]);
