        }

        // Validate service name (alphanumeric + hyphens only)
        if (!preg_match('/^[a-z0-9\-]+$/', $serviceName)) {
            agent_panel_json(['error' => 'Invalid service name']);
            exit;
        }

        $output = shell_exec('/home/gositeme/.local/node_modules/.bin/pm2 restart ' . escapeshellarg($serviceName) . ' 2>&1');

        // Log the restart as a dispatch
        try {
            $db->exec("CREATE TABLE IF NOT EXISTS alfred_agent_dispatches (
                id INT AUTO_INCREMENT PRIMARY KEY,
                agent_id VARCHAR(32) NOT NULL,
                mission TEXT NOT NULL,
                priority ENUM('critical','high','normal','low') DEFAULT 'normal',
                status ENUM('pending','active','completed','failed') DEFAULT 'pending',
                dispatched_by INT DEFAULT 33,
                dispatched_at DATETIME DEFAULT CURRENT_TIMESTAMP,
                completed_at DATETIME NULL,
                result TEXT NULL,
                INDEX idx_agent (agent_id),
                INDEX idx_status (status)
            )");
            $ins = $db->prepare("INSERT INTO alfred_agent_dispatches (agent_id, mission, priority, status, completed_at, result) VALUES (?, ?, 'normal', 'completed', NOW(), ?)");
            $ins->execute([$agentId, 'Service restart: ' . $serviceName, 'Restarted via War Room']);
        } catch (PDOException $e) {}

        agent_panel_json(['ok' => true, 'service' => $serviceName, 'output' => $output]);
