    case 'health_history':
        // Health trend data for all agents over last 24 hours
        $agentId = $_GET['agent_id'] ?? '';
        $hours = min((int)($_GET['hours'] ?? 24), 168); // max 7 days

        try {
            if ($agentId) {
                $stmt = $db->prepare("SELECT agent_id, overall_status, services_online, services_total, 
                    domain_files_ok, domain_files_total, memory_bytes, checked_at 
                    FROM alfred_agent_health WHERE agent_id = ? AND checked_at > DATE_SUB(NOW(), INTERVAL ? HOUR) 
                    ORDER BY checked_at ASC");
                $stmt->execute([$agentId, $hours]);
            } else {
                $stmt = $db->prepare("SELECT agent_id, overall_status, services_online, services_total, 
                    domain_files_ok, domain_files_total, memory_bytes, checked_at 
                    FROM alfred_agent_health WHERE checked_at > DATE_SUB(NOW(), INTERVAL ? HOUR) 
                    ORDER BY checked_at ASC");
                $stmt->execute([$hours]);
            }
            $history = $stmt->fetchAll(PDO::FETCH_ASSOC);

            // Also get latest status per agent
            $latest = $db->query("SELECT h1.* FROM alfred_agent_health h1
                INNER JOIN (SELECT agent_id, MAX(id) as max_id FROM alfred_agent_health GROUP BY agent_id) h2
                ON h1.id = h2.max_id")->fetchAll(PDO::FETCH_ASSOC);

            $latestMap = [];
            foreach ($latest as $l) $latestMap[$l['agent_id']] = $l;

            // Summary
            $healthy = count(array_filter($latestMap, fn($l) => $l['overall_status'] === 'healthy'));
            $degraded = count(array_filter($latestMap, fn($l) => $l['overall_status'] === 'degraded'));
            $critical = count(array_filter($latestMap, fn($l) => $l['overall_status'] === 'critical'));
            $offline = count(array_filter($latestMap, fn($l) => $l['overall_status'] === 'offline'));

            agent_panel_json([
                'ok' => true,
                'summary' => [
                    'healthy' => $healthy,
                    'degraded' => $degraded,
                    'critical' => $critical,
                    'offline' => $offline,
                    'total' => count($latestMap),
                ],
                'latest' => $latestMap,
                'history' => $history,
                'hours' => $hours,
            ]);
        } catch (PDOException $e) {
            agent_panel_json(['ok' => true, 'summary' => ['healthy'=>0], 'latest' => [], 'history' => []]);
        }
        break;

    case 'comms_send':
        // Inter-agent communication — send a message from one agent to another
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_agent_comms (
            id INT AUTO_INCREMENT PRIMARY KEY,
            from_agent VARCHAR(32) NOT NULL,
            to_agent VARCHAR(32) NOT NULL,
            channel ENUM('direct','broadcast','alert','request','handoff') DEFAULT 'direct',
            subject VARCHAR(255) NOT NULL,
            body TEXT NOT NULL,
            priority ENUM('critical','high','normal','low') DEFAULT 'normal',
            status ENUM('sent','delivered','read','acknowledged','expired') DEFAULT 'sent',
            parent_id INT NULL,
            sent_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            read_at DATETIME NULL,
            INDEX idx_to (to_agent, status),
            INDEX idx_from (from_agent),
            INDEX idx_channel (channel),
            INDEX idx_parent (parent_id)
        )");

        $from = $_POST['from_agent'] ?? 'commander';
        $to = $_POST['to_agent'] ?? '';
        $channel = $_POST['channel'] ?? 'direct';
        $subject = trim($_POST['subject'] ?? '');
        $body = trim($_POST['body'] ?? '');
        $priority = $_POST['priority'] ?? 'normal';
        $parentId = $_POST['parent_id'] ? (int)$_POST['parent_id'] : null;

        if (!$to || !$subject || !$body) {
            agent_panel_json(['error' => 'to_agent, subject, and body required']);
            exit;
        }

        // Validate agents (broadcast = all)
        $validChannels = ['direct', 'broadcast', 'alert', 'request', 'handoff'];
        if (!in_array($channel, $validChannels)) $channel = 'direct';

        if ($to === 'all' && $channel !== 'broadcast') $channel = 'broadcast';

        if ($channel === 'broadcast') {
            // Send to all agents
            $ins = $db->prepare("INSERT INTO alfred_agent_comms (from_agent, to_agent, channel, subject, body, priority, parent_id) VALUES (?, ?, ?, ?, ?, ?, ?)");
            $ids = [];
            foreach ($agents as $a) {
                if ($a['id'] !== $from) {
                    $ins->execute([$from, $a['id'], 'broadcast', $subject, $body, $priority, $parentId]);
                    $ids[] = $db->lastInsertId();
                }
            }
            agent_panel_json(['ok' => true, 'broadcast' => true, 'message_ids' => $ids, 'recipients' => count($ids)]);
        } else {
            $ins = $db->prepare("INSERT INTO alfred_agent_comms (from_agent, to_agent, channel, subject, body, priority, parent_id) VALUES (?, ?, ?, ?, ?, ?, ?)");
            $ins->execute([$from, $to, $channel, $subject, $body, $priority, $parentId]);
            agent_panel_json(['ok' => true, 'message_id' => $db->lastInsertId()]);
        }
        break;

    case 'comms_inbox':
        // Get messages for an agent or all comms
        $agentId = $_GET['agent_id'] ?? '';
        $channel = $_GET['channel'] ?? '';
        $limit = min((int)($_GET['limit'] ?? 50), 200);

        $sql = "SELECT * FROM alfred_agent_comms WHERE 1=1";
        $params = [];

        if ($agentId) {
            $sql .= " AND (to_agent = ? OR from_agent = ?)";
            $params[] = $agentId;
            $params[] = $agentId;
        }
        if ($channel) {
            $sql .= " AND channel = ?";
            $params[] = $channel;
        }
        $sql .= " ORDER BY sent_at DESC LIMIT " . $limit;

        try {
            $stmt = $db->prepare($sql);
            $stmt->execute($params);
            $messages = $stmt->fetchAll(PDO::FETCH_ASSOC);

            // Unread count per agent
            $unread = $db->query("SELECT to_agent, COUNT(*) as cnt FROM alfred_agent_comms WHERE status = 'sent' GROUP BY to_agent")->fetchAll(PDO::FETCH_ASSOC);
            $unreadMap = [];
            foreach ($unread as $u) $unreadMap[$u['to_agent']] = (int)$u['cnt'];

            agent_panel_json(['ok' => true, 'messages' => $messages, 'unread' => $unreadMap]);
        } catch (PDOException $e) {
            agent_panel_json(['ok' => true, 'messages' => [], 'unread' => []]);
        }
        break;

    case 'comms_ack':
        // Mark a message as read/acknowledged
        $msgId = (int)($_POST['message_id'] ?? 0);
        $newStatus = $_POST['status'] ?? 'read';
        if (!in_array($newStatus, ['delivered', 'read', 'acknowledged'])) $newStatus = 'read';

        if (!$msgId) {
            agent_panel_json(['error' => 'message_id required']);
            exit;
        }

        $upd = $db->prepare("UPDATE alfred_agent_comms SET status = ?, read_at = COALESCE(read_at, NOW()) WHERE id = ?");
        $upd->execute([$newStatus, $msgId]);
        agent_panel_json(['ok' => true, 'message_id' => $msgId, 'status' => $newStatus]);
        break;

    case 'comms_thread':
        // Get a message thread (parent + all replies)
        $parentId = (int)($_GET['parent_id'] ?? 0);
        if (!$parentId) {
            agent_panel_json(['error' => 'parent_id required']);
            exit;
        }

        $stmt = $db->prepare("SELECT * FROM alfred_agent_comms WHERE id = ? OR parent_id = ? ORDER BY sent_at ASC");
        $stmt->execute([$parentId, $parentId]);
        agent_panel_json(['ok' => true, 'thread' => $stmt->fetchAll(PDO::FETCH_ASSOC)]);
        break;

    case 'mesh_status':
        // Inter-agent coordination mesh — shows relationships, handoffs, request chains
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_agent_mesh (
            id INT AUTO_INCREMENT PRIMARY KEY,
            source_agent VARCHAR(32) NOT NULL,
            target_agent VARCHAR(32) NOT NULL,
            link_type ENUM('dependency','handoff','collaboration','escalation','backup') DEFAULT 'dependency',
            strength INT DEFAULT 1,
            description VARCHAR(255),
            active TINYINT(1) DEFAULT 1,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
            UNIQUE KEY unique_link (source_agent, target_agent, link_type),
            INDEX idx_source (source_agent),
            INDEX idx_target (target_agent)
        )");

        // Static mesh (built-in relationships)
        $staticMesh = [
            ['fortress', 'architect', 'dependency', 'Fortress needs Architect for infrastructure security'],
            ['fortress', 'veil', 'collaboration', 'Fortress & Veil share encryption protocols'],
            ['sentinel', 'forge', 'dependency', 'Sentinel agents run in Forge IDE platform'],
            ['sentinel', 'herald', 'collaboration', 'Sentinel orchestrates Herald voice agents'],
            ['quartermaster', 'forge', 'dependency', 'Quartermaster billing gates Forge workspaces'],
            ['garrison', 'sentinel', 'escalation', 'Garrison escalates to Sentinel for AI enforcement'],
            ['pulse', 'metadome', 'collaboration', 'Pulse social integrates with MetaDome VR'],
            ['herald', 'veil', 'dependency', 'Herald voice uses Veil encryption for secure calls'],
            ['architect', 'quartermaster', 'backup', 'Architect backs up Quartermaster hosting data'],
            ['forge', 'sentinel', 'handoff', 'Forge IDE hands off agent deploys to Sentinel'],
        ];

        // Ensure static links exist
        $meshIns = $db->prepare("INSERT IGNORE INTO alfred_agent_mesh (source_agent, target_agent, link_type, description) VALUES (?, ?, ?, ?)");
        foreach ($staticMesh as $link) {
            $meshIns->execute($link);
        }

        // Get all active mesh links
        $links = $db->query("SELECT * FROM alfred_agent_mesh WHERE active = 1 ORDER BY source_agent, target_agent")->fetchAll(PDO::FETCH_ASSOC);

        // Compute connectivity score per agent
        $connectivity = [];
        foreach ($links as $l) {
            $connectivity[$l['source_agent']] = ($connectivity[$l['source_agent']] ?? 0) + $l['strength'];
            $connectivity[$l['target_agent']] = ($connectivity[$l['target_agent']] ?? 0) + $l['strength'];
        }

        // Recent handoffs from comms
        $handoffs = [];
        try {
            $handoffs = $db->query("SELECT * FROM alfred_agent_comms WHERE channel IN ('handoff','request') ORDER BY sent_at DESC LIMIT 10")->fetchAll(PDO::FETCH_ASSOC);
        } catch (PDOException $e) {}

        agent_panel_json([
            'ok' => true,
            'links' => $links,
            'connectivity' => $connectivity,
            'handoffs' => $handoffs,
            'total_links' => count($links),
        ]);
        break;

    case 'mesh_link':
        // Add or update a mesh link
        $source = $_POST['source_agent'] ?? '';
        $target = $_POST['target_agent'] ?? '';
        $linkType = $_POST['link_type'] ?? 'dependency';
        $description = trim($_POST['description'] ?? '');

        if (!$source || !$target) {
            agent_panel_json(['error' => 'source_agent and target_agent required']);
            exit;
        }
        if ($source === $target) {
            agent_panel_json(['error' => 'Cannot link agent to itself']);
            exit;
        }

        $validTypes = ['dependency', 'handoff', 'collaboration', 'escalation', 'backup'];
        if (!in_array($linkType, $validTypes)) $linkType = 'dependency';

        $db->exec("CREATE TABLE IF NOT EXISTS alfred_agent_mesh (
            id INT AUTO_INCREMENT PRIMARY KEY,
            source_agent VARCHAR(32) NOT NULL,
            target_agent VARCHAR(32) NOT NULL,
            link_type ENUM('dependency','handoff','collaboration','escalation','backup') DEFAULT 'dependency',
            strength INT DEFAULT 1,
            description VARCHAR(255),
            active TINYINT(1) DEFAULT 1,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
            UNIQUE KEY unique_link (source_agent, target_agent, link_type),
            INDEX idx_source (source_agent),
            INDEX idx_target (target_agent)
        )");

        $ins = $db->prepare("INSERT INTO alfred_agent_mesh (source_agent, target_agent, link_type, description) VALUES (?, ?, ?, ?) ON DUPLICATE KEY UPDATE description = VALUES(description), strength = strength + 1, updated_at = NOW()");
        $ins->execute([$source, $target, $linkType, $description]);
        agent_panel_json(['ok' => true, 'source' => $source, 'target' => $target, 'type' => $linkType]);
        break;

    case 'activity_feed':
        // Unified activity feed — merges dispatches, comms, health changes into one timeline
        $limit = min((int)($_GET['limit'] ?? 30), 100);
        $agentId = $_GET['agent_id'] ?? '';

        $activities = [];

        // Dispatches
        try {
            $sql = "SELECT id, agent_id, mission AS text, priority, status, dispatched_at AS ts FROM alfred_agent_dispatches";
            $params = [];
            if ($agentId) { $sql .= " WHERE agent_id = ?"; $params[] = $agentId; }
            $sql .= " ORDER BY dispatched_at DESC LIMIT " . $limit;
            $stmt = $db->prepare($sql);
            $stmt->execute($params);
            foreach ($stmt->fetchAll(PDO::FETCH_ASSOC) as $r) {
                $activities[] = [
                    'type' => 'dispatch',
                    'icon' => 'fa-paper-plane',
                    'agent_id' => $r['agent_id'],
                    'text' => $r['text'],
                    'detail' => $r['priority'] . ' / ' . $r['status'],
                    'status' => $r['status'],
                    'ts' => $r['ts'],
                    'id' => 'd-' . $r['id'],
                ];
            }
        } catch (PDOException $e) {}

        // Comms
        try {
            $sql = "SELECT id, from_agent, to_agent, channel, subject, body, status, sent_at AS ts FROM alfred_agent_comms";
            $params = [];
            if ($agentId) { $sql .= " WHERE from_agent = ? OR to_agent = ?"; $params = [$agentId, $agentId]; }
            $sql .= " ORDER BY sent_at DESC LIMIT " . $limit;
            $stmt = $db->prepare($sql);
            $stmt->execute($params);
            foreach ($stmt->fetchAll(PDO::FETCH_ASSOC) as $r) {
                $activities[] = [
                    'type' => 'comm',
                    'icon' => 'fa-satellite',
                    'agent_id' => $r['from_agent'],
                    'text' => $r['subject'],
                    'detail' => $r['from_agent'] . ' → ' . $r['to_agent'] . ' [' . $r['channel'] . ']',
                    'status' => $r['status'],
                    'ts' => $r['ts'],
                    'id' => 'c-' . $r['id'],
                ];
            }
        } catch (PDOException $e) {}

        // Health changes (sample last N, looking for status changes)
        try {
            $sql = "SELECT agent_id, overall_status, services_online, services_total, checked_at AS ts FROM alfred_agent_health";
            $params = [];
            if ($agentId) { $sql .= " WHERE agent_id = ?"; $params[] = $agentId; }
            $sql .= " ORDER BY checked_at DESC LIMIT " . ($limit * 2);
            $stmt = $db->prepare($sql);
            $stmt->execute($params);
            $healthRows = $stmt->fetchAll(PDO::FETCH_ASSOC);

            // Only include health entries where status differs from the previous check
            $lastStatus = [];
            foreach (array_reverse($healthRows) as $r) {
                $prev = $lastStatus[$r['agent_id']] ?? null;
                if ($prev !== $r['overall_status']) {
                    $iconMap = ['healthy' => 'fa-heart', 'degraded' => 'fa-exclamation-triangle', 'critical' => 'fa-skull-crossbones', 'offline' => 'fa-power-off'];
                    $activities[] = [
                        'type' => 'health',
                        'icon' => $iconMap[$r['overall_status']] ?? 'fa-heartbeat',
                        'agent_id' => $r['agent_id'],
                        'text' => ucfirst($r['overall_status']) . ' — ' . $r['services_online'] . '/' . $r['services_total'] . ' services',
                        'detail' => ($prev ? "was $prev → " : '') . $r['overall_status'],
                        'status' => $r['overall_status'],
                        'ts' => $r['ts'],
                        'id' => 'h-' . $r['agent_id'] . '-' . strtotime($r['ts']),
                    ];
                }
                $lastStatus[$r['agent_id']] = $r['overall_status'];
            }
        } catch (PDOException $e) {}

        // Sort all by timestamp descending
        usort($activities, fn($a, $b) => strtotime($b['ts']) - strtotime($a['ts']));
        $activities = array_slice($activities, 0, $limit);

        agent_panel_json(['ok' => true, 'activities' => $activities]);
        break;

    case 'metrics':
        // Aggregate metrics per agent — operational KPIs
        $metrics = [];

        foreach ($agents as $a) {
            $id = $a['id'];
            $m = [
                'agent_id' => $id,
                'missions_total' => 0,
                'missions_completed' => 0,
                'missions_failed' => 0,
                'missions_pending' => 0,
                'comms_sent' => 0,
                'comms_received' => 0,
                'comms_unread' => 0,
                'avg_mission_time_sec' => null,
                'health_uptime_pct' => null,
                'current_status' => 'unknown',
                'services_online' => 0,
                'services_total' => 0,
                'memory_bytes' => 0,
                'mesh_connections' => 0,
            ];

            // Missions
            try {
                $s = $db->prepare("SELECT status, COUNT(*) as cnt FROM alfred_agent_dispatches WHERE agent_id = ? GROUP BY status");
                $s->execute([$id]);
                foreach ($s->fetchAll(PDO::FETCH_ASSOC) as $r) {
                    $m['missions_total'] += $r['cnt'];
                    if ($r['status'] === 'completed') $m['missions_completed'] = $r['cnt'];
                    if ($r['status'] === 'failed') $m['missions_failed'] = $r['cnt'];
                    if ($r['status'] === 'pending') $m['missions_pending'] = $r['cnt'];
                }

                // Avg mission completion time
                $s = $db->prepare("SELECT AVG(TIMESTAMPDIFF(SECOND, dispatched_at, completed_at)) as avg_time FROM alfred_agent_dispatches WHERE agent_id = ? AND status = 'completed' AND completed_at IS NOT NULL");
                $s->execute([$id]);
                $avgRow = $s->fetch(PDO::FETCH_ASSOC);
                if ($avgRow && $avgRow['avg_time']) $m['avg_mission_time_sec'] = round($avgRow['avg_time']);
            } catch (PDOException $e) {}

            // Comms
            try {
                $s = $db->prepare("SELECT COUNT(*) as cnt FROM alfred_agent_comms WHERE from_agent = ?");
                $s->execute([$id]);
                $m['comms_sent'] = (int)$s->fetch(PDO::FETCH_ASSOC)['cnt'];

                $s = $db->prepare("SELECT COUNT(*) as cnt FROM alfred_agent_comms WHERE to_agent = ?");
                $s->execute([$id]);
                $m['comms_received'] = (int)$s->fetch(PDO::FETCH_ASSOC)['cnt'];

                $s = $db->prepare("SELECT COUNT(*) as cnt FROM alfred_agent_comms WHERE to_agent = ? AND status = 'sent'");
                $s->execute([$id]);
                $m['comms_unread'] = (int)$s->fetch(PDO::FETCH_ASSOC)['cnt'];
            } catch (PDOException $e) {}

            // Health uptime (% of healthy checks in last 24h)
            try {
                $s = $db->prepare("SELECT overall_status, COUNT(*) as cnt FROM alfred_agent_health WHERE agent_id = ? AND checked_at > DATE_SUB(NOW(), INTERVAL 24 HOUR) GROUP BY overall_status");
                $s->execute([$id]);
                $healthCounts = $s->fetchAll(PDO::FETCH_KEY_PAIR);
                $totalChecks = array_sum($healthCounts);
                if ($totalChecks > 0) {
                    $healthyChecks = $healthCounts['healthy'] ?? 0;
                    $m['health_uptime_pct'] = round(($healthyChecks / $totalChecks) * 100, 1);
                }

                // Latest status
                $s = $db->prepare("SELECT overall_status, services_online, services_total, memory_bytes FROM alfred_agent_health WHERE agent_id = ? ORDER BY id DESC LIMIT 1");
                $s->execute([$id]);
                $latest = $s->fetch(PDO::FETCH_ASSOC);
                if ($latest) {
                    $m['current_status'] = $latest['overall_status'];
                    $m['services_online'] = (int)$latest['services_online'];
                    $m['services_total'] = (int)$latest['services_total'];
                    $m['memory_bytes'] = (int)$latest['memory_bytes'];
                }
            } catch (PDOException $e) {}

            // Mesh connections
            try {
                $s = $db->prepare("SELECT COUNT(*) as cnt FROM alfred_agent_mesh WHERE (source_agent = ? OR target_agent = ?) AND active = 1");
                $s->execute([$id, $id]);
                $m['mesh_connections'] = (int)$s->fetch(PDO::FETCH_ASSOC)['cnt'];
            } catch (PDOException $e) {}

            $metrics[$id] = $m;
        }

        // Fleet totals
        $totalMissions = array_sum(array_column($metrics, 'missions_total'));
        $totalCompleted = array_sum(array_column($metrics, 'missions_completed'));
        $totalServices = array_sum(array_column($metrics, 'services_total'));
        $totalOnline = array_sum(array_column($metrics, 'services_online'));
        $totalMemory = array_sum(array_column($metrics, 'memory_bytes'));
        $avgUptime = count(array_filter(array_column($metrics, 'health_uptime_pct'), fn($v) => $v !== null)) > 0
            ? round(array_sum(array_filter(array_column($metrics, 'health_uptime_pct'), fn($v) => $v !== null)) / count(array_filter(array_column($metrics, 'health_uptime_pct'), fn($v) => $v !== null)), 1)
            : null;

        agent_panel_json([
            'ok' => true,
            'agents' => $metrics,
            'fleet_totals' => [
                'missions' => $totalMissions,
                'completed' => $totalCompleted,
                'completion_rate' => $totalMissions > 0 ? round(($totalCompleted/$totalMissions)*100, 1) : 0,
                'services_online' => $totalOnline,
                'services_total' => $totalServices,
                'memory_bytes' => $totalMemory,
                'avg_uptime_pct' => $avgUptime,
            ],
        ]);
        break;

    case 'task_queue':
        // Create table if needed
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_agent_tasks (
            id INT AUTO_INCREMENT PRIMARY KEY,
            agent_id VARCHAR(32) NOT NULL,
            title VARCHAR(255) NOT NULL,
            description TEXT,
            priority ENUM('critical','high','normal','low') DEFAULT 'normal',
            status ENUM('queued','assigned','running','completed','failed','cancelled') DEFAULT 'queued',
            assigned_by VARCHAR(64) DEFAULT 'commander',
            result TEXT,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            started_at TIMESTAMP NULL,
            completed_at TIMESTAMP NULL,
            INDEX idx_agent_status (agent_id, status),
            INDEX idx_priority (priority, created_at)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        // GET = list tasks
        $agentFilter = $_GET['agent_id'] ?? '';
        $statusFilter = $_GET['status'] ?? '';
        $limit = min((int)($_GET['limit'] ?? 50), 200);

        $where = [];
        $params = [];
        if ($agentFilter) { $where[] = 'agent_id = ?'; $params[] = $agentFilter; }
        if ($statusFilter) { $where[] = 'status = ?'; $params[] = $statusFilter; }
        $whereStr = $where ? 'WHERE ' . implode(' AND ', $where) : '';

        $s = $db->prepare("SELECT * FROM alfred_agent_tasks $whereStr ORDER BY FIELD(priority,'critical','high','normal','low'), created_at DESC LIMIT $limit");
        $s->execute($params);
        $tasks = $s->fetchAll(PDO::FETCH_ASSOC);

        // Queue stats
        $s = $db->query("SELECT agent_id, status, COUNT(*) as cnt FROM alfred_agent_tasks GROUP BY agent_id, status");
        $stats = [];
        foreach ($s->fetchAll(PDO::FETCH_ASSOC) as $r) {
            if (!isset($stats[$r['agent_id']])) $stats[$r['agent_id']] = [];
            $stats[$r['agent_id']][$r['status']] = (int)$r['cnt'];
        }

        agent_panel_json(['ok' => true, 'tasks' => $tasks, 'stats' => $stats]);
        break;

    case 'task_add':
        $input = json_decode(file_get_contents('php://input'), true);
        $agentId = $input['agent_id'] ?? '';
        $title = trim($input['title'] ?? '');
        $desc = trim($input['description'] ?? '');
        $priority = $input['priority'] ?? 'normal';

        if (!$agentId || !$title) {
            agent_panel_json(['error' => 'agent_id and title required']);
            break;
        }
        if (!in_array($priority, ['critical', 'high', 'normal', 'low'])) $priority = 'normal';

        // Ensure table exists
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_agent_tasks (
            id INT AUTO_INCREMENT PRIMARY KEY,
            agent_id VARCHAR(32) NOT NULL,
            title VARCHAR(255) NOT NULL,
            description TEXT,
            priority ENUM('critical','high','normal','low') DEFAULT 'normal',
            status ENUM('queued','assigned','running','completed','failed','cancelled') DEFAULT 'queued',
            assigned_by VARCHAR(64) DEFAULT 'commander',
            result TEXT,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            started_at TIMESTAMP NULL,
            completed_at TIMESTAMP NULL,
            INDEX idx_agent_status (agent_id, status),
            INDEX idx_priority (priority, created_at)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $s = $db->prepare("INSERT INTO alfred_agent_tasks (agent_id, title, description, priority, assigned_by) VALUES (?, ?, ?, ?, 'commander')");
        $s->execute([$agentId, $title, $desc, $priority]);

        agent_panel_json(['ok' => true, 'task_id' => $db->lastInsertId()]);
        break;

    case 'task_update':
        $input = json_decode(file_get_contents('php://input'), true);
        $taskId = (int)($input['task_id'] ?? 0);
        $status = $input['status'] ?? '';
        $result = $input['result'] ?? null;

        if (!$taskId || !in_array($status, ['assigned', 'running', 'completed', 'failed', 'cancelled'])) {
            agent_panel_json(['error' => 'Valid task_id and status required']);
            break;
        }

        $sets = ['status = ?'];
        $params = [$status];

        if (in_array($status, ['assigned', 'running'])) {
            $sets[] = 'started_at = COALESCE(started_at, NOW())';
        }
        if (in_array($status, ['completed', 'failed', 'cancelled'])) {
            $sets[] = 'completed_at = NOW()';
        }
        if ($result !== null) {
            $sets[] = 'result = ?';
            $params[] = $result;
        }
        $params[] = $taskId;

        $s = $db->prepare("UPDATE alfred_agent_tasks SET " . implode(', ', $sets) . " WHERE id = ?");
        $s->execute($params);

        agent_panel_json(['ok' => true, 'updated' => $s->rowCount()]);
        break;

    case 'remediation_log':
        $agentFilter = $_GET['agent_id'] ?? '';
        $limit = min((int)($_GET['limit'] ?? 30), 100);

        try {
            $where = '';
            $params = [];
            if ($agentFilter) { $where = 'WHERE agent_id = ?'; $params[] = $agentFilter; }
            $s = $db->prepare("SELECT * FROM alfred_agent_remediation $where ORDER BY created_at DESC LIMIT $limit");
            $s->execute($params);
            $logs = $s->fetchAll(PDO::FETCH_ASSOC);

            // Stats
            $s2 = $db->query("SELECT COUNT(*) as total, SUM(services_recovered) as recovered FROM alfred_agent_remediation WHERE created_at > DATE_SUB(NOW(), INTERVAL 24 HOUR)");
            $summary = $s2->fetch(PDO::FETCH_ASSOC);

            agent_panel_json([
                'ok' => true,
                'logs' => $logs,
                'summary_24h' => [
                    'attempts' => (int)($summary['total'] ?? 0),
                    'recovered' => (int)($summary['recovered'] ?? 0),
                ],
            ]);
        } catch (PDOException $e) {
            agent_panel_json(['ok' => true, 'logs' => [], 'summary_24h' => ['attempts' => 0, 'recovered' => 0]]);
        }
        break;

    case 'capabilities':
        // Static capability matrix — domain expertise per agent
        $capabilities = [
            'fortress' => [
