    case 'readiness':
        // Fleet readiness score: composite 0-100 per agent
        // Weights: health uptime 40%, service availability 30%, mission completion 20%, comms responsiveness 10%
        $scores = [];

        foreach ($agents as $a) {
            $id = $a['id'];
            $score = ['agent_id' => $id, 'health' => 0, 'services' => 0, 'missions' => 0, 'comms' => 0, 'total' => 0, 'grade' => 'F'];

            // Health uptime (40%) — % healthy in last 24h
            try {
                $s = $db->prepare("SELECT overall_status, COUNT(*) as cnt FROM alfred_agent_health WHERE agent_id = ? AND checked_at > DATE_SUB(NOW(), INTERVAL 24 HOUR) GROUP BY overall_status");
                $s->execute([$id]);
                $hc = $s->fetchAll(PDO::FETCH_KEY_PAIR);
                $total = array_sum($hc);
                $score['health'] = $total > 0 ? round((($hc['healthy'] ?? 0) / $total) * 100) : 50;
            } catch (PDOException $e) { $score['health'] = 50; }

            // Service availability (30%) — current online/total
            try {
                $s = $db->prepare("SELECT services_online, services_total FROM alfred_agent_health WHERE agent_id = ? ORDER BY id DESC LIMIT 1");
                $s->execute([$id]);
                $sv = $s->fetch(PDO::FETCH_ASSOC);
                if ($sv && $sv['services_total'] > 0) {
                    $score['services'] = round(($sv['services_online'] / $sv['services_total']) * 100);
                } else {
                    $score['services'] = $sv ? 100 : 50; // no services = 100 (agent-only)
                }
            } catch (PDOException $e) { $score['services'] = 50; }

            // Mission completion (20%) — completed/(completed+failed) ratio
            try {
                $s = $db->prepare("SELECT status, COUNT(*) as cnt FROM alfred_agent_dispatches WHERE agent_id = ? AND status IN ('completed','failed') GROUP BY status");
                $s->execute([$id]);
                $mc = $s->fetchAll(PDO::FETCH_KEY_PAIR);
                $mTotal = array_sum($mc);
                $score['missions'] = $mTotal > 0 ? round((($mc['completed'] ?? 0) / $mTotal) * 100) : 80; // no missions yet = neutral good
            } catch (PDOException $e) { $score['missions'] = 80; }

            // Comms responsiveness (10%) — % acknowledged within last 24h
            try {
                $s = $db->prepare("SELECT status, COUNT(*) as cnt FROM alfred_agent_comms WHERE to_agent = ? AND sent_at > DATE_SUB(NOW(), INTERVAL 24 HOUR) GROUP BY status");
                $s->execute([$id]);
                $cc = $s->fetchAll(PDO::FETCH_KEY_PAIR);
                $cTotal = array_sum($cc);
                $acked = ($cc['acknowledged'] ?? 0) + ($cc['read'] ?? 0) + ($cc['delivered'] ?? 0);
                $score['comms'] = $cTotal > 0 ? round(($acked / $cTotal) * 100) : 90; // no comms = neutral
            } catch (PDOException $e) { $score['comms'] = 90; }

            // Weighted total
            $score['total'] = round(
                $score['health'] * 0.40 +
                $score['services'] * 0.30 +
                $score['missions'] * 0.20 +
                $score['comms'] * 0.10
            );

            // Letter grade
            if ($score['total'] >= 95) $score['grade'] = 'A+';
            elseif ($score['total'] >= 90) $score['grade'] = 'A';
            elseif ($score['total'] >= 85) $score['grade'] = 'B+';
            elseif ($score['total'] >= 80) $score['grade'] = 'B';
            elseif ($score['total'] >= 70) $score['grade'] = 'C';
            elseif ($score['total'] >= 60) $score['grade'] = 'D';
            else $score['grade'] = 'F';

            $scores[$id] = $score;
        }

        // Fleet average
        $fleetAvg = count($scores) > 0 ? round(array_sum(array_column($scores, 'total')) / count($scores)) : 0;
        $fleetGrade = 'F';
        if ($fleetAvg >= 95) $fleetGrade = 'A+';
        elseif ($fleetAvg >= 90) $fleetGrade = 'A';
        elseif ($fleetAvg >= 85) $fleetGrade = 'B+';
        elseif ($fleetAvg >= 80) $fleetGrade = 'B';
        elseif ($fleetAvg >= 70) $fleetGrade = 'C';
        elseif ($fleetAvg >= 60) $fleetGrade = 'D';

        agent_panel_json([
            'ok' => true,
            'agents' => $scores,
            'fleet_score' => $fleetAvg,
            'fleet_grade' => $fleetGrade,
        ]);
        break;

    case 'batch_dispatch':
        // Send a mission to multiple agents at once
        $input = json_decode(file_get_contents('php://input'), true);
        $agentIds = $input['agent_ids'] ?? [];
        $mission = trim($input['mission'] ?? '');
        $priority = $input['priority'] ?? 'normal';

        if (empty($agentIds) || !$mission) {
            agent_panel_json(['error' => 'agent_ids array and mission required']);
            break;
        }
        if (!in_array($priority, ['critical', 'high', 'normal', 'low'])) $priority = 'normal';

        $validAgents = array_column($agents, 'id');
        $results = [];

        foreach ($agentIds as $aid) {
            $aid = trim($aid);
            if (!in_array($aid, $validAgents)) {
                $results[] = ['agent_id' => $aid, 'ok' => false, 'error' => 'Unknown agent'];
                continue;
            }
            try {
                $s = $db->prepare("INSERT INTO alfred_agent_dispatches (agent_id, mission, priority, status, dispatched_by) VALUES (?, ?, ?, 'pending', 'commander')");
                $s->execute([$aid, $mission, $priority]);
                $results[] = ['agent_id' => $aid, 'ok' => true, 'dispatch_id' => $db->lastInsertId()];
            } catch (PDOException $e) {
                $results[] = ['agent_id' => $aid, 'ok' => false, 'error' => 'DB error'];
            }
        }

        agent_panel_json([
            'ok' => true,
            'dispatched' => count(array_filter($results, fn($r) => $r['ok'])),
            'failed' => count(array_filter($results, fn($r) => !$r['ok'])),
            'results' => $results,
        ]);
        break;

    case 'escalation':
        // Get or set escalation chains
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_agent_escalations (
            id INT AUTO_INCREMENT PRIMARY KEY,
            agent_id VARCHAR(32) NOT NULL,
            escalate_to VARCHAR(32) NOT NULL,
            condition_type ENUM('critical','failed_mission','timeout','manual') DEFAULT 'critical',
            priority_override VARCHAR(16) DEFAULT NULL,
            active TINYINT DEFAULT 1,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            UNIQUE KEY uk_chain (agent_id, escalate_to, condition_type),
            INDEX idx_agent (agent_id)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        if ($_SERVER['REQUEST_METHOD'] === 'POST') {
            $input = json_decode(file_get_contents('php://input'), true);
            $agentId = $input['agent_id'] ?? '';
            $escalateTo = $input['escalate_to'] ?? '';
            $condition = $input['condition_type'] ?? 'critical';

            if (!$agentId || !$escalateTo) {
                agent_panel_json(['error' => 'agent_id and escalate_to required']);
                break;
            }

            $s = $db->prepare("INSERT INTO alfred_agent_escalations (agent_id, escalate_to, condition_type) VALUES (?, ?, ?) ON DUPLICATE KEY UPDATE active = 1");
            $s->execute([$agentId, $escalateTo, $condition]);
            agent_panel_json(['ok' => true]);
        } else {
            $s = $db->query("SELECT * FROM alfred_agent_escalations WHERE active = 1 ORDER BY agent_id");
            $chains = [];
            foreach ($s->fetchAll(PDO::FETCH_ASSOC) as $r) {
                $chains[$r['agent_id']][] = $r;
            }
            agent_panel_json(['ok' => true, 'chains' => $chains]);
        }
        break;

    case 'audit_log':
        // Fleet command audit trail — log and retrieve commander actions
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_audit_log (
            id INT AUTO_INCREMENT PRIMARY KEY,
            action_type VARCHAR(64) NOT NULL,
            target_agent VARCHAR(32) DEFAULT NULL,
            details TEXT,
            actor VARCHAR(64) DEFAULT 'commander',
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            INDEX idx_type (action_type),
            INDEX idx_agent (target_agent),
            INDEX idx_time (created_at)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        if ($_SERVER['REQUEST_METHOD'] === 'POST') {
            $input = json_decode(file_get_contents('php://input'), true);
            $s = $db->prepare("INSERT INTO alfred_audit_log (action_type, target_agent, details) VALUES (?, ?, ?)");
            $s->execute([
                $input['action_type'] ?? 'unknown',
                $input['target_agent'] ?? null,
                $input['details'] ?? null,
            ]);
            agent_panel_json(['ok' => true, 'log_id' => $db->lastInsertId()]);
        } else {
            $limit = min((int)($_GET['limit'] ?? 50), 200);
            $agentFilter = $_GET['agent_id'] ?? '';
            $typeFilter = $_GET['type'] ?? '';

            $where = [];
            $params = [];
            if ($agentFilter) { $where[] = 'target_agent = ?'; $params[] = $agentFilter; }
            if ($typeFilter) { $where[] = 'action_type = ?'; $params[] = $typeFilter; }
            $whereStr = $where ? 'WHERE ' . implode(' AND ', $where) : '';

            $s = $db->prepare("SELECT * FROM alfred_audit_log $whereStr ORDER BY created_at DESC LIMIT $limit");
            $s->execute($params);
            agent_panel_json(['ok' => true, 'logs' => $s->fetchAll(PDO::FETCH_ASSOC)]);
        }
        break;

    case 'schedule':
        // Agent scheduled tasks (cron-like)
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_agent_schedules (
            id INT AUTO_INCREMENT PRIMARY KEY,
            agent_id VARCHAR(32) NOT NULL,
            title VARCHAR(255) NOT NULL,
            description TEXT,
            cron_expr VARCHAR(64) NOT NULL,
            mission_template TEXT NOT NULL,
            priority ENUM('critical','high','normal','low') DEFAULT 'normal',
            active TINYINT DEFAULT 1,
            last_run TIMESTAMP NULL,
            next_run TIMESTAMP NULL,
            run_count INT DEFAULT 0,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            INDEX idx_agent (agent_id),
            INDEX idx_next (next_run),
            INDEX idx_active (active)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        if ($_SERVER['REQUEST_METHOD'] === 'POST') {
            $input = json_decode(file_get_contents('php://input'), true);
            $subAction = $input['sub_action'] ?? 'add';

            if ($subAction === 'add') {
                $agentId = $input['agent_id'] ?? '';
                $title = trim($input['title'] ?? '');
                $cronExpr = trim($input['cron_expr'] ?? '');
                $missionTpl = trim($input['mission_template'] ?? '');
                $priority = $input['priority'] ?? 'normal';

                if (!$agentId || !$title || !$cronExpr || !$missionTpl) {
                    agent_panel_json(['error' => 'agent_id, title, cron_expr, and mission_template required']);
                    break;
                }

                $s = $db->prepare("INSERT INTO alfred_agent_schedules (agent_id, title, description, cron_expr, mission_template, priority) VALUES (?, ?, ?, ?, ?, ?)");
                $s->execute([$agentId, $title, $input['description'] ?? '', $cronExpr, $missionTpl, $priority]);
                agent_panel_json(['ok' => true, 'schedule_id' => $db->lastInsertId()]);
            } elseif ($subAction === 'toggle') {
                $schedId = (int)($input['schedule_id'] ?? 0);
                $active = (int)($input['active'] ?? 0);
                $s = $db->prepare("UPDATE alfred_agent_schedules SET active = ? WHERE id = ?");
                $s->execute([$active, $schedId]);
                agent_panel_json(['ok' => true]);
            } elseif ($subAction === 'delete') {
                $schedId = (int)($input['schedule_id'] ?? 0);
                $s = $db->prepare("DELETE FROM alfred_agent_schedules WHERE id = ?");
                $s->execute([$schedId]);
                agent_panel_json(['ok' => true]);
            }
        } else {
            $s = $db->query("SELECT * FROM alfred_agent_schedules ORDER BY active DESC, agent_id, title");
            agent_panel_json(['ok' => true, 'schedules' => $s->fetchAll(PDO::FETCH_ASSOC)]);
        }
        break;

    case 'knowledge':
        // Agent knowledge base — persistent learned context
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_agent_knowledge (
            id INT AUTO_INCREMENT PRIMARY KEY,
            agent_id VARCHAR(32) NOT NULL,
            category VARCHAR(64) DEFAULT 'general',
            title VARCHAR(255) NOT NULL,
            content TEXT NOT NULL,
            source VARCHAR(128) DEFAULT 'commander',
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
            INDEX idx_agent (agent_id),
            INDEX idx_cat (agent_id, category),
            FULLTEXT idx_search (title, content)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        if ($_SERVER['REQUEST_METHOD'] === 'POST') {
            $input = json_decode(file_get_contents('php://input'), true);
            $subAction = $input['sub_action'] ?? 'add';

            if ($subAction === 'add') {
                $s = $db->prepare("INSERT INTO alfred_agent_knowledge (agent_id, category, title, content, source) VALUES (?, ?, ?, ?, ?)");
                $s->execute([
                    $input['agent_id'] ?? '',
                    $input['category'] ?? 'general',
                    trim($input['title'] ?? ''),
                    trim($input['content'] ?? ''),
                    $input['source'] ?? 'commander',
                ]);
                agent_panel_json(['ok' => true, 'knowledge_id' => $db->lastInsertId()]);
            } elseif ($subAction === 'delete') {
                $s = $db->prepare("DELETE FROM alfred_agent_knowledge WHERE id = ?");
                $s->execute([(int)($input['id'] ?? 0)]);
                agent_panel_json(['ok' => true]);
            }
        } else {
            $agentFilter = $_GET['agent_id'] ?? '';
            $search = $_GET['q'] ?? '';
            $where = [];
            $params = [];
            if ($agentFilter) { $where[] = 'agent_id = ?'; $params[] = $agentFilter; }
            if ($search) { $where[] = 'MATCH(title, content) AGAINST(? IN BOOLEAN MODE)'; $params[] = $search; }
            $whereStr = $where ? 'WHERE ' . implode(' AND ', $where) : '';

            $s = $db->prepare("SELECT * FROM alfred_agent_knowledge $whereStr ORDER BY updated_at DESC LIMIT 100");
            $s->execute($params);

            // Stats per agent
            $s2 = $db->query("SELECT agent_id, COUNT(*) as cnt FROM alfred_agent_knowledge GROUP BY agent_id");
            $stats = $s2->fetchAll(PDO::FETCH_KEY_PAIR);

            agent_panel_json(['ok' => true, 'entries' => $s->fetchAll(PDO::FETCH_ASSOC), 'stats' => $stats]);
        }
        break;

    case 'search':
        $q = trim($_GET['q'] ?? '');
        if (!$q || strlen($q) < 2) {
            agent_panel_json(['error' => 'Query too short']);
            break;
        }
        $like = '%' . $q . '%';

        // Missions
        $s = $pdo->prepare("SELECT agent_id, mission, status, priority, dispatched_at FROM alfred_agent_dispatches WHERE mission LIKE ? OR agent_id LIKE ? ORDER BY dispatched_at DESC LIMIT 15");
        $s->execute([$like, $like]);
        $missions = $s->fetchAll(PDO::FETCH_ASSOC);

        // Comms
        $s = $pdo->prepare("SELECT from_agent, to_agent, subject, body, channel, sent_at FROM alfred_agent_comms WHERE subject LIKE ? OR body LIKE ? OR from_agent LIKE ? OR to_agent LIKE ? ORDER BY sent_at DESC LIMIT 15");
        $s->execute([$like, $like, $like, $like]);
        $comms = $s->fetchAll(PDO::FETCH_ASSOC);

        // Tasks
        $s = $pdo->prepare("SELECT agent_id, title, description, status, priority, created_at FROM alfred_agent_tasks WHERE title LIKE ? OR description LIKE ? OR agent_id LIKE ? ORDER BY created_at DESC LIMIT 15");
        $s->execute([$like, $like, $like]);
        $tasks = $s->fetchAll(PDO::FETCH_ASSOC);

        // Knowledge
        $s = $pdo->prepare("SELECT agent_id, category, title, content, created_at FROM alfred_agent_knowledge WHERE title LIKE ? OR content LIKE ? OR category LIKE ? ORDER BY created_at DESC LIMIT 15");
        $s->execute([$like, $like, $like]);
        $knowledge = $s->fetchAll(PDO::FETCH_ASSOC);

        // Audit
        $s = $pdo->prepare("SELECT action_type, target_agent, details, actor, created_at FROM alfred_audit_log WHERE action_type LIKE ? OR details LIKE ? OR target_agent LIKE ? ORDER BY created_at DESC LIMIT 15");
        $s->execute([$like, $like, $like]);
        $audit = $s->fetchAll(PDO::FETCH_ASSOC);

        agent_panel_json(['ok' => true, 'missions' => $missions, 'comms' => $comms, 'tasks' => $tasks, 'knowledge' => $knowledge, 'audit' => $audit]);
        break;

    case 'sop':
        // Create table if not exists
        $pdo->exec("CREATE TABLE IF NOT EXISTS alfred_agent_sops (
            id INT AUTO_INCREMENT PRIMARY KEY,
            agent_id VARCHAR(32) NOT NULL,
            title VARCHAR(255) NOT NULL,
            category ENUM('operations','security','comms','escalation','maintenance','deployment','emergency') DEFAULT 'operations',
            severity ENUM('info','advisory','mandatory','critical') DEFAULT 'advisory',
            body TEXT NOT NULL,
            version INT DEFAULT 1,
            status ENUM('draft','active','archived') DEFAULT 'active',
            approved_by VARCHAR(64) DEFAULT 'commander',
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
            INDEX idx_agent (agent_id),
            INDEX idx_category (category),
            INDEX idx_status (status)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $sub = $_POST['sub_action'] ?? $_GET['sub_action'] ?? 'list';

        if ($sub === 'list') {
            $agentFilter = $_GET['agent_id'] ?? '';
            $catFilter = $_GET['category'] ?? '';
            $sql = "SELECT * FROM alfred_agent_sops WHERE status != 'archived'";
            $params = [];
            if ($agentFilter) { $sql .= " AND agent_id = ?"; $params[] = $agentFilter; }
            if ($catFilter) { $sql .= " AND category = ?"; $params[] = $catFilter; }
            $sql .= " ORDER BY severity = 'critical' DESC, severity = 'mandatory' DESC, updated_at DESC";
            $s = $pdo->prepare($sql);
            $s->execute($params);

            // Stats per category
            $s2 = $pdo->query("SELECT category, COUNT(*) c FROM alfred_agent_sops WHERE status = 'active' GROUP BY category");
            $stats = $s2->fetchAll(PDO::FETCH_KEY_PAIR);

            agent_panel_json(['ok' => true, 'sops' => $s->fetchAll(PDO::FETCH_ASSOC), 'stats' => $stats]);
        } elseif ($sub === 'add') {
            $data = json_decode(file_get_contents('php://input'), true) ?: $_POST;
            $agentId = trim($data['agent_id'] ?? '');
            $title = trim($data['title'] ?? '');
            $body = trim($data['body'] ?? '');
            $category = $data['category'] ?? 'operations';
            $severity = $data['severity'] ?? 'advisory';

            if (!$agentId || !$title || !$body) {
                agent_panel_json(['error' => 'agent_id, title, and body required']);
                break;
            }

            $s = $pdo->prepare("INSERT INTO alfred_agent_sops (agent_id, title, category, severity, body) VALUES (?, ?, ?, ?, ?)");
            $s->execute([$agentId, $title, $category, $severity, $body]);
            agent_panel_json(['ok' => true, 'sop_id' => $pdo->lastInsertId()]);
        } elseif ($sub === 'update') {
            $data = json_decode(file_get_contents('php://input'), true) ?: $_POST;
            $sopId = intval($data['sop_id'] ?? 0);
            $title = trim($data['title'] ?? '');
            $body = trim($data['body'] ?? '');
            $category = $data['category'] ?? null;
            $severity = $data['severity'] ?? null;

            if (!$sopId) { agent_panel_json(['error' => 'sop_id required']); break; }

            $updates = ['version = version + 1'];
            $params = [];
            if ($title) { $updates[] = 'title = ?'; $params[] = $title; }
            if ($body) { $updates[] = 'body = ?'; $params[] = $body; }
            if ($category) { $updates[] = 'category = ?'; $params[] = $category; }
            if ($severity) { $updates[] = 'severity = ?'; $params[] = $severity; }
            $params[] = $sopId;

            $s = $pdo->prepare("UPDATE alfred_agent_sops SET " . implode(', ', $updates) . " WHERE id = ?");
            $s->execute($params);
            agent_panel_json(['ok' => true]);
        } elseif ($sub === 'archive') {
            $sopId = intval($_POST['sop_id'] ?? $_GET['sop_id'] ?? 0);
            if (!$sopId) { agent_panel_json(['error' => 'sop_id required']); break; }
            $pdo->prepare("UPDATE alfred_agent_sops SET status = 'archived' WHERE id = ?")->execute([$sopId]);
            agent_panel_json(['ok' => true]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    case 'analytics':
        // Fleet analytics — time-series data for trend charts
        $range = $_GET['range'] ?? '24h';
        $rangeMap = ['1h' => '1 HOUR', '6h' => '6 HOUR', '24h' => '24 HOUR', '7d' => '7 DAY', '30d' => '30 DAY'];
        $interval = $rangeMap[$range] ?? '24 HOUR';

        // Health trend (status counts over time)
        $s = $pdo->prepare("SELECT 
            DATE_FORMAT(checked_at, '%Y-%m-%d %H:%i') as ts,
            SUM(overall_status = 'healthy') as healthy,
            SUM(overall_status = 'degraded') as degraded,
            SUM(overall_status = 'critical') as critical,
            ROUND(AVG(memory_bytes)/1048576, 1) as avg_memory_mb,
            ROUND(AVG(services_online/GREATEST(services_total,1)*100), 1) as avg_service_pct
        FROM alfred_agent_health 
        WHERE checked_at >= NOW() - INTERVAL $interval
        GROUP BY DATE_FORMAT(checked_at, '%Y-%m-%d %H:%i')
        ORDER BY ts ASC");
        $s->execute();
        $healthTrend = $s->fetchAll(PDO::FETCH_ASSOC);

        // Dispatch volume (missions per hour/day)
        $groupBy = in_array($range, ['7d','30d']) ? '%Y-%m-%d' : '%Y-%m-%d %H:00';
        $s = $pdo->prepare("SELECT 
            DATE_FORMAT(dispatched_at, '$groupBy') as ts,
            COUNT(*) as total,
            SUM(status = 'completed') as completed,
            SUM(status = 'failed') as failed,
            SUM(status = 'pending') as pending
        FROM alfred_agent_dispatches 
        WHERE dispatched_at >= NOW() - INTERVAL $interval
        GROUP BY DATE_FORMAT(dispatched_at, '$groupBy')
        ORDER BY ts ASC");
        $s->execute();
        $dispatchTrend = $s->fetchAll(PDO::FETCH_ASSOC);

        // Comms volume
        $s = $pdo->prepare("SELECT 
            DATE_FORMAT(sent_at, '$groupBy') as ts,
            COUNT(*) as total,
            SUM(channel = 'alert') as alerts,
            SUM(channel = 'ops') as ops
        FROM alfred_agent_comms 
        WHERE sent_at >= NOW() - INTERVAL $interval
        GROUP BY DATE_FORMAT(sent_at, '$groupBy')
        ORDER BY ts ASC");
        $s->execute();
        $commsTrend = $s->fetchAll(PDO::FETCH_ASSOC);

        // Per-agent stats (top performers)
        $s = $pdo->prepare("SELECT agent_id, 
            COUNT(*) as total_dispatches,
            SUM(status = 'completed') as completed,
            ROUND(SUM(status = 'completed')/COUNT(*)*100, 1) as success_rate
        FROM alfred_agent_dispatches 
        WHERE dispatched_at >= NOW() - INTERVAL $interval
        GROUP BY agent_id
        ORDER BY total_dispatches DESC");
        $s->execute();
        $agentStats = $s->fetchAll(PDO::FETCH_ASSOC);

        // Remediation events
        $s = $pdo->prepare("SELECT 
            DATE_FORMAT(created_at, '$groupBy') as ts,
            COUNT(*) as total,
            SUM(services_recovered) as recovered
        FROM alfred_agent_remediation 
        WHERE created_at >= NOW() - INTERVAL $interval
        GROUP BY DATE_FORMAT(created_at, '$groupBy')
        ORDER BY ts ASC");
        $s->execute();
        $remediationTrend = $s->fetchAll(PDO::FETCH_ASSOC);

        agent_panel_json([
            'ok' => true, 'range' => $range,
            'health_trend' => $healthTrend,
            'dispatch_trend' => $dispatchTrend,
            'comms_trend' => $commsTrend,
            'agent_stats' => $agentStats,
            'remediation_trend' => $remediationTrend
        ]);
        break;

    case 'dependency_graph':
        // Build agent dependency map from mesh links + service relationships
        $meshLinks = [];
        try {
            $s = $pdo->query("SELECT source_agent, target_agent, link_type, strength FROM alfred_agent_mesh WHERE active = 1 ORDER BY strength DESC");
            $meshLinks = $s->fetchAll(PDO::FETCH_ASSOC);
        } catch(Exception $e) {}

        // Agent → services mapping from agents.json
        $agentsFile = dirname(__DIR__) . '/agents/agents.json';
        $agentServices = [];
        if (file_exists($agentsFile)) {
            $agents = json_decode(file_get_contents($agentsFile), true);
            if (is_array($agents)) {
                foreach ($agents as $agent) {
                    $id = $agent['id'] ?? '';
                    $agentServices[$id] = [
                        'services' => $agent['services'] ?? [],
                        'domains' => $agent['domains'] ?? [],
                        'depends_on' => $agent['depends_on'] ?? []
                    ];
                }
            }
        }

        // Escalation chains as dependency edges
        $escalations = [];
        try {
            $s = $pdo->query("SELECT agent_id, escalate_to, condition_type FROM alfred_agent_escalations WHERE active = 1");
            $escalations = $s->fetchAll(PDO::FETCH_ASSOC);
        } catch(Exception $e) {}

        // Recent comms patterns (who talks to whom)
        $commPatterns = [];
        try {
            $s = $pdo->query("SELECT from_agent, to_agent, COUNT(*) as msg_count FROM alfred_agent_comms WHERE sent_at >= NOW() - INTERVAL 7 DAY AND to_agent != 'all' GROUP BY from_agent, to_agent ORDER BY msg_count DESC LIMIT 30");
            $commPatterns = $s->fetchAll(PDO::FETCH_ASSOC);
        } catch(Exception $e) {}

        agent_panel_json([
            'ok' => true,
            'mesh_links' => $meshLinks,
            'agent_services' => $agentServices,
            'escalations' => $escalations,
            'comm_patterns' => $commPatterns
        ]);
        break;

    case 'benchmark':
        // Agent performance benchmarks
        $sub = $_GET['sub_action'] ?? 'summary';

        if ($sub === 'summary') {
            // Per-agent benchmarks: avg response time, throughput, uptime, mission stats
            $s = $pdo->query("SELECT 
                d.agent_id,
                COUNT(*) as total_missions,
                SUM(d.status = 'completed') as completed,
                SUM(d.status = 'failed') as failed,
                ROUND(SUM(d.status = 'completed')/COUNT(*)*100, 1) as success_rate,
                ROUND(AVG(TIMESTAMPDIFF(SECOND, d.dispatched_at, COALESCE(d.completed_at, NOW()))), 1) as avg_response_sec,
                MIN(d.dispatched_at) as first_dispatch,
                MAX(d.dispatched_at) as last_dispatch
            FROM alfred_agent_dispatches d 
            GROUP BY d.agent_id 
            ORDER BY success_rate DESC, total_missions DESC");
            $missions = $s->fetchAll(PDO::FETCH_ASSOC);

            // Uptime from health records
            $s = $pdo->query("SELECT 
                agent_id,
                COUNT(*) as checks,
                SUM(overall_status = 'healthy') as healthy_checks,
                ROUND(SUM(overall_status = 'healthy')/COUNT(*)*100, 1) as uptime_pct,
                ROUND(AVG(memory_bytes)/1048576, 1) as avg_memory_mb,
                ROUND(AVG(services_online/GREATEST(services_total,1)*100), 1) as avg_service_pct
            FROM alfred_agent_health 
            GROUP BY agent_id");
            $health = $s->fetchAll(PDO::FETCH_ASSOC);
            $healthMap = [];
            foreach ($health as $h) $healthMap[$h['agent_id']] = $h;

            // Comms volume
            $s = $pdo->query("SELECT 
                from_agent as agent_id,
                COUNT(*) as sent,
                SUM(status = 'read' OR status = 'acknowledged') as read_count
            FROM alfred_agent_comms 
            GROUP BY from_agent");
            $comms = $s->fetchAll(PDO::FETCH_ASSOC);
            $commsMap = [];
            foreach ($comms as $c) $commsMap[$c['agent_id']] = $c;

            // Remediation effectiveness
            $s = $pdo->query("SELECT 
                agent_id,
                COUNT(*) as total_remediations,
                SUM(services_recovered) as total_recovered
            FROM alfred_agent_remediation 
            GROUP BY agent_id");
            $remediation = $s->fetchAll(PDO::FETCH_ASSOC);
            $remMap = [];
            foreach ($remediation as $r) $remMap[$r['agent_id']] = $r;

            // Build combined benchmark
            $benchmarks = [];
            foreach ($missions as $m) {
                $id = $m['agent_id'];
                $h = $healthMap[$id] ?? [];
                $c = $commsMap[$id] ?? [];
                $r = $remMap[$id] ?? [];

                // Composite score (0-100)
                $successW = ($m['success_rate'] ?? 0) * 0.3;
                $uptimeW = ($h['uptime_pct'] ?? 0) * 0.3;
                $serviceW = ($h['avg_service_pct'] ?? 0) * 0.2;
                $throughputW = min(100, ($m['total_missions'] ?? 0) * 2) * 0.1;
                $commsW = min(100, ($c['sent'] ?? 0) * 5) * 0.1;
                $composite = round($successW + $uptimeW + $serviceW + $throughputW + $commsW, 1);

                $benchmarks[] = [
                    'agent_id' => $id,
                    'composite_score' => $composite,
                    'success_rate' => $m['success_rate'],
                    'total_missions' => $m['total_missions'],
                    'completed' => $m['completed'],
                    'failed' => $m['failed'],
                    'avg_response_sec' => $m['avg_response_sec'],
                    'uptime_pct' => $h['uptime_pct'] ?? null,
                    'avg_memory_mb' => $h['avg_memory_mb'] ?? null,
                    'avg_service_pct' => $h['avg_service_pct'] ?? null,
                    'comms_sent' => $c['sent'] ?? 0,
                    'remediations' => $r['total_remediations'] ?? 0,
                    'recovered' => $r['total_recovered'] ?? 0,
                ];
            }

            usort($benchmarks, function($a, $b) { return $b['composite_score'] <=> $a['composite_score']; });

            agent_panel_json(['ok' => true, 'benchmarks' => $benchmarks]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    case 'incident':
        $pdo->exec("CREATE TABLE IF NOT EXISTS alfred_agent_incidents (
            id INT AUTO_INCREMENT PRIMARY KEY,
            agent_id VARCHAR(32) NOT NULL,
            title VARCHAR(255) NOT NULL,
            severity ENUM('low','medium','high','critical') DEFAULT 'medium',
            status ENUM('open','investigating','mitigated','resolved','postmortem') DEFAULT 'open',
            description TEXT NOT NULL,
            root_cause TEXT DEFAULT NULL,
            resolution TEXT DEFAULT NULL,
            impact VARCHAR(255) DEFAULT NULL,
            reported_by VARCHAR(64) DEFAULT 'commander',
            assigned_to VARCHAR(32) DEFAULT NULL,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
            resolved_at DATETIME DEFAULT NULL,
            INDEX idx_agent (agent_id),
            INDEX idx_status (status),
            INDEX idx_severity (severity)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $sub = $_POST['sub_action'] ?? $_GET['sub_action'] ?? 'list';

        if ($sub === 'list') {
            $statusFilter = $_GET['status'] ?? '';
            $sql = "SELECT * FROM alfred_agent_incidents";
            $params = [];
            if ($statusFilter) { $sql .= " WHERE status = ?"; $params[] = $statusFilter; }
            $sql .= " ORDER BY FIELD(severity,'critical','high','medium','low'), created_at DESC LIMIT 50";
            $s = $pdo->prepare($sql);
            $s->execute($params);

            $s2 = $pdo->query("SELECT status, COUNT(*) c FROM alfred_agent_incidents GROUP BY status");
            $stats = $s2->fetchAll(PDO::FETCH_KEY_PAIR);

            agent_panel_json(['ok' => true, 'incidents' => $s->fetchAll(PDO::FETCH_ASSOC), 'stats' => $stats]);
        } elseif ($sub === 'add') {
            $data = json_decode(file_get_contents('php://input'), true) ?: $_POST;
            $agentId = trim($data['agent_id'] ?? '');
            $title = trim($data['title'] ?? '');
            $desc = trim($data['description'] ?? '');
            $severity = $data['severity'] ?? 'medium';
            $impact = trim($data['impact'] ?? '');

            if (!$agentId || !$title || !$desc) { agent_panel_json(['error' => 'agent_id, title, description required']); break; }

            $s = $pdo->prepare("INSERT INTO alfred_agent_incidents (agent_id, title, severity, description, impact) VALUES (?, ?, ?, ?, ?)");
            $s->execute([$agentId, $title, $severity, $desc, $impact]);
            agent_panel_json(['ok' => true, 'incident_id' => $pdo->lastInsertId()]);
        } elseif ($sub === 'update') {
            $data = json_decode(file_get_contents('php://input'), true) ?: $_POST;
            $id = intval($data['incident_id'] ?? 0);
            if (!$id) { agent_panel_json(['error' => 'incident_id required']); break; }

            $updates = []; $params = [];
            foreach (['status','root_cause','resolution','assigned_to','severity'] as $f) {
                if (isset($data[$f]) && $data[$f] !== '') { $updates[] = "$f = ?"; $params[] = $data[$f]; }
            }
            if (isset($data['status']) && $data['status'] === 'resolved') { $updates[] = "resolved_at = NOW()"; }
            $params[] = $id;

            if (count($updates)) {
                $pdo->prepare("UPDATE alfred_agent_incidents SET " . implode(', ', $updates) . " WHERE id = ?")->execute($params);
            }
            agent_panel_json(['ok' => true]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    case 'formation':
        $pdo->exec("CREATE TABLE IF NOT EXISTS alfred_fleet_formations (
            id INT AUTO_INCREMENT PRIMARY KEY,
            name VARCHAR(128) NOT NULL,
            description TEXT DEFAULT NULL,
            agents JSON NOT NULL,
            config JSON DEFAULT NULL,
            status ENUM('active','standby','archived') DEFAULT 'standby',
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            activated_at DATETIME DEFAULT NULL,
            INDEX idx_status (status)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $sub = $_POST['sub_action'] ?? $_GET['sub_action'] ?? 'list';

        if ($sub === 'list') {
            $s = $pdo->query("SELECT * FROM alfred_fleet_formations WHERE status != 'archived' ORDER BY status = 'active' DESC, created_at DESC");
            agent_panel_json(['ok' => true, 'formations' => $s->fetchAll(PDO::FETCH_ASSOC)]);
        } elseif ($sub === 'add') {
            $data = json_decode(file_get_contents('php://input'), true) ?: $_POST;
            $name = trim($data['name'] ?? '');
            $desc = trim($data['description'] ?? '');
            $agents = $data['agents'] ?? [];
            $config = $data['config'] ?? [];

            if (!$name || empty($agents)) { agent_panel_json(['error' => 'name and agents required']); break; }

            $s = $pdo->prepare("INSERT INTO alfred_fleet_formations (name, description, agents, config) VALUES (?, ?, ?, ?)");
            $s->execute([$name, $desc, json_encode($agents), json_encode($config)]);
            agent_panel_json(['ok' => true, 'formation_id' => $pdo->lastInsertId()]);
        } elseif ($sub === 'activate') {
            $id = intval($_POST['formation_id'] ?? $_GET['formation_id'] ?? 0);
            if (!$id) { agent_panel_json(['error' => 'formation_id required']); break; }
            // Deactivate all, then activate selected
            $pdo->exec("UPDATE alfred_fleet_formations SET status = 'standby' WHERE status = 'active'");
            $pdo->prepare("UPDATE alfred_fleet_formations SET status = 'active', activated_at = NOW() WHERE id = ?")->execute([$id]);
            agent_panel_json(['ok' => true]);
        } elseif ($sub === 'delete') {
            $id = intval($_POST['formation_id'] ?? $_GET['formation_id'] ?? 0);
            if (!$id) { agent_panel_json(['error' => 'formation_id required']); break; }
            $pdo->prepare("UPDATE alfred_fleet_formations SET status = 'archived' WHERE id = ?")->execute([$id]);
            agent_panel_json(['ok' => true]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    case 'journal':
        $pdo->exec("CREATE TABLE IF NOT EXISTS alfred_agent_journal (
            id INT AUTO_INCREMENT PRIMARY KEY,
            agent_id VARCHAR(32) DEFAULT NULL,
            entry_type ENUM('observation','decision','milestone','warning','discovery','lesson') DEFAULT 'observation',
            title VARCHAR(255) NOT NULL,
            body TEXT NOT NULL,
            tags VARCHAR(255) DEFAULT NULL,
            author VARCHAR(64) DEFAULT 'commander',
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            INDEX idx_agent (agent_id),
            INDEX idx_type (entry_type)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $sub = $_POST['sub_action'] ?? $_GET['sub_action'] ?? 'list';

        if ($sub === 'list') {
            $agentFilter = $_GET['agent_id'] ?? '';
            $typeFilter = $_GET['entry_type'] ?? '';
            $sql = "SELECT * FROM alfred_agent_journal WHERE 1=1";
            $params = [];
            if ($agentFilter) { $sql .= " AND agent_id = ?"; $params[] = $agentFilter; }
            if ($typeFilter) { $sql .= " AND entry_type = ?"; $params[] = $typeFilter; }
            $sql .= " ORDER BY created_at DESC LIMIT 50";
            $s = $pdo->prepare($sql);
            $s->execute($params);

            $s2 = $pdo->query("SELECT entry_type, COUNT(*) c FROM alfred_agent_journal GROUP BY entry_type");
            $stats = $s2->fetchAll(PDO::FETCH_KEY_PAIR);

            agent_panel_json(['ok' => true, 'entries' => $s->fetchAll(PDO::FETCH_ASSOC), 'stats' => $stats]);
