            $sql .= " ORDER BY status = 'learning' DESC, xp DESC";
            $s = $pdo->prepare($sql);
            $s->execute($params);

            // Per-agent summary
            $s2 = $pdo->query("SELECT agent_id, COUNT(*) total, SUM(status='mastered') mastered, SUM(status='proficient') proficient, SUM(status='learning') learning FROM alfred_agent_training GROUP BY agent_id");
            $summary = $s2->fetchAll(PDO::FETCH_ASSOC);

            agent_panel_json(['ok' => true, 'skills' => $s->fetchAll(PDO::FETCH_ASSOC), 'summary' => $summary]);
        } elseif ($sub === 'add') {
            $data = json_decode(file_get_contents('php://input'), true) ?: $_POST;
            $agentId = trim($data['agent_id'] ?? '');
            $skillName = trim($data['skill_name'] ?? '');
            $category = $data['category'] ?? 'combat';

            if (!$agentId || !$skillName) { agent_panel_json(['error' => 'agent_id and skill_name required']); break; }

            $s = $pdo->prepare("INSERT INTO alfred_agent_training (agent_id, skill_name, category) VALUES (?, ?, ?)");
            $s->execute([$agentId, $skillName, $category]);
            agent_panel_json(['ok' => true, 'skill_id' => $pdo->lastInsertId()]);
        } elseif ($sub === 'grant_xp') {
            $data = json_decode(file_get_contents('php://input'), true) ?: $_POST;
            $skillId = intval($data['skill_id'] ?? 0);
            $xp = intval($data['xp'] ?? 10);
            if (!$skillId) { agent_panel_json(['error' => 'skill_id required']); break; }

            // Add XP and auto-level
            $s = $pdo->prepare("SELECT * FROM alfred_agent_training WHERE id = ?");
            $s->execute([$skillId]);
            $skill = $s->fetch(PDO::FETCH_ASSOC);
            if (!$skill) { agent_panel_json(['error' => 'Skill not found']); break; }

            $newXp = $skill['xp'] + $xp;
            $newLevel = $skill['level'];
            $newTarget = $skill['xp_target'];
            $newStatus = $skill['status'];

            while ($newXp >= $newTarget) {
                $newXp -= $newTarget;
                $newLevel++;
                $newTarget = intval($newTarget * 1.5);
                if ($newLevel >= 10) { $newStatus = 'mastered'; break; }
                elseif ($newLevel >= 5) $newStatus = 'proficient';
            }

            $completedAt = ($newStatus === 'mastered') ? 'NOW()' : 'NULL';
            $pdo->prepare("UPDATE alfred_agent_training SET xp = ?, level = ?, xp_target = ?, status = ?, completed_at = $completedAt WHERE id = ?")->execute([$newXp, $newLevel, $newTarget, $newStatus, $skillId]);
            agent_panel_json(['ok' => true, 'new_level' => $newLevel, 'new_xp' => $newXp, 'status' => $newStatus]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
