    case 'sla':
        // Auto-create table
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_agent_sla (
            id INT AUTO_INCREMENT PRIMARY KEY,
            agent_id VARCHAR(64) NOT NULL,
            metric ENUM('uptime','response_time','mission_success','health_score') NOT NULL DEFAULT 'uptime',
            target DECIMAL(6,2) NOT NULL DEFAULT 99.00,
            current_value DECIMAL(6,2) NOT NULL DEFAULT 100.00,
            period ENUM('daily','weekly','monthly') NOT NULL DEFAULT 'monthly',
            violations INT NOT NULL DEFAULT 0,
            last_checked DATETIME DEFAULT NULL,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
            UNIQUE KEY uniq_sla (agent_id, metric, period)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $sub = $_GET['sub_action'] ?? ($input['sub_action'] ?? 'dashboard');

        if ($sub === 'dashboard') {
            // Calculate live SLA data from existing tables
            $agents = $db->query("SELECT DISTINCT agent_id FROM alfred_agent_health ORDER BY agent_id")->fetchAll(PDO::FETCH_COLUMN);
            $result = [];

            foreach ($agents as $aid) {
                $agent = ['agent_id' => $aid, 'metrics' => []];

                // Uptime: % of healthy checks in last 30 days
                $total = $db->prepare("SELECT COUNT(*) FROM alfred_agent_health WHERE agent_id = ? AND checked_at > DATE_SUB(NOW(), INTERVAL 30 DAY)");
                $total->execute([$aid]);
                $totalChecks = (int)$total->fetchColumn();

                $healthy = $db->prepare("SELECT COUNT(*) FROM alfred_agent_health WHERE agent_id = ? AND overall_status = 'healthy' AND checked_at > DATE_SUB(NOW(), INTERVAL 30 DAY)");
                $healthy->execute([$aid]);
                $healthyChecks = (int)$healthy->fetchColumn();

                $uptimePct = $totalChecks > 0 ? round($healthyChecks / $totalChecks * 100, 2) : 100;
                $agent['metrics']['uptime'] = ['value' => $uptimePct, 'target' => 99.0, 'met' => $uptimePct >= 99.0, 'samples' => $totalChecks];

                // Mission success rate
                $mTotal = $db->prepare("SELECT COUNT(*) FROM alfred_agent_dispatches WHERE agent_id = ? AND dispatched_at > DATE_SUB(NOW(), INTERVAL 30 DAY)");
                $mTotal->execute([$aid]);
                $mTotalN = (int)$mTotal->fetchColumn();

                $mOk = $db->prepare("SELECT COUNT(*) FROM alfred_agent_dispatches WHERE agent_id = ? AND status = 'completed' AND dispatched_at > DATE_SUB(NOW(), INTERVAL 30 DAY)");
                $mOk->execute([$aid]);
                $mOkN = (int)$mOk->fetchColumn();

                $missionPct = $mTotalN > 0 ? round($mOkN / $mTotalN * 100, 2) : 100;
                $agent['metrics']['mission_success'] = ['value' => $missionPct, 'target' => 95.0, 'met' => $missionPct >= 95.0, 'samples' => $mTotalN];

                // Health score avg
                $hAvg = $db->prepare("SELECT AVG(CASE overall_status WHEN 'healthy' THEN 100 WHEN 'degraded' THEN 60 WHEN 'critical' THEN 20 ELSE 0 END) FROM alfred_agent_health WHERE agent_id = ? AND checked_at > DATE_SUB(NOW(), INTERVAL 7 DAY)");
                $hAvg->execute([$aid]);
                $healthAvg = round((float)$hAvg->fetchColumn(), 2);
                $agent['metrics']['health_score'] = ['value' => $healthAvg, 'target' => 90.0, 'met' => $healthAvg >= 90.0];

                // Remediation count (violations)
                $remCount = $db->prepare("SELECT COUNT(*) FROM alfred_agent_remediation WHERE agent_id = ? AND created_at > DATE_SUB(NOW(), INTERVAL 30 DAY)");
                $remCount->execute([$aid]);
                $agent['violations'] = (int)$remCount->fetchColumn();

                // Overall SLA compliance
                $metCount = 0;
                $totalMetrics = 0;
                foreach ($agent['metrics'] as $m) { $totalMetrics++; if ($m['met']) $metCount++; }
                $agent['compliance'] = $totalMetrics > 0 ? round($metCount / $totalMetrics * 100, 1) : 100;
                $agent['grade'] = $agent['compliance'] >= 99 ? 'A+' : ($agent['compliance'] >= 95 ? 'A' : ($agent['compliance'] >= 90 ? 'B' : ($agent['compliance'] >= 80 ? 'C' : ($agent['compliance'] >= 70 ? 'D' : 'F'))));

                $result[] = $agent;
            }

            agent_panel_json(['ok' => true, 'agents' => $result]);
        } elseif ($sub === 'set_target') {
            $aid = $input['agent_id'] ?? '';
            $metric = $input['metric'] ?? '';
            $target = (float)($input['target'] ?? 99);
            $period = $input['period'] ?? 'monthly';

            if (!$aid || !$metric) { agent_panel_json(['error' => 'agent_id and metric required']); break; }

            $stmt = $db->prepare("INSERT INTO alfred_agent_sla (agent_id, metric, target, period) VALUES (?, ?, ?, ?)
                ON DUPLICATE KEY UPDATE target = VALUES(target)");
            $stmt->execute([$aid, $metric, $target, $period]);
            agent_panel_json(['ok' => true]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

