            foreach ($agentIds as $aid) {
                $dStmt->execute([$aid, $tpl['mission_text'], $tpl['priority']]);
                $dispatched++;
            }

            $db->prepare("UPDATE alfred_mission_templates SET use_count = use_count + 1 WHERE id = ?")->execute([$templateId]);

            agent_panel_json(['ok' => true, 'dispatched' => $dispatched, 'template' => $tpl['name']]);

        } elseif ($sub === 'delete') {
            $id = (int)($input['id'] ?? 0);
            if (!$id) { agent_panel_json(['error' => 'id required']); break; }
