    case 'alert_rules':
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_alert_rules (
            id INT AUTO_INCREMENT PRIMARY KEY,
            name VARCHAR(128) NOT NULL,
            agent_id VARCHAR(64) DEFAULT NULL,
            metric ENUM('uptime','health','mission_fail','critical_count','memory','remediation') NOT NULL,
            operator ENUM('lt','gt','eq','lte','gte') NOT NULL DEFAULT 'lt',
            threshold DECIMAL(10,2) NOT NULL,
            severity ENUM('info','warning','critical') NOT NULL DEFAULT 'warning',
            action_type ENUM('notify','dispatch','escalate','lockdown') NOT NULL DEFAULT 'notify',
            action_payload TEXT DEFAULT NULL,
            cooldown_minutes INT NOT NULL DEFAULT 30,
            enabled TINYINT(1) NOT NULL DEFAULT 1,
            last_triggered DATETIME DEFAULT NULL,
            trigger_count INT NOT NULL DEFAULT 0,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $sub = $_GET['sub_action'] ?? ($input['sub_action'] ?? 'list');

        if ($sub === 'list') {
            $stmt = $db->query("SELECT * FROM alfred_alert_rules ORDER BY enabled DESC, severity DESC, created_at DESC");
            agent_panel_json(['ok' => true, 'rules' => $stmt->fetchAll(PDO::FETCH_ASSOC)]);

        } elseif ($sub === 'add') {
            $name = trim($input['name'] ?? '');
            $agentId = $input['agent_id'] ?? null;
            $metric = $input['metric'] ?? 'health';
            $operator = $input['operator'] ?? 'lt';
            $threshold = (float)($input['threshold'] ?? 0);
            $severity = $input['severity'] ?? 'warning';
            $actionType = $input['action_type'] ?? 'notify';
            $actionPayload = trim($input['action_payload'] ?? '');
            $cooldown = (int)($input['cooldown_minutes'] ?? 30);

            if (!$name) { agent_panel_json(['error' => 'Name required']); break; }

            $stmt = $db->prepare("INSERT INTO alfred_alert_rules (name, agent_id, metric, operator, threshold, severity, action_type, action_payload, cooldown_minutes) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)");
            $stmt->execute([$name, $agentId ?: null, $metric, $operator, $threshold, $severity, $actionType, $actionPayload, $cooldown]);
            agent_panel_json(['ok' => true, 'id' => $db->lastInsertId()]);

        } elseif ($sub === 'toggle') {
            $id = (int)($input['id'] ?? 0);
            if (!$id) { agent_panel_json(['error' => 'id required']); break; }
            $db->prepare("UPDATE alfred_alert_rules SET enabled = NOT enabled WHERE id = ?")->execute([$id]);
            agent_panel_json(['ok' => true]);

        } elseif ($sub === 'delete') {
            $id = (int)($input['id'] ?? 0);
            if (!$id) { agent_panel_json(['error' => 'id required']); break; }
            $db->prepare("DELETE FROM alfred_alert_rules WHERE id = ?")->execute([$id]);
            agent_panel_json(['ok' => true]);

        } elseif ($sub === 'evaluate') {
            // Evaluate all enabled rules against current data
            $rules = $db->query("SELECT * FROM alfred_alert_rules WHERE enabled = 1")->fetchAll(PDO::FETCH_ASSOC);
            $triggered = [];

            foreach ($rules as $rule) {
                $agents = [];
                if ($rule['agent_id']) {
                    $agents = [$rule['agent_id']];
                } else {
                    $aStmt = $db->query("SELECT DISTINCT agent_id FROM alfred_agent_health");
                    $agents = $aStmt->fetchAll(PDO::FETCH_COLUMN);
                }

                foreach ($agents as $aid) {
                    $value = null;
                    switch ($rule['metric']) {
                        case 'health':
                            $s = $db->prepare("SELECT CASE overall_status WHEN 'healthy' THEN 100 WHEN 'degraded' THEN 50 ELSE 0 END AS v FROM alfred_agent_health WHERE agent_id = ? ORDER BY checked_at DESC LIMIT 1");
                            $s->execute([$aid]);
                            $value = (float)($s->fetchColumn() ?: 100);
                            break;
                        case 'uptime':
                            $total = $db->prepare("SELECT COUNT(*) FROM alfred_agent_health WHERE agent_id = ? AND checked_at > DATE_SUB(NOW(), INTERVAL 24 HOUR)");
                            $total->execute([$aid]);
                            $t = (int)$total->fetchColumn();
                            $ok = $db->prepare("SELECT COUNT(*) FROM alfred_agent_health WHERE agent_id = ? AND overall_status = 'healthy' AND checked_at > DATE_SUB(NOW(), INTERVAL 24 HOUR)");
                            $ok->execute([$aid]);
                            $value = $t > 0 ? round((int)$ok->fetchColumn() / $t * 100, 2) : 100;
                            break;
                        case 'mission_fail':
                            $s = $db->prepare("SELECT COUNT(*) FROM alfred_agent_dispatches WHERE agent_id = ? AND status = 'failed' AND dispatched_at > DATE_SUB(NOW(), INTERVAL 24 HOUR)");
                            $s->execute([$aid]);
                            $value = (float)$s->fetchColumn();
                            break;
                        case 'critical_count':
                            $s = $db->prepare("SELECT COUNT(*) FROM alfred_agent_health WHERE agent_id = ? AND overall_status = 'critical' AND checked_at > DATE_SUB(NOW(), INTERVAL 24 HOUR)");
                            $s->execute([$aid]);
                            $value = (float)$s->fetchColumn();
                            break;
                        case 'remediation':
                            $s = $db->prepare("SELECT COUNT(*) FROM alfred_agent_remediation WHERE agent_id = ? AND created_at > DATE_SUB(NOW(), INTERVAL 24 HOUR)");
                            $s->execute([$aid]);
                            $value = (float)$s->fetchColumn();
                            break;
                    }

                    if ($value === null) continue;

                    $fire = false;
                    switch ($rule['operator']) {
                        case 'lt': $fire = $value < $rule['threshold']; break;
                        case 'gt': $fire = $value > $rule['threshold']; break;
                        case 'eq': $fire = $value == $rule['threshold']; break;
                        case 'lte': $fire = $value <= $rule['threshold']; break;
                        case 'gte': $fire = $value >= $rule['threshold']; break;
                    }

                    if ($fire) {
                        // Check cooldown
                        if ($rule['last_triggered']) {
                            $last = strtotime($rule['last_triggered']);
                            if (time() - $last < $rule['cooldown_minutes'] * 60) continue;
                        }
                        $triggered[] = ['rule_id' => $rule['id'], 'rule_name' => $rule['name'], 'agent_id' => $aid, 'metric' => $rule['metric'], 'value' => $value, 'threshold' => $rule['threshold'], 'severity' => $rule['severity'], 'action_type' => $rule['action_type']];
                        $db->prepare("UPDATE alfred_alert_rules SET last_triggered = NOW(), trigger_count = trigger_count + 1 WHERE id = ?")->execute([$rule['id']]);
                    }
                }
            }

            agent_panel_json(['ok' => true, 'triggered' => $triggered, 'evaluated' => count($rules)]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

