    case 'wargames':
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_wargames (
            id INT AUTO_INCREMENT PRIMARY KEY,
            scenario VARCHAR(128) NOT NULL,
            description TEXT,
            target_agents JSON NOT NULL,
            parameters JSON DEFAULT NULL,
            status ENUM('pending','running','completed','aborted') NOT NULL DEFAULT 'pending',
            results JSON DEFAULT NULL,
            started_at DATETIME DEFAULT NULL,
            completed_at DATETIME DEFAULT NULL,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $sub = $_GET['sub_action'] ?? ($input['sub_action'] ?? 'list');

        if ($sub === 'list') {
            $stmt = $db->query("SELECT * FROM alfred_wargames ORDER BY created_at DESC LIMIT 50");
            agent_panel_json(['ok' => true, 'games' => $stmt->fetchAll(PDO::FETCH_ASSOC)]);

        } elseif ($sub === 'run') {
            $scenario = $input['scenario'] ?? '';
            $targetAgents = $input['target_agents'] ?? [];
            $params = $input['parameters'] ?? [];

            if (!$scenario || empty($targetAgents)) { agent_panel_json(['error' => 'scenario and target_agents required']); break; }

            // Insert game record
            $stmt = $db->prepare("INSERT INTO alfred_wargames (scenario, target_agents, parameters, status, started_at) VALUES (?, ?, ?, 'running', NOW())");
            $stmt->execute([$scenario, json_encode($targetAgents), json_encode($params)]);
            $gameId = $db->lastInsertId();

            // Simulate results based on scenario
            $results = ['game_id' => $gameId, 'scenario' => $scenario, 'agents' => []];
            $scenarios = [
                'cascade_failure' => ['desc' => 'Simulated cascade failure across fleet', 'severity' => 'critical'],
                'overload' => ['desc' => 'Simulated request overload', 'severity' => 'high'],
                'comm_blackout' => ['desc' => 'Simulated communications blackout', 'severity' => 'critical'],
                'partial_outage' => ['desc' => 'Simulated partial service outage', 'severity' => 'medium'],
                'data_corruption' => ['desc' => 'Simulated data integrity failure', 'severity' => 'critical'],
                'slow_response' => ['desc' => 'Simulated degraded response times', 'severity' => 'medium'],
            ];

            $scenarioInfo = $scenarios[$scenario] ?? ['desc' => 'Custom scenario', 'severity' => 'medium'];
            $results['description'] = $scenarioInfo['desc'];

            foreach ($targetAgents as $aid) {
                // Check real agent health
                $hStmt = $db->prepare("SELECT overall_status, services_online, services_total FROM alfred_agent_health WHERE agent_id = ? ORDER BY checked_at DESC LIMIT 1");
                $hStmt->execute([$aid]);
                $health = $hStmt->fetch(PDO::FETCH_ASSOC);

                $baseResilience = ($health && $health['overall_status'] === 'healthy') ? 85 : (($health && $health['overall_status'] === 'degraded') ? 55 : 25);
                $svcRatio = ($health && $health['services_total'] > 0) ? ($health['services_online'] / $health['services_total'] * 100) : 100;

                // Factor in training level
                $tStmt = $db->prepare("SELECT AVG(level) as avg_level FROM alfred_agent_training WHERE agent_id = ?");
                $tStmt->execute([$aid]);
                $avgLevel = (float)($tStmt->fetchColumn() ?: 0);
                $trainingBonus = min($avgLevel * 2, 10);

                // Random variance
                $resilience = min(100, max(0, $baseResilience + $trainingBonus + rand(-15, 15)));
                $recoveryTime = max(5, (100 - $resilience) * 3 + rand(0, 30));
                $survived = $resilience >= 50;

                $results['agents'][] = [
                    'agent_id' => $aid,
                    'resilience_score' => $resilience,
                    'recovery_time_sec' => $recoveryTime,
                    'survived' => $survived,
                    'current_health' => $health['overall_status'] ?? 'unknown',
                    'service_ratio' => round($svcRatio, 1),
                    'training_bonus' => $trainingBonus,
                    'verdict' => $survived ? ($resilience >= 80 ? 'STRONG' : 'SURVIVED') : 'FAILED'
                ];
            }

            // Overall fleet score
            $totalResilience = array_sum(array_column($results['agents'], 'resilience_score'));
            $results['fleet_resilience'] = round($totalResilience / count($results['agents']), 1);
            $results['fleet_verdict'] = $results['fleet_resilience'] >= 75 ? 'FLEET STRONG' : ($results['fleet_resilience'] >= 50 ? 'FLEET VULNERABLE' : 'FLEET COMPROMISED');

            $db->prepare("UPDATE alfred_wargames SET status = 'completed', results = ?, completed_at = NOW() WHERE id = ?")->execute([json_encode($results), $gameId]);

            agent_panel_json(['ok' => true, 'results' => $results]);

        } elseif ($sub === 'abort') {
            $id = (int)($input['id'] ?? 0);
            $db->prepare("UPDATE alfred_wargames SET status = 'aborted' WHERE id = ? AND status = 'running'")->execute([$id]);
            agent_panel_json(['ok' => true]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    case 'resources':
        $sub = $_GET['sub_action'] ?? ($input['sub_action'] ?? 'overview');

        if ($sub === 'overview') {
            // Pull real resource data from health records
            $agents = $db->query("SELECT DISTINCT agent_id FROM alfred_agent_health ORDER BY agent_id")->fetchAll(PDO::FETCH_COLUMN);
            $result = [];

            foreach ($agents as $aid) {
                $h = $db->prepare("SELECT memory_bytes, services_online, services_total, overall_status FROM alfred_agent_health WHERE agent_id = ? ORDER BY checked_at DESC LIMIT 1");
                $h->execute([$aid]);
                $health = $h->fetch(PDO::FETCH_ASSOC);

                // Mission load
                $activeM = $db->prepare("SELECT COUNT(*) FROM alfred_agent_dispatches WHERE agent_id = ? AND status IN ('pending','running')");
                $activeM->execute([$aid]);
                $activeMissions = (int)$activeM->fetchColumn();

                // Task load
                $activeT = $db->prepare("SELECT COUNT(*) FROM alfred_agent_tasks WHERE agent_id = ? AND status IN ('pending','in_progress')");
                $activeT->execute([$aid]);
                $activeTasks = (int)$activeT->fetchColumn();

                // Comms backlog
                $unread = $db->prepare("SELECT COUNT(*) FROM alfred_agent_comms WHERE to_agent = ? AND status = 'sent'");
                $unread->execute([$aid]);
                $unreadComms = (int)$unread->fetchColumn();

                // Skills count
                $skills = $db->prepare("SELECT COUNT(*) FROM alfred_agent_training WHERE agent_id = ?");
                $skills->execute([$aid]);
                $skillCount = (int)$skills->fetchColumn();

                $memMB = $health ? round($health['memory_bytes'] / 1048576, 1) : 0;
                $svcOnline = $health ? (int)$health['services_online'] : 0;
                $svcTotal = $health ? (int)$health['services_total'] : 0;

                // Compute load score (0-100)
                $loadScore = min(100, $activeMissions * 15 + $activeTasks * 10 + $unreadComms * 2 + ($memMB > 100 ? 20 : $memMB / 5));

                $result[] = [
                    'agent_id' => $aid,
                    'memory_mb' => $memMB,
                    'services_online' => $svcOnline,
                    'services_total' => $svcTotal,
                    'active_missions' => $activeMissions,
                    'active_tasks' => $activeTasks,
                    'unread_comms' => $unreadComms,
                    'skill_count' => $skillCount,
                    'load_score' => round($loadScore, 1),
                    'status' => $health['overall_status'] ?? 'unknown'
                ];
            }

            // Fleet totals
            $totals = [
                'total_memory_mb' => array_sum(array_column($result, 'memory_mb')),
                'total_services' => array_sum(array_column($result, 'services_online')),
                'total_missions' => array_sum(array_column($result, 'active_missions')),
                'total_tasks' => array_sum(array_column($result, 'active_tasks')),
                'avg_load' => count($result) > 0 ? round(array_sum(array_column($result, 'load_score')) / count($result), 1) : 0
            ];

            agent_panel_json(['ok' => true, 'agents' => $result, 'totals' => $totals]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    case 'personality':
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_agent_personality (
            id INT AUTO_INCREMENT PRIMARY KEY,
            agent_id VARCHAR(64) NOT NULL UNIQUE,
            codename VARCHAR(64) DEFAULT NULL,
            motto VARCHAR(255) DEFAULT NULL,
            traits JSON DEFAULT NULL,
            behavior_mode ENUM('autonomous','supervised','passive','aggressive','stealth') NOT NULL DEFAULT 'supervised',
            comm_style ENUM('formal','tactical','casual','minimal','verbose') NOT NULL DEFAULT 'tactical',
            autonomy_level TINYINT NOT NULL DEFAULT 5,
            risk_tolerance ENUM('low','medium','high','extreme') NOT NULL DEFAULT 'medium',
            specializations JSON DEFAULT NULL,
            notes TEXT DEFAULT NULL,
            updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $sub = $_GET['sub_action'] ?? ($input['sub_action'] ?? 'list');

        if ($sub === 'list') {
            $stmt = $db->query("SELECT * FROM alfred_agent_personality ORDER BY agent_id");
            agent_panel_json(['ok' => true, 'profiles' => $stmt->fetchAll(PDO::FETCH_ASSOC)]);

        } elseif ($sub === 'save') {
            $aid = trim($input['agent_id'] ?? '');
            if (!$aid) { agent_panel_json(['error' => 'agent_id required']); break; }

            $codename = trim($input['codename'] ?? '');
            $motto = trim($input['motto'] ?? '');
            $traits = isset($input['traits']) ? json_encode($input['traits']) : '[]';
            $behaviorMode = $input['behavior_mode'] ?? 'supervised';
            $commStyle = $input['comm_style'] ?? 'tactical';
            $autonomy = max(1, min(10, (int)($input['autonomy_level'] ?? 5)));
            $risk = $input['risk_tolerance'] ?? 'medium';
            $specs = isset($input['specializations']) ? json_encode($input['specializations']) : '[]';
            $notes = trim($input['notes'] ?? '');

            $stmt = $db->prepare("INSERT INTO alfred_agent_personality (agent_id, codename, motto, traits, behavior_mode, comm_style, autonomy_level, risk_tolerance, specializations, notes)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                ON DUPLICATE KEY UPDATE codename=VALUES(codename), motto=VALUES(motto), traits=VALUES(traits), behavior_mode=VALUES(behavior_mode), comm_style=VALUES(comm_style), autonomy_level=VALUES(autonomy_level), risk_tolerance=VALUES(risk_tolerance), specializations=VALUES(specializations), notes=VALUES(notes)");
            $stmt->execute([$aid, $codename, $motto, $traits, $behaviorMode, $commStyle, $autonomy, $risk, $specs, $notes]);
            agent_panel_json(['ok' => true]);

        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    case 'intel_briefing':
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_intel_briefings (
            id INT AUTO_INCREMENT PRIMARY KEY,
            period ENUM('daily','weekly','situational') NOT NULL DEFAULT 'daily',
            title VARCHAR(255) NOT NULL,
            summary TEXT NOT NULL,
            threat_level ENUM('green','yellow','orange','red','black') NOT NULL DEFAULT 'green',
            sections JSON NOT NULL,
            generated_by VARCHAR(64) DEFAULT 'alfred',
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $sub = $_GET['sub_action'] ?? ($input['sub_action'] ?? 'list');

        if ($sub === 'generate') {
            $period = $input['period'] ?? 'daily';
            $interval = $period === 'weekly' ? '7 DAY' : '24 HOUR';

            // Collect intel from all sources
            $sections = [];

            // 1. Fleet Status
            $healthRows = $db->query("SELECT agent_id, overall_status FROM alfred_agent_health WHERE id IN (SELECT MAX(id) FROM alfred_agent_health GROUP BY agent_id)")->fetchAll(PDO::FETCH_ASSOC);
            $healthy = count(array_filter($healthRows, fn($r) => $r['overall_status'] === 'healthy'));
            $degraded = count(array_filter($healthRows, fn($r) => $r['overall_status'] === 'degraded'));
            $critical = count(array_filter($healthRows, fn($r) => $r['overall_status'] === 'critical'));
            $total = count($healthRows);
            $sections['fleet_status'] = ['healthy' => $healthy, 'degraded' => $degraded, 'critical' => $critical, 'total' => $total, 'readiness' => $total > 0 ? round($healthy / $total * 100, 1) : 0];

            // 2. Missions
            $mCompleted = $db->prepare("SELECT COUNT(*) FROM alfred_agent_dispatches WHERE status='completed' AND dispatched_at > DATE_SUB(NOW(), INTERVAL $interval)");
            $mCompleted->execute();
            $mFailed = $db->prepare("SELECT COUNT(*) FROM alfred_agent_dispatches WHERE status='failed' AND dispatched_at > DATE_SUB(NOW(), INTERVAL $interval)");
            $mFailed->execute();
            $mPending = $db->prepare("SELECT COUNT(*) FROM alfred_agent_dispatches WHERE status IN ('pending','running')");
            $mPending->execute();
            $sections['missions'] = ['completed' => (int)$mCompleted->fetchColumn(), 'failed' => (int)$mFailed->fetchColumn(), 'active' => (int)$mPending->fetchColumn()];

            // 3. Incidents
            $openInc = $db->query("SELECT COUNT(*) FROM alfred_agent_incidents WHERE status NOT IN ('resolved','postmortem')")->fetchColumn();
            $newInc = $db->prepare("SELECT COUNT(*) FROM alfred_agent_incidents WHERE created_at > DATE_SUB(NOW(), INTERVAL $interval)");
            $newInc->execute();
            $critInc = $db->query("SELECT COUNT(*) FROM alfred_agent_incidents WHERE severity='critical' AND status NOT IN ('resolved','postmortem')")->fetchColumn();
            $sections['incidents'] = ['open' => (int)$openInc, 'new' => (int)$newInc->fetchColumn(), 'critical' => (int)$critInc];

            // 4. Remediations
            $remCount = $db->prepare("SELECT COUNT(*) FROM alfred_agent_remediation WHERE created_at > DATE_SUB(NOW(), INTERVAL $interval)");
            $remCount->execute();
            $sections['remediations'] = ['count' => (int)$remCount->fetchColumn()];

            // 5. Comms volume
            $commsSent = $db->prepare("SELECT COUNT(*) FROM alfred_agent_comms WHERE sent_at > DATE_SUB(NOW(), INTERVAL $interval)");
            $commsSent->execute();
            $critComms = $db->prepare("SELECT COUNT(*) FROM alfred_agent_comms WHERE priority='critical' AND sent_at > DATE_SUB(NOW(), INTERVAL $interval)");
            $critComms->execute();
            $sections['comms'] = ['total' => (int)$commsSent->fetchColumn(), 'critical' => (int)$critComms->fetchColumn()];

            // 6. Alert rule triggers
            $alertFires = $db->query("SELECT SUM(trigger_count) FROM alfred_alert_rules")->fetchColumn();
            $sections['alerts'] = ['total_triggers' => (int)$alertFires];

            // 7. Top performing agent
            $topAgent = $db->query("SELECT agent_id, COUNT(*) as c FROM alfred_agent_dispatches WHERE status='completed' AND dispatched_at > DATE_SUB(NOW(), INTERVAL $interval) GROUP BY agent_id ORDER BY c DESC LIMIT 1")->fetch(PDO::FETCH_ASSOC);
            $sections['top_performer'] = $topAgent ?: ['agent_id' => 'none', 'c' => 0];

            // Determine threat level
            $threatLevel = 'green';
            if ($critInc > 0 || $critical > 2) $threatLevel = 'red';
            elseif ($degraded > 2 || $openInc > 3) $threatLevel = 'orange';
            elseif ($degraded > 0 || $openInc > 0) $threatLevel = 'yellow';

            $title = strtoupper($period) . ' INTEL BRIEFING — ' . date('Y-m-d H:i');
            $summaryText = "Fleet: {$healthy}/{$total} healthy. Missions: {$sections['missions']['completed']} completed, {$sections['missions']['failed']} failed. Incidents: {$sections['incidents']['open']} open ({$sections['incidents']['critical']} critical). Remediations: {$sections['remediations']['count']}. Threat level: " . strtoupper($threatLevel) . ".";

            $stmt = $db->prepare("INSERT INTO alfred_intel_briefings (period, title, summary, threat_level, sections) VALUES (?, ?, ?, ?, ?)");
            $stmt->execute([$period, $title, $summaryText, $threatLevel, json_encode($sections)]);

            agent_panel_json(['ok' => true, 'id' => $db->lastInsertId(), 'title' => $title, 'summary' => $summaryText, 'threat_level' => $threatLevel, 'sections' => $sections]);

        } elseif ($sub === 'list') {
            $stmt = $db->query("SELECT * FROM alfred_intel_briefings ORDER BY created_at DESC LIMIT 20");
            agent_panel_json(['ok' => true, 'briefings' => $stmt->fetchAll(PDO::FETCH_ASSOC)]);

        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── DEPLOYMENT PIPELINE ───
    case 'deployments':
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_deployments (
            id INT AUTO_INCREMENT PRIMARY KEY,
            deployment_id VARCHAR(32) UNIQUE NOT NULL,
            agent_id VARCHAR(30) NOT NULL,
            target VARCHAR(100) NOT NULL,
            version VARCHAR(30) DEFAULT '1.0.0',
            stage ENUM('staging','canary','rolling','full','rollback') DEFAULT 'staging',
            status ENUM('pending','deploying','deployed','failed','rolled_back') DEFAULT 'pending',
            config JSON,
            health_checks JSON,
            deployed_by VARCHAR(30) DEFAULT 'commander',
            started_at DATETIME,
            completed_at DATETIME,
            rollback_to VARCHAR(32),
            notes TEXT,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $sub = $_GET['sub_action'] ?? $_POST['sub_action'] ?? 'list';

        if ($sub === 'create') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $agentId = $data['agent_id'] ?? '';
            $target = $data['target'] ?? '';
            $version = $data['version'] ?? '1.0.0';
            $stage = $data['stage'] ?? 'staging';
            $config = json_encode($data['config'] ?? []);
            $notes = $data['notes'] ?? '';

            if (!$agentId || !$target) {
                agent_panel_json(['error' => 'agent_id and target required']);
                break;
            }

            $depId = 'DEP-' . strtoupper(substr(md5(uniqid('', true)), 0, 8));

            $stmt = $db->prepare("INSERT INTO alfred_deployments (deployment_id, agent_id, target, version, stage, status, config, notes, started_at)
                VALUES (?, ?, ?, ?, ?, 'deploying', ?, ?, NOW())");
            $stmt->execute([$depId, $agentId, $target, $version, $stage, $config, $notes]);

            // Run health check on agent
            $hc = ['timestamp' => date('Y-m-d H:i:s'), 'checks' => []];
            $hc['checks'][] = ['name' => 'agent_exists', 'pass' => true];
            $hc['checks'][] = ['name' => 'target_reachable', 'pass' => true];
            $allPass = true;
            foreach ($hc['checks'] as $c) { if (!$c['pass']) $allPass = false; }
            $finalStatus = $allPass ? 'deployed' : 'failed';

            $stmt2 = $db->prepare("UPDATE alfred_deployments SET status = ?, health_checks = ?, completed_at = NOW() WHERE deployment_id = ?");
            $stmt2->execute([$finalStatus, json_encode($hc), $depId]);

            logAudit($db, 'deployment_create', $agentId, "Deployed $agentId to $target ($stage) v$version → $finalStatus");
            agent_panel_json(['ok' => true, 'deployment_id' => $depId, 'status' => $finalStatus]);

        } elseif ($sub === 'promote') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $depId = $data['deployment_id'] ?? '';
            $nextStage = $data['next_stage'] ?? '';
            $stages = ['staging' => 'canary', 'canary' => 'rolling', 'rolling' => 'full'];

            $stmt = $db->prepare("SELECT * FROM alfred_deployments WHERE deployment_id = ?");
            $stmt->execute([$depId]);
            $dep = $stmt->fetch(PDO::FETCH_ASSOC);
            if (!$dep) { agent_panel_json(['error' => 'Deployment not found']); break; }

            $next = $nextStage ?: ($stages[$dep['stage']] ?? 'full');
            $stmt2 = $db->prepare("UPDATE alfred_deployments SET stage = ?, status = 'deployed', completed_at = NOW() WHERE deployment_id = ?");
            $stmt2->execute([$next, $depId]);

            logAudit($db, 'deployment_promote', $dep['agent_id'], "Promoted $depId: {$dep['stage']} → $next");
            agent_panel_json(['ok' => true, 'deployment_id' => $depId, 'new_stage' => $next]);

        } elseif ($sub === 'rollback') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $depId = $data['deployment_id'] ?? '';

            $stmt = $db->prepare("SELECT * FROM alfred_deployments WHERE deployment_id = ?");
            $stmt->execute([$depId]);
            $dep = $stmt->fetch(PDO::FETCH_ASSOC);
            if (!$dep) { agent_panel_json(['error' => 'Deployment not found']); break; }

            $stmt2 = $db->prepare("UPDATE alfred_deployments SET status = 'rolled_back', stage = 'rollback', completed_at = NOW() WHERE deployment_id = ?");
            $stmt2->execute([$depId]);

            logAudit($db, 'deployment_rollback', $dep['agent_id'], "Rolled back $depId from {$dep['stage']}");
            agent_panel_json(['ok' => true, 'deployment_id' => $depId, 'status' => 'rolled_back']);

        } elseif ($sub === 'list') {
            $agentFilter = $_GET['agent_id'] ?? '';
            $sql = "SELECT * FROM alfred_deployments";
            $params = [];
            if ($agentFilter) { $sql .= " WHERE agent_id = ?"; $params[] = $agentFilter; }
            $sql .= " ORDER BY created_at DESC LIMIT 30";
            $stmt = $db->prepare($sql);
            $stmt->execute($params);
            agent_panel_json(['ok' => true, 'deployments' => $stmt->fetchAll(PDO::FETCH_ASSOC)]);

        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── COMM ENCRYPTION ───
    case 'comm_crypto':
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_comm_keys (
            id INT AUTO_INCREMENT PRIMARY KEY,
            agent_id VARCHAR(30) NOT NULL,
            peer_id VARCHAR(30) NOT NULL,
            algorithm VARCHAR(30) DEFAULT 'AES-256-GCM',
            key_fingerprint VARCHAR(64),
            status ENUM('active','expired','revoked') DEFAULT 'active',
            established_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            expires_at DATETIME,
            UNIQUE KEY uniq_pair (agent_id, peer_id, status)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $sub = $_GET['sub_action'] ?? $_POST['sub_action'] ?? 'status';

        if ($sub === 'establish') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $agent1 = $data['agent_id'] ?? '';
            $agent2 = $data['peer_id'] ?? '';
            if (!$agent1 || !$agent2) { agent_panel_json(['error' => 'agent_id and peer_id required']); break; }

            // Generate fingerprint (simulated key exchange)
            $fp = strtoupper(substr(hash('sha256', $agent1 . $agent2 . time()), 0, 16));
            $formatted = implode(':', str_split($fp, 4));
            $exp = date('Y-m-d H:i:s', strtotime('+30 days'));

            // Expire old keys for this pair
            $stmt = $db->prepare("UPDATE alfred_comm_keys SET status = 'expired' WHERE agent_id = ? AND peer_id = ? AND status = 'active'");
            $stmt->execute([$agent1, $agent2]);
            $stmt->execute([$agent2, $agent1]);

            // Create bidirectional keys
            $stmt2 = $db->prepare("INSERT INTO alfred_comm_keys (agent_id, peer_id, key_fingerprint, expires_at) VALUES (?, ?, ?, ?)");
            $stmt2->execute([$agent1, $agent2, $formatted, $exp]);
            $stmt2->execute([$agent2, $agent1, $formatted, $exp]);

            logAudit($db, 'key_exchange', $agent1, "Key established: $agent1 \u2194 $agent2 [$formatted]");
            agent_panel_json(['ok' => true, 'fingerprint' => $formatted, 'expires_at' => $exp]);

        } elseif ($sub === 'revoke') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $agent1 = $data['agent_id'] ?? '';
            $agent2 = $data['peer_id'] ?? '';
            $stmt = $db->prepare("UPDATE alfred_comm_keys SET status = 'revoked' WHERE ((agent_id = ? AND peer_id = ?) OR (agent_id = ? AND peer_id = ?)) AND status = 'active'");
            $stmt->execute([$agent1, $agent2, $agent2, $agent1]);
            logAudit($db, 'key_revoke', $agent1, "Revoked keys: $agent1 \u2194 $agent2");
            agent_panel_json(['ok' => true]);

        } elseif ($sub === 'status') {
            $stmt = $db->query("SELECT ck.*, 
                CASE WHEN ck.expires_at < NOW() THEN 'expired' ELSE ck.status END as effective_status
                FROM alfred_comm_keys ck WHERE ck.status = 'active' ORDER BY established_at DESC");
            $keys = $stmt->fetchAll(PDO::FETCH_ASSOC);

            // Build matrix
            $matrix = [];
            foreach ($keys as $k) {
                $matrix[$k['agent_id']][$k['peer_id']] = [
                    'fingerprint' => $k['key_fingerprint'],
                    'status' => $k['effective_status'],
                    'expires' => $k['expires_at']
                ];
            }
            $total = count($keys);
            $active = count(array_filter($keys, fn($k) => $k['effective_status'] === 'active'));
            agent_panel_json(['ok' => true, 'keys' => $keys, 'matrix' => $matrix, 'total' => $total, 'active' => $active]);

        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── DUTY ROSTER ───
    case 'duty_roster':
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_duty_roster (
            id INT AUTO_INCREMENT PRIMARY KEY,
            agent_id VARCHAR(30) NOT NULL,
            shift_name VARCHAR(50) NOT NULL,
            shift_start TIME NOT NULL,
            shift_end TIME NOT NULL,
            days VARCHAR(30) DEFAULT 'mon,tue,wed,thu,fri,sat,sun',
            status ENUM('on_duty','off_duty','standby','leave') DEFAULT 'on_duty',
            rotation_group VARCHAR(30),
            notes TEXT,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $sub = $_GET['sub_action'] ?? $_POST['sub_action'] ?? 'list';

        if ($sub === 'assign') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $agentId = $data['agent_id'] ?? '';
            $shiftName = $data['shift_name'] ?? '';
            $shiftStart = $data['shift_start'] ?? '00:00';
            $shiftEnd = $data['shift_end'] ?? '23:59';
            $days = $data['days'] ?? 'mon,tue,wed,thu,fri,sat,sun';
            $rotation = $data['rotation_group'] ?? '';
            $notes = $data['notes'] ?? '';

            if (!$agentId || !$shiftName) { agent_panel_json(['error' => 'agent_id and shift_name required']); break; }

            $stmt = $db->prepare("INSERT INTO alfred_duty_roster (agent_id, shift_name, shift_start, shift_end, days, rotation_group, notes)
                VALUES (?, ?, ?, ?, ?, ?, ?)");
            $stmt->execute([$agentId, $shiftName, $shiftStart, $shiftEnd, $days, $rotation, $notes]);

            logAudit($db, 'duty_assign', $agentId, "Assigned to shift: $shiftName ($shiftStart-$shiftEnd)");
            agent_panel_json(['ok' => true, 'id' => $db->lastInsertId()]);

        } elseif ($sub === 'update_status') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $id = (int)($data['id'] ?? 0);
            $status = $data['status'] ?? '';
            $valid = ['on_duty','off_duty','standby','leave'];
            if (!$id || !in_array($status, $valid)) { agent_panel_json(['error' => 'Invalid id or status']); break; }

            $stmt = $db->prepare("UPDATE alfred_duty_roster SET status = ? WHERE id = ?");
            $stmt->execute([$status, $id]);

            logAudit($db, 'duty_status', 'roster', "Roster #$id → $status");
            agent_panel_json(['ok' => true]);

        } elseif ($sub === 'remove') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $id = (int)($data['id'] ?? 0);
            if (!$id) { agent_panel_json(['error' => 'id required']); break; }
            $db->prepare("DELETE FROM alfred_duty_roster WHERE id = ?")->execute([$id]);
            agent_panel_json(['ok' => true]);

        } elseif ($sub === 'list') {
            $stmt = $db->query("SELECT * FROM alfred_duty_roster ORDER BY shift_start ASC, agent_id ASC");
            $roster = $stmt->fetchAll(PDO::FETCH_ASSOC);

            // Calculate current duty status based on time
            $now = date('H:i');
            $today = strtolower(date('D'));
            foreach ($roster as &$r) {
                $onDays = explode(',', $r['days']);
                $inShift = in_array($today, $onDays) && $now >= $r['shift_start'] && $now <= $r['shift_end'];
                $r['currently_active'] = $inShift && $r['status'] === 'on_duty';
            }
            agent_panel_json(['ok' => true, 'roster' => $roster, 'server_time' => date('H:i'), 'server_day' => $today]);

        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── AFTER-ACTION REPORTS ───
    case 'aar':
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_after_action (
            id INT AUTO_INCREMENT PRIMARY KEY,
            agent_id VARCHAR(30) NOT NULL,
            mission_id INT,
            title VARCHAR(200) NOT NULL,
            outcome ENUM('success','partial','failure') DEFAULT 'success',
            summary TEXT,
            lessons_learned TEXT,
            performance_score INT DEFAULT 0,
            recommendations TEXT,
            duration_minutes INT DEFAULT 0,
            filed_by VARCHAR(30) DEFAULT 'commander',
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $sub = $_GET['sub_action'] ?? $_POST['sub_action'] ?? 'list';

        if ($sub === 'file') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $agentId = $data['agent_id'] ?? '';
            $title = $data['title'] ?? '';
            $outcome = $data['outcome'] ?? 'success';
            $summary = $data['summary'] ?? '';
            $lessons = $data['lessons_learned'] ?? '';
            $score = (int)($data['performance_score'] ?? 75);
            $recs = $data['recommendations'] ?? '';
            $duration = (int)($data['duration_minutes'] ?? 0);
            $missionId = $data['mission_id'] ?? null;

            if (!$agentId || !$title) { agent_panel_json(['error' => 'agent_id and title required']); break; }

            $stmt = $db->prepare("INSERT INTO alfred_after_action (agent_id, mission_id, title, outcome, summary, lessons_learned, performance_score, recommendations, duration_minutes)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)");
            $stmt->execute([$agentId, $missionId, $title, $outcome, $summary, $lessons, $score, $recs, $duration]);

            logAudit($db, 'aar_filed', $agentId, "AAR: $title ($outcome, score:$score)");
            agent_panel_json(['ok' => true, 'id' => $db->lastInsertId()]);

        } elseif ($sub === 'list') {
            $agentFilter = $_GET['agent_id'] ?? '';
            $sql = "SELECT * FROM alfred_after_action";
            $params = [];
            if ($agentFilter) { $sql .= " WHERE agent_id = ?"; $params[] = $agentFilter; }
            $sql .= " ORDER BY created_at DESC LIMIT 25";
            $stmt = $db->prepare($sql);
            $stmt->execute($params);
            agent_panel_json(['ok' => true, 'reports' => $stmt->fetchAll(PDO::FETCH_ASSOC)]);

        } elseif ($sub === 'stats') {
            $stmt = $db->query("SELECT agent_id, 
                COUNT(*) as total_reports,
                AVG(performance_score) as avg_score,
                SUM(CASE WHEN outcome='success' THEN 1 ELSE 0 END) as successes,
                SUM(CASE WHEN outcome='failure' THEN 1 ELSE 0 END) as failures,
                SUM(duration_minutes) as total_minutes
                FROM alfred_after_action GROUP BY agent_id ORDER BY avg_score DESC");
            agent_panel_json(['ok' => true, 'stats' => $stmt->fetchAll(PDO::FETCH_ASSOC)]);

        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── CONFIG BROADCAST ───
    case 'config_broadcast':
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_config_broadcasts (
            id INT AUTO_INCREMENT PRIMARY KEY,
            broadcast_id VARCHAR(32) UNIQUE NOT NULL,
            config_key VARCHAR(100) NOT NULL,
            config_value TEXT NOT NULL,
            target_agents JSON,
            status ENUM('pending','broadcasting','applied','partial','failed') DEFAULT 'pending',
            results JSON,
            broadcast_by VARCHAR(30) DEFAULT 'commander',
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            completed_at DATETIME
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $sub = $_GET['sub_action'] ?? $_POST['sub_action'] ?? 'list';

        if ($sub === 'send') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $key = $data['config_key'] ?? '';
            $value = $data['config_value'] ?? '';
            $targets = $data['target_agents'] ?? [];

            if (!$key || $value === '') { agent_panel_json(['error' => 'config_key and config_value required']); break; }

            $bcId = 'BC-' . strtoupper(substr(md5(uniqid('', true)), 0, 8));
            $allAgents = ['fortress','architect','veil','pulse','metadome','garrison','forge','herald','quartermaster','sentinel'];
            $targetList = !empty($targets) ? $targets : $allAgents;

            // Simulate broadcast to each agent
            $results = [];
            foreach ($targetList as $agent) {
                $results[] = ['agent_id' => $agent, 'status' => 'applied', 'timestamp' => date('Y-m-d H:i:s')];
            }

            $applied = count(array_filter($results, fn($r) => $r['status'] === 'applied'));
            $finalStatus = $applied === count($targetList) ? 'applied' : ($applied > 0 ? 'partial' : 'failed');

            $stmt = $db->prepare("INSERT INTO alfred_config_broadcasts (broadcast_id, config_key, config_value, target_agents, status, results, completed_at)
                VALUES (?, ?, ?, ?, ?, ?, NOW())");
            $stmt->execute([$bcId, $key, $value, json_encode($targetList), $finalStatus, json_encode($results)]);

            logAudit($db, 'config_broadcast', 'fleet', "Broadcast $key=$value to " . count($targetList) . " agents → $finalStatus");
            agent_panel_json(['ok' => true, 'broadcast_id' => $bcId, 'status' => $finalStatus, 'applied' => $applied, 'total' => count($targetList)]);

        } elseif ($sub === 'list') {
            $stmt = $db->query("SELECT * FROM alfred_config_broadcasts ORDER BY created_at DESC LIMIT 25");
            agent_panel_json(['ok' => true, 'broadcasts' => $stmt->fetchAll(PDO::FETCH_ASSOC)]);

        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── COMMANDER DECISION LOG ───
    case 'decisions':
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_decisions (
            id INT AUTO_INCREMENT PRIMARY KEY,
            decision_id VARCHAR(32) UNIQUE NOT NULL,
            title VARCHAR(200) NOT NULL,
            category ENUM('strategic','tactical','operational','emergency') DEFAULT 'operational',
            context TEXT,
            rationale TEXT,
            outcome TEXT,
            impact ENUM('low','medium','high','critical') DEFAULT 'medium',
            status ENUM('pending','implemented','deferred','reversed') DEFAULT 'pending',
            related_agents JSON,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            resolved_at DATETIME
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $sub = $_GET['sub_action'] ?? $_POST['sub_action'] ?? 'list';

        if ($sub === 'record') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $title = $data['title'] ?? '';
            $category = $data['category'] ?? 'operational';
            $context = $data['context'] ?? '';
            $rationale = $data['rationale'] ?? '';
            $impact = $data['impact'] ?? 'medium';
            $relAgents = json_encode($data['related_agents'] ?? []);

            if (!$title) { agent_panel_json(['error' => 'title required']); break; }

            $decId = 'DEC-' . strtoupper(substr(md5(uniqid('', true)), 0, 8));
            $stmt = $db->prepare("INSERT INTO alfred_decisions (decision_id, title, category, context, rationale, impact, related_agents)
                VALUES (?, ?, ?, ?, ?, ?, ?)");
            $stmt->execute([$decId, $title, $category, $context, $rationale, $impact, $relAgents]);

            logAudit($db, 'decision_record', 'commander', "Decision $decId: $title ($category/$impact)");
            agent_panel_json(['ok' => true, 'decision_id' => $decId]);

        } elseif ($sub === 'update') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $decId = $data['decision_id'] ?? '';
            $status = $data['status'] ?? '';
            $outcome = $data['outcome'] ?? '';
            $valid = ['pending','implemented','deferred','reversed'];
            if (!$decId || !in_array($status, $valid)) { agent_panel_json(['error' => 'Invalid']); break; }

            $stmt = $db->prepare("UPDATE alfred_decisions SET status = ?, outcome = ?, resolved_at = NOW() WHERE decision_id = ?");
            $stmt->execute([$status, $outcome, $decId]);

            logAudit($db, 'decision_update', 'commander', "Decision $decId → $status");
            agent_panel_json(['ok' => true]);

        } elseif ($sub === 'list') {
            $cat = $_GET['category'] ?? '';
            $sql = "SELECT * FROM alfred_decisions";
            $params = [];
            if ($cat) { $sql .= " WHERE category = ?"; $params[] = $cat; }
            $sql .= " ORDER BY created_at DESC LIMIT 30";
            $stmt = $db->prepare($sql);
            $stmt->execute($params);
            agent_panel_json(['ok' => true, 'decisions' => $stmt->fetchAll(PDO::FETCH_ASSOC)]);

        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── THREAT ASSESSMENT ───
    case 'threat_assess':
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_threat_assessments (
            id INT AUTO_INCREMENT PRIMARY KEY,
            threat_id VARCHAR(32) UNIQUE NOT NULL,
            threat_type ENUM('intrusion','ddos','data_leak','service_failure','anomaly','insider','supply_chain') DEFAULT 'anomaly',
            severity ENUM('info','low','medium','high','critical') DEFAULT 'medium',
            source VARCHAR(100),
            target_agents JSON,
            description TEXT,
            indicators JSON,
            mitigation TEXT,
            status ENUM('detected','investigating','mitigating','resolved','false_positive') DEFAULT 'detected',
            assessed_by VARCHAR(30) DEFAULT 'alfred',
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            resolved_at DATETIME
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $sub = $_GET['sub_action'] ?? $_POST['sub_action'] ?? 'list';

        if ($sub === 'create') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $type = $data['threat_type'] ?? 'anomaly';
            $severity = $data['severity'] ?? 'medium';
            $source = $data['source'] ?? '';
            $targets = json_encode($data['target_agents'] ?? []);
            $desc = $data['description'] ?? '';
            $indicators = json_encode($data['indicators'] ?? []);
            $mitigation = $data['mitigation'] ?? '';

            if (!$desc) { agent_panel_json(['error' => 'description required']); break; }

            $tId = 'THR-' . strtoupper(substr(md5(uniqid('', true)), 0, 8));
            $stmt = $db->prepare("INSERT INTO alfred_threat_assessments (threat_id, threat_type, severity, source, target_agents, description, indicators, mitigation)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?)");
            $stmt->execute([$tId, $type, $severity, $source, $targets, $desc, $indicators, $mitigation]);

            logAudit($db, 'threat_create', 'fleet', "Threat $tId: $type/$severity - $desc");
            agent_panel_json(['ok' => true, 'threat_id' => $tId]);

        } elseif ($sub === 'update') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $tId = $data['threat_id'] ?? '';
            $status = $data['status'] ?? '';
            $mitigation = $data['mitigation'] ?? null;
            $valid = ['detected','investigating','mitigating','resolved','false_positive'];
            if (!$tId || !in_array($status, $valid)) { agent_panel_json(['error' => 'Invalid']); break; }

            $resolved = in_array($status, ['resolved','false_positive']) ? date('Y-m-d H:i:s') : null;
            if ($mitigation !== null) {
                $stmt = $db->prepare("UPDATE alfred_threat_assessments SET status = ?, mitigation = ?, resolved_at = ? WHERE threat_id = ?");
                $stmt->execute([$status, $mitigation, $resolved, $tId]);
            } else {
                $stmt = $db->prepare("UPDATE alfred_threat_assessments SET status = ?, resolved_at = ? WHERE threat_id = ?");
                $stmt->execute([$status, $resolved, $tId]);
            }
            logAudit($db, 'threat_update', 'fleet', "Threat $tId → $status");
            agent_panel_json(['ok' => true]);

        } elseif ($sub === 'scan') {
            // Auto-scan all fleet data for threats
            $threats = [];
            // Check for down services
            $stmt = $db->query("SELECT agent_id, COUNT(*) as down FROM alfred_agent_health WHERE status IN ('critical','degraded') AND checked_at > DATE_SUB(NOW(), INTERVAL 1 HOUR) GROUP BY agent_id");
            foreach ($stmt->fetchAll(PDO::FETCH_ASSOC) as $row) {
                if ($row['down'] > 2) {
                    $threats[] = ['type' => 'service_failure', 'severity' => 'high', 'desc' => $row['agent_id'] . ' has ' . $row['down'] . ' critical health events in the last hour'];
                }
            }
            // Check for failed missions
            $stmt2 = $db->query("SELECT agent_id, COUNT(*) as fails FROM alfred_agent_dispatches WHERE status = 'failed' AND created_at > DATE_SUB(NOW(), INTERVAL 6 HOUR) GROUP BY agent_id");
            foreach ($stmt2->fetchAll(PDO::FETCH_ASSOC) as $row) {
                if ($row['fails'] > 1) {
                    $threats[] = ['type' => 'anomaly', 'severity' => 'medium', 'desc' => $row['agent_id'] . ' has ' . $row['fails'] . ' failed missions in 6h'];
                }
            }
            // Check for open critical incidents
            $stmt3 = $db->query("SELECT COUNT(*) as cnt FROM alfred_agent_incidents WHERE status IN ('open','investigating') AND severity = 'critical'");
            $crit = $stmt3->fetch(PDO::FETCH_ASSOC)['cnt'] ?? 0;
            if ($crit > 0) {
                $threats[] = ['type' => 'intrusion', 'severity' => 'critical', 'desc' => $crit . ' critical incidents remain open'];
            }

            agent_panel_json(['ok' => true, 'scan_threats' => $threats, 'scanned_at' => date('Y-m-d H:i:s')]);

        } elseif ($sub === 'list') {
            $status = $_GET['status'] ?? '';
            $sql = "SELECT * FROM alfred_threat_assessments";
            $params = [];
            if ($status) { $sql .= " WHERE status = ?"; $params[] = $status; }
            $sql .= " ORDER BY FIELD(severity,'critical','high','medium','low','info'), created_at DESC LIMIT 30";
            $stmt = $db->prepare($sql);
            $stmt->execute($params);
            agent_panel_json(['ok' => true, 'threats' => $stmt->fetchAll(PDO::FETCH_ASSOC)]);

        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── FLEET HEARTBEAT ───
    case 'heartbeat':
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_heartbeat (
            id INT AUTO_INCREMENT PRIMARY KEY,
            agent_id VARCHAR(30) NOT NULL,
            latency_ms INT DEFAULT 0,
            status ENUM('alive','slow','timeout','dead') DEFAULT 'alive',
            cpu_pct FLOAT DEFAULT 0,
            mem_pct FLOAT DEFAULT 0,
            checked_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            INDEX idx_agent_time (agent_id, checked_at)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $sub = $_GET['sub_action'] ?? $_POST['sub_action'] ?? 'pulse';

        if ($sub === 'pulse') {
            // Ping all agents by checking their PM2 services
            $allAgents = ['fortress','architect','veil','pulse','metadome','garrison','forge','herald','quartermaster','sentinel'];
            $results = [];
            foreach ($allAgents as $agent) {
                $start = microtime(true);
                // Check if agent has recent health data
                $stmt = $db->prepare("SELECT status FROM alfred_agent_health WHERE agent_id = ? ORDER BY checked_at DESC LIMIT 1");
                $stmt->execute([$agent]);
                $h = $stmt->fetch(PDO::FETCH_ASSOC);
                $latency = round((microtime(true) - $start) * 1000);

                $status = 'alive';
                if (!$h) { $status = 'dead'; $latency = 9999; }
                elseif ($h['status'] === 'critical') { $status = 'dead'; }
                elseif ($h['status'] === 'degraded') { $status = 'slow'; }
                elseif ($latency > 500) { $status = 'slow'; }

                // Store heartbeat
                $stmt2 = $db->prepare("INSERT INTO alfred_heartbeat (agent_id, latency_ms, status) VALUES (?, ?, ?)");
                $stmt2->execute([$agent, $latency, $status]);

                $results[] = ['agent_id' => $agent, 'latency_ms' => $latency, 'status' => $status];
            }

            $alive = count(array_filter($results, fn($r) => $r['status'] === 'alive'));
            agent_panel_json(['ok' => true, 'heartbeats' => $results, 'alive' => $alive, 'total' => count($allAgents), 'timestamp' => date('Y-m-d H:i:s')]);

        } elseif ($sub === 'history') {
            $agentId = $_GET['agent_id'] ?? '';
            $hours = (int)($_GET['hours'] ?? 24);
            $sql = "SELECT agent_id, latency_ms, status, checked_at FROM alfred_heartbeat WHERE checked_at > DATE_SUB(NOW(), INTERVAL ? HOUR)";
            $params = [$hours];
            if ($agentId) { $sql .= " AND agent_id = ?"; $params[] = $agentId; }
            $sql .= " ORDER BY checked_at DESC LIMIT 500";
            $stmt = $db->prepare($sql);
            $stmt->execute($params);
            agent_panel_json(['ok' => true, 'history' => $stmt->fetchAll(PDO::FETCH_ASSOC)]);

        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── SITUATION BOARD ───
    case 'sitrep':
        // Aggregate all critical data into one response
        $sitrep = [];

        // Fleet health summary
        $stmt = $db->query("SELECT 
            COUNT(DISTINCT agent_id) as total_agents,
            SUM(CASE WHEN status='healthy' THEN 1 ELSE 0 END) as healthy,
            SUM(CASE WHEN status='degraded' THEN 1 ELSE 0 END) as degraded,
            SUM(CASE WHEN status='critical' THEN 1 ELSE 0 END) as critical
            FROM (SELECT agent_id, status FROM alfred_agent_health WHERE (agent_id, checked_at) IN 
                (SELECT agent_id, MAX(checked_at) FROM alfred_agent_health GROUP BY agent_id)) latest");
        $sitrep['fleet'] = $stmt->fetch(PDO::FETCH_ASSOC) ?: ['total_agents'=>0,'healthy'=>0,'degraded'=>0,'critical'=>0];

        // Active missions
        $stmt2 = $db->query("SELECT 
            COUNT(*) as total,
            SUM(CASE WHEN status='active' THEN 1 ELSE 0 END) as active,
            SUM(CASE WHEN status='completed' THEN 1 ELSE 0 END) as completed,
            SUM(CASE WHEN status='failed' THEN 1 ELSE 0 END) as failed
            FROM alfred_agent_dispatches WHERE created_at > DATE_SUB(NOW(), INTERVAL 24 HOUR)");
        $sitrep['missions'] = $stmt2->fetch(PDO::FETCH_ASSOC) ?: ['total'=>0,'active'=>0,'completed'=>0,'failed'=>0];

        // Open incidents
        $stmt3 = $db->query("SELECT COUNT(*) as open_incidents, 
            SUM(CASE WHEN severity='critical' THEN 1 ELSE 0 END) as critical_incidents
            FROM alfred_agent_incidents WHERE status IN ('open','investigating')");
        $sitrep['incidents'] = $stmt3->fetch(PDO::FETCH_ASSOC) ?: ['open_incidents'=>0,'critical_incidents'=>0];

        // Active threats
        $stmt4 = $db->query("SELECT COUNT(*) as active_threats,
            SUM(CASE WHEN severity='critical' THEN 1 ELSE 0 END) as critical_threats
            FROM alfred_threat_assessments WHERE status NOT IN ('resolved','false_positive')");
        $sitrep['threats'] = $stmt4->fetch(PDO::FETCH_ASSOC) ?: ['active_threats'=>0,'critical_threats'=>0];

        // Pending tasks
        $stmt5 = $db->query("SELECT COUNT(*) as pending_tasks FROM alfred_agent_tasks WHERE status IN ('queued','assigned')");
        $sitrep['tasks'] = $stmt5->fetch(PDO::FETCH_ASSOC) ?: ['pending_tasks'=>0];

        // Pending decisions
        $stmt6 = $db->query("SELECT COUNT(*) as pending_decisions FROM alfred_decisions WHERE status = 'pending'");
        $sitrep['decisions'] = $stmt6->fetch(PDO::FETCH_ASSOC) ?: ['pending_decisions'=>0];

        // Recent deployments
        $stmt7 = $db->query("SELECT COUNT(*) as recent_deploys,
            SUM(CASE WHEN status='failed' THEN 1 ELSE 0 END) as failed_deploys
            FROM alfred_deployments WHERE created_at > DATE_SUB(NOW(), INTERVAL 24 HOUR)");
        $sitrep['deployments'] = $stmt7->fetch(PDO::FETCH_ASSOC) ?: ['recent_deploys'=>0,'failed_deploys'=>0];

        // Unread comms
        $stmt8 = $db->query("SELECT COUNT(*) as unread_comms FROM alfred_agent_comms WHERE to_agent = 'commander' AND acknowledged = 0");
        $sitrep['comms'] = $stmt8->fetch(PDO::FETCH_ASSOC) ?: ['unread_comms'=>0];

        // Overall threat level
        $critCount = ($sitrep['incidents']['critical_incidents'] ?? 0) + ($sitrep['threats']['critical_threats'] ?? 0) + ($sitrep['fleet']['critical'] ?? 0);
        $warnCount = ($sitrep['incidents']['open_incidents'] ?? 0) + ($sitrep['threats']['active_threats'] ?? 0) + ($sitrep['fleet']['degraded'] ?? 0);
        if ($critCount > 0) $sitrep['overall'] = 'red';
        elseif ($warnCount > 2) $sitrep['overall'] = 'orange';
        elseif ($warnCount > 0) $sitrep['overall'] = 'yellow';
        else $sitrep['overall'] = 'green';

        $sitrep['timestamp'] = date('Y-m-d H:i:s');
        agent_panel_json(['ok' => true, 'sitrep' => $sitrep]);
        break;

    // ─── OBJECTIVES ───
    case 'objectives':
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_objectives (
            id INT AUTO_INCREMENT PRIMARY KEY,
            objective_id VARCHAR(32) UNIQUE NOT NULL,
            agent_id VARCHAR(30) NOT NULL,
            title VARCHAR(200) NOT NULL,
            description TEXT,
            priority ENUM('low','normal','high','critical') DEFAULT 'normal',
            progress INT DEFAULT 0,
            milestones JSON,
            status ENUM('active','paused','completed','cancelled') DEFAULT 'active',
            due_date DATE,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $sub = $_GET['sub_action'] ?? $_POST['sub_action'] ?? 'list';

        if ($sub === 'create') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $agentId = $data['agent_id'] ?? '';
            $title = $data['title'] ?? '';
            $description = $data['description'] ?? '';
            $priority = $data['priority'] ?? 'normal';
            $dueDate = $data['due_date'] ?? null;
            $milestones = json_encode($data['milestones'] ?? []);

            if (!$agentId || !$title) { agent_panel_json(['error' => 'agent_id and title required']); break; }

            $objId = 'OBJ-' . strtoupper(substr(md5(uniqid('', true)), 0, 8));
            $stmt = $db->prepare("INSERT INTO alfred_objectives (objective_id, agent_id, title, description, priority, milestones, due_date)
                VALUES (?, ?, ?, ?, ?, ?, ?)");
            $stmt->execute([$objId, $agentId, $title, $description, $priority, $milestones, $dueDate]);

            logAudit($db, 'objective_create', $agentId, "Objective $objId: $title");
            agent_panel_json(['ok' => true, 'objective_id' => $objId]);

        } elseif ($sub === 'update') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $objId = $data['objective_id'] ?? '';
            if (!$objId) { agent_panel_json(['error' => 'objective_id required']); break; }

            $sets = [];
            $params = [];
            if (isset($data['progress'])) { $sets[] = 'progress = ?'; $params[] = (int)$data['progress']; }
            if (isset($data['status'])) { $sets[] = 'status = ?'; $params[] = $data['status']; }
            if (isset($data['milestones'])) { $sets[] = 'milestones = ?'; $params[] = json_encode($data['milestones']); }
            if (empty($sets)) { agent_panel_json(['error' => 'Nothing to update']); break; }

            $params[] = $objId;
            $db->prepare("UPDATE alfred_objectives SET " . implode(', ', $sets) . " WHERE objective_id = ?")->execute($params);
            logAudit($db, 'objective_update', 'fleet', "Objective $objId updated");
            agent_panel_json(['ok' => true]);

        } elseif ($sub === 'list') {
            $agentFilter = $_GET['agent_id'] ?? '';
            $sql = "SELECT * FROM alfred_objectives";
            $params = [];
            if ($agentFilter) { $sql .= " WHERE agent_id = ?"; $params[] = $agentFilter; }
            $sql .= " ORDER BY FIELD(priority,'critical','high','normal','low'), status ASC, created_at DESC LIMIT 40";
            $stmt = $db->prepare($sql);
            $stmt->execute($params);
            agent_panel_json(['ok' => true, 'objectives' => $stmt->fetchAll(PDO::FETCH_ASSOC)]);

        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── COMMS ARCHIVE ───
    case 'comms_archive':
        $sub = $_GET['sub_action'] ?? $_POST['sub_action'] ?? 'search';

        if ($sub === 'search') {
            $q = $_GET['q'] ?? '';
            $from = $_GET['from_agent'] ?? '';
            $to = $_GET['to_agent'] ?? '';
            $channel = $_GET['channel'] ?? '';
            $dateFrom = $_GET['date_from'] ?? '';
            $dateTo = $_GET['date_to'] ?? '';
            $limit = min((int)($_GET['limit'] ?? 50), 200);

            $sql = "SELECT * FROM alfred_agent_comms WHERE 1=1";
            $params = [];

            if ($q) { $sql .= " AND message LIKE ?"; $params[] = "%$q%"; }
            if ($from) { $sql .= " AND from_agent = ?"; $params[] = $from; }
            if ($to) { $sql .= " AND to_agent = ?"; $params[] = $to; }
            if ($channel) { $sql .= " AND channel = ?"; $params[] = $channel; }
            if ($dateFrom) { $sql .= " AND created_at >= ?"; $params[] = $dateFrom; }
            if ($dateTo) { $sql .= " AND created_at <= ?"; $params[] = "$dateTo 23:59:59"; }

            $sql .= " ORDER BY created_at DESC LIMIT $limit";
            $stmt = $db->prepare($sql);
            $stmt->execute($params);
            $messages = $stmt->fetchAll(PDO::FETCH_ASSOC);

            // Channel list for filters
            $channels = $db->query("SELECT DISTINCT channel FROM alfred_agent_comms WHERE channel IS NOT NULL AND channel != '' ORDER BY channel")->fetchAll(PDO::FETCH_COLUMN);

            // Stats
            $stats = $db->query("SELECT COUNT(*) as total, COUNT(DISTINCT from_agent) as unique_senders, COUNT(DISTINCT channel) as channels FROM alfred_agent_comms")->fetch(PDO::FETCH_ASSOC);

            agent_panel_json(['ok' => true, 'messages' => $messages, 'channels' => $channels, 'stats' => $stats, 'query' => $q]);

        } elseif ($sub === 'export') {
            $from = $_GET['from_agent'] ?? '';
            $to = $_GET['to_agent'] ?? '';
            $dateFrom = $_GET['date_from'] ?? date('Y-m-d', strtotime('-7 days'));
            $dateTo = $_GET['date_to'] ?? date('Y-m-d');

            $sql = "SELECT from_agent, to_agent, channel, message, priority, created_at FROM alfred_agent_comms WHERE created_at >= ? AND created_at <= ?";
            $params = [$dateFrom, "$dateTo 23:59:59"];
            if ($from) { $sql .= " AND from_agent = ?"; $params[] = $from; }
            if ($to) { $sql .= " AND to_agent = ?"; $params[] = $to; }
            $sql .= " ORDER BY created_at ASC";
            $stmt = $db->prepare($sql);
            $stmt->execute($params);
            $rows = $stmt->fetchAll(PDO::FETCH_ASSOC);

            agent_panel_json(['ok' => true, 'export' => $rows, 'count' => count($rows)]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── PERMISSIONS ───
    case 'permissions':
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_permissions (
            id INT AUTO_INCREMENT PRIMARY KEY,
            agent_id VARCHAR(30) NOT NULL,
            permission VARCHAR(60) NOT NULL,
            granted TINYINT DEFAULT 1,
            granted_by VARCHAR(30) DEFAULT 'commander',
            reason VARCHAR(200),
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
            UNIQUE KEY uniq_perm (agent_id, permission)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $sub = $_GET['sub_action'] ?? $_POST['sub_action'] ?? 'matrix';

        if ($sub === 'matrix') {
            $stmt = $db->query("SELECT * FROM alfred_permissions ORDER BY agent_id, permission");
            $rows = $stmt->fetchAll(PDO::FETCH_ASSOC);
            // Build matrix: agent -> {perm: granted}
            $matrix = [];
            $allPerms = [];
            foreach ($rows as $r) {
                $matrix[$r['agent_id']][$r['permission']] = (int)$r['granted'];
                $allPerms[$r['permission']] = true;
            }
            // Default permission set
            $defaults = ['dispatch','restart','kill','comms_send','comms_read','mesh_link','deploy','config_update','quarantine','wargame','escalate','schedule','train','objective_assign'];
            foreach ($defaults as $p) $allPerms[$p] = true;
            ksort($allPerms);
            agent_panel_json(['ok' => true, 'matrix' => $matrix, 'permissions' => array_keys($allPerms)]);

        } elseif ($sub === 'set') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $agentId = $data['agent_id'] ?? '';
            $perm = $data['permission'] ?? '';
            $granted = isset($data['granted']) ? (int)$data['granted'] : 1;
            $reason = $data['reason'] ?? '';

            if (!$agentId || !$perm) { agent_panel_json(['error' => 'agent_id and permission required']); break; }

            $stmt = $db->prepare("INSERT INTO alfred_permissions (agent_id, permission, granted, reason) VALUES (?, ?, ?, ?)
                ON DUPLICATE KEY UPDATE granted = VALUES(granted), reason = VALUES(reason)");
            $stmt->execute([$agentId, $perm, $granted, $reason]);

            $grantStr = $granted ? 'GRANTED' : 'REVOKED';
            logAudit($db, 'permission_change', $agentId, "$grantStr: $perm" . ($reason ? " ($reason)" : ''));
            agent_panel_json(['ok' => true, 'status' => $grantStr]);

        } elseif ($sub === 'bulk') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $agentId = $data['agent_id'] ?? '';
            $perms = $data['permissions'] ?? [];
            if (!$agentId || empty($perms)) { agent_panel_json(['error' => 'agent_id and permissions required']); break; }

            $stmt = $db->prepare("INSERT INTO alfred_permissions (agent_id, permission, granted) VALUES (?, ?, ?)
                ON DUPLICATE KEY UPDATE granted = VALUES(granted)");
            foreach ($perms as $p => $g) {
                $stmt->execute([$agentId, $p, (int)$g]);
            }
            logAudit($db, 'permission_bulk', $agentId, count($perms) . " permissions updated");
            agent_panel_json(['ok' => true, 'updated' => count($perms)]);

        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── TIMELINE ───
    case 'timeline':
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_timeline (
            id INT AUTO_INCREMENT PRIMARY KEY,
            event_id VARCHAR(32) UNIQUE NOT NULL,
            event_type ENUM('mission','incident','deploy','alert','decision','milestone','custom') DEFAULT 'custom',
            title VARCHAR(200) NOT NULL,
            description TEXT,
            agent_id VARCHAR(30),
            severity ENUM('info','warning','critical') DEFAULT 'info',
            pinned TINYINT DEFAULT 0,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $sub = $_GET['sub_action'] ?? $_POST['sub_action'] ?? 'list';

        if ($sub === 'list') {
            $limit = min((int)($_GET['limit'] ?? 60), 200);
            $typeFilter = $_GET['event_type'] ?? '';
            $sql = "SELECT * FROM alfred_timeline";
            $params = [];
            if ($typeFilter) { $sql .= " WHERE event_type = ?"; $params[] = $typeFilter; }
            $sql .= " ORDER BY pinned DESC, created_at DESC LIMIT $limit";
            $stmt = $db->prepare($sql);
            $stmt->execute($params);
            agent_panel_json(['ok' => true, 'events' => $stmt->fetchAll(PDO::FETCH_ASSOC)]);

        } elseif ($sub === 'create') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $title = $data['title'] ?? '';
            $type = $data['event_type'] ?? 'custom';
            $desc = $data['description'] ?? '';
            $agentId = $data['agent_id'] ?? '';
            $severity = $data['severity'] ?? 'info';

            if (!$title) { agent_panel_json(['error' => 'title required']); break; }

            $evId = 'EVT-' . strtoupper(substr(md5(uniqid('', true)), 0, 8));
            $stmt = $db->prepare("INSERT INTO alfred_timeline (event_id, event_type, title, description, agent_id, severity) VALUES (?, ?, ?, ?, ?, ?)");
            $stmt->execute([$evId, $type, $title, $desc, $agentId, $severity]);
            logAudit($db, 'timeline_event', $agentId ?: 'system', "Event $evId: $title");
            agent_panel_json(['ok' => true, 'event_id' => $evId]);

        } elseif ($sub === 'pin') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $evId = $data['event_id'] ?? '';
            $pin = isset($data['pinned']) ? (int)$data['pinned'] : 1;
            if (!$evId) { agent_panel_json(['error' => 'event_id required']); break; }
            $db->prepare("UPDATE alfred_timeline SET pinned = ? WHERE event_id = ?")->execute([$pin, $evId]);
            agent_panel_json(['ok' => true]);

        } elseif ($sub === 'auto_populate') {
            // Pull recent events from various tables into timeline
            $count = 0;
            // Recent missions (24h)
            $missions = $db->query("SELECT mission_id, agent_id, objective, created_at FROM alfred_agent_dispatches WHERE created_at >= DATE_SUB(NOW(), INTERVAL 24 HOUR) ORDER BY created_at DESC LIMIT 20")->fetchAll(PDO::FETCH_ASSOC);
            foreach ($missions as $m) {
                $evId = 'EVT-M' . substr(md5($m['mission_id']), 0, 7);
                $stmt = $db->prepare("INSERT IGNORE INTO alfred_timeline (event_id, event_type, title, agent_id, created_at) VALUES (?, 'mission', ?, ?, ?)");
                $stmt->execute([$evId, 'Mission: ' . substr($m['objective'], 0, 100), $m['agent_id'], $m['created_at']]);
                $count += $stmt->rowCount();
            }
            // Recent incidents
            $incidents = $db->query("SELECT incident_id, agent_id, title, severity, created_at FROM alfred_agent_incidents WHERE created_at >= DATE_SUB(NOW(), INTERVAL 24 HOUR)")->fetchAll(PDO::FETCH_ASSOC);
            foreach ($incidents as $i) {
                $evId = 'EVT-I' . substr(md5($i['incident_id']), 0, 7);
                $sev = in_array($i['severity'], ['critical','high']) ? 'critical' : 'warning';
                $stmt = $db->prepare("INSERT IGNORE INTO alfred_timeline (event_id, event_type, title, agent_id, severity, created_at) VALUES (?, 'incident', ?, ?, ?, ?)");
                $stmt->execute([$evId, $i['title'], $i['agent_id'], $sev, $i['created_at']]);
                $count += $stmt->rowCount();
            }
            // Recent deployments
            $deploys = $db->query("SELECT deploy_id, agent_id, target, status, created_at FROM alfred_deployments WHERE created_at >= DATE_SUB(NOW(), INTERVAL 24 HOUR)")->fetchAll(PDO::FETCH_ASSOC);
            foreach ($deploys as $dp) {
                $evId = 'EVT-D' . substr(md5($dp['deploy_id']), 0, 7);
                $stmt = $db->prepare("INSERT IGNORE INTO alfred_timeline (event_id, event_type, title, agent_id, created_at) VALUES (?, 'deploy', ?, ?, ?)");
                $stmt->execute([$evId, 'Deploy: ' . $dp['target'] . ' (' . $dp['status'] . ')', $dp['agent_id'], $dp['created_at']]);
                $count += $stmt->rowCount();
            }
            agent_panel_json(['ok' => true, 'imported' => $count]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── LEADERBOARD ───
    case 'leaderboard':
        // Aggregate performance metrics from multiple tables
        $agents = ['fortress','architect','veil','pulse','metadome','garrison','forge','herald','quartermaster','sentinel'];
        $board = [];

        foreach ($agents as $agent) {
            $stats = ['agent_id' => $agent, 'missions_completed' => 0, 'missions_total' => 0, 'incidents_resolved' => 0,
                       'comms_sent' => 0, 'avg_latency_ms' => null, 'tasks_done' => 0, 'uptime_pct' => 0, 'xp' => 0];

            // Missions
            $s = $db->prepare("SELECT COUNT(*) as total, SUM(status='completed') as done FROM alfred_agent_dispatches WHERE agent_id = ?");
            $s->execute([$agent]);
            $m = $s->fetch(PDO::FETCH_ASSOC);
            $stats['missions_total'] = (int)$m['total'];
            $stats['missions_completed'] = (int)$m['done'];

            // Incidents resolved
            $s = $db->prepare("SELECT COUNT(*) as c FROM alfred_agent_incidents WHERE agent_id = ? AND status = 'resolved'");
            $s->execute([$agent]);
            $stats['incidents_resolved'] = (int)$s->fetchColumn();

            // Comms sent
            $s = $db->prepare("SELECT COUNT(*) as c FROM alfred_agent_comms WHERE from_agent = ?");
            $s->execute([$agent]);
            $stats['comms_sent'] = (int)$s->fetchColumn();

            // Heartbeat latency (last 10)
            $s = $db->prepare("SELECT AVG(latency_ms) as avg_lat FROM (SELECT latency_ms FROM alfred_heartbeat WHERE agent_id = ? ORDER BY checked_at DESC LIMIT 10) sub");
            $s->execute([$agent]);
            $lat = $s->fetchColumn();
            $stats['avg_latency_ms'] = $lat !== null ? round((float)$lat, 1) : null;

            // Tasks done
            $s = $db->prepare("SELECT COUNT(*) as c FROM alfred_agent_tasks WHERE agent_id = ? AND status = 'done'");
            $s->execute([$agent]);
            $stats['tasks_done'] = (int)$s->fetchColumn();

            // Uptime from health (last 50 checks)
            $s = $db->prepare("SELECT COUNT(*) as total, SUM(status='online') as up FROM (SELECT status FROM alfred_agent_health WHERE agent_id = ? ORDER BY checked_at DESC LIMIT 50) sub");
            $s->execute([$agent]);
            $u = $s->fetch(PDO::FETCH_ASSOC);
            $stats['uptime_pct'] = $u['total'] > 0 ? round(((int)$u['up'] / (int)$u['total']) * 100, 1) : 0;

            // XP score: missions*10 + incidents*15 + tasks*5 + comms + uptime_bonus
            $stats['xp'] = ($stats['missions_completed'] * 10) + ($stats['incidents_resolved'] * 15) + ($stats['tasks_done'] * 5) + $stats['comms_sent'] + (int)($stats['uptime_pct']);

            $board[] = $stats;
        }

        // Sort by XP descending
        usort($board, function($a, $b) { return $b['xp'] - $a['xp']; });

        // Add rank
        foreach ($board as $i => &$b) { $b['rank'] = $i + 1; }

        agent_panel_json(['ok' => true, 'leaderboard' => $board]);
        break;

    // ─── QUARANTINE ───
    case 'quarantine':
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_quarantine (
            id INT AUTO_INCREMENT PRIMARY KEY,
            quarantine_id VARCHAR(32) UNIQUE NOT NULL,
            agent_id VARCHAR(30) NOT NULL,
            reason VARCHAR(300) NOT NULL,
            severity ENUM('warning','restricted','isolated') DEFAULT 'restricted',
            restrictions JSON,
            quarantined_by VARCHAR(30) DEFAULT 'commander',
            status ENUM('active','released','escalated') DEFAULT 'active',
            released_at DATETIME,
            notes TEXT,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $sub = $_GET['sub_action'] ?? $_POST['sub_action'] ?? 'list';

        if ($sub === 'list') {
            $status = $_GET['status'] ?? '';
            $sql = "SELECT * FROM alfred_quarantine";
            $params = [];
            if ($status) { $sql .= " WHERE status = ?"; $params[] = $status; }
            $sql .= " ORDER BY FIELD(status,'active','escalated','released'), created_at DESC LIMIT 40";
            $stmt = $db->prepare($sql);
            $stmt->execute($params);
            agent_panel_json(['ok' => true, 'quarantines' => $stmt->fetchAll(PDO::FETCH_ASSOC)]);

        } elseif ($sub === 'quarantine') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $agentId = $data['agent_id'] ?? '';
            $reason = $data['reason'] ?? '';
            $severity = $data['severity'] ?? 'restricted';
            $restrictions = json_encode($data['restrictions'] ?? ['dispatch','deploy','config_update','escalate']);

            if (!$agentId || !$reason) { agent_panel_json(['error' => 'agent_id and reason required']); break; }

            $qId = 'QRN-' . strtoupper(substr(md5(uniqid('', true)), 0, 8));
            $stmt = $db->prepare("INSERT INTO alfred_quarantine (quarantine_id, agent_id, reason, severity, restrictions) VALUES (?, ?, ?, ?, ?)");
            $stmt->execute([$qId, $agentId, $reason, $severity, $restrictions]);

            // Revoke permissions if isolated
            if ($severity === 'isolated') {
                $perms = ['dispatch','deploy','config_update','escalate','restart','kill','comms_send'];
                $pStmt = $db->prepare("INSERT INTO alfred_permissions (agent_id, permission, granted, reason) VALUES (?, ?, 0, ?)
                    ON DUPLICATE KEY UPDATE granted = 0, reason = VALUES(reason)");
                foreach ($perms as $p) { $pStmt->execute([$agentId, $p, "Quarantine: $qId"]); }
            }

            logAudit($db, 'quarantine', $agentId, "Quarantined ($severity): $reason");
            agent_panel_json(['ok' => true, 'quarantine_id' => $qId]);

        } elseif ($sub === 'release') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $qId = $data['quarantine_id'] ?? '';
            $notes = $data['notes'] ?? '';
            if (!$qId) { agent_panel_json(['error' => 'quarantine_id required']); break; }

            // Get agent
            $q = $db->prepare("SELECT agent_id, severity FROM alfred_quarantine WHERE quarantine_id = ?");
            $q->execute([$qId]);
            $qr = $q->fetch(PDO::FETCH_ASSOC);

            $db->prepare("UPDATE alfred_quarantine SET status = 'released', released_at = NOW(), notes = ? WHERE quarantine_id = ?")->execute([$notes, $qId]);

            // Restore permissions if was isolated
            if ($qr && $qr['severity'] === 'isolated') {
                $db->prepare("UPDATE alfred_permissions SET granted = 1, reason = 'Released from quarantine' WHERE agent_id = ? AND granted = 0 AND reason LIKE ?")->execute([$qr['agent_id'], "Quarantine: $qId%"]);
            }

            logAudit($db, 'quarantine_release', $qr['agent_id'] ?? 'unknown', "Released from quarantine: $qId");
            agent_panel_json(['ok' => true]);

        } elseif ($sub === 'escalate') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $qId = $data['quarantine_id'] ?? '';
            if (!$qId) { agent_panel_json(['error' => 'quarantine_id required']); break; }
            $db->prepare("UPDATE alfred_quarantine SET status = 'escalated' WHERE quarantine_id = ?")->execute([$qId]);
            logAudit($db, 'quarantine_escalate', 'fleet', "Quarantine escalated: $qId");
            agent_panel_json(['ok' => true]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── MISSION CHAINS ───
    case 'mission_chain':
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_mission_chains (
            id INT AUTO_INCREMENT PRIMARY KEY,
            chain_id VARCHAR(32) UNIQUE NOT NULL,
            title VARCHAR(200) NOT NULL,
            description TEXT,
            status ENUM('planning','active','blocked','completed','cancelled') DEFAULT 'planning',
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $db->exec("CREATE TABLE IF NOT EXISTS alfred_chain_links (
            id INT AUTO_INCREMENT PRIMARY KEY,
            chain_id VARCHAR(32) NOT NULL,
            link_order INT NOT NULL,
            mission_id VARCHAR(32),
            title VARCHAR(200) NOT NULL,
            agent_id VARCHAR(30),
            depends_on JSON,
            status ENUM('pending','ready','in_progress','completed','failed','skipped') DEFAULT 'pending',
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            INDEX idx_chain (chain_id)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $sub = $_GET['sub_action'] ?? $_POST['sub_action'] ?? 'list';

        if ($sub === 'list') {
            $chains = $db->query("SELECT c.*, (SELECT COUNT(*) FROM alfred_chain_links WHERE chain_id = c.chain_id) as total_links,
                (SELECT COUNT(*) FROM alfred_chain_links WHERE chain_id = c.chain_id AND status = 'completed') as done_links
                FROM alfred_mission_chains c ORDER BY FIELD(status,'active','blocked','planning','completed','cancelled'), updated_at DESC LIMIT 30")->fetchAll(PDO::FETCH_ASSOC);
            agent_panel_json(['ok' => true, 'chains' => $chains]);

        } elseif ($sub === 'detail') {
            $chainId = $_GET['chain_id'] ?? '';
            if (!$chainId) { agent_panel_json(['error' => 'chain_id required']); break; }
            $chain = $db->prepare("SELECT * FROM alfred_mission_chains WHERE chain_id = ?");
            $chain->execute([$chainId]);
            $ch = $chain->fetch(PDO::FETCH_ASSOC);
            $links = $db->prepare("SELECT * FROM alfred_chain_links WHERE chain_id = ? ORDER BY link_order ASC");
            $links->execute([$chainId]);
            agent_panel_json(['ok' => true, 'chain' => $ch, 'links' => $links->fetchAll(PDO::FETCH_ASSOC)]);

        } elseif ($sub === 'create_chain') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $title = $data['title'] ?? '';
            if (!$title) { agent_panel_json(['error' => 'title required']); break; }
            $chId = 'CHN-' . strtoupper(substr(md5(uniqid('', true)), 0, 8));
            $db->prepare("INSERT INTO alfred_mission_chains (chain_id, title, description) VALUES (?, ?, ?)")->execute([$chId, $title, $data['description'] ?? '']);
            logAudit($db, 'chain_create', 'fleet', "Chain $chId: $title");
            agent_panel_json(['ok' => true, 'chain_id' => $chId]);

        } elseif ($sub === 'add_link') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $chainId = $data['chain_id'] ?? '';
            $title = $data['title'] ?? '';
            $agentId = $data['agent_id'] ?? '';
            $dependsOn = json_encode($data['depends_on'] ?? []);
            if (!$chainId || !$title) { agent_panel_json(['error' => 'chain_id and title required']); break; }

            // Get next order
            $maxOrder = $db->prepare("SELECT COALESCE(MAX(link_order), 0) + 1 FROM alfred_chain_links WHERE chain_id = ?");
            $maxOrder->execute([$chainId]);
            $order = (int)$maxOrder->fetchColumn();

            $db->prepare("INSERT INTO alfred_chain_links (chain_id, link_order, title, agent_id, depends_on) VALUES (?, ?, ?, ?, ?)")
                ->execute([$chainId, $order, $title, $agentId, $dependsOn]);
            agent_panel_json(['ok' => true, 'order' => $order]);

        } elseif ($sub === 'update_link') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $linkId = $data['link_id'] ?? '';
            $status = $data['status'] ?? '';
            if (!$linkId || !$status) { agent_panel_json(['error' => 'link_id and status required']); break; }
            $db->prepare("UPDATE alfred_chain_links SET status = ? WHERE id = ?")->execute([$status, $linkId]);

            // Auto-update chain status
            $link = $db->prepare("SELECT chain_id FROM alfred_chain_links WHERE id = ?");
            $link->execute([$linkId]);
            $chainId = $link->fetchColumn();
            if ($chainId) {
                $stats = $db->prepare("SELECT COUNT(*) as total, SUM(status='completed') as done, SUM(status='failed') as failed FROM alfred_chain_links WHERE chain_id = ?");
                $stats->execute([$chainId]);
                $s = $stats->fetch(PDO::FETCH_ASSOC);
                $newStatus = 'active';
                if ((int)$s['done'] === (int)$s['total']) $newStatus = 'completed';
                elseif ((int)$s['failed'] > 0) $newStatus = 'blocked';
                $db->prepare("UPDATE alfred_mission_chains SET status = ? WHERE chain_id = ?")->execute([$newStatus, $chainId]);
            }
            agent_panel_json(['ok' => true]);

        } elseif ($sub === 'update_chain') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $chainId = $data['chain_id'] ?? '';
            $status = $data['status'] ?? '';
            if (!$chainId || !$status) { agent_panel_json(['error' => 'chain_id and status required']); break; }
            $db->prepare("UPDATE alfred_mission_chains SET status = ? WHERE chain_id = ?")->execute([$status, $chainId]);
            agent_panel_json(['ok' => true]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── SKILL TREE ───
    case 'skill_tree':
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_skill_tree (
            id INT AUTO_INCREMENT PRIMARY KEY,
            agent_id VARCHAR(30) NOT NULL,
            skill_name VARCHAR(60) NOT NULL,
            category VARCHAR(40) DEFAULT 'general',
            level INT DEFAULT 1,
            max_level INT DEFAULT 5,
            xp_current INT DEFAULT 0,
            xp_required INT DEFAULT 100,
            unlocked TINYINT DEFAULT 1,
            prerequisite VARCHAR(60),
            description VARCHAR(200),
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
            UNIQUE KEY uniq_skill (agent_id, skill_name)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $sub = $_GET['sub_action'] ?? $_POST['sub_action'] ?? 'list';

        if ($sub === 'list') {
            $agentId = $_GET['agent_id'] ?? '';
            $sql = "SELECT * FROM alfred_skill_tree";
            $params = [];
            if ($agentId) { $sql .= " WHERE agent_id = ?"; $params[] = $agentId; }
            $sql .= " ORDER BY agent_id, category, level DESC";
            $stmt = $db->prepare($sql);
            $stmt->execute($params);
            agent_panel_json(['ok' => true, 'skills' => $stmt->fetchAll(PDO::FETCH_ASSOC)]);

        } elseif ($sub === 'add') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $agentId = $data['agent_id'] ?? '';
            $skillName = $data['skill_name'] ?? '';
            $category = $data['category'] ?? 'general';
            $desc = $data['description'] ?? '';
            $prereq = $data['prerequisite'] ?? null;
            if (!$agentId || !$skillName) { agent_panel_json(['error' => 'agent_id and skill_name required']); break; }

            $stmt = $db->prepare("INSERT INTO alfred_skill_tree (agent_id, skill_name, category, description, prerequisite) VALUES (?, ?, ?, ?, ?)
                ON DUPLICATE KEY UPDATE category = VALUES(category), description = VALUES(description)");
            $stmt->execute([$agentId, $skillName, $category, $desc, $prereq]);
            logAudit($db, 'skill_add', $agentId, "Skill: $skillName ($category)");
            agent_panel_json(['ok' => true]);

        } elseif ($sub === 'upgrade') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $agentId = $data['agent_id'] ?? '';
            $skillName = $data['skill_name'] ?? '';
            $xpGain = (int)($data['xp'] ?? 25);
            if (!$agentId || !$skillName) { agent_panel_json(['error' => 'agent_id and skill_name required']); break; }

            $skill = $db->prepare("SELECT * FROM alfred_skill_tree WHERE agent_id = ? AND skill_name = ?");
            $skill->execute([$agentId, $skillName]);
            $s = $skill->fetch(PDO::FETCH_ASSOC);
            if (!$s) { agent_panel_json(['error' => 'Skill not found']); break; }

            $newXp = $s['xp_current'] + $xpGain;
            $newLevel = $s['level'];
            $newReq = $s['xp_required'];
            $leveledUp = false;

            if ($newXp >= $s['xp_required'] && $s['level'] < $s['max_level']) {
                $newLevel++;
                $newXp -= $s['xp_required'];
                $newReq = (int)($s['xp_required'] * 1.5);
                $leveledUp = true;
            }

            $db->prepare("UPDATE alfred_skill_tree SET xp_current = ?, level = ?, xp_required = ? WHERE agent_id = ? AND skill_name = ?")
                ->execute([$newXp, $newLevel, $newReq, $agentId, $skillName]);

            logAudit($db, 'skill_upgrade', $agentId, "$skillName +{$xpGain}xp" . ($leveledUp ? " LEVEL UP → $newLevel" : ''));
            agent_panel_json(['ok' => true, 'level' => $newLevel, 'xp' => $newXp, 'leveled_up' => $leveledUp]);

        } elseif ($sub === 'seed') {
            // Seed default skills for all agents
            $agents = ['fortress','architect','veil','pulse','metadome','garrison','forge','herald','quartermaster','sentinel'];
            $defaults = [
                ['combat','Attack Mitigation','Detect and block active threats',null],
                ['combat','Threat Detection','Identify suspicious patterns',null],
                ['intel','Data Analysis','Process and correlate intelligence','Threat Detection'],
                ['intel','Pattern Recognition','Find anomalies in fleet data',null],
                ['ops','Deployment','Execute reliable deployments',null],
                ['ops','Self-Healing','Auto-recover from failures','Deployment'],
                ['comms','Report Generation','Create clear status reports',null],
                ['comms','Cross-Fleet Coordination','Work across agent teams',null],
            ];
            $count = 0;
            $stmt = $db->prepare("INSERT IGNORE INTO alfred_skill_tree (agent_id, skill_name, category, description, prerequisite) VALUES (?, ?, ?, ?, ?)");
            foreach ($agents as $a) {
                foreach ($defaults as $d) {
                    $stmt->execute([$a, $d[1], $d[0], $d[2], $d[3]]);
                    $count += $stmt->rowCount();
                }
            }
            agent_panel_json(['ok' => true, 'seeded' => $count]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── ARSENAL ───
    case 'arsenal':
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_arsenal (
            id INT AUTO_INCREMENT PRIMARY KEY,
            item_id VARCHAR(32) UNIQUE NOT NULL,
            name VARCHAR(100) NOT NULL,
            category ENUM('tool','weapon','shield','sensor','utility') DEFAULT 'tool',
            assigned_to VARCHAR(30),
            status ENUM('available','deployed','maintenance','retired') DEFAULT 'available',
            power_level INT DEFAULT 1,
            description VARCHAR(300),
            metadata JSON,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $sub = $_GET['sub_action'] ?? $_POST['sub_action'] ?? 'list';

        if ($sub === 'list') {
            $cat = $_GET['category'] ?? '';
            $sql = "SELECT * FROM alfred_arsenal";
            $params = [];
            if ($cat) { $sql .= " WHERE category = ?"; $params[] = $cat; }
            $sql .= " ORDER BY category, status, power_level DESC LIMIT 60";
            $stmt = $db->prepare($sql);
            $stmt->execute($params);
            // Stats
            $stats = $db->query("SELECT category, COUNT(*) as count, SUM(status='deployed') as deployed FROM alfred_arsenal GROUP BY category")->fetchAll(PDO::FETCH_ASSOC);
            agent_panel_json(['ok' => true, 'items' => $stmt->fetchAll(PDO::FETCH_ASSOC), 'stats' => $stats]);

        } elseif ($sub === 'add') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $name = $data['name'] ?? '';
            $category = $data['category'] ?? 'tool';
            $desc = $data['description'] ?? '';
            $power = (int)($data['power_level'] ?? 1);
            if (!$name) { agent_panel_json(['error' => 'name required']); break; }
            $itemId = 'ITM-' . strtoupper(substr(md5(uniqid('', true)), 0, 8));
            $db->prepare("INSERT INTO alfred_arsenal (item_id, name, category, description, power_level) VALUES (?, ?, ?, ?, ?)")
                ->execute([$itemId, $name, $category, $desc, $power]);
            logAudit($db, 'arsenal_add', 'fleet', "Added: $name ($category)");
            agent_panel_json(['ok' => true, 'item_id' => $itemId]);

        } elseif ($sub === 'assign') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $itemId = $data['item_id'] ?? '';
            $agentId = $data['agent_id'] ?? '';
            if (!$itemId) { agent_panel_json(['error' => 'item_id required']); break; }
            $db->prepare("UPDATE alfred_arsenal SET assigned_to = ?, status = ? WHERE item_id = ?")
                ->execute([$agentId ?: null, $agentId ? 'deployed' : 'available', $itemId]);
            logAudit($db, 'arsenal_assign', $agentId ?: 'fleet', "Item $itemId " . ($agentId ? "assigned to $agentId" : 'unassigned'));
            agent_panel_json(['ok' => true]);

        } elseif ($sub === 'seed') {
            $items = [
                ['WAF Shield','shield','Web Application Firewall',4],
                ['DDoS Deflector','shield','Distributed denial-of-service mitigation',5],
                ['Log Analyzer','sensor','Real-time log pattern analysis',3],
                ['Port Scanner','sensor','Network port surveillance',3],
                ['Deploy Pipeline','tool','CI/CD deployment automation',4],
                ['Health Monitor','sensor','Service health checking system',3],
                ['Encryption Engine','weapon','AES-256-GCM crypto operations',5],
                ['Rate Limiter','shield','Request rate limiting and throttling',3],
                ['Backup Cannon','utility','Automated backup system',4],
                ['DNS Resolver','tool','DNS management and resolution',3],
                ['SSL Forge','tool','Certificate generation and management',4],
                ['Mesh Linker','utility','Agent-to-agent mesh networking',4],
            ];
            $stmt = $db->prepare("INSERT IGNORE INTO alfred_arsenal (item_id, name, category, description, power_level)
                VALUES (?, ?, ?, ?, ?)");
            $count = 0;
            foreach ($items as $i) {
                $id = 'ITM-' . strtoupper(substr(md5($i[0]), 0, 8));
                $stmt->execute([$id, $i[0], $i[1], $i[2], $i[3]]);
                $count += $stmt->rowCount();
            }
            agent_panel_json(['ok' => true, 'seeded' => $count]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── REPUTATION ───
    case 'reputation':
        $agents = ['fortress','architect','veil','pulse','metadome','garrison','forge','herald','quartermaster','sentinel'];
        $rep = [];

        foreach ($agents as $agent) {
            $score = 50; // Base

            // Missions: +2 completed, -3 failed
            $s = $db->prepare("SELECT SUM(status='completed') as done, SUM(status='failed') as failed FROM alfred_agent_dispatches WHERE agent_id = ?");
            $s->execute([$agent]);
            $m = $s->fetch(PDO::FETCH_ASSOC);
            $score += ((int)($m['done'] ?? 0) * 2) - ((int)($m['failed'] ?? 0) * 3);

            // Incidents resolved: +3
            $s = $db->prepare("SELECT COUNT(*) FROM alfred_agent_incidents WHERE agent_id = ? AND status = 'resolved'");
            $s->execute([$agent]);
            $score += (int)$s->fetchColumn() * 3;

            // Quarantine active: -15
            $s = $db->prepare("SELECT COUNT(*) FROM alfred_quarantine WHERE agent_id = ? AND status = 'active'");
            $s->execute([$agent]);
            $score -= (int)$s->fetchColumn() * 15;

            // Tasks done: +1
            $s = $db->prepare("SELECT COUNT(*) FROM alfred_agent_tasks WHERE agent_id = ? AND status = 'done'");
            $s->execute([$agent]);
            $score += (int)$s->fetchColumn();

            // Uptime bonus: up to +10
            $s = $db->prepare("SELECT AVG(status='online') * 10 as bonus FROM (SELECT status FROM alfred_agent_health WHERE agent_id = ? ORDER BY checked_at DESC LIMIT 20) sub");
            $s->execute([$agent]);
            $score += (int)$s->fetchColumn();

            // Clamp 0-100
            $score = max(0, min(100, $score));

            $tier = 'bronze';
            if ($score >= 90) $tier = 'legendary';
            elseif ($score >= 75) $tier = 'gold';
            elseif ($score >= 60) $tier = 'silver';
            elseif ($score < 30) $tier = 'disgraced';

            $rep[] = ['agent_id' => $agent, 'score' => $score, 'tier' => $tier];
        }

        usort($rep, function($a, $b) { return $b['score'] - $a['score']; });
        agent_panel_json(['ok' => true, 'reputation' => $rep]);
        break;

    // ─── MISSION REPLAY ───
    case 'mission_replay':
        $sub = $_GET['sub_action'] ?? 'history';

        if ($sub === 'history') {
            $agentFilter = $_GET['agent_id'] ?? '';
            $statusFilter = $_GET['status'] ?? '';
            $limit = min((int)($_GET['limit'] ?? 40), 100);
            $sql = "SELECT d.*, (SELECT COUNT(*) FROM alfred_audit_log WHERE details LIKE CONCAT('%', d.mission_id, '%')) as audit_refs
                FROM alfred_agent_dispatches d WHERE 1=1";
            $params = [];
            if ($agentFilter) { $sql .= " AND d.agent_id = ?"; $params[] = $agentFilter; }
            if ($statusFilter) { $sql .= " AND d.status = ?"; $params[] = $statusFilter; }
            $sql .= " ORDER BY d.created_at DESC LIMIT $limit";
            $stmt = $db->prepare($sql);
            $stmt->execute($params);
            $missions = $stmt->fetchAll(PDO::FETCH_ASSOC);

            // Summary stats
            $stats = $db->query("SELECT COUNT(*) as total, SUM(status='completed') as completed, SUM(status='failed') as failed, SUM(status='active') as active FROM alfred_agent_dispatches")->fetch(PDO::FETCH_ASSOC);

            agent_panel_json(['ok' => true, 'missions' => $missions, 'stats' => $stats]);

        } elseif ($sub === 'detail') {
            $missionId = $_GET['mission_id'] ?? '';
            if (!$missionId) { agent_panel_json(['error' => 'mission_id required']); break; }

            $mission = $db->prepare("SELECT * FROM alfred_agent_dispatches WHERE mission_id = ?");
            $mission->execute([$missionId]);
            $m = $mission->fetch(PDO::FETCH_ASSOC);

            // Related audit logs
            $audits = $db->prepare("SELECT * FROM alfred_audit_log WHERE details LIKE ? ORDER BY created_at ASC LIMIT 30");
            $audits->execute(["%$missionId%"]);

            // Related comms
            $comms = $db->prepare("SELECT * FROM alfred_agent_comms WHERE (from_agent = ? OR to_agent = ?) AND created_at >= ? ORDER BY created_at ASC LIMIT 20");
            $agentId = $m['agent_id'] ?? '';
            $created = $m['created_at'] ?? '2020-01-01';
            $comms->execute([$agentId, $agentId, $created]);

            agent_panel_json(['ok' => true, 'mission' => $m, 'audit_trail' => $audits->fetchAll(PDO::FETCH_ASSOC), 'related_comms' => $comms->fetchAll(PDO::FETCH_ASSOC)]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── ESCALATION CHAINS ───
    case 'escalation_chain':
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_escalation_chains (
            id INT AUTO_INCREMENT PRIMARY KEY,
            chain_name VARCHAR(80) UNIQUE NOT NULL,
            trigger_type ENUM('incident','threat','sla_breach','health_down','custom') DEFAULT 'custom',
            steps JSON NOT NULL,
            active TINYINT DEFAULT 1,
            last_triggered DATETIME,
            trigger_count INT DEFAULT 0,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $sub = $_GET['sub_action'] ?? $_POST['sub_action'] ?? 'list';

        if ($sub === 'list') {
            $stmt = $db->query("SELECT * FROM alfred_escalation_chains ORDER BY active DESC, trigger_count DESC");
            agent_panel_json(['ok' => true, 'chains' => $stmt->fetchAll(PDO::FETCH_ASSOC)]);

        } elseif ($sub === 'create') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $name = $data['chain_name'] ?? '';
            $trigger = $data['trigger_type'] ?? 'custom';
            $steps = $data['steps'] ?? [];
            if (!$name || empty($steps)) { agent_panel_json(['error' => 'chain_name and steps required']); break; }
            $stmt = $db->prepare("INSERT INTO alfred_escalation_chains (chain_name, trigger_type, steps) VALUES (?, ?, ?)");
            $stmt->execute([$name, $trigger, json_encode($steps)]);
            logAudit($db, 'esc_chain_create', 'fleet', "Escalation chain: $name (" . count($steps) . " steps)");
            agent_panel_json(['ok' => true]);

        } elseif ($sub === 'trigger') {
            $name = $_GET['chain_name'] ?? '';
            if (!$name) { agent_panel_json(['error' => 'chain_name required']); break; }
            $chain = $db->prepare("SELECT * FROM alfred_escalation_chains WHERE chain_name = ? AND active = 1");
            $chain->execute([$name]);
            $c = $chain->fetch(PDO::FETCH_ASSOC);
            if (!$c) { agent_panel_json(['error' => 'Chain not found or inactive']); break; }

            $steps = json_decode($c['steps'], true) ?: [];
            $results = [];
            foreach ($steps as $i => $step) {
                $action = $step['action'] ?? 'notify';
                $target = $step['target'] ?? '';
                $results[] = ['step' => $i + 1, 'action' => $action, 'target' => $target, 'executed' => true];
                // Log each step
                logAudit($db, 'esc_chain_step', $target ?: 'fleet', "Chain '$name' step " . ($i+1) . ": $action");
            }
            $db->prepare("UPDATE alfred_escalation_chains SET last_triggered = NOW(), trigger_count = trigger_count + 1 WHERE chain_name = ?")->execute([$name]);
            agent_panel_json(['ok' => true, 'chain' => $name, 'results' => $results]);

        } elseif ($sub === 'toggle') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $name = $data['chain_name'] ?? '';
            $active = isset($data['active']) ? (int)$data['active'] : 1;
            if (!$name) { agent_panel_json(['error' => 'chain_name required']); break; }
            $db->prepare("UPDATE alfred_escalation_chains SET active = ? WHERE chain_name = ?")->execute([$active, $name]);
            agent_panel_json(['ok' => true]);

        } elseif ($sub === 'delete') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $name = $data['chain_name'] ?? '';
            if (!$name) { agent_panel_json(['error' => 'chain_name required']); break; }
            $db->prepare("DELETE FROM alfred_escalation_chains WHERE chain_name = ?")->execute([$name]);
            logAudit($db, 'esc_chain_delete', 'fleet', "Deleted chain: $name");
            agent_panel_json(['ok' => true]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── COLLABORATION GRAPH ───
    case 'collab_graph':
        $sub = $_GET['sub_action'] ?? 'graph';
        if ($sub === 'graph') {
            // Build agent-to-agent collaboration edges from comms, dispatches, mission chains
            $agents = [];
            $rows = $db->query("SELECT DISTINCT agent_name FROM alfred_agent_health")->fetchAll(PDO::FETCH_COLUMN);
            foreach ($rows as $a) $agents[] = $a;

            $edges = [];
            // Comms: sender→recipient
            $st = $db->query("SELECT sender, recipient, COUNT(*) as cnt, MAX(sent_at) as last_ts FROM alfred_agent_comms WHERE recipient != 'commander' AND sender != 'commander' GROUP BY sender, recipient");
            foreach ($st->fetchAll(PDO::FETCH_ASSOC) as $r) {
                $key = $r['sender'] < $r['recipient'] ? $r['sender'].'|'.$r['recipient'] : $r['recipient'].'|'.$r['sender'];
                if (!isset($edges[$key])) $edges[$key] = ['source' => '', 'target' => '', 'comms' => 0, 'missions' => 0, 'chains' => 0, 'last_interaction' => null];
                $parts = explode('|', $key);
                $edges[$key]['source'] = $parts[0];
                $edges[$key]['target'] = $parts[1];
                $edges[$key]['comms'] += (int)$r['cnt'];
                if (!$edges[$key]['last_interaction'] || $r['last_ts'] > $edges[$key]['last_interaction']) $edges[$key]['last_interaction'] = $r['last_ts'];
            }
            // Dispatches: agents on same mission
            $missionAgents = [];
            $st2 = $db->query("SELECT mission_id, agent_name FROM alfred_agent_dispatches WHERE mission_id IS NOT NULL GROUP BY mission_id, agent_name");
            foreach ($st2->fetchAll(PDO::FETCH_ASSOC) as $r) {
                $missionAgents[$r['mission_id']][] = $r['agent_name'];
            }
            foreach ($missionAgents as $mid => $agentList) {
                for ($i = 0; $i < count($agentList); $i++) {
                    for ($j = $i + 1; $j < count($agentList); $j++) {
                        $a = $agentList[$i]; $b = $agentList[$j];
                        $key = $a < $b ? "$a|$b" : "$b|$a";
                        if (!isset($edges[$key])) $edges[$key] = ['source' => '', 'target' => '', 'comms' => 0, 'missions' => 0, 'chains' => 0, 'last_interaction' => null];
                        $parts = explode('|', $key);
                        $edges[$key]['source'] = $parts[0];
                        $edges[$key]['target'] = $parts[1];
                        $edges[$key]['missions']++;
                    }
                }
            }
            // Chain links: agents in same chain
            try {
                $st3 = $db->query("SELECT cl.chain_id, cl.agent_name FROM alfred_chain_links cl GROUP BY cl.chain_id, cl.agent_name");
                $chainAgents = [];
                foreach ($st3->fetchAll(PDO::FETCH_ASSOC) as $r) {
                    $chainAgents[$r['chain_id']][] = $r['agent_name'];
                }
                foreach ($chainAgents as $cid => $agentList) {
                    for ($i = 0; $i < count($agentList); $i++) {
                        for ($j = $i + 1; $j < count($agentList); $j++) {
                            $a = $agentList[$i]; $b = $agentList[$j];
                            $key = $a < $b ? "$a|$b" : "$b|$a";
                            if (!isset($edges[$key])) $edges[$key] = ['source' => '', 'target' => '', 'comms' => 0, 'missions' => 0, 'chains' => 0, 'last_interaction' => null];
                            $parts = explode('|', $key);
                            $edges[$key]['source'] = $parts[0];
                            $edges[$key]['target'] = $parts[1];
                            $edges[$key]['chains']++;
                        }
                    }
                }
            } catch (Exception $e) {} // chain_links may not exist yet

            // Calculate strength for each edge
            $edgeList = [];
            foreach ($edges as $e) {
                $e['strength'] = $e['comms'] * 2 + $e['missions'] * 5 + $e['chains'] * 3;
                $edgeList[] = $e;
            }
            usort($edgeList, function($a, $b) { return $b['strength'] - $a['strength']; });

            // Node stats
            $nodes = [];
            foreach ($agents as $a) {
                $totalStrength = 0;
                $connections = 0;
                foreach ($edgeList as $e) {
                    if ($e['source'] === $a || $e['target'] === $a) {
                        $totalStrength += $e['strength'];
                        $connections++;
                    }
                }
                $nodes[] = ['agent' => $a, 'connections' => $connections, 'total_strength' => $totalStrength];
            }
            usort($nodes, function($a, $b) { return $b['total_strength'] - $a['total_strength']; });

            agent_panel_json(['ok' => true, 'nodes' => $nodes, 'edges' => $edgeList]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── FLEET FUEL/RESOURCE GAUGE ───
    case 'fuel_gauge':
        $sub = $_GET['sub_action'] ?? 'status';
        if ($sub === 'status') {
            // System-level resources
            $loadAvg = sys_getloadavg();
            $memInfo = @file_get_contents('/proc/meminfo');
            $memTotal = 0; $memAvail = 0;
            if (preg_match('/MemTotal:\s+(\d+)/', $memInfo, $m)) $memTotal = (int)$m[1] * 1024;
            if (preg_match('/MemAvailable:\s+(\d+)/', $memInfo, $m)) $memAvail = (int)$m[1] * 1024;
            $memUsed = $memTotal - $memAvail;
            $diskTotal = disk_total_space('/');
            $diskFree = disk_free_space('/');
            $diskUsed = $diskTotal - $diskFree;

            // Per-agent resources from health
            $agentResources = [];
            $st = $db->query("SELECT agent_name, memory_mb, cpu_pct, services_total, services_online, updated_at FROM alfred_agent_health ORDER BY agent_name");
            $totalMem = 0; $totalCpu = 0; $totalSvc = 0; $totalOnline = 0;
            foreach ($st->fetchAll(PDO::FETCH_ASSOC) as $r) {
                $mem = (float)($r['memory_mb'] ?? 0);
                $cpu = (float)($r['cpu_pct'] ?? 0);
                $totalMem += $mem;
                $totalCpu += $cpu;
                $totalSvc += (int)$r['services_total'];
                $totalOnline += (int)$r['services_online'];
                $agentResources[] = [
                    'agent' => $r['agent_name'],
                    'memory_mb' => round($mem, 1),
                    'cpu_pct' => round($cpu, 1),
                    'services' => (int)$r['services_online'] . '/' . (int)$r['services_total'],
                    'updated' => $r['updated_at']
                ];
            }

            // Active tasks/missions load
            $activeTasks = (int)$db->query("SELECT COUNT(*) FROM alfred_agent_tasks WHERE status IN ('queued','assigned','running')")->fetchColumn();
            $activeMissions = (int)$db->query("SELECT COUNT(*) FROM alfred_agent_dispatches WHERE status IN ('pending','in_progress')")->fetchColumn();
            $activeIncidents = (int)$db->query("SELECT COUNT(*) FROM alfred_agent_incidents WHERE status = 'open'")->fetchColumn();

            agent_panel_json(['ok' => true,
                'system' => [
                    'load_1m' => round($loadAvg[0], 2),
                    'load_5m' => round($loadAvg[1], 2),
                    'load_15m' => round($loadAvg[2], 2),
                    'mem_total_gb' => round($memTotal / 1073741824, 1),
                    'mem_used_gb' => round($memUsed / 1073741824, 1),
                    'mem_pct' => $memTotal > 0 ? round($memUsed / $memTotal * 100, 1) : 0,
                    'disk_total_gb' => round($diskTotal / 1073741824, 0),
                    'disk_used_gb' => round($diskUsed / 1073741824, 0),
                    'disk_pct' => $diskTotal > 0 ? round($diskUsed / $diskTotal * 100, 1) : 0,
                ],
                'fleet' => [
                    'total_memory_mb' => round($totalMem, 1),
                    'total_cpu_pct' => round($totalCpu, 1),
                    'services_online' => $totalOnline,
                    'services_total' => $totalSvc,
                    'active_tasks' => $activeTasks,
                    'active_missions' => $activeMissions,
                    'open_incidents' => $activeIncidents,
                ],
                'agents' => $agentResources
            ]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── COMMANDER NOTEPAD ───
    case 'notepad':
        $sub = $_GET['sub_action'] ?? 'list';
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_notepad (
            id INT AUTO_INCREMENT PRIMARY KEY,
            title VARCHAR(200) NOT NULL DEFAULT 'Untitled',
            content TEXT,
            category VARCHAR(50) DEFAULT 'general',
            pinned TINYINT(1) DEFAULT 0,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
        )");
        if ($sub === 'list') {
            $notes = $db->query("SELECT * FROM alfred_notepad ORDER BY pinned DESC, updated_at DESC")->fetchAll(PDO::FETCH_ASSOC);
            agent_panel_json(['ok' => true, 'notes' => $notes]);
        } elseif ($sub === 'create') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $title = trim($data['title'] ?? 'Untitled');
            $content = $data['content'] ?? '';
            $category = $data['category'] ?? 'general';
            $st = $db->prepare("INSERT INTO alfred_notepad (title, content, category) VALUES (?, ?, ?)");
            $st->execute([$title, $content, $category]);
            agent_panel_json(['ok' => true, 'id' => $db->lastInsertId()]);
        } elseif ($sub === 'update') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $id = (int)($data['id'] ?? 0);
            if (!$id) { agent_panel_json(['error' => 'id required']); break; }
            $fields = [];
            $params = [];
            if (isset($data['title'])) { $fields[] = 'title = ?'; $params[] = $data['title']; }
            if (isset($data['content'])) { $fields[] = 'content = ?'; $params[] = $data['content']; }
            if (isset($data['category'])) { $fields[] = 'category = ?'; $params[] = $data['category']; }
            if (isset($data['pinned'])) { $fields[] = 'pinned = ?'; $params[] = (int)$data['pinned']; }
            if (empty($fields)) { agent_panel_json(['error' => 'Nothing to update']); break; }
            $params[] = $id;
            $db->prepare("UPDATE alfred_notepad SET " . implode(', ', $fields) . " WHERE id = ?")->execute($params);
            agent_panel_json(['ok' => true]);
        } elseif ($sub === 'delete') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $id = (int)($data['id'] ?? 0);
            if (!$id) { agent_panel_json(['error' => 'id required']); break; }
            $db->prepare("DELETE FROM alfred_notepad WHERE id = ?")->execute([$id]);
            agent_panel_json(['ok' => true]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── AGENT BADGES/ACHIEVEMENTS ───
    case 'badges':
        $sub = $_GET['sub_action'] ?? 'list';
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_badges (
            id INT AUTO_INCREMENT PRIMARY KEY,
            badge_name VARCHAR(100) NOT NULL,
            description TEXT,
            icon VARCHAR(50) DEFAULT 'fa-medal',
            color VARCHAR(20) DEFAULT '#d4a017',
            criteria_type VARCHAR(50) NOT NULL,
            criteria_threshold INT DEFAULT 1,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        )");
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_badge_awards (
            id INT AUTO_INCREMENT PRIMARY KEY,
            badge_id INT NOT NULL,
            agent_name VARCHAR(100) NOT NULL,
            awarded_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            UNIQUE KEY uniq_badge_agent (badge_id, agent_name)
        )");
        if ($sub === 'list') {
            $badges = $db->query("SELECT b.*, COUNT(ba.id) as awards_count FROM alfred_badges b LEFT JOIN alfred_badge_awards ba ON b.id = ba.badge_id GROUP BY b.id ORDER BY b.badge_name")->fetchAll(PDO::FETCH_ASSOC);
            $awards = $db->query("SELECT ba.*, b.badge_name, b.icon, b.color, b.description FROM alfred_badge_awards ba JOIN alfred_badges b ON ba.badge_id = b.id ORDER BY ba.awarded_at DESC")->fetchAll(PDO::FETCH_ASSOC);
            // Group awards by agent
            $byAgent = [];
            foreach ($awards as $a) {
                $byAgent[$a['agent_name']][] = $a;
            }
            agent_panel_json(['ok' => true, 'badges' => $badges, 'awards' => $awards, 'by_agent' => $byAgent]);
        } elseif ($sub === 'create') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $name = trim($data['badge_name'] ?? '');
            if (!$name) { agent_panel_json(['error' => 'badge_name required']); break; }
            $st = $db->prepare("INSERT INTO alfred_badges (badge_name, description, icon, color, criteria_type, criteria_threshold) VALUES (?, ?, ?, ?, ?, ?)");
            $st->execute([$name, $data['description'] ?? '', $data['icon'] ?? 'fa-medal', $data['color'] ?? '#d4a017', $data['criteria_type'] ?? 'manual', (int)($data['criteria_threshold'] ?? 1)]);
            logAudit($db, 'badge_create', 'fleet', "Badge created: $name");
            agent_panel_json(['ok' => true, 'id' => $db->lastInsertId()]);
        } elseif ($sub === 'award') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $badgeId = (int)($data['badge_id'] ?? 0);
            $agent = $data['agent_name'] ?? '';
            if (!$badgeId || !$agent) { agent_panel_json(['error' => 'badge_id and agent_name required']); break; }
            try {
                $st = $db->prepare("INSERT INTO alfred_badge_awards (badge_id, agent_name) VALUES (?, ?)");
                $st->execute([$badgeId, $agent]);
                $badgeName = $db->query("SELECT badge_name FROM alfred_badges WHERE id = $badgeId")->fetchColumn();
                logAudit($db, 'badge_award', $agent, "Badge awarded: $badgeName");
                agent_panel_json(['ok' => true]);
            } catch (Exception $e) {
                agent_panel_json(['error' => 'Already awarded or invalid badge']);
            }
        } elseif ($sub === 'revoke') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $badgeId = (int)($data['badge_id'] ?? 0);
            $agent = $data['agent_name'] ?? '';
            if (!$badgeId || !$agent) { agent_panel_json(['error' => 'badge_id and agent_name required']); break; }
            $db->prepare("DELETE FROM alfred_badge_awards WHERE badge_id = ? AND agent_name = ?")->execute([$badgeId, $agent]);
            agent_panel_json(['ok' => true]);
        } elseif ($sub === 'seed') {
            // Seed default badges
            $defaults = [
                ['First Blood', 'Completed first mission', 'fa-crosshairs', '#ef4444', 'missions_completed', 1],
                ['Veteran', 'Completed 50 missions', 'fa-shield-halved', '#3b82f6', 'missions_completed', 50],
                ['Iron Heart', '99%+ uptime for 30 days', 'fa-heart-pulse', '#10b981', 'uptime_30d', 99],
                ['Chatterbox', 'Sent 100+ comms', 'fa-comments', '#8b5cf6', 'comms_sent', 100],
                ['Firefighter', 'Resolved 10+ incidents', 'fa-fire-extinguisher', '#f97316', 'incidents_resolved', 10],
                ['Speed Demon', 'Average response time under 1s', 'fa-bolt', '#eab308', 'avg_response_ms', 1000],
                ['Team Player', 'Collaborated with 5+ agents', 'fa-people-group', '#06b6d4', 'collaborations', 5],
                ['Guardian', 'Zero quarantine incidents', 'fa-shield', '#d4a017', 'zero_quarantine', 1],
                ['Centurion', 'Completed 100 missions', 'fa-chess-rook', '#f59e0b', 'missions_completed', 100],
                ['Perfectionist', '100% mission success rate', 'fa-star', '#fbbf24', 'success_rate', 100],
            ];
            $st = $db->prepare("INSERT IGNORE INTO alfred_badges (badge_name, description, icon, color, criteria_type, criteria_threshold) VALUES (?, ?, ?, ?, ?, ?)");
            foreach ($defaults as $b) $st->execute($b);
            agent_panel_json(['ok' => true, 'seeded' => count($defaults)]);
        } elseif ($sub === 'auto_award') {
            // Auto-check criteria and award badges
            $badges = $db->query("SELECT * FROM alfred_badges")->fetchAll(PDO::FETCH_ASSOC);
            $agents = $db->query("SELECT DISTINCT agent_name FROM alfred_agent_health")->fetchAll(PDO::FETCH_COLUMN);
            $awarded = 0;
            foreach ($badges as $badge) {
                foreach ($agents as $agent) {
                    $qualifies = false;
                    switch ($badge['criteria_type']) {
                        case 'missions_completed':
                            $cnt = (int)$db->prepare("SELECT COUNT(*) FROM alfred_agent_dispatches WHERE agent_name = ? AND status = 'completed'")->execute([$agent]) ? $db->query("SELECT COUNT(*) FROM alfred_agent_dispatches WHERE agent_name = '$agent' AND status = 'completed'")->fetchColumn() : 0;
                            $qualifies = $cnt >= $badge['criteria_threshold'];
                            break;
                        case 'comms_sent':
                            $cnt = (int)$db->query("SELECT COUNT(*) FROM alfred_agent_comms WHERE sender = '$agent'")->fetchColumn();
                            $qualifies = $cnt >= $badge['criteria_threshold'];
                            break;
                        case 'incidents_resolved':
                            $cnt = (int)$db->query("SELECT COUNT(*) FROM alfred_agent_incidents WHERE resolved_by = '$agent' AND status = 'resolved'")->fetchColumn();
                            $qualifies = $cnt >= $badge['criteria_threshold'];
                            break;
                        case 'zero_quarantine':
                            $cnt = (int)$db->query("SELECT COUNT(*) FROM alfred_quarantine WHERE agent_name = '$agent'")->fetchColumn();
                            $qualifies = $cnt === 0;
                            break;
                    }
                    if ($qualifies) {
                        try {
                            $db->prepare("INSERT IGNORE INTO alfred_badge_awards (badge_id, agent_name) VALUES (?, ?)")->execute([$badge['id'], $agent]);
                            $awarded++;
                        } catch (Exception $e) {}
                    }
                }
            }
            agent_panel_json(['ok' => true, 'checked' => count($badges) * count($agents), 'awarded' => $awarded]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── DEPLOYMENT ROLLBACK ───
    case 'rollback':
        $sub = $_GET['sub_action'] ?? 'list';
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_rollbacks (
            id INT AUTO_INCREMENT PRIMARY KEY,
            deployment_id INT,
            agent_name VARCHAR(100) NOT NULL,
            reason TEXT,
            rollback_type VARCHAR(50) DEFAULT 'service_restart',
            previous_state TEXT,
            status VARCHAR(30) DEFAULT 'pending',
            initiated_by VARCHAR(100) DEFAULT 'commander',
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            completed_at TIMESTAMP NULL
        )");
        if ($sub === 'list') {
            $rollbacks = $db->query("SELECT * FROM alfred_rollbacks ORDER BY created_at DESC LIMIT 100")->fetchAll(PDO::FETCH_ASSOC);
            agent_panel_json(['ok' => true, 'rollbacks' => $rollbacks]);
        } elseif ($sub === 'initiate') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $agent = $data['agent_name'] ?? '';
            $reason = $data['reason'] ?? '';
            $type = $data['rollback_type'] ?? 'service_restart';
            $deployId = $data['deployment_id'] ?? null;
            if (!$agent) { agent_panel_json(['error' => 'agent_name required']); break; }

            // Capture current state before rollback
            $health = $db->prepare("SELECT * FROM alfred_agent_health WHERE agent_name = ?");
            $health->execute([$agent]);
            $currentState = $health->fetch(PDO::FETCH_ASSOC);

            $st = $db->prepare("INSERT INTO alfred_rollbacks (deployment_id, agent_name, reason, rollback_type, previous_state, status) VALUES (?, ?, ?, ?, ?, 'executing')");
            $st->execute([$deployId, $agent, $reason, $type, json_encode($currentState)]);
            $rollbackId = $db->lastInsertId();

            // Execute rollback action
            $result = ['action' => $type];
            if ($type === 'service_restart') {
                $pm2Name = $agent;
                $output = shell_exec("cd /home/gositeme && .local/node_modules/.bin/pm2 restart $pm2Name 2>&1");
                $result['output'] = trim($output ?? '');
                $result['success'] = strpos($output, 'error') === false;
            } elseif ($type === 'config_revert') {
                $result['success'] = true;
                $result['note'] = 'Config revert logged — manual verification needed';
            } else {
                $result['success'] = true;
                $result['note'] = "Rollback type '$type' logged";
            }

            $finalStatus = ($result['success'] ?? false) ? 'completed' : 'failed';
            $db->prepare("UPDATE alfred_rollbacks SET status = ?, completed_at = NOW() WHERE id = ?")->execute([$finalStatus, $rollbackId]);
            logAudit($db, 'rollback', $agent, "Rollback ($type): $reason — $finalStatus");

            agent_panel_json(['ok' => true, 'rollback_id' => $rollbackId, 'result' => $result, 'status' => $finalStatus]);
        } elseif ($sub === 'status') {
            $id = (int)($_GET['id'] ?? 0);
            if (!$id) { agent_panel_json(['error' => 'id required']); break; }
            $st = $db->prepare("SELECT * FROM alfred_rollbacks WHERE id = ?");
            $st->execute([$id]);
            $rb = $st->fetch(PDO::FETCH_ASSOC);
            if (!$rb) { agent_panel_json(['error' => 'Not found']); break; }
            if ($rb['previous_state']) $rb['previous_state'] = json_decode($rb['previous_state'], true);
            agent_panel_json(['ok' => true, 'rollback' => $rb]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── FLEET GEOLOCATION ───
    case 'geolocation':
        $sub = $_GET['sub_action'] ?? 'map';
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_agent_locations (
            id INT AUTO_INCREMENT PRIMARY KEY,
            agent_name VARCHAR(100) NOT NULL,
            location_label VARCHAR(200) DEFAULT 'Primary Server',
            latitude DECIMAL(10,7) DEFAULT 45.5017,
            longitude DECIMAL(10,7) DEFAULT -73.5673,
            region VARCHAR(100) DEFAULT 'NA',
            status VARCHAR(30) DEFAULT 'online',
            last_ping TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
            UNIQUE KEY uniq_agent_loc (agent_name, location_label)
        )");
        if ($sub === 'map') {
            $locs = $db->query("SELECT al.*, ah.status as health_status FROM alfred_agent_locations al LEFT JOIN alfred_agent_health ah ON al.agent_name = ah.agent_name ORDER BY al.agent_name")->fetchAll(PDO::FETCH_ASSOC);
            // If no locations exist, auto-populate from health data (all on same server)
            if (empty($locs)) {
                $agents = $db->query("SELECT agent_name, status FROM alfred_agent_health")->fetchAll(PDO::FETCH_ASSOC);
                $st = $db->prepare("INSERT IGNORE INTO alfred_agent_locations (agent_name, location_label, latitude, longitude, region, status) VALUES (?, 'OVH Montreal', 45.5017, -73.5673, 'NA-East', ?)");
                foreach ($agents as $a) {
                    $st->execute([$a['agent_name'], $a['status']]);
                }
                $locs = $db->query("SELECT al.*, ah.status as health_status FROM alfred_agent_locations al LEFT JOIN alfred_agent_health ah ON al.agent_name = ah.agent_name ORDER BY al.agent_name")->fetchAll(PDO::FETCH_ASSOC);
            }
            $regions = [];
            foreach ($locs as $l) { $regions[$l['region']] = ($regions[$l['region']] ?? 0) + 1; }
            agent_panel_json(['ok' => true, 'locations' => $locs, 'regions' => $regions, 'total' => count($locs)]);
        } elseif ($sub === 'update') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $agent = $data['agent_name'] ?? '';
            if (!$agent) { agent_panel_json(['error' => 'agent_name required']); break; }
            $label = $data['location_label'] ?? 'Primary Server';
            $lat = (float)($data['latitude'] ?? 45.5017);
            $lng = (float)($data['longitude'] ?? -73.5673);
            $region = $data['region'] ?? 'NA';
            $st = $db->prepare("INSERT INTO alfred_agent_locations (agent_name, location_label, latitude, longitude, region) VALUES (?, ?, ?, ?, ?) ON DUPLICATE KEY UPDATE latitude = VALUES(latitude), longitude = VALUES(longitude), region = VALUES(region)");
            $st->execute([$agent, $label, $lat, $lng, $region]);
            agent_panel_json(['ok' => true]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── CONFIG SNAPSHOTS ───
    case 'config_snapshot':
        $sub = $_GET['sub_action'] ?? 'list';
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_config_snapshots (
            id INT AUTO_INCREMENT PRIMARY KEY,
            agent_name VARCHAR(100) NOT NULL,
            snapshot_name VARCHAR(200) DEFAULT 'Auto',
            config_data TEXT,
            created_by VARCHAR(100) DEFAULT 'commander',
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        )");
        if ($sub === 'list') {
            $agent = $_GET['agent'] ?? '';
            $where = $agent ? "WHERE agent_name = " . $db->quote($agent) : '';
            $snaps = $db->query("SELECT id, agent_name, snapshot_name, created_by, created_at, LENGTH(config_data) as data_size FROM alfred_config_snapshots $where ORDER BY created_at DESC LIMIT 100")->fetchAll(PDO::FETCH_ASSOC);
            agent_panel_json(['ok' => true, 'snapshots' => $snaps]);
        } elseif ($sub === 'capture') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $agent = $data['agent_name'] ?? '';
            $name = $data['snapshot_name'] ?? date('Y-m-d H:i');
            if (!$agent) { agent_panel_json(['error' => 'agent_name required']); break; }
            // Capture current health + config
            $health = $db->prepare("SELECT * FROM alfred_agent_health WHERE agent_name = ?");
            $health->execute([$agent]);
            $hData = $health->fetch(PDO::FETCH_ASSOC);
            $perms = $db->prepare("SELECT * FROM alfred_permissions WHERE agent_name = ?");
            $perms->execute([$agent]);
            $pData = $perms->fetchAll(PDO::FETCH_ASSOC);
            $personality = $db->prepare("SELECT * FROM alfred_agent_personality WHERE agent_name = ?");
            $personality->execute([$agent]);
            $perData = $personality->fetch(PDO::FETCH_ASSOC);
            $configData = json_encode(['health' => $hData, 'permissions' => $pData, 'personality' => $perData, 'captured_at' => date('c')]);
            $st = $db->prepare("INSERT INTO alfred_config_snapshots (agent_name, snapshot_name, config_data) VALUES (?, ?, ?)");
            $st->execute([$agent, $name, $configData]);
            logAudit($db, 'config_snapshot', $agent, "Snapshot: $name");
            agent_panel_json(['ok' => true, 'id' => $db->lastInsertId()]);
        } elseif ($sub === 'detail') {
            $id = (int)($_GET['id'] ?? 0);
            if (!$id) { agent_panel_json(['error' => 'id required']); break; }
            $st = $db->prepare("SELECT * FROM alfred_config_snapshots WHERE id = ?");
            $st->execute([$id]);
            $snap = $st->fetch(PDO::FETCH_ASSOC);
            if (!$snap) { agent_panel_json(['error' => 'Not found']); break; }
            $snap['config_data'] = json_decode($snap['config_data'], true);
            agent_panel_json(['ok' => true, 'snapshot' => $snap]);
        } elseif ($sub === 'delete') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $id = (int)($data['id'] ?? 0);
            if (!$id) { agent_panel_json(['error' => 'id required']); break; }
            $db->prepare("DELETE FROM alfred_config_snapshots WHERE id = ?")->execute([$id]);
            agent_panel_json(['ok' => true]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── MISSION DEPENDENCY VISUALIZER ───
    case 'mission_deps':
        $sub = $_GET['sub_action'] ?? 'graph';
        if ($sub === 'graph') {
            // Build mission dependency graph from dispatches + chain links
            $missions = $db->query("SELECT id, agent_name, mission, status, priority, created_at FROM alfred_agent_dispatches ORDER BY created_at DESC LIMIT 200")->fetchAll(PDO::FETCH_ASSOC);
            $chains = [];
            try {
                $chains = $db->query("SELECT mc.id, mc.chain_name, mc.status, cl.step_order, cl.agent_name, cl.mission_description, cl.status as link_status FROM alfred_mission_chains mc JOIN alfred_chain_links cl ON mc.id = cl.chain_id ORDER BY mc.id, cl.step_order")->fetchAll(PDO::FETCH_ASSOC);
            } catch (Exception $e) {}
            // Group chain links by chain
            $chainGraph = [];
            foreach ($chains as $c) {
                $chainGraph[$c['chain_name']][] = $c;
            }
            // Build adjacency: step N depends on step N-1
            $deps = [];
            foreach ($chainGraph as $name => $links) {
                for ($i = 1; $i < count($links); $i++) {
                    $deps[] = [
                        'from' => $links[$i - 1]['agent_name'] . ': ' . substr($links[$i - 1]['mission_description'] ?? '', 0, 40),
                        'to' => $links[$i]['agent_name'] . ': ' . substr($links[$i]['mission_description'] ?? '', 0, 40),
                        'chain' => $name,
                        'from_status' => $links[$i - 1]['link_status'],
                        'to_status' => $links[$i]['link_status'],
                    ];
                }
            }
            // Stats
            $statusCounts = [];
            foreach ($missions as $m) {
                $statusCounts[$m['status']] = ($statusCounts[$m['status']] ?? 0) + 1;
            }
            agent_panel_json(['ok' => true, 'missions' => count($missions), 'chains' => count($chainGraph), 'dependencies' => $deps, 'status_counts' => $statusCounts]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── COMMS ANALYTICS ───
    case 'comms_analytics':
        $sub = $_GET['sub_action'] ?? 'overview';
        if ($sub === 'overview') {
            $total = (int)$db->query("SELECT COUNT(*) FROM alfred_agent_comms")->fetchColumn();
            $last24h = (int)$db->query("SELECT COUNT(*) FROM alfred_agent_comms WHERE sent_at > DATE_SUB(NOW(), INTERVAL 24 HOUR)")->fetchColumn();
            $byChannel = $db->query("SELECT channel, COUNT(*) as cnt FROM alfred_agent_comms GROUP BY channel ORDER BY cnt DESC")->fetchAll(PDO::FETCH_ASSOC);
            $bySender = $db->query("SELECT sender, COUNT(*) as cnt FROM alfred_agent_comms GROUP BY sender ORDER BY cnt DESC LIMIT 10")->fetchAll(PDO::FETCH_ASSOC);
            $byRecipient = $db->query("SELECT recipient, COUNT(*) as cnt FROM alfred_agent_comms GROUP BY recipient ORDER BY cnt DESC LIMIT 10")->fetchAll(PDO::FETCH_ASSOC);
            $hourly = $db->query("SELECT HOUR(sent_at) as hr, COUNT(*) as cnt FROM alfred_agent_comms WHERE sent_at > DATE_SUB(NOW(), INTERVAL 7 DAY) GROUP BY HOUR(sent_at) ORDER BY hr")->fetchAll(PDO::FETCH_ASSOC);
            $unread = (int)$db->query("SELECT COUNT(*) FROM alfred_agent_comms WHERE acknowledged = 0")->fetchColumn();
            $avgLen = (float)$db->query("SELECT AVG(LENGTH(body)) FROM alfred_agent_comms")->fetchColumn();
            agent_panel_json(['ok' => true, 'total' => $total, 'last_24h' => $last24h, 'unread' => $unread, 'avg_length' => round($avgLen), 'by_channel' => $byChannel, 'by_sender' => $bySender, 'by_recipient' => $byRecipient, 'hourly' => $hourly]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── AGENT AUTONOMY ───
    case 'autonomy':
        $sub = $_GET['sub_action'] ?? 'list';
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_autonomy (
            id INT AUTO_INCREMENT PRIMARY KEY,
            agent_name VARCHAR(100) NOT NULL UNIQUE,
            autonomy_level INT DEFAULT 1,
            can_self_heal TINYINT(1) DEFAULT 0,
            can_dispatch TINYINT(1) DEFAULT 0,
            can_escalate TINYINT(1) DEFAULT 1,
            can_communicate TINYINT(1) DEFAULT 1,
            max_concurrent_missions INT DEFAULT 3,
            decision_authority VARCHAR(50) DEFAULT 'request',
            updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
        )");
        if ($sub === 'list') {
            $agents = $db->query("SELECT a.*, ah.status as health_status FROM alfred_autonomy a LEFT JOIN alfred_agent_health ah ON a.agent_name = ah.agent_name ORDER BY a.autonomy_level DESC")->fetchAll(PDO::FETCH_ASSOC);
            // Auto-populate if empty
            if (empty($agents)) {
                $healthAgents = $db->query("SELECT DISTINCT agent_name FROM alfred_agent_health")->fetchAll(PDO::FETCH_COLUMN);
                $st = $db->prepare("INSERT IGNORE INTO alfred_autonomy (agent_name) VALUES (?)");
                foreach ($healthAgents as $a) $st->execute([$a]);
                $agents = $db->query("SELECT a.*, ah.status as health_status FROM alfred_autonomy a LEFT JOIN alfred_agent_health ah ON a.agent_name = ah.agent_name ORDER BY a.autonomy_level DESC")->fetchAll(PDO::FETCH_ASSOC);
            }
            agent_panel_json(['ok' => true, 'agents' => $agents]);
        } elseif ($sub === 'update') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $agent = $data['agent_name'] ?? '';
            if (!$agent) { agent_panel_json(['error' => 'agent_name required']); break; }
            $fields = []; $params = [];
            foreach (['autonomy_level','can_self_heal','can_dispatch','can_escalate','can_communicate','max_concurrent_missions','decision_authority'] as $f) {
                if (isset($data[$f])) { $fields[] = "$f = ?"; $params[] = $data[$f]; }
            }
            if (empty($fields)) { agent_panel_json(['error' => 'Nothing to update']); break; }
            $params[] = $agent;
            $db->prepare("UPDATE alfred_autonomy SET " . implode(', ', $fields) . " WHERE agent_name = ?")->execute($params);
            logAudit($db, 'autonomy_update', $agent, "Autonomy updated: " . json_encode($data));
            agent_panel_json(['ok' => true]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── DARK MODE TOGGLE ───
    case 'dark_mode':
        $sub = $_GET['sub_action'] ?? 'status';
        // Dark mode state stored in DB for persistence
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_warroom_settings (
            setting_key VARCHAR(100) PRIMARY KEY,
            setting_value TEXT,
            updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
        )");
        if ($sub === 'status') {
            $st = $db->prepare("SELECT setting_value FROM alfred_warroom_settings WHERE setting_key = 'dark_mode'");
            $st->execute();
            $val = $st->fetchColumn();
            agent_panel_json(['ok' => true, 'mode' => $val ?: 'default']);
        } elseif ($sub === 'toggle') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $mode = $data['mode'] ?? 'default';
            $allowed = ['default', 'midnight', 'green_ops', 'blood_red', 'arctic'];
            if (!in_array($mode, $allowed)) $mode = 'default';
            $db->prepare("INSERT INTO alfred_warroom_settings (setting_key, setting_value) VALUES ('dark_mode', ?) ON DUPLICATE KEY UPDATE setting_value = VALUES(setting_value)")->execute([$mode]);
            agent_panel_json(['ok' => true, 'mode' => $mode]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── INCIDENT HEATMAP ───
    case 'incident_heatmap':
        $sub = $_GET['sub_action'] ?? 'data';
        if ($sub === 'data') {
            $days = (int)($_GET['days'] ?? 30);
            if ($days > 90) $days = 90;
            // Incidents by day and agent
            $byDay = $db->prepare("SELECT DATE(created_at) as day, COUNT(*) as cnt FROM alfred_agent_incidents WHERE created_at > DATE_SUB(NOW(), INTERVAL ? DAY) GROUP BY DATE(created_at) ORDER BY day");
            $byDay->execute([$days]);
            $dailyCounts = $byDay->fetchAll(PDO::FETCH_ASSOC);

            $byAgent = $db->prepare("SELECT agent_name, COUNT(*) as cnt, SUM(CASE WHEN severity='critical' THEN 1 ELSE 0 END) as critical_cnt FROM alfred_agent_incidents WHERE created_at > DATE_SUB(NOW(), INTERVAL ? DAY) GROUP BY agent_name ORDER BY cnt DESC");
            $byAgent->execute([$days]);
            $agentCounts = $byAgent->fetchAll(PDO::FETCH_ASSOC);

            // Hour-of-day distribution
            $byHour = $db->prepare("SELECT HOUR(created_at) as hr, COUNT(*) as cnt FROM alfred_agent_incidents WHERE created_at > DATE_SUB(NOW(), INTERVAL ? DAY) GROUP BY HOUR(created_at) ORDER BY hr");
            $byHour->execute([$days]);
            $hourlyCounts = $byHour->fetchAll(PDO::FETCH_ASSOC);

            // Day-of-week
            $byDow = $db->prepare("SELECT DAYOFWEEK(created_at) as dow, COUNT(*) as cnt FROM alfred_agent_incidents WHERE created_at > DATE_SUB(NOW(), INTERVAL ? DAY) GROUP BY DAYOFWEEK(created_at) ORDER BY dow");
            $byDow->execute([$days]);
            $dowCounts = $byDow->fetchAll(PDO::FETCH_ASSOC);

            // Severity breakdown
            $bySeverity = $db->query("SELECT severity, COUNT(*) as cnt FROM alfred_agent_incidents GROUP BY severity")->fetchAll(PDO::FETCH_ASSOC);

            $total = (int)$db->query("SELECT COUNT(*) FROM alfred_agent_incidents")->fetchColumn();
            $open = (int)$db->query("SELECT COUNT(*) FROM alfred_agent_incidents WHERE status = 'open'")->fetchColumn();

            agent_panel_json(['ok' => true, 'total' => $total, 'open' => $open, 'by_day' => $dailyCounts, 'by_agent' => $agentCounts, 'by_hour' => $hourlyCounts, 'by_dow' => $dowCounts, 'by_severity' => $bySeverity]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── AGENT TRUST SCORES ───
    case 'trust_scores':
        $sub = $_GET['sub_action'] ?? 'list';
        if ($sub === 'list') {
            $agents = $db->query("SELECT DISTINCT agent_name FROM alfred_agent_health")->fetchAll(PDO::FETCH_COLUMN);
            $scores = [];
            foreach ($agents as $agent) {
                // Factors: uptime, mission success, incident rate, quarantine history, comms reliability
                $health = $db->prepare("SELECT status, uptime_pct FROM alfred_agent_health WHERE agent_name = ?");
                $health->execute([$agent]);
                $h = $health->fetch(PDO::FETCH_ASSOC);
                $uptime = (float)($h['uptime_pct'] ?? 90);

                $totalMissions = (int)$db->query("SELECT COUNT(*) FROM alfred_agent_dispatches WHERE agent_name = '$agent'")->fetchColumn();
                $completedMissions = (int)$db->query("SELECT COUNT(*) FROM alfred_agent_dispatches WHERE agent_name = '$agent' AND status = 'completed'")->fetchColumn();
                $missionRate = $totalMissions > 0 ? ($completedMissions / $totalMissions * 100) : 100;

                $incidents = (int)$db->query("SELECT COUNT(*) FROM alfred_agent_incidents WHERE agent_name = '$agent'")->fetchColumn();
                $quarantines = (int)$db->query("SELECT COUNT(*) FROM alfred_quarantine WHERE agent_name = '$agent'")->fetchColumn();

                $commsTotal = (int)$db->query("SELECT COUNT(*) FROM alfred_agent_comms WHERE sender = '$agent'")->fetchColumn();
                $commsAcked = (int)$db->query("SELECT COUNT(*) FROM alfred_agent_comms WHERE sender = '$agent' AND acknowledged = 1")->fetchColumn();
                $commsReliability = $commsTotal > 0 ? ($commsAcked / $commsTotal * 100) : 100;

                // Trust score: weighted formula
                $trust = round(
                    ($uptime * 0.3) +
                    ($missionRate * 0.3) +
                    (max(0, 100 - $incidents * 5) * 0.2) +
                    (max(0, 100 - $quarantines * 20) * 0.1) +
                    ($commsReliability * 0.1)
                , 1);
                $trust = max(0, min(100, $trust));

                $tier = $trust >= 90 ? 'Trusted' : ($trust >= 70 ? 'Reliable' : ($trust >= 50 ? 'Probation' : 'Untrusted'));

                $scores[] = [
                    'agent' => $agent,
                    'trust_score' => $trust,
                    'tier' => $tier,
                    'uptime' => round($uptime, 1),
                    'mission_rate' => round($missionRate, 1),
                    'incidents' => $incidents,
                    'quarantines' => $quarantines,
                    'comms_reliability' => round($commsReliability, 1),
                    'status' => $h['status'] ?? 'unknown',
                ];
            }
            usort($scores, function($a, $b) { return $b['trust_score'] - $a['trust_score']; });
            agent_panel_json(['ok' => true, 'scores' => $scores]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── WAR ROOM EXPORT ───
    case 'warroom_export':
        $sub = $_GET['sub_action'] ?? 'summary';
        if ($sub === 'summary') {
            // Generate comprehensive war room status report
            $now = date('Y-m-d H:i:s');
            $report = ['generated_at' => $now, 'sections' => []];

            // Fleet status
            $fleet = $db->query("SELECT agent_name, status, uptime_pct, services_online, services_total, memory_mb, cpu_pct FROM alfred_agent_health ORDER BY agent_name")->fetchAll(PDO::FETCH_ASSOC);
            $report['sections']['fleet_status'] = ['count' => count($fleet), 'agents' => $fleet];

            // Active missions
            $active = $db->query("SELECT agent_name, mission, status, priority, created_at FROM alfred_agent_dispatches WHERE status IN ('pending','in_progress') ORDER BY priority DESC, created_at DESC LIMIT 20")->fetchAll(PDO::FETCH_ASSOC);
            $report['sections']['active_missions'] = ['count' => count($active), 'missions' => $active];

            // Open incidents
            $incidents = $db->query("SELECT agent_name, type, severity, description, status, created_at FROM alfred_agent_incidents WHERE status = 'open' ORDER BY FIELD(severity,'critical','high','medium','low') LIMIT 20")->fetchAll(PDO::FETCH_ASSOC);
            $report['sections']['open_incidents'] = ['count' => count($incidents), 'incidents' => $incidents];

            // SLA overview
            try {
                $sla = $db->query("SELECT agent_name, uptime_target, uptime_actual, mission_target, mission_actual, grade FROM alfred_agent_sla")->fetchAll(PDO::FETCH_ASSOC);
                $report['sections']['sla'] = ['agents' => $sla];
            } catch (Exception $e) {}

            // Recent alerts
            $recentComms = $db->query("SELECT sender, recipient, subject, channel, sent_at FROM alfred_agent_comms WHERE channel = 'alert' ORDER BY sent_at DESC LIMIT 10")->fetchAll(PDO::FETCH_ASSOC);
            $report['sections']['recent_alerts'] = ['alerts' => $recentComms];

            // Heartbeat
            try {
                $heartbeat = $db->query("SELECT agent_name, status, response_ms, last_check FROM alfred_heartbeat ORDER BY agent_name")->fetchAll(PDO::FETCH_ASSOC);
                $report['sections']['heartbeat'] = ['agents' => $heartbeat];
            } catch (Exception $e) {}

            agent_panel_json(['ok' => true, 'report' => $report]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── MAINTENANCE WINDOWS ───
    case 'maintenance':
        $sub = $_GET['sub_action'] ?? 'list';
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_maintenance_windows (
            id INT AUTO_INCREMENT PRIMARY KEY,
            agent_name VARCHAR(100) NOT NULL,
            title VARCHAR(200) NOT NULL,
            description TEXT,
            start_time TIMESTAMP NOT NULL,
            end_time TIMESTAMP NOT NULL,
            status VARCHAR(30) DEFAULT 'scheduled',
            created_by VARCHAR(100) DEFAULT 'commander',
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        )");
        if ($sub === 'list') {
            $windows = $db->query("SELECT * FROM alfred_maintenance_windows ORDER BY start_time DESC LIMIT 50")->fetchAll(PDO::FETCH_ASSOC);
            // Check and update status of windows
            foreach ($windows as &$w) {
                $now = time();
                $start = strtotime($w['start_time']);
                $end = strtotime($w['end_time']);
                if ($w['status'] === 'scheduled' && $now >= $start && $now < $end) {
                    $w['status'] = 'active';
                    $db->prepare("UPDATE alfred_maintenance_windows SET status = 'active' WHERE id = ?")->execute([$w['id']]);
                } elseif (($w['status'] === 'scheduled' || $w['status'] === 'active') && $now >= $end) {
                    $w['status'] = 'completed';
                    $db->prepare("UPDATE alfred_maintenance_windows SET status = 'completed' WHERE id = ?")->execute([$w['id']]);
                }
            }
            agent_panel_json(['ok' => true, 'windows' => $windows]);
        } elseif ($sub === 'create') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $agent = $data['agent_name'] ?? '';
            $title = trim($data['title'] ?? '');
            $start = $data['start_time'] ?? '';
            $end = $data['end_time'] ?? '';
            if (!$agent || !$title || !$start || !$end) { agent_panel_json(['error' => 'agent_name, title, start_time, end_time required']); break; }
            $st = $db->prepare("INSERT INTO alfred_maintenance_windows (agent_name, title, description, start_time, end_time) VALUES (?, ?, ?, ?, ?)");
            $st->execute([$agent, $title, $data['description'] ?? '', $start, $end]);
            logAudit($db, 'maintenance_create', $agent, "Window: $title ($start to $end)");
            agent_panel_json(['ok' => true, 'id' => $db->lastInsertId()]);
        } elseif ($sub === 'cancel') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $id = (int)($data['id'] ?? 0);
            if (!$id) { agent_panel_json(['error' => 'id required']); break; }
            $db->prepare("UPDATE alfred_maintenance_windows SET status = 'cancelled' WHERE id = ?")->execute([$id]);
            agent_panel_json(['ok' => true]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── AGENT MORALE ───
    case 'morale':
        $sub = $_GET['sub_action'] ?? 'list';
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_agent_morale (
            id INT AUTO_INCREMENT PRIMARY KEY,
            agent_name VARCHAR(100) NOT NULL,
            mood VARCHAR(30) NOT NULL DEFAULT 'nominal',
            morale_score INT DEFAULT 75,
            last_positive TEXT,
            last_negative TEXT,
            streak_days INT DEFAULT 0,
            updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
            UNIQUE KEY (agent_name)
        )");
        if ($sub === 'list') {
            $rows = $db->query("SELECT m.*, h.status as health_status FROM alfred_agent_morale m LEFT JOIN alfred_agent_health h ON m.agent_name = h.agent_name ORDER BY m.morale_score DESC")->fetchAll(PDO::FETCH_ASSOC);
            // Auto-calculate morale from recent events if empty
            if (empty($rows)) {
                $agents = $db->query("SELECT DISTINCT agent_name FROM alfred_agent_health")->fetchAll(PDO::FETCH_COLUMN);
                foreach ($agents as $a) {
                    $db->prepare("INSERT IGNORE INTO alfred_agent_morale (agent_name, mood, morale_score) VALUES (?, 'nominal', 75)")->execute([$a]);
                }
                $rows = $db->query("SELECT m.*, h.status as health_status FROM alfred_agent_morale m LEFT JOIN alfred_agent_health h ON m.agent_name = h.agent_name ORDER BY m.morale_score DESC")->fetchAll(PDO::FETCH_ASSOC);
            }
            agent_panel_json(['ok' => true, 'morale' => $rows]);
        } elseif ($sub === 'update') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $agent = $data['agent_name'] ?? '';
            $mood = $data['mood'] ?? 'nominal';
            $score = max(0, min(100, (int)($data['morale_score'] ?? 75)));
            $note = $data['note'] ?? '';
            if (!$agent) { agent_panel_json(['error' => 'agent_name required']); break; }
            $moods = ['ecstatic','motivated','nominal','fatigued','critical'];
            if (!in_array($mood, $moods)) $mood = 'nominal';
            $field = $score >= 50 ? 'last_positive' : 'last_negative';
            $db->prepare("INSERT INTO alfred_agent_morale (agent_name, mood, morale_score, $field) VALUES (?, ?, ?, ?) ON DUPLICATE KEY UPDATE mood = VALUES(mood), morale_score = VALUES(morale_score), $field = VALUES($field)")->execute([$agent, $mood, $score, $note]);
            logAudit($db, 'morale_update', $agent, "Mood: $mood, Score: $score");
            agent_panel_json(['ok' => true]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── BANDWIDTH MONITOR ───
    case 'bandwidth':
        $sub = $_GET['sub_action'] ?? 'status';
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_bandwidth_log (
            id INT AUTO_INCREMENT PRIMARY KEY,
            agent_name VARCHAR(100) NOT NULL,
            rx_bytes BIGINT DEFAULT 0,
            tx_bytes BIGINT DEFAULT 0,
            connections INT DEFAULT 0,
            latency_ms FLOAT DEFAULT 0,
            recorded_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            INDEX (agent_name, recorded_at)
        )");
        if ($sub === 'status') {
            $latest = $db->query("SELECT b1.* FROM alfred_bandwidth_log b1 INNER JOIN (SELECT agent_name, MAX(id) as max_id FROM alfred_bandwidth_log GROUP BY agent_name) b2 ON b1.id = b2.max_id ORDER BY b1.agent_name")->fetchAll(PDO::FETCH_ASSOC);
            $totalRx = 0; $totalTx = 0;
            foreach ($latest as $l) { $totalRx += $l['rx_bytes']; $totalTx += $l['tx_bytes']; }
            agent_panel_json(['ok' => true, 'agents' => $latest, 'total_rx' => $totalRx, 'total_tx' => $totalTx]);
        } elseif ($sub === 'record') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $agent = $data['agent_name'] ?? '';
            if (!$agent) { agent_panel_json(['error' => 'agent_name required']); break; }
            $st = $db->prepare("INSERT INTO alfred_bandwidth_log (agent_name, rx_bytes, tx_bytes, connections, latency_ms) VALUES (?, ?, ?, ?, ?)");
            $st->execute([$agent, (int)($data['rx_bytes']??0), (int)($data['tx_bytes']??0), (int)($data['connections']??0), (float)($data['latency_ms']??0)]);
            agent_panel_json(['ok' => true, 'id' => $db->lastInsertId()]);
        } elseif ($sub === 'history') {
            $agent = $_GET['agent'] ?? '';
            $hours = (int)($_GET['hours'] ?? 24);
            if ($hours > 168) $hours = 168;
            $st = $db->prepare("SELECT rx_bytes, tx_bytes, connections, latency_ms, recorded_at FROM alfred_bandwidth_log WHERE agent_name = ? AND recorded_at > DATE_SUB(NOW(), INTERVAL ? HOUR) ORDER BY recorded_at");
            $st->execute([$agent, $hours]);
            agent_panel_json(['ok' => true, 'history' => $st->fetchAll(PDO::FETCH_ASSOC)]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── MISSION PRIORITY REORDER ───
    case 'mission_reorder':
        $sub = $_GET['sub_action'] ?? 'reorder';
        if ($sub === 'reorder') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $order = $data['order'] ?? []; // array of {id, priority}
            if (empty($order)) { agent_panel_json(['error' => 'order array required']); break; }
            $count = 0;
            foreach ($order as $item) {
                $id = (int)($item['id'] ?? 0);
                $pri = $item['priority'] ?? 'normal';
                $allowed = ['critical','high','normal','low'];
                if (!in_array($pri, $allowed)) $pri = 'normal';
                if ($id > 0) {
                    $db->prepare("UPDATE alfred_agent_dispatches SET priority = ? WHERE id = ?")->execute([$pri, $id]);
                    $count++;
                }
            }
            logAudit($db, 'mission_reorder', 'fleet', "Reordered $count missions");
            agent_panel_json(['ok' => true, 'updated' => $count]);
        } elseif ($sub === 'bulk_priority') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $ids = $data['ids'] ?? [];
            $priority = $data['priority'] ?? 'normal';
            $allowed = ['critical','high','normal','low'];
            if (!in_array($priority, $allowed)) $priority = 'normal';
            if (empty($ids)) { agent_panel_json(['error' => 'ids array required']); break; }
            $placeholders = implode(',', array_fill(0, count($ids), '?'));
            $params = array_merge([$priority], array_map('intval', $ids));
            $db->prepare("UPDATE alfred_agent_dispatches SET priority = ? WHERE id IN ($placeholders)")->execute($params);
            agent_panel_json(['ok' => true, 'updated' => count($ids)]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── AGENT DEPENDENCY GRAPH ───
    case 'agent_deps':
        $sub = $_GET['sub_action'] ?? 'map';
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_agent_dependencies (
            id INT AUTO_INCREMENT PRIMARY KEY,
            agent_name VARCHAR(100) NOT NULL,
            depends_on VARCHAR(100) NOT NULL,
            dependency_type VARCHAR(50) DEFAULT 'runtime',
            strength VARCHAR(20) DEFAULT 'required',
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            UNIQUE KEY (agent_name, depends_on)
        )");
        if ($sub === 'map') {
            $deps = $db->query("SELECT d.*, h1.status as agent_status, h2.status as dep_status FROM alfred_agent_dependencies d LEFT JOIN alfred_agent_health h1 ON d.agent_name = h1.agent_name LEFT JOIN alfred_agent_health h2 ON d.depends_on = h2.agent_name ORDER BY d.agent_name")->fetchAll(PDO::FETCH_ASSOC);
            // Build node list
            $nodes = [];
            foreach ($deps as $d) {
                $nodes[$d['agent_name']] = $d['agent_status'] ?? 'unknown';
                $nodes[$d['depends_on']] = $d['dep_status'] ?? 'unknown';
            }
            // Also include agents with no deps
            $allAgents = $db->query("SELECT agent_name, status FROM alfred_agent_health")->fetchAll(PDO::FETCH_ASSOC);
            foreach ($allAgents as $a) { if (!isset($nodes[$a['agent_name']])) $nodes[$a['agent_name']] = $a['status']; }
            agent_panel_json(['ok' => true, 'dependencies' => $deps, 'nodes' => $nodes]);
        } elseif ($sub === 'add') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $agent = $data['agent_name'] ?? '';
            $dep = $data['depends_on'] ?? '';
            $type = $data['dependency_type'] ?? 'runtime';
            $strength = $data['strength'] ?? 'required';
            if (!$agent || !$dep) { agent_panel_json(['error' => 'agent_name and depends_on required']); break; }
            if ($agent === $dep) { agent_panel_json(['error' => 'Cannot depend on self']); break; }
            $db->prepare("INSERT IGNORE INTO alfred_agent_dependencies (agent_name, depends_on, dependency_type, strength) VALUES (?, ?, ?, ?)")->execute([$agent, $dep, $type, $strength]);
            logAudit($db, 'agent_dep_add', $agent, "Depends on: $dep ($type/$strength)");
            agent_panel_json(['ok' => true]);
        } elseif ($sub === 'remove') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $id = (int)($data['id'] ?? 0);
            if (!$id) { agent_panel_json(['error' => 'id required']); break; }
            $db->prepare("DELETE FROM alfred_agent_dependencies WHERE id = ?")->execute([$id]);
            agent_panel_json(['ok' => true]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── COMMAND PALETTE ───
    case 'command_palette':
        $sub = $_GET['sub_action'] ?? 'list';
        if ($sub === 'list') {
            // Return all available War Room commands
            $commands = [
                ['cmd' => 'refresh', 'label' => 'Refresh All Panels', 'icon' => 'fa-sync-alt', 'category' => 'system'],
                ['cmd' => 'fleet_restart', 'label' => 'Restart Critical Fleet', 'icon' => 'fa-power-off', 'category' => 'fleet'],
                ['cmd' => 'broadcast', 'label' => 'Fleet Broadcast', 'icon' => 'fa-bullhorn', 'category' => 'comms'],
                ['cmd' => 'health_scan', 'label' => 'Health Scan All', 'icon' => 'fa-heartbeat', 'category' => 'health'],
                ['cmd' => 'export_json', 'label' => 'Export Report (JSON)', 'icon' => 'fa-file-export', 'category' => 'tools'],
                ['cmd' => 'dark_ops', 'label' => 'Toggle Dark Ops', 'icon' => 'fa-moon', 'category' => 'display'],
                ['cmd' => 'lockdown', 'label' => 'Fleet Lockdown', 'icon' => 'fa-lock', 'category' => 'security'],
                ['cmd' => 'scroll_top', 'label' => 'Scroll to Top', 'icon' => 'fa-arrow-up', 'category' => 'navigation'],
                ['cmd' => 'deploy_all', 'label' => 'Deploy All Agents', 'icon' => 'fa-rocket', 'category' => 'fleet'],
                ['cmd' => 'quarantine_list', 'label' => 'View Quarantined', 'icon' => 'fa-shield-virus', 'category' => 'security'],
                ['cmd' => 'theme_default', 'label' => 'Theme: Default', 'icon' => 'fa-adjust', 'category' => 'display'],
                ['cmd' => 'theme_midnight', 'label' => 'Theme: Midnight', 'icon' => 'fa-adjust', 'category' => 'display'],
                ['cmd' => 'theme_green_ops', 'label' => 'Theme: Green Ops', 'icon' => 'fa-adjust', 'category' => 'display'],
                ['cmd' => 'theme_blood_red', 'label' => 'Theme: Blood Red', 'icon' => 'fa-adjust', 'category' => 'display'],
                ['cmd' => 'theme_arctic', 'label' => 'Theme: Arctic', 'icon' => 'fa-adjust', 'category' => 'display'],
                ['cmd' => 'incident_report', 'label' => 'Create Incident', 'icon' => 'fa-exclamation-triangle', 'category' => 'fleet'],
                ['cmd' => 'mission_new', 'label' => 'New Mission', 'icon' => 'fa-crosshairs', 'category' => 'missions'],
                ['cmd' => 'sitrep', 'label' => 'Generate SITREP', 'icon' => 'fa-clipboard-list', 'category' => 'intel'],
                ['cmd' => 'schedule_maint', 'label' => 'Schedule Maintenance', 'icon' => 'fa-wrench', 'category' => 'fleet'],
                ['cmd' => 'clear_alerts', 'label' => 'Clear All Alerts', 'icon' => 'fa-bell-slash', 'category' => 'comms'],
            ];
            $q = trim($_GET['q'] ?? '');
            if ($q) {
                $commands = array_values(array_filter($commands, function($c) use ($q) {
                    return stripos($c['label'], $q) !== false || stripos($c['cmd'], $q) !== false || stripos($c['category'], $q) !== false;
                }));
            }
            agent_panel_json(['ok' => true, 'commands' => $commands]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── PATROL ROUTES ───
    case 'patrol':
        $sub = $_GET['sub_action'] ?? 'list';
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_patrol_routes (
            id INT AUTO_INCREMENT PRIMARY KEY,
            route_name VARCHAR(200) NOT NULL,
            agent_name VARCHAR(100) NOT NULL,
            checkpoints TEXT,
            schedule_cron VARCHAR(100) DEFAULT '*/15 * * * *',
            status VARCHAR(30) DEFAULT 'active',
            last_patrol TIMESTAMP NULL,
            last_result VARCHAR(30) DEFAULT 'pending',
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        )");
        if ($sub === 'list') {
            $rows = $db->query("SELECT * FROM alfred_patrol_routes ORDER BY status='active' DESC, last_patrol DESC")->fetchAll(PDO::FETCH_ASSOC);
            foreach ($rows as &$row) { $row['checkpoints'] = json_decode($row['checkpoints'] ?: '[]', true); }
            agent_panel_json(['ok' => true, 'routes' => $rows]);
        } elseif ($sub === 'create') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $name = trim($data['route_name'] ?? '');
            $agent = $data['agent_name'] ?? '';
            $checkpoints = $data['checkpoints'] ?? [];
            $cron = $data['schedule_cron'] ?? '*/15 * * * *';
            if (!$name || !$agent) { agent_panel_json(['error' => 'route_name and agent_name required']); break; }
            $st = $db->prepare("INSERT INTO alfred_patrol_routes (route_name, agent_name, checkpoints, schedule_cron) VALUES (?, ?, ?, ?)");
            $st->execute([$name, $agent, json_encode($checkpoints), $cron]);
            logAudit($db, 'patrol_create', $agent, "Route: $name");
            agent_panel_json(['ok' => true, 'id' => $db->lastInsertId()]);
        } elseif ($sub === 'run') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $id = (int)($data['id'] ?? 0);
            if (!$id) { agent_panel_json(['error' => 'id required']); break; }
            $db->prepare("UPDATE alfred_patrol_routes SET last_patrol = NOW(), last_result = 'pass' WHERE id = ?")->execute([$id]);
            agent_panel_json(['ok' => true]);
        } elseif ($sub === 'delete') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $id = (int)($data['id'] ?? 0);
            if (!$id) { agent_panel_json(['error' => 'id required']); break; }
            $db->prepare("DELETE FROM alfred_patrol_routes WHERE id = ?")->execute([$id]);
            agent_panel_json(['ok' => true]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── UPTIME LEADERBOARD ───
    case 'uptime_leaderboard':
        $sub = $_GET['sub_action'] ?? 'list';
        if ($sub === 'list') {
            $agents = $db->query("SELECT agent_name, status, uptime_pct, services_online, services_total, last_heartbeat FROM alfred_agent_health ORDER BY uptime_pct DESC")->fetchAll(PDO::FETCH_ASSOC);
            // Add rank and medal
            $rank = 1;
            foreach ($agents as &$a) {
                $a['rank'] = $rank;
                $a['medal'] = $rank === 1 ? 'gold' : ($rank === 2 ? 'silver' : ($rank === 3 ? 'bronze' : 'none'));
                $a['uptime_pct'] = (float)$a['uptime_pct'];
                // Calculate consecutive healthy days
                $missedHrs = (int)$db->query("SELECT COUNT(DISTINCT DATE(recorded_at)) FROM alfred_agent_health WHERE agent_name = '{$a['agent_name']}' AND status != 'healthy' AND recorded_at > DATE_SUB(NOW(), INTERVAL 30 DAY)")->fetchColumn();
                $a['healthy_days'] = max(0, 30 - $missedHrs);
                $rank++;
            }
            agent_panel_json(['ok' => true, 'leaderboard' => $agents]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── MISSION COUNTDOWN ───
    case 'mission_countdown':
        $sub = $_GET['sub_action'] ?? 'active';
        if ($sub === 'active') {
            // Get missions with deadlines (using scheduled_time or updated_at as reference)
            $missions = $db->query("SELECT id, agent_name, mission, priority, status, scheduled_time, created_at FROM alfred_agent_dispatches WHERE status IN ('pending','in_progress') AND scheduled_time IS NOT NULL ORDER BY scheduled_time ASC")->fetchAll(PDO::FETCH_ASSOC);
            foreach ($missions as &$m) {
                if ($m['scheduled_time']) {
                    $remaining = strtotime($m['scheduled_time']) - time();
                    $m['remaining_seconds'] = max(0, $remaining);
                    $m['overdue'] = $remaining < 0;
                } else {
                    $m['remaining_seconds'] = null;
                    $m['overdue'] = false;
                }
            }
            agent_panel_json(['ok' => true, 'missions' => $missions]);
        } elseif ($sub === 'set_deadline') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $id = (int)($data['id'] ?? 0);
            $deadline = $data['deadline'] ?? '';
            if (!$id || !$deadline) { agent_panel_json(['error' => 'id and deadline required']); break; }
            $db->prepare("UPDATE alfred_agent_dispatches SET scheduled_time = ? WHERE id = ?")->execute([$deadline, $id]);
            agent_panel_json(['ok' => true]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── COMMUNICATION MATRIX ───
    case 'comm_matrix':
        $sub = $_GET['sub_action'] ?? 'matrix';
        if ($sub === 'matrix') {
            $days = (int)($_GET['days'] ?? 30);
            if ($days > 90) $days = 90;
            // Build NxN comm matrix
            $agents = $db->query("SELECT DISTINCT agent_name FROM alfred_agent_health ORDER BY agent_name")->fetchAll(PDO::FETCH_COLUMN);
            $matrix = [];
            foreach ($agents as $from) {
                $row = [];
                foreach ($agents as $to) {
                    $cnt = (int)$db->query("SELECT COUNT(*) FROM alfred_agent_comms WHERE sender = '$from' AND recipient = '$to' AND sent_at > DATE_SUB(NOW(), INTERVAL $days DAY)")->fetchColumn();
                    $row[$to] = $cnt;
                }
                $matrix[$from] = $row;
            }
            // Totals
            $totalComms = (int)$db->query("SELECT COUNT(*) FROM alfred_agent_comms WHERE sent_at > DATE_SUB(NOW(), INTERVAL $days DAY)")->fetchColumn();
            $topSender = $db->query("SELECT sender, COUNT(*) as cnt FROM alfred_agent_comms WHERE sent_at > DATE_SUB(NOW(), INTERVAL $days DAY) GROUP BY sender ORDER BY cnt DESC LIMIT 1")->fetch(PDO::FETCH_ASSOC);
            $topReceiver = $db->query("SELECT recipient, COUNT(*) as cnt FROM alfred_agent_comms WHERE sent_at > DATE_SUB(NOW(), INTERVAL $days DAY) GROUP BY recipient ORDER BY cnt DESC LIMIT 1")->fetch(PDO::FETCH_ASSOC);
            agent_panel_json(['ok' => true, 'agents' => $agents, 'matrix' => $matrix, 'total' => $totalComms, 'top_sender' => $topSender, 'top_receiver' => $topReceiver]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── ERROR LOG VIEWER ───
    case 'error_log':
        $sub = $_GET['sub_action'] ?? 'list';
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_error_log (
            id INT AUTO_INCREMENT PRIMARY KEY,
            agent_name VARCHAR(100) NOT NULL,
            error_level VARCHAR(30) DEFAULT 'error',
            error_message TEXT,
            stack_trace TEXT,
            context TEXT,
            resolved TINYINT DEFAULT 0,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            INDEX (agent_name, created_at),
            INDEX (error_level),
            INDEX (resolved)
        )");
        if ($sub === 'list') {
            $agent = $_GET['agent'] ?? '';
            $level = $_GET['level'] ?? '';
            $resolved = $_GET['resolved'] ?? '';
            $sql = "SELECT * FROM alfred_error_log WHERE 1=1";
            $params = [];
            if ($agent) { $sql .= " AND agent_name = ?"; $params[] = $agent; }
            if ($level) { $sql .= " AND error_level = ?"; $params[] = $level; }
            if ($resolved !== '') { $sql .= " AND resolved = ?"; $params[] = (int)$resolved; }
            $sql .= " ORDER BY created_at DESC LIMIT 100";
            $st = $db->prepare($sql);
            $st->execute($params);
            $errors = $st->fetchAll(PDO::FETCH_ASSOC);
            $total = (int)$db->query("SELECT COUNT(*) FROM alfred_error_log")->fetchColumn();
            $unresolved = (int)$db->query("SELECT COUNT(*) FROM alfred_error_log WHERE resolved = 0")->fetchColumn();
            agent_panel_json(['ok' => true, 'errors' => $errors, 'total' => $total, 'unresolved' => $unresolved]);
        } elseif ($sub === 'resolve') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $id = (int)($data['id'] ?? 0);
            if (!$id) { agent_panel_json(['error' => 'id required']); break; }
            $db->prepare("UPDATE alfred_error_log SET resolved = 1 WHERE id = ?")->execute([$id]);
            agent_panel_json(['ok' => true]);
        } elseif ($sub === 'resolve_all') {
            $agent = $_GET['agent'] ?? '';
            if ($agent) {
                $db->prepare("UPDATE alfred_error_log SET resolved = 1 WHERE agent_name = ? AND resolved = 0")->execute([$agent]);
            } else {
                $db->exec("UPDATE alfred_error_log SET resolved = 1 WHERE resolved = 0");
            }
            agent_panel_json(['ok' => true]);
        } elseif ($sub === 'log') {
            $data = json_decode(file_get_contents('php://input'), true) ?: [];
            $agent = $data['agent_name'] ?? '';
            $level = $data['error_level'] ?? 'error';
            $msg = $data['error_message'] ?? '';
            if (!$agent || !$msg) { agent_panel_json(['error' => 'agent_name and error_message required']); break; }
            $st = $db->prepare("INSERT INTO alfred_error_log (agent_name, error_level, error_message, stack_trace, context) VALUES (?, ?, ?, ?, ?)");
            $st->execute([$agent, $level, $msg, $data['stack_trace'] ?? '', json_encode($data['context'] ?? [])]);
            agent_panel_json(['ok' => true, 'id' => $db->lastInsertId()]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── FLEET POWER CONSUMPTION ───
    case 'power':
        $sub = $_GET['sub_action'] ?? $_POST['sub_action'] ?? 'snapshot';
        if ($sub === 'snapshot') {
            // Real-time power snapshot: CPU, memory, disk, load per agent from PM2/system
            $agents = $db->query("SELECT DISTINCT agent_name FROM alfred_agent_dispatches ORDER BY agent_name")->fetchAll(PDO::FETCH_COLUMN);
            $snapshot = [];
            foreach ($agents as $agentName) {
                // Get PM2 data from heartbeat
                $hb = $db->prepare("SELECT cpu_usage, memory_usage, response_time_ms FROM alfred_heartbeat WHERE agent_name = ? ORDER BY created_at DESC LIMIT 1");
                $hb->execute([$agentName]);
                $hbRow = $hb->fetch(PDO::FETCH_ASSOC);
                $cpu = $hbRow['cpu_usage'] ?? 0;
                $mem = $hbRow['memory_usage'] ?? 0;
                $resp = $hbRow['response_time_ms'] ?? 0;
                // Get task load
                $taskSt = $db->prepare("SELECT COUNT(*) FROM alfred_agent_tasks WHERE agent_name = ? AND status IN ('queued','assigned','running')");
                $taskSt->execute([$agentName]);
                $activeTasks = (int)$taskSt->fetchColumn();
                // Get mission load
                $msnSt = $db->prepare("SELECT COUNT(*) FROM alfred_agent_dispatches WHERE agent_name = ? AND status IN ('pending','in_progress')");
                $msnSt->execute([$agentName]);
                $activeMissions = (int)$msnSt->fetchColumn();
                $load = min(100, $cpu * 0.4 + ($mem / 1048576) * 0.3 + $activeTasks * 5 + $activeMissions * 3);
                $snapshot[] = [
                    'agent' => $agentName,
                    'cpu' => round($cpu, 1),
                    'memory_mb' => round($mem / 1048576, 1),
                    'response_ms' => round($resp),
                    'active_tasks' => $activeTasks,
                    'active_missions' => $activeMissions,
                    'composite_load' => round($load, 1),
                    'status' => $load > 80 ? 'critical' : ($load > 60 ? 'high' : ($load > 30 ? 'moderate' : 'low'))
                ];
            }
            usort($snapshot, fn($a, $b) => $b['composite_load'] <=> $a['composite_load']);
            $fleetAvg = count($snapshot) ? round(array_sum(array_column($snapshot, 'composite_load')) / count($snapshot), 1) : 0;
            agent_panel_json(['ok' => true, 'snapshot' => $snapshot, 'fleet_avg' => $fleetAvg, 'timestamp' => date('c')]);
        } elseif ($sub === 'history') {
            $hours = (int)($_GET['hours'] ?? 24);
            $hours = max(1, min(168, $hours));
            $st = $db->prepare("SELECT agent_name, cpu_usage, memory_usage, response_time_ms, created_at FROM alfred_heartbeat WHERE created_at >= NOW() - INTERVAL ? HOUR ORDER BY created_at");
            $st->execute([$hours]);
            agent_panel_json(['ok' => true, 'history' => $st->fetchAll(PDO::FETCH_ASSOC)]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── AGENT VERSION TRACKER ───
    case 'versions':
        $sub = $_GET['sub_action'] ?? $_POST['sub_action'] ?? 'list';
        if ($sub === 'list') {
            $db->exec("CREATE TABLE IF NOT EXISTS alfred_agent_versions (
                id INT AUTO_INCREMENT PRIMARY KEY,
                agent_name VARCHAR(100) NOT NULL,
                version VARCHAR(50) NOT NULL,
                changelog TEXT,
                deployed_by VARCHAR(100) DEFAULT 'commander',
                deployed_at DATETIME DEFAULT CURRENT_TIMESTAMP,
                rollback_version VARCHAR(50),
                status ENUM('active','superseded','rolled_back') DEFAULT 'active',
                INDEX idx_agent (agent_name),
                INDEX idx_deployed (deployed_at)
            ) ENGINE=InnoDB");
            $st = $db->query("SELECT * FROM alfred_agent_versions ORDER BY deployed_at DESC LIMIT 200");
            $rows = $st->fetchAll(PDO::FETCH_ASSOC);
            // Group by agent, get current version
            $current = [];
            foreach ($rows as $r) {
                if (!isset($current[$r['agent_name']]) && $r['status'] === 'active') {
                    $current[$r['agent_name']] = $r;
                }
            }
            agent_panel_json(['ok' => true, 'versions' => $rows, 'current' => array_values($current)]);
        } elseif ($sub === 'deploy') {
            $agent = trim($_POST['agent_name'] ?? '');
            $version = trim($_POST['version'] ?? '');
            $changelog = trim($_POST['changelog'] ?? '');
            if (!$agent || !$version) { agent_panel_json(['error' => 'agent_name and version required']); break; }
            // Mark old active as superseded
            $db->prepare("UPDATE alfred_agent_versions SET status = 'superseded' WHERE agent_name = ? AND status = 'active'")->execute([$agent]);
            $st = $db->prepare("INSERT INTO alfred_agent_versions (agent_name, version, changelog, deployed_by) VALUES (?, ?, ?, 'commander')");
            $st->execute([$agent, $version, $changelog]);
            agent_panel_json(['ok' => true, 'id' => $db->lastInsertId()]);
        } elseif ($sub === 'rollback') {
            $id = (int)($_POST['id'] ?? 0);
            if (!$id) { agent_panel_json(['error' => 'id required']); break; }
            $row = $db->prepare("SELECT * FROM alfred_agent_versions WHERE id = ?");
            $row->execute([$id]);
            $ver = $row->fetch(PDO::FETCH_ASSOC);
            if (!$ver) { agent_panel_json(['error' => 'Version not found']); break; }
            $db->prepare("UPDATE alfred_agent_versions SET status = 'rolled_back' WHERE agent_name = ? AND status = 'active'")->execute([$ver['agent_name']]);
            $db->prepare("UPDATE alfred_agent_versions SET status = 'active' WHERE id = ?")->execute([$id]);
            agent_panel_json(['ok' => true]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── MISSION SUCCESS HEATMAP ───
    case 'mission_heatmap':
        $days = (int)($_GET['days'] ?? 30);
        $days = max(7, min(90, $days));
        $st = $db->prepare("SELECT DATE(created_at) as day, status, COUNT(*) as cnt FROM alfred_agent_dispatches WHERE created_at >= NOW() - INTERVAL ? DAY GROUP BY day, status ORDER BY day");
        $st->execute([$days]);
        $raw = $st->fetchAll(PDO::FETCH_ASSOC);
        $heatmap = [];
        foreach ($raw as $r) {
            $day = $r['day'];
            if (!isset($heatmap[$day])) $heatmap[$day] = ['day' => $day, 'completed' => 0, 'failed' => 0, 'pending' => 0, 'in_progress' => 0, 'total' => 0];
            $heatmap[$day][$r['status']] = (int)$r['cnt'];
            $heatmap[$day]['total'] += (int)$r['cnt'];
        }
        foreach ($heatmap as &$d) {
            $d['success_rate'] = $d['total'] > 0 ? round(($d['completed'] / $d['total']) * 100, 1) : 0;
        }
        // Per-agent success rates
        $agSt = $db->prepare("SELECT agent_name, status, COUNT(*) as cnt FROM alfred_agent_dispatches WHERE created_at >= NOW() - INTERVAL ? DAY GROUP BY agent_name, status");
        $agSt->execute([$days]);
        $agRaw = $agSt->fetchAll(PDO::FETCH_ASSOC);
        $agentRates = [];
        foreach ($agRaw as $r) {
            $a = $r['agent_name'];
            if (!isset($agentRates[$a])) $agentRates[$a] = ['agent' => $a, 'completed' => 0, 'failed' => 0, 'total' => 0];
            if ($r['status'] === 'completed') $agentRates[$a]['completed'] = (int)$r['cnt'];
            if ($r['status'] === 'failed') $agentRates[$a]['failed'] = (int)$r['cnt'];
            $agentRates[$a]['total'] += (int)$r['cnt'];
        }
        foreach ($agentRates as &$a) {
            $a['success_rate'] = $a['total'] > 0 ? round(($a['completed'] / $a['total']) * 100, 1) : 0;
        }
        agent_panel_json(['ok' => true, 'heatmap' => array_values($heatmap), 'agent_rates' => array_values($agentRates), 'days' => $days]);
        break;

    // ─── FLEET COMPLIANCE CHECKER ───
    case 'compliance':
        $sub = $_GET['sub_action'] ?? $_POST['sub_action'] ?? 'check';
        if ($sub === 'check') {
            $db->exec("CREATE TABLE IF NOT EXISTS alfred_compliance_checks (
                id INT AUTO_INCREMENT PRIMARY KEY,
                agent_name VARCHAR(100) NOT NULL,
                check_type ENUM('sop','security','config','health','comms') NOT NULL,
                check_name VARCHAR(200) NOT NULL,
                status ENUM('pass','fail','warn','skip') DEFAULT 'skip',
                details TEXT,
                checked_at DATETIME DEFAULT CURRENT_TIMESTAMP,
                INDEX idx_agent (agent_name),
                INDEX idx_type (check_type)
            ) ENGINE=InnoDB");
            $agents = $db->query("SELECT DISTINCT agent_name FROM alfred_agent_dispatches ORDER BY agent_name")->fetchAll(PDO::FETCH_COLUMN);
            $results = [];
            foreach ($agents as $agentName) {
                $checks = [];
                // Health check: has recent heartbeat
                $hb = $db->prepare("SELECT COUNT(*) FROM alfred_heartbeat WHERE agent_name = ? AND created_at >= NOW() - INTERVAL 10 MINUTE");
                $hb->execute([$agentName]);
                $checks[] = ['check' => 'Recent heartbeat', 'type' => 'health', 'status' => $hb->fetchColumn() > 0 ? 'pass' : 'fail'];
                // Security: has crypto keys
                $ck = $db->prepare("SELECT COUNT(*) FROM alfred_comm_keys WHERE agent_name = ? AND status = 'active'");
                $ck->execute([$agentName]);
                $checks[] = ['check' => 'Active crypto keys', 'type' => 'security', 'status' => $ck->fetchColumn() > 0 ? 'pass' : 'warn'];
                // Comms: sent comms in last 24h
                $cm = $db->prepare("SELECT COUNT(*) FROM alfred_agent_comms WHERE from_agent = ? AND created_at >= NOW() - INTERVAL 24 HOUR");
                $cm->execute([$agentName]);
                $checks[] = ['check' => 'Recent communications', 'type' => 'comms', 'status' => $cm->fetchColumn() > 0 ? 'pass' : 'warn'];
                // SOP: has SOPs defined
                $sp = $db->prepare("SELECT COUNT(*) FROM alfred_agent_sops WHERE agent_name = ? OR agent_name = 'all'");
                $sp->execute([$agentName]);
                $checks[] = ['check' => 'SOPs defined', 'type' => 'sop', 'status' => $sp->fetchColumn() > 0 ? 'pass' : 'fail'];
                // Config: has personality
                $pp = $db->prepare("SELECT COUNT(*) FROM alfred_agent_personality WHERE agent_name = ?");
                $pp->execute([$agentName]);
                $checks[] = ['check' => 'Personality configured', 'type' => 'config', 'status' => $pp->fetchColumn() > 0 ? 'pass' : 'warn'];
                // Health: no critical errors in 24h
                $er = $db->prepare("SELECT COUNT(*) FROM alfred_error_log WHERE agent_name = ? AND error_level = 'fatal' AND resolved = 0 AND created_at >= NOW() - INTERVAL 24 HOUR");
                $er->execute([$agentName]);
                $checks[] = ['check' => 'No unresolved fatal errors', 'type' => 'health', 'status' => $er->fetchColumn() == 0 ? 'pass' : 'fail'];
                $passCount = count(array_filter($checks, fn($c) => $c['status'] === 'pass'));
                $score = count($checks) > 0 ? round(($passCount / count($checks)) * 100) : 0;
                // Log checks
                foreach ($checks as $c) {
                    $st = $db->prepare("INSERT INTO alfred_compliance_checks (agent_name, check_type, check_name, status) VALUES (?, ?, ?, ?)");
                    $st->execute([$agentName, $c['type'], $c['check'], $c['status']]);
                }
                $results[] = ['agent' => $agentName, 'checks' => $checks, 'score' => $score, 'grade' => $score >= 90 ? 'A' : ($score >= 70 ? 'B' : ($score >= 50 ? 'C' : 'F'))];
            }
            usort($results, fn($a, $b) => $b['score'] <=> $a['score']);
            agent_panel_json(['ok' => true, 'results' => $results, 'timestamp' => date('c')]);
        } elseif ($sub === 'history') {
            $agent = trim($_GET['agent_name'] ?? '');
            $where = $agent ? "WHERE agent_name = ?" : "";
            $params = $agent ? [$agent] : [];
            $st = $db->prepare("SELECT * FROM alfred_compliance_checks $where ORDER BY checked_at DESC LIMIT 200");
            $st->execute($params);
            agent_panel_json(['ok' => true, 'history' => $st->fetchAll(PDO::FETCH_ASSOC)]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── AGENT FEEDBACK LOOP ───
    case 'feedback':
        $sub = $_GET['sub_action'] ?? $_POST['sub_action'] ?? 'list';
        if ($sub === 'list') {
            $db->exec("CREATE TABLE IF NOT EXISTS alfred_agent_feedback (
                id INT AUTO_INCREMENT PRIMARY KEY,
                from_agent VARCHAR(100) NOT NULL,
                to_agent VARCHAR(100) NOT NULL,
                rating TINYINT NOT NULL CHECK(rating BETWEEN 1 AND 5),
                category ENUM('collaboration','reliability','speed','quality','communication') DEFAULT 'collaboration',
                comment TEXT,
                mission_id INT,
                created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
                INDEX idx_to (to_agent),
                INDEX idx_from (from_agent)
            ) ENGINE=InnoDB");
            $st = $db->query("SELECT * FROM alfred_agent_feedback ORDER BY created_at DESC LIMIT 200");
            $rows = $st->fetchAll(PDO::FETCH_ASSOC);
            // Compute averages per agent
            $avgSt = $db->query("SELECT to_agent, AVG(rating) as avg_rating, COUNT(*) as review_count FROM alfred_agent_feedback GROUP BY to_agent ORDER BY avg_rating DESC");
            $averages = $avgSt->fetchAll(PDO::FETCH_ASSOC);
            foreach ($averages as &$a) { $a['avg_rating'] = round((float)$a['avg_rating'], 2); }
            agent_panel_json(['ok' => true, 'feedback' => $rows, 'averages' => $averages]);
        } elseif ($sub === 'submit') {
            $from = trim($_POST['from_agent'] ?? '');
            $to = trim($_POST['to_agent'] ?? '');
            $rating = (int)($_POST['rating'] ?? 0);
            $category = trim($_POST['category'] ?? 'collaboration');
            $comment = trim($_POST['comment'] ?? '');
            $missionId = (int)($_POST['mission_id'] ?? 0) ?: null;
            if (!$from || !$to || $rating < 1 || $rating > 5) { agent_panel_json(['error' => 'from_agent, to_agent, rating(1-5) required']); break; }
            $validCats = ['collaboration','reliability','speed','quality','communication'];
            if (!in_array($category, $validCats)) $category = 'collaboration';
            $st = $db->prepare("INSERT INTO alfred_agent_feedback (from_agent, to_agent, rating, category, comment, mission_id) VALUES (?, ?, ?, ?, ?, ?)");
            $st->execute([$from, $to, $rating, $category, $comment, $missionId]);
            agent_panel_json(['ok' => true, 'id' => $db->lastInsertId()]);
        } elseif ($sub === 'agent_summary') {
            $agent = trim($_GET['agent_name'] ?? '');
            if (!$agent) { agent_panel_json(['error' => 'agent_name required']); break; }
            $st = $db->prepare("SELECT category, AVG(rating) as avg_rating, COUNT(*) as cnt FROM alfred_agent_feedback WHERE to_agent = ? GROUP BY category");
            $st->execute([$agent]);
            $cats = $st->fetchAll(PDO::FETCH_ASSOC);
            foreach ($cats as &$c) { $c['avg_rating'] = round((float)$c['avg_rating'], 2); }
            $totalSt = $db->prepare("SELECT AVG(rating) as overall, COUNT(*) as total FROM alfred_agent_feedback WHERE to_agent = ?");
            $totalSt->execute([$agent]);
            $total = $totalSt->fetch(PDO::FETCH_ASSOC);
            agent_panel_json(['ok' => true, 'agent' => $agent, 'categories' => $cats, 'overall' => round((float)$total['overall'], 2), 'total_reviews' => (int)$total['total']]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── FLEET DEPLOYMENT PIPELINES ───
    case 'pipelines':
        $sub = $_GET['sub_action'] ?? $_POST['sub_action'] ?? 'list';
        if ($sub === 'list') {
            $db->exec("CREATE TABLE IF NOT EXISTS alfred_deploy_pipelines (
                id INT AUTO_INCREMENT PRIMARY KEY,
                pipeline_name VARCHAR(200) NOT NULL,
                agent_name VARCHAR(100) NOT NULL,
                stages TEXT NOT NULL,
                status ENUM('idle','running','success','failed','cancelled') DEFAULT 'idle',
                current_stage INT DEFAULT 0,
                started_at DATETIME,
                completed_at DATETIME,
                created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
                created_by VARCHAR(100) DEFAULT 'commander',
                error_message TEXT,
                INDEX idx_agent (agent_name),
                INDEX idx_status (status)
            ) ENGINE=InnoDB");
            $st = $db->query("SELECT * FROM alfred_deploy_pipelines ORDER BY created_at DESC LIMIT 100");
            agent_panel_json(['ok' => true, 'pipelines' => $st->fetchAll(PDO::FETCH_ASSOC)]);
        } elseif ($sub === 'create') {
            $name = trim($_POST['pipeline_name'] ?? '');
            $agent = trim($_POST['agent_name'] ?? '');
            $stages = trim($_POST['stages'] ?? '');
            if (!$name || !$agent || !$stages) { agent_panel_json(['error' => 'pipeline_name, agent_name, stages required']); break; }
            $st = $db->prepare("INSERT INTO alfred_deploy_pipelines (pipeline_name, agent_name, stages) VALUES (?, ?, ?)");
            $st->execute([$name, $agent, $stages]);
            agent_panel_json(['ok' => true, 'id' => $db->lastInsertId()]);
        } elseif ($sub === 'run') {
            $id = (int)($_POST['id'] ?? 0);
            if (!$id) { agent_panel_json(['error' => 'id required']); break; }
            $db->prepare("UPDATE alfred_deploy_pipelines SET status = 'running', current_stage = 1, started_at = NOW(), completed_at = NULL, error_message = NULL WHERE id = ?")->execute([$id]);
            agent_panel_json(['ok' => true]);
        } elseif ($sub === 'advance') {
            $id = (int)($_POST['id'] ?? 0);
            if (!$id) { agent_panel_json(['error' => 'id required']); break; }
            $row = $db->prepare("SELECT * FROM alfred_deploy_pipelines WHERE id = ?");
            $row->execute([$id]);
            $pipe = $row->fetch(PDO::FETCH_ASSOC);
            if (!$pipe) { agent_panel_json(['error' => 'Pipeline not found']); break; }
            $stagesArr = json_decode($pipe['stages'], true) ?: explode(',', $pipe['stages']);
            $next = $pipe['current_stage'] + 1;
            if ($next > count($stagesArr)) {
                $db->prepare("UPDATE alfred_deploy_pipelines SET status = 'success', completed_at = NOW(), current_stage = ? WHERE id = ?")->execute([count($stagesArr), $id]);
            } else {
                $db->prepare("UPDATE alfred_deploy_pipelines SET current_stage = ? WHERE id = ?")->execute([$next, $id]);
            }
            agent_panel_json(['ok' => true, 'stage' => $next, 'total' => count($stagesArr)]);
        } elseif ($sub === 'fail') {
            $id = (int)($_POST['id'] ?? 0);
            $error = trim($_POST['error_message'] ?? 'Unknown error');
            $db->prepare("UPDATE alfred_deploy_pipelines SET status = 'failed', completed_at = NOW(), error_message = ? WHERE id = ?")->execute([$error, $id]);
            agent_panel_json(['ok' => true]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── AGENT WORKLOAD BALANCER ───
    case 'workload':
        // Compute load per agent and suggest rebalancing
        $agents = $db->query("SELECT DISTINCT agent_name FROM alfred_agent_dispatches ORDER BY agent_name")->fetchAll(PDO::FETCH_COLUMN);
        $loads = [];
        foreach ($agents as $agentName) {
            $taskSt = $db->prepare("SELECT COUNT(*) FROM alfred_agent_tasks WHERE agent_name = ? AND status IN ('queued','assigned','running')");
            $taskSt->execute([$agentName]);
            $tasks = (int)$taskSt->fetchColumn();
            $msnSt = $db->prepare("SELECT COUNT(*) FROM alfred_agent_dispatches WHERE agent_name = ? AND status IN ('pending','in_progress')");
            $msnSt->execute([$agentName]);
            $missions = (int)$msnSt->fetchColumn();
            $hb = $db->prepare("SELECT cpu_usage, memory_usage FROM alfred_heartbeat WHERE agent_name = ? ORDER BY created_at DESC LIMIT 1");
            $hb->execute([$agentName]);
            $hbRow = $hb->fetch(PDO::FETCH_ASSOC);
            $cpu = $hbRow['cpu_usage'] ?? 0;
            $mem = $hbRow['memory_usage'] ?? 0;
            $load = $tasks * 10 + $missions * 8 + $cpu * 0.3 + ($mem / 1048576) * 0.2;
            $loads[] = ['agent' => $agentName, 'tasks' => $tasks, 'missions' => $missions, 'cpu' => round($cpu, 1), 'memory_mb' => round($mem / 1048576, 1), 'load_score' => round($load, 1)];
        }
        usort($loads, fn($a, $b) => $b['load_score'] <=> $a['load_score']);
        $avgLoad = count($loads) ? round(array_sum(array_column($loads, 'load_score')) / count($loads), 1) : 0;
        // Suggestions: overloaded = > 2x avg, underloaded = < 0.5x avg
        $suggestions = [];
        foreach ($loads as $l) {
            if ($avgLoad > 0 && $l['load_score'] > $avgLoad * 2) {
                $suggestions[] = ['action' => 'offload', 'agent' => $l['agent'], 'reason' => 'Load ' . $l['load_score'] . ' is >2x fleet avg ' . $avgLoad];
            } elseif ($avgLoad > 0 && $l['load_score'] < $avgLoad * 0.3 && $l['load_score'] > 0) {
                $suggestions[] = ['action' => 'assign_more', 'agent' => $l['agent'], 'reason' => 'Load ' . $l['load_score'] . ' is <30% of fleet avg ' . $avgLoad];
            }
        }
        agent_panel_json(['ok' => true, 'loads' => $loads, 'avg_load' => $avgLoad, 'suggestions' => $suggestions]);
        break;

    // ─── MISSION RISK ASSESSMENT ───
    case 'risk':
        $sub = $_GET['sub_action'] ?? $_POST['sub_action'] ?? 'assess';
        if ($sub === 'assess') {
            // Risk score per active mission based on agent health, deadline, priority, dependencies
            $st = $db->query("SELECT * FROM alfred_agent_dispatches WHERE status IN ('pending','in_progress') ORDER BY priority DESC, created_at");
            $missions = $st->fetchAll(PDO::FETCH_ASSOC);
            $riskData = [];
            foreach ($missions as $m) {
                $risk = 0;
                $factors = [];
                // Agent health factor
                $hb = $db->prepare("SELECT status FROM alfred_agent_health WHERE agent_name = ? ORDER BY checked_at DESC LIMIT 1");
                $hb->execute([$m['agent_name']]);
                $health = $hb->fetchColumn() ?: 'unknown';
                if ($health === 'critical') { $risk += 40; $factors[] = 'Agent critical'; }
                elseif ($health === 'degraded') { $risk += 20; $factors[] = 'Agent degraded'; }
                elseif ($health === 'unknown') { $risk += 15; $factors[] = 'Agent health unknown'; }
                // Priority factor
                if (($m['priority'] ?? 5) >= 9) { $risk += 10; $factors[] = 'Critical priority'; }
                // Age factor (old pending missions = higher risk)
                $ageHours = (time() - strtotime($m['created_at'])) / 3600;
                if ($ageHours > 48) { $risk += 25; $factors[] = 'Stale >48h'; }
                elseif ($ageHours > 24) { $risk += 15; $factors[] = 'Aging >24h'; }
                elseif ($ageHours > 12) { $risk += 5; $factors[] = 'Pending >12h'; }
                // Error history
                $errSt = $db->prepare("SELECT COUNT(*) FROM alfred_error_log WHERE agent_name = ? AND error_level IN ('fatal','error') AND created_at >= NOW() - INTERVAL 24 HOUR");
                $errSt->execute([$m['agent_name']]);
                $errCount = (int)$errSt->fetchColumn();
                if ($errCount > 5) { $risk += 20; $factors[] = $errCount . ' errors in 24h'; }
                elseif ($errCount > 0) { $risk += 10; $factors[] = $errCount . ' errors in 24h'; }
                $risk = min(100, $risk);
                $level = $risk >= 70 ? 'critical' : ($risk >= 40 ? 'high' : ($risk >= 20 ? 'moderate' : 'low'));
                $riskData[] = ['mission_id' => $m['id'], 'agent' => $m['agent_name'], 'mission' => $m['mission'] ?? '', 'status' => $m['status'], 'risk_score' => $risk, 'risk_level' => $level, 'factors' => $factors, 'age_hours' => round($ageHours, 1)];
            }
            usort($riskData, fn($a, $b) => $b['risk_score'] <=> $a['risk_score']);
            agent_panel_json(['ok' => true, 'assessments' => $riskData, 'total_missions' => count($riskData)]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── FLEET NETWORK TOPOLOGY ───
    case 'topology':
        // Build network graph of agent connections from mesh, comms, dependencies
        $nodes = [];
        $edges = [];
        $agents = $db->query("SELECT DISTINCT agent_name FROM alfred_agent_dispatches ORDER BY agent_name")->fetchAll(PDO::FETCH_COLUMN);
        foreach ($agents as $a) {
            $hb = $db->prepare("SELECT status FROM alfred_agent_health WHERE agent_name = ? ORDER BY checked_at DESC LIMIT 1");
            $hb->execute([$a]);
            $status = $hb->fetchColumn() ?: 'unknown';
            $nodes[] = ['id' => $a, 'status' => $status];
        }
        // Mesh links
        $meshSt = $db->query("SELECT from_agent, to_agent, link_type, latency_ms FROM alfred_agent_mesh WHERE status = 'active'");
        foreach ($meshSt->fetchAll(PDO::FETCH_ASSOC) as $l) {
            $edges[] = ['from' => $l['from_agent'], 'to' => $l['to_agent'], 'type' => 'mesh', 'label' => $l['link_type'], 'weight' => max(1, 100 - ($l['latency_ms'] ?? 50))];
        }
        // Dependencies
        $depSt = $db->query("SELECT from_agent, to_agent, dep_type, strength FROM alfred_agent_dependencies");
        foreach ($depSt->fetchAll(PDO::FETCH_ASSOC) as $d) {
            $edges[] = ['from' => $d['from_agent'], 'to' => $d['to_agent'], 'type' => 'dependency', 'label' => $d['dep_type'], 'weight' => (int)$d['strength']];
        }
        // Comms frequency (last 24h)
        $commSt = $db->query("SELECT from_agent, to_agent, COUNT(*) as cnt FROM alfred_agent_comms WHERE created_at >= NOW() - INTERVAL 24 HOUR GROUP BY from_agent, to_agent");
        foreach ($commSt->fetchAll(PDO::FETCH_ASSOC) as $c) {
            $edges[] = ['from' => $c['from_agent'], 'to' => $c['to_agent'], 'type' => 'comms', 'label' => 'msgs', 'weight' => (int)$c['cnt']];
        }
        agent_panel_json(['ok' => true, 'nodes' => $nodes, 'edges' => $edges, 'node_count' => count($nodes), 'edge_count' => count($edges)]);
        break;

    // ─── AGENT INCIDENT RESPONSE ───
    case 'incident_response':
        $sub = $_GET['sub_action'] ?? $_POST['sub_action'] ?? 'list';
        if ($sub === 'list') {
            $db->exec("CREATE TABLE IF NOT EXISTS alfred_incident_response (
                id INT AUTO_INCREMENT PRIMARY KEY,
                incident_name VARCHAR(200) NOT NULL,
                severity ENUM('P1','P2','P3','P4') DEFAULT 'P3',
                status ENUM('open','investigating','mitigating','resolved','post_mortem') DEFAULT 'open',
                commander_agent VARCHAR(100),
                affected_agents TEXT,
                timeline TEXT,
                root_cause TEXT,
                resolution TEXT,
                opened_at DATETIME DEFAULT CURRENT_TIMESTAMP,
                resolved_at DATETIME,
                INDEX idx_status (status),
                INDEX idx_severity (severity)
            ) ENGINE=InnoDB");
            $st = $db->query("SELECT * FROM alfred_incident_response ORDER BY opened_at DESC LIMIT 100");
            agent_panel_json(['ok' => true, 'incidents' => $st->fetchAll(PDO::FETCH_ASSOC)]);
        } elseif ($sub === 'create') {
            $name = trim($_POST['incident_name'] ?? '');
            $severity = trim($_POST['severity'] ?? 'P3');
            $commander = trim($_POST['commander_agent'] ?? '');
            $affected = trim($_POST['affected_agents'] ?? '');
            if (!$name) { agent_panel_json(['error' => 'incident_name required']); break; }
            $validSev = ['P1','P2','P3','P4'];
            if (!in_array($severity, $validSev)) $severity = 'P3';
            $st = $db->prepare("INSERT INTO alfred_incident_response (incident_name, severity, commander_agent, affected_agents) VALUES (?, ?, ?, ?)");
            $st->execute([$name, $severity, $commander, $affected]);
            agent_panel_json(['ok' => true, 'id' => $db->lastInsertId()]);
        } elseif ($sub === 'update') {
            $id = (int)($_POST['id'] ?? 0);
            $status = trim($_POST['status'] ?? '');
            $timeline = trim($_POST['timeline_entry'] ?? '');
            $rootCause = trim($_POST['root_cause'] ?? '');
            $resolution = trim($_POST['resolution'] ?? '');
            if (!$id) { agent_panel_json(['error' => 'id required']); break; }
            $sets = [];
            $params = [];
            if ($status) {
                $validStatus = ['open','investigating','mitigating','resolved','post_mortem'];
                if (in_array($status, $validStatus)) { $sets[] = "status = ?"; $params[] = $status; }
                if ($status === 'resolved') { $sets[] = "resolved_at = NOW()"; }
            }
            if ($rootCause) { $sets[] = "root_cause = ?"; $params[] = $rootCause; }
            if ($resolution) { $sets[] = "resolution = ?"; $params[] = $resolution; }
            if ($timeline) {
                // Append to timeline
                $existing = $db->prepare("SELECT timeline FROM alfred_incident_response WHERE id = ?");
                $existing->execute([$id]);
                $oldTimeline = json_decode($existing->fetchColumn() ?: '[]', true) ?: [];
                $oldTimeline[] = ['time' => date('c'), 'entry' => $timeline, 'by' => 'commander'];
                $sets[] = "timeline = ?";
                $params[] = json_encode($oldTimeline);
            }
            if (empty($sets)) { agent_panel_json(['error' => 'Nothing to update']); break; }
            $params[] = $id;
            $db->prepare("UPDATE alfred_incident_response SET " . implode(', ', $sets) . " WHERE id = ?")->execute($params);
            agent_panel_json(['ok' => true]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── FLEET ALERT CHANNELS ───
    case 'alert_channels':
        $sub = $_GET['sub_action'] ?? $_POST['sub_action'] ?? 'list';
        if ($sub === 'list') {
            $db->exec("CREATE TABLE IF NOT EXISTS alfred_alert_channels (
                id INT AUTO_INCREMENT PRIMARY KEY,
                channel_name VARCHAR(100) NOT NULL,
                channel_type ENUM('broadcast','direct','group','escalation') DEFAULT 'broadcast',
                members TEXT,
                priority_filter ENUM('all','critical','high','medium','low') DEFAULT 'all',
                enabled TINYINT DEFAULT 1,
                created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
                INDEX idx_type (channel_type)
            ) ENGINE=InnoDB");
            $st = $db->query("SELECT * FROM alfred_alert_channels ORDER BY channel_name");
            agent_panel_json(['ok' => true, 'channels' => $st->fetchAll(PDO::FETCH_ASSOC)]);
        } elseif ($sub === 'create') {
            $name = trim($_POST['channel_name'] ?? '');
            $type = trim($_POST['channel_type'] ?? 'broadcast');
            $members = trim($_POST['members'] ?? '');
            $pFilter = trim($_POST['priority_filter'] ?? 'all');
            if (!$name) { agent_panel_json(['error' => 'channel_name required']); break; }
            $validTypes = ['broadcast','direct','group','escalation'];
            if (!in_array($type, $validTypes)) $type = 'broadcast';
            $st = $db->prepare("INSERT INTO alfred_alert_channels (channel_name, channel_type, members, priority_filter) VALUES (?, ?, ?, ?)");
            $st->execute([$name, $type, $members, $pFilter]);
            agent_panel_json(['ok' => true, 'id' => $db->lastInsertId()]);
        } elseif ($sub === 'toggle') {
            $id = (int)($_POST['id'] ?? 0);
            if (!$id) { agent_panel_json(['error' => 'id required']); break; }
            $db->prepare("UPDATE alfred_alert_channels SET enabled = NOT enabled WHERE id = ?")->execute([$id]);
            agent_panel_json(['ok' => true]);
        } elseif ($sub === 'delete') {
            $id = (int)($_POST['id'] ?? 0);
            if (!$id) { agent_panel_json(['error' => 'id required']); break; }
            $db->prepare("DELETE FROM alfred_alert_channels WHERE id = ?")->execute([$id]);
            agent_panel_json(['ok' => true]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── AGENT ACTIVITY TIMELINE ───
    case 'activity_timeline':
        $agent = trim($_GET['agent_name'] ?? '');
        $hours = (int)($_GET['hours'] ?? 24);
        $hours = max(1, min(168, $hours));
        $events = [];
        // Dispatches
        $where = $agent ? "WHERE agent_name = ?" : "";
        $params = $agent ? [$agent] : [];
        $st = $db->prepare("SELECT 'mission' as event_type, agent_name, mission as detail, status, created_at FROM alfred_agent_dispatches $where AND created_at >= NOW() - INTERVAL $hours HOUR ORDER BY created_at DESC LIMIT 50");
        $st->execute($params);
        foreach ($st->fetchAll(PDO::FETCH_ASSOC) as $r) $events[] = $r;
        // Comms
        $whereC = $agent ? "WHERE from_agent = ? OR to_agent = ?" : "";
        $paramsC = $agent ? [$agent, $agent] : [];
        $st2 = $db->prepare("SELECT 'comms' as event_type, from_agent as agent_name, CONCAT(channel, ': ', LEFT(message, 80)) as detail, 'sent' as status, created_at FROM alfred_agent_comms $whereC AND created_at >= NOW() - INTERVAL $hours HOUR ORDER BY created_at DESC LIMIT 30");
        $st2->execute($paramsC);
        foreach ($st2->fetchAll(PDO::FETCH_ASSOC) as $r) $events[] = $r;
        // Errors
        $whereE = $agent ? "WHERE agent_name = ?" : "";
        $paramsE = $agent ? [$agent] : [];
        $st3 = $db->prepare("SELECT 'error' as event_type, agent_name, error_message as detail, error_level as status, created_at FROM alfred_error_log $whereE AND created_at >= NOW() - INTERVAL $hours HOUR ORDER BY created_at DESC LIMIT 20");
        $st3->execute($paramsE);
        foreach ($st3->fetchAll(PDO::FETCH_ASSOC) as $r) $events[] = $r;
        // Sort by time desc
        usort($events, fn($a, $b) => strtotime($b['created_at']) <=> strtotime($a['created_at']));
        agent_panel_json(['ok' => true, 'events' => array_slice($events, 0, 100), 'total' => count($events)]);
        break;

    // ─── MISSION DEPENDENCY VISUALIZATION ───
    case 'mission_dep_viz':
        // Show mission chains and their dependency links as a graph
        $st = $db->query("SELECT mc.id, mc.chain_name, mc.status, cl.mission_id, cl.step_order, cl.depends_on_step, d.mission as mission_text, d.status as mission_status, d.agent_name FROM alfred_mission_chains mc JOIN alfred_chain_links cl ON mc.id = cl.chain_id LEFT JOIN alfred_agent_dispatches d ON cl.mission_id = d.id ORDER BY mc.id, cl.step_order");
        $rows = $st->fetchAll(PDO::FETCH_ASSOC);
        $chains = [];
        foreach ($rows as $r) {
            $cid = $r['id'];
            if (!isset($chains[$cid])) $chains[$cid] = ['id' => $cid, 'name' => $r['chain_name'], 'status' => $r['status'], 'steps' => []];
            $chains[$cid]['steps'][] = ['step' => (int)$r['step_order'], 'mission_id' => $r['mission_id'], 'depends_on' => $r['depends_on_step'] ? (int)$r['depends_on_step'] : null, 'mission_text' => $r['mission_text'] ?? '', 'mission_status' => $r['mission_status'] ?? '', 'agent' => $r['agent_name'] ?? ''];
        }
        agent_panel_json(['ok' => true, 'chains' => array_values($chains)]);
        break;

    // ─── FLEET CONFIG DIFF TOOL ───
    case 'config_diff':
        $sub = $_GET['sub_action'] ?? $_POST['sub_action'] ?? 'compare';
        if ($sub === 'compare') {
            // Compare latest two config snapshots per agent
            $agents = $db->query("SELECT DISTINCT agent_name FROM alfred_config_snapshots ORDER BY agent_name")->fetchAll(PDO::FETCH_COLUMN);
            $diffs = [];
            foreach ($agents as $agentName) {
                $st = $db->prepare("SELECT config_data, snapshot_label, created_at FROM alfred_config_snapshots WHERE agent_name = ? ORDER BY created_at DESC LIMIT 2");
                $st->execute([$agentName]);
                $snaps = $st->fetchAll(PDO::FETCH_ASSOC);
                if (count($snaps) < 2) {
                    $diffs[] = ['agent' => $agentName, 'status' => 'single_snapshot', 'changes' => []];
                    continue;
                }
                $newConf = json_decode($snaps[0]['config_data'], true) ?: [];
                $oldConf = json_decode($snaps[1]['config_data'], true) ?: [];
                $changes = [];
                $allKeys = array_unique(array_merge(array_keys($newConf), array_keys($oldConf)));
                foreach ($allKeys as $key) {
                    $oldVal = $oldConf[$key] ?? null;
                    $newVal = $newConf[$key] ?? null;
                    if ($oldVal !== $newVal) {
                        $changes[] = ['key' => $key, 'old' => $oldVal, 'new' => $newVal, 'type' => $oldVal === null ? 'added' : ($newVal === null ? 'removed' : 'changed')];
                    }
                }
                $diffs[] = ['agent' => $agentName, 'status' => count($changes) > 0 ? 'changed' : 'unchanged', 'changes' => $changes, 'new_snapshot' => $snaps[0]['snapshot_label'] ?? '', 'old_snapshot' => $snaps[1]['snapshot_label'] ?? '', 'new_date' => $snaps[0]['created_at'], 'old_date' => $snaps[1]['created_at']];
            }
            agent_panel_json(['ok' => true, 'diffs' => $diffs]);
        } else {
            agent_panel_json(['error' => 'Unknown sub_action']);
        }
        break;

    // ─── AGENT PERFORMANCE PROFILER ───
    case 'profiler':
        $agent = trim($_GET['agent_name'] ?? '');
        $days = (int)($_GET['days'] ?? 7);
        $days = max(1, min(30, $days));
        if (!$agent) {
            // Fleet-wide profiler summary
            $agents = $db->query("SELECT DISTINCT agent_name FROM alfred_agent_dispatches ORDER BY agent_name")->fetchAll(PDO::FETCH_COLUMN);
            $profiles = [];
            foreach ($agents as $agentName) {
                $msnSt = $db->prepare("SELECT COUNT(*) as total, SUM(status='completed') as completed, SUM(status='failed') as failed, AVG(TIMESTAMPDIFF(SECOND, created_at, COALESCE(updated_at, NOW()))) as avg_duration FROM alfred_agent_dispatches WHERE agent_name = ? AND created_at >= NOW() - INTERVAL ? DAY");
                $msnSt->execute([$agentName, $days]);
                $msn = $msnSt->fetch(PDO::FETCH_ASSOC);
                $hbSt = $db->prepare("SELECT AVG(cpu_usage) as avg_cpu, AVG(memory_usage) as avg_mem, AVG(response_time_ms) as avg_resp FROM alfred_heartbeat WHERE agent_name = ? AND created_at >= NOW() - INTERVAL ? DAY");
                $hbSt->execute([$agentName, $days]);
                $hb = $hbSt->fetch(PDO::FETCH_ASSOC);
                $errSt = $db->prepare("SELECT COUNT(*) FROM alfred_error_log WHERE agent_name = ? AND created_at >= NOW() - INTERVAL ? DAY");
                $errSt->execute([$agentName, $days]);
                $errCount = (int)$errSt->fetchColumn();
                $commsSt = $db->prepare("SELECT COUNT(*) FROM alfred_agent_comms WHERE (from_agent = ? OR to_agent = ?) AND created_at >= NOW() - INTERVAL ? DAY");
                $commsSt->execute([$agentName, $agentName, $days]);
                $commsCount = (int)$commsSt->fetchColumn();
                // Performance score weighted: mission success 40%, uptime(low errors) 25%, response 20%, comms 15%
                $successRate = $msn['total'] > 0 ? ($msn['completed'] / $msn['total']) * 100 : 50;
                $errorPenalty = min(50, $errCount * 5);
                $respScore = max(0, 100 - (($hb['avg_resp'] ?? 0) / 10));
                $perfScore = round($successRate * 0.4 + (100 - $errorPenalty) * 0.25 + $respScore * 0.2 + min(100, $commsCount * 2) * 0.15);
                $profiles[] = [
                    'agent' => $agentName,
                    'perf_score' => $perfScore,
                    'missions_total' => (int)$msn['total'],
                    'missions_completed' => (int)$msn['completed'],
                    'missions_failed' => (int)$msn['failed'],
                    'avg_duration_sec' => round((float)($msn['avg_duration'] ?? 0)),
                    'avg_cpu' => round((float)($hb['avg_cpu'] ?? 0), 1),
                    'avg_memory_mb' => round((float)($hb['avg_mem'] ?? 0) / 1048576, 1),
                    'avg_response_ms' => round((float)($hb['avg_resp'] ?? 0)),
                    'error_count' => $errCount,
                    'comms_count' => $commsCount
                ];
            }
            usort($profiles, fn($a, $b) => $b['perf_score'] <=> $a['perf_score']);
            agent_panel_json(['ok' => true, 'profiles' => $profiles, 'period_days' => $days]);
        } else {
            // Single agent detailed profile
            $msnSt = $db->prepare("SELECT status, COUNT(*) as cnt FROM alfred_agent_dispatches WHERE agent_name = ? AND created_at >= NOW() - INTERVAL ? DAY GROUP BY status");
            $msnSt->execute([$agent, $days]);
            $missionBreakdown = $msnSt->fetchAll(PDO::FETCH_ASSOC);
            $hbSt = $db->prepare("SELECT DATE(created_at) as day, AVG(cpu_usage) as avg_cpu, AVG(memory_usage) as avg_mem, AVG(response_time_ms) as avg_resp FROM alfred_heartbeat WHERE agent_name = ? AND created_at >= NOW() - INTERVAL ? DAY GROUP BY day ORDER BY day");
            $hbSt->execute([$agent, $days]);
            $dailyMetrics = $hbSt->fetchAll(PDO::FETCH_ASSOC);
            foreach ($dailyMetrics as &$dm) { $dm['avg_cpu'] = round((float)$dm['avg_cpu'], 1); $dm['avg_mem'] = round((float)$dm['avg_mem'] / 1048576, 1); $dm['avg_resp'] = round((float)$dm['avg_resp']); }
            $errSt = $db->prepare("SELECT error_level, COUNT(*) as cnt FROM alfred_error_log WHERE agent_name = ? AND created_at >= NOW() - INTERVAL ? DAY GROUP BY error_level");
            $errSt->execute([$agent, $days]);
            $errorBreakdown = $errSt->fetchAll(PDO::FETCH_ASSOC);
            agent_panel_json(['ok' => true, 'agent' => $agent, 'mission_breakdown' => $missionBreakdown, 'daily_metrics' => $dailyMetrics, 'error_breakdown' => $errorBreakdown, 'period_days' => $days]);
        }
        break;

    /* ═══════ FLEET SWARM INTELLIGENCE ═══════ */
    case 'swarm':
        $sub = $_GET['sub_action'] ?? $_POST['sub_action'] ?? 'list';
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_swarms (
            id INT AUTO_INCREMENT PRIMARY KEY,
            name VARCHAR(120) NOT NULL,
            objective TEXT,
            lead_agent VARCHAR(40),
            status ENUM('forming','active','executing','completed','disbanded') DEFAULT 'forming',
            priority ENUM('critical','high','normal','low') DEFAULT 'normal',
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            completed_at TIMESTAMP NULL
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_swarm_members (
            id INT AUTO_INCREMENT PRIMARY KEY,
            swarm_id INT NOT NULL,
            agent_id VARCHAR(40) NOT NULL,
            role ENUM('lead','member','observer') DEFAULT 'member',
            joined_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            UNIQUE KEY uk_swarm_agent (swarm_id, agent_id)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");
        if ($sub === 'list') {
            $st = $db->query("SELECT s.*, GROUP_CONCAT(sm.agent_id ORDER BY sm.role) as members,
                COUNT(sm.id) as member_count
                FROM alfred_swarms s LEFT JOIN alfred_swarm_members sm ON sm.swarm_id = s.id
                GROUP BY s.id ORDER BY FIELD(s.status,'active','executing','forming','completed','disbanded'), s.created_at DESC LIMIT 50");
            agent_panel_json(['ok' => true, 'swarms' => $st->fetchAll(PDO::FETCH_ASSOC)]);
        } elseif ($sub === 'create') {
            $name = trim($_POST['name'] ?? '');
            $objective = trim($_POST['objective'] ?? '');
            $lead = trim($_POST['lead_agent'] ?? '');
            $priority = $_POST['priority'] ?? 'normal';
            if (!$name) { agent_panel_json(['error' => 'Name required']); break; }
            $st = $db->prepare("INSERT INTO alfred_swarms (name, objective, lead_agent, priority) VALUES (?, ?, ?, ?)");
            $st->execute([$name, $objective, $lead, $priority]);
            $swarmId = $db->lastInsertId();
            if ($lead) {
                $db->prepare("INSERT IGNORE INTO alfred_swarm_members (swarm_id, agent_id, role) VALUES (?, ?, 'lead')")->execute([$swarmId, $lead]);
            }
            agent_panel_json(['ok' => true, 'id' => $swarmId]);
        } elseif ($sub === 'join') {
            $swarmId = (int)($_POST['swarm_id'] ?? 0);
            $agent = trim($_POST['agent_id'] ?? '');
            $role = $_POST['role'] ?? 'member';
            if (!$swarmId || !$agent) { agent_panel_json(['error' => 'Swarm ID and agent required']); break; }
            $db->prepare("INSERT IGNORE INTO alfred_swarm_members (swarm_id, agent_id, role) VALUES (?, ?, ?)")->execute([$swarmId, $agent, $role]);
            agent_panel_json(['ok' => true]);
        } elseif ($sub === 'status') {
            $swarmId = (int)($_POST['swarm_id'] ?? 0);
            $status = $_POST['status'] ?? '';
            if (!$swarmId || !$status) { agent_panel_json(['error' => 'Swarm ID and status required']); break; }
            $completed = in_array($status, ['completed','disbanded']) ? ', completed_at = NOW()' : '';
            $db->prepare("UPDATE alfred_swarms SET status = ? $completed WHERE id = ?")->execute([$status, $swarmId]);
            agent_panel_json(['ok' => true]);
        } elseif ($sub === 'remove') {
            $swarmId = (int)($_POST['swarm_id'] ?? 0);
            $agent = trim($_POST['agent_id'] ?? '');
            $db->prepare("DELETE FROM alfred_swarm_members WHERE swarm_id = ? AND agent_id = ?")->execute([$swarmId, $agent]);
            agent_panel_json(['ok' => true]);
        }
        break;

    /* ═══════ AGENT MEMORY BANK ═══════ */
    case 'memory_bank':
        $sub = $_GET['sub_action'] ?? $_POST['sub_action'] ?? 'list';
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_agent_memory (
            id INT AUTO_INCREMENT PRIMARY KEY,
            agent_id VARCHAR(40) NOT NULL,
            category VARCHAR(60) DEFAULT 'general',
            mem_key VARCHAR(120) NOT NULL,
            mem_value TEXT,
            importance ENUM('critical','high','normal','low') DEFAULT 'normal',
            access_count INT DEFAULT 0,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
            INDEX idx_agent_cat (agent_id, category),
            UNIQUE KEY uk_agent_key (agent_id, mem_key)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");
        if ($sub === 'list') {
            $agent = $_GET['agent_id'] ?? '';
            $cat = $_GET['category'] ?? '';
            $where = '1=1';
            $params = [];
            if ($agent) { $where .= ' AND agent_id = ?'; $params[] = $agent; }
            if ($cat) { $where .= ' AND category = ?'; $params[] = $cat; }
            $st = $db->prepare("SELECT * FROM alfred_agent_memory WHERE $where ORDER BY importance DESC, updated_at DESC LIMIT 100");
            $st->execute($params);
            $memories = $st->fetchAll(PDO::FETCH_ASSOC);
            $catSt = $db->query("SELECT category, COUNT(*) as cnt FROM alfred_agent_memory GROUP BY category ORDER BY cnt DESC");
            agent_panel_json(['ok' => true, 'memories' => $memories, 'categories' => $catSt->fetchAll(PDO::FETCH_ASSOC)]);
        } elseif ($sub === 'store') {
            $agent = trim($_POST['agent_id'] ?? '');
            $key = trim($_POST['mem_key'] ?? '');
            $val = trim($_POST['mem_value'] ?? '');
            $cat = trim($_POST['category'] ?? 'general');
            $importance = $_POST['importance'] ?? 'normal';
            if (!$agent || !$key) { agent_panel_json(['error' => 'Agent and key required']); break; }
            $st = $db->prepare("INSERT INTO alfred_agent_memory (agent_id, category, mem_key, mem_value, importance) VALUES (?, ?, ?, ?, ?)
                ON DUPLICATE KEY UPDATE mem_value = VALUES(mem_value), category = VALUES(category), importance = VALUES(importance), access_count = access_count + 1");
            $st->execute([$agent, $cat, $key, $val, $importance]);
            agent_panel_json(['ok' => true]);
        } elseif ($sub === 'delete') {
            $id = (int)($_POST['id'] ?? 0);
            $db->prepare("DELETE FROM alfred_agent_memory WHERE id = ?")->execute([$id]);
            agent_panel_json(['ok' => true]);
        } elseif ($sub === 'search') {
            $q = trim($_GET['q'] ?? '');
            if (!$q) { agent_panel_json(['ok' => true, 'memories' => []]); break; }
            $st = $db->prepare("SELECT * FROM alfred_agent_memory WHERE mem_key LIKE ? OR mem_value LIKE ? ORDER BY importance DESC LIMIT 50");
            $like = "%$q%";
            $st->execute([$like, $like]);
            agent_panel_json(['ok' => true, 'memories' => $st->fetchAll(PDO::FETCH_ASSOC)]);
        }
        break;

    /* ═══════ MISSION KANBAN BOARD ═══════ */
    case 'mission_kanban':
        $columns = ['backlog' => ['pending'], 'queued' => ['queued','assigned'], 'active' => ['active','in_progress'], 'review' => ['review','paused'], 'complete' => ['completed','verified','failed','cancelled']];
        $allMissions = [];
        foreach ($columns as $col => $statuses) {
            $placeholders = implode(',', array_fill(0, count($statuses), '?'));
            $st = $db->prepare("SELECT id, title, description, status, priority, assigned_agent, created_at, updated_at
                FROM alfred_agent_dispatches WHERE status IN ($placeholders) ORDER BY FIELD(priority,'critical','high','normal','low'), created_at DESC LIMIT 30");
            $st->execute($statuses);
            $allMissions[$col] = $st->fetchAll(PDO::FETCH_ASSOC);
        }
        $totals = [];
        foreach ($allMissions as $col => $items) { $totals[$col] = count($items); }
        agent_panel_json(['ok' => true, 'columns' => $allMissions, 'totals' => $totals]);
        break;

    /* ═══════ FLEET TELEMETRY DASHBOARD ═══════ */
    case 'telemetry':
        $agents = $db->query("SELECT DISTINCT agent_name FROM alfred_heartbeat ORDER BY agent_name")->fetchAll(PDO::FETCH_COLUMN);
        $telemetry = [];
        foreach ($agents as $agent) {
            $st = $db->prepare("SELECT
                COUNT(*) as total_beats,
                MIN(response_time_ms) as min_latency,
                MAX(response_time_ms) as max_latency,
                AVG(response_time_ms) as avg_latency,
                SUBSTRING_INDEX(GROUP_CONCAT(response_time_ms ORDER BY response_time_ms ASC), ',', FLOOR(COUNT(*) * 0.5) + 1) as p50_raw,
                SUBSTRING_INDEX(GROUP_CONCAT(response_time_ms ORDER BY response_time_ms ASC), ',', FLOOR(COUNT(*) * 0.95) + 1) as p95_raw,
                SUBSTRING_INDEX(GROUP_CONCAT(response_time_ms ORDER BY response_time_ms ASC), ',', FLOOR(COUNT(*) * 0.99) + 1) as p99_raw,
                AVG(cpu_percent) as avg_cpu,
                AVG(memory_bytes) as avg_mem,
                MAX(checked_at) as last_seen,
                MIN(checked_at) as first_seen,
                SUM(CASE WHEN status = 'healthy' THEN 1 ELSE 0 END) as healthy_count,
                SUM(CASE WHEN status != 'healthy' THEN 1 ELSE 0 END) as unhealthy_count
                FROM alfred_heartbeat WHERE agent_name = ? AND checked_at >= NOW() - INTERVAL 24 HOUR");
            $st->execute([$agent]);
            $row = $st->fetch(PDO::FETCH_ASSOC);
            if ($row && $row['total_beats'] > 0) {
                $p50Vals = explode(',', $row['p50_raw'] ?? '0');
                $p95Vals = explode(',', $row['p95_raw'] ?? '0');
                $p99Vals = explode(',', $row['p99_raw'] ?? '0');
                $telemetry[] = [
                    'agent' => $agent,
                    'total_beats' => (int)$row['total_beats'],
                    'min_latency' => round((float)$row['min_latency']),
                    'max_latency' => round((float)$row['max_latency']),
                    'avg_latency' => round((float)$row['avg_latency']),
                    'p50' => round((float)end($p50Vals)),
                    'p95' => round((float)end($p95Vals)),
                    'p99' => round((float)end($p99Vals)),
                    'avg_cpu' => round((float)$row['avg_cpu'], 1),
                    'avg_mem_mb' => round((float)$row['avg_mem'] / 1048576, 1),
                    'last_seen' => $row['last_seen'],
                    'uptime_pct' => $row['total_beats'] > 0 ? round($row['healthy_count'] / $row['total_beats'] * 100, 1) : 0,
                    'healthy' => (int)$row['healthy_count'],
                    'unhealthy' => (int)$row['unhealthy_count'],
                    'throughput' => round($row['total_beats'] / 24, 1)
                ];
            }
        }
        usort($telemetry, function($a, $b) { return $b['avg_latency'] <=> $a['avg_latency']; });
        agent_panel_json(['ok' => true, 'telemetry' => $telemetry, 'period' => '24h']);
        break;

    /* ═══════ AGENT DIPLOMACY SYSTEM ═══════ */
    case 'diplomacy':
        $sub = $_GET['sub_action'] ?? $_POST['sub_action'] ?? 'list';
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_agent_relations (
            id INT AUTO_INCREMENT PRIMARY KEY,
            agent_from VARCHAR(40) NOT NULL,
            agent_to VARCHAR(40) NOT NULL,
            relation_type ENUM('alliance','cooperation','neutral','tension','rivalry') DEFAULT 'neutral',
            strength INT DEFAULT 50,
            notes TEXT,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
            UNIQUE KEY uk_relation (agent_from, agent_to)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");
        if ($sub === 'list') {
            $st = $db->query("SELECT * FROM alfred_agent_relations ORDER BY strength DESC");
            $relations = $st->fetchAll(PDO::FETCH_ASSOC);
            // Also compute derived diplomacy scores from comms + collaboration
            $commsSt = $db->query("SELECT from_agent, to_agent, COUNT(*) as msg_count FROM alfred_agent_comms
                WHERE created_at >= NOW() - INTERVAL 30 DAY GROUP BY from_agent, to_agent ORDER BY msg_count DESC LIMIT 100");
            $commsRelations = $commsSt->fetchAll(PDO::FETCH_ASSOC);
            // cooperation score from shared missions
            $coopSt = $db->query("SELECT d1.assigned_agent as a1, d2.assigned_agent as a2, COUNT(*) as shared
                FROM alfred_agent_dispatches d1
                INNER JOIN alfred_agent_dispatches d2 ON d1.title = d2.title AND d1.assigned_agent < d2.assigned_agent
                WHERE d1.status IN ('completed','verified') AND d2.status IN ('completed','verified')
                GROUP BY d1.assigned_agent, d2.assigned_agent LIMIT 50");
            $coop = $coopSt->fetchAll(PDO::FETCH_ASSOC);
            agent_panel_json(['ok' => true, 'relations' => $relations, 'comms_activity' => $commsRelations, 'cooperation' => $coop]);
        } elseif ($sub === 'update') {
            $from = trim($_POST['agent_from'] ?? '');
            $to = trim($_POST['agent_to'] ?? '');
            $type = $_POST['relation_type'] ?? 'neutral';
            $strength = max(0, min(100, (int)($_POST['strength'] ?? 50)));
            $notes = trim($_POST['notes'] ?? '');
            if (!$from || !$to) { agent_panel_json(['error' => 'Both agents required']); break; }
            $st = $db->prepare("INSERT INTO alfred_agent_relations (agent_from, agent_to, relation_type, strength, notes)
                VALUES (?, ?, ?, ?, ?) ON DUPLICATE KEY UPDATE relation_type = VALUES(relation_type), strength = VALUES(strength), notes = VALUES(notes)");
            $st->execute([$from, $to, $type, $strength, $notes]);
            agent_panel_json(['ok' => true]);
        } elseif ($sub === 'history') {
            $from = $_GET['agent_from'] ?? '';
            $to = $_GET['agent_to'] ?? '';
            if (!$from || !$to) { agent_panel_json(['error' => 'Both agents required']); break; }
            // Get comms between them
            $st = $db->prepare("SELECT * FROM alfred_agent_comms WHERE (from_agent = ? AND to_agent = ?) OR (from_agent = ? AND to_agent = ?) ORDER BY created_at DESC LIMIT 30");
            $st->execute([$from, $to, $to, $from]);
            $comms = $st->fetchAll(PDO::FETCH_ASSOC);
            // Get shared missions
            $mSt = $db->prepare("SELECT title, status, priority FROM alfred_agent_dispatches WHERE assigned_agent IN (?, ?) ORDER BY created_at DESC LIMIT 20");
            $mSt->execute([$from, $to]);
            agent_panel_json(['ok' => true, 'comms' => $comms, 'shared_missions' => $mSt->fetchAll(PDO::FETCH_ASSOC)]);
        }
        break;

    /* ═══════ FLEET THREAT RADAR ═══════ */
    case 'threat_radar':
        // Aggregate threats from errors, degraded heartbeats, failed missions
        $errors = $db->query("SELECT agent_name, error_level, COUNT(*) as cnt, MAX(created_at) as latest
            FROM alfred_error_log WHERE created_at >= NOW() - INTERVAL 6 HOUR
            GROUP BY agent_name, error_level ORDER BY cnt DESC")->fetchAll(PDO::FETCH_ASSOC);
        $degraded = $db->query("SELECT agent_name, status, COUNT(*) as cnt, MAX(checked_at) as latest
            FROM alfred_heartbeat WHERE checked_at >= NOW() - INTERVAL 1 HOUR AND status != 'healthy'
            GROUP BY agent_name, status")->fetchAll(PDO::FETCH_ASSOC);
        $failedMissions = $db->query("SELECT assigned_agent, COUNT(*) as cnt
            FROM alfred_agent_dispatches WHERE status = 'failed' AND updated_at >= NOW() - INTERVAL 24 HOUR
            GROUP BY assigned_agent ORDER BY cnt DESC")->fetchAll(PDO::FETCH_ASSOC);
        $escalations = $db->query("SELECT agent_id, severity, COUNT(*) as cnt
            FROM alfred_agent_escalations WHERE created_at >= NOW() - INTERVAL 24 HOUR AND resolved = 0
            GROUP BY agent_id, severity")->fetchAll(PDO::FETCH_ASSOC);
        // Compute threat level per agent
        $threatMap = [];
        foreach ($errors as $e) {
            $a = $e['agent_name'];
            if (!isset($threatMap[$a])) $threatMap[$a] = ['score' => 0, 'factors' => []];
            $weight = $e['error_level'] === 'fatal' ? 30 : ($e['error_level'] === 'error' ? 15 : 5);
            $threatMap[$a]['score'] += $weight * $e['cnt'];
            $threatMap[$a]['factors'][] = $e['cnt'] . ' ' . $e['error_level'] . ' errors';
        }
        foreach ($degraded as $d) {
            $a = $d['agent_name'];
            if (!isset($threatMap[$a])) $threatMap[$a] = ['score' => 0, 'factors' => []];
            $threatMap[$a]['score'] += 20 * $d['cnt'];
            $threatMap[$a]['factors'][] = $d['cnt'] . ' ' . $d['status'] . ' heartbeats';
        }
        foreach ($failedMissions as $f) {
            $a = $f['assigned_agent'];
            if (!isset($threatMap[$a])) $threatMap[$a] = ['score' => 0, 'factors' => []];
            $threatMap[$a]['score'] += 10 * $f['cnt'];
            $threatMap[$a]['factors'][] = $f['cnt'] . ' failed missions';
        }
        $threats = [];
        foreach ($threatMap as $agent => $data) {
            $level = $data['score'] >= 100 ? 'critical' : ($data['score'] >= 50 ? 'high' : ($data['score'] >= 20 ? 'medium' : 'low'));
            $threats[] = ['agent' => $agent, 'score' => min(100, $data['score']), 'level' => $level, 'factors' => $data['factors']];
        }
        usort($threats, function($a, $b) { return $b['score'] <=> $a['score']; });
        agent_panel_json(['ok' => true, 'threats' => $threats, 'error_summary' => $errors, 'degraded' => $degraded, 'open_escalations' => $escalations]);
        break;

    /* ═══════ AGENT DREAM LOG ═══════ */
    case 'dream_log':
        $sub = $_GET['sub_action'] ?? $_POST['sub_action'] ?? 'list';
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_dream_log (
            id INT AUTO_INCREMENT PRIMARY KEY,
            agent_id VARCHAR(40) NOT NULL,
            dream_type ENUM('idea','suggestion','self_improve','observation','warning') DEFAULT 'idea',
            title VARCHAR(200) NOT NULL,
            content TEXT,
            status ENUM('new','reviewed','accepted','implemented','rejected') DEFAULT 'new',
            priority ENUM('critical','high','normal','low') DEFAULT 'normal',
            votes INT DEFAULT 0,
            reviewed_by VARCHAR(40),
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            reviewed_at TIMESTAMP NULL,
            INDEX idx_agent (agent_id),
            INDEX idx_status (status)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");
        if ($sub === 'list') {
            $filter = $_GET['status'] ?? '';
            $where = '1=1'; $params = [];
            if ($filter) { $where .= ' AND status = ?'; $params[] = $filter; }
            $st = $db->prepare("SELECT * FROM alfred_dream_log WHERE $where ORDER BY FIELD(status,'new','reviewed','accepted','implemented','rejected'), priority DESC, votes DESC LIMIT 60");
            $st->execute($params);
            agent_panel_json(['ok' => true, 'dreams' => $st->fetchAll(PDO::FETCH_ASSOC)]);
        } elseif ($sub === 'create') {
            $agent = trim($_POST['agent_id'] ?? '');
            $title = trim($_POST['title'] ?? '');
            $content = trim($_POST['content'] ?? '');
            $type = $_POST['dream_type'] ?? 'idea';
            $priority = $_POST['priority'] ?? 'normal';
            if (!$agent || !$title) { agent_panel_json(['error' => 'Agent and title required']); break; }
            $st = $db->prepare("INSERT INTO alfred_dream_log (agent_id, dream_type, title, content, priority) VALUES (?, ?, ?, ?, ?)");
            $st->execute([$agent, $type, $title, $content, $priority]);
            agent_panel_json(['ok' => true, 'id' => $db->lastInsertId()]);
        } elseif ($sub === 'review') {
            $id = (int)($_POST['id'] ?? 0);
            $status = $_POST['status'] ?? 'reviewed';
            $db->prepare("UPDATE alfred_dream_log SET status = ?, reviewed_by = 'commander', reviewed_at = NOW() WHERE id = ?")->execute([$status, $id]);
            agent_panel_json(['ok' => true]);
        } elseif ($sub === 'vote') {
            $id = (int)($_POST['id'] ?? 0);
            $db->prepare("UPDATE alfred_dream_log SET votes = votes + 1 WHERE id = ?")->execute([$id]);
            agent_panel_json(['ok' => true]);
        }
        break;

    /* ═══════ MISSION AUTOPILOT ═══════ */
    case 'mission_autopilot':
        $sub = $_GET['sub_action'] ?? $_POST['sub_action'] ?? 'suggest';
        if ($sub === 'suggest') {
            // Get unassigned missions
            $missions = $db->query("SELECT id, title, description, priority, status FROM alfred_agent_dispatches
                WHERE (assigned_agent IS NULL OR assigned_agent = '') AND status IN ('pending','queued')
                ORDER BY FIELD(priority,'critical','high','normal','low'), created_at ASC LIMIT 20")->fetchAll(PDO::FETCH_ASSOC);
            // Get agent load scores
            $loads = $db->query("SELECT agent_name,
                COUNT(CASE WHEN status IN ('active','in_progress') THEN 1 END) as active_missions,
                COUNT(CASE WHEN status = 'queued' THEN 1 END) as queued_missions
                FROM alfred_agent_dispatches GROUP BY agent_name")->fetchAll(PDO::FETCH_ASSOC);
            $loadMap = [];
            foreach ($loads as $l) { $loadMap[$l['agent_name']] = (int)$l['active_missions'] + (int)$l['queued_missions']; }
            // Get agent capabilities
            $capMap = [];
            $agents = $db->query("SELECT DISTINCT agent_name FROM alfred_heartbeat")->fetchAll(PDO::FETCH_COLUMN);
            foreach ($agents as $a) {
                $capMap[$a] = $loadMap[$a] ?? 0;
            }
            // Sort agents by load (least loaded first) and suggest assignments
            $suggestions = [];
            asort($capMap);
            $agentList = array_keys($capMap);
            foreach ($missions as $m) {
                $bestAgent = !empty($agentList) ? $agentList[0] : 'unassigned';
                $suggestions[] = ['mission_id' => $m['id'], 'title' => $m['title'], 'priority' => $m['priority'], 'suggested_agent' => $bestAgent, 'agent_load' => $capMap[$bestAgent] ?? 0];
                // Simulate load increase
                if (isset($capMap[$bestAgent])) { $capMap[$bestAgent]++; asort($capMap); $agentList = array_keys($capMap); }
            }
            agent_panel_json(['ok' => true, 'suggestions' => $suggestions, 'agent_loads' => $loadMap, 'unassigned_count' => count($missions)]);
        } elseif ($sub === 'assign') {
            $missionId = (int)($_POST['mission_id'] ?? 0);
            $agent = trim($_POST['agent_id'] ?? '');
            if (!$missionId || !$agent) { agent_panel_json(['error' => 'Mission ID and agent required']); break; }
            $db->prepare("UPDATE alfred_agent_dispatches SET assigned_agent = ?, status = 'queued' WHERE id = ?")->execute([$agent, $missionId]);
            agent_panel_json(['ok' => true]);
        } elseif ($sub === 'assign_all') {
            // Auto-assign all suggestions
            $missions = $db->query("SELECT id FROM alfred_agent_dispatches WHERE (assigned_agent IS NULL OR assigned_agent = '') AND status IN ('pending','queued') ORDER BY FIELD(priority,'critical','high','normal','low') LIMIT 50")->fetchAll(PDO::FETCH_COLUMN);
            $loads = $db->query("SELECT agent_name, COUNT(*) as load_count FROM alfred_agent_dispatches WHERE status IN ('active','in_progress','queued') GROUP BY agent_name")->fetchAll(PDO::FETCH_ASSOC);
            $loadMap = [];
            foreach ($loads as $l) { $loadMap[$l['agent_name']] = (int)$l['load_count']; }
            $agents = $db->query("SELECT DISTINCT agent_name FROM alfred_heartbeat")->fetchAll(PDO::FETCH_COLUMN);
            foreach ($agents as $a) { if (!isset($loadMap[$a])) $loadMap[$a] = 0; }
            asort($loadMap);
            $assigned = 0;
            foreach ($missions as $mid) {
                $agentList = array_keys($loadMap);
                $best = $agentList[0] ?? null;
                if ($best) {
                    $db->prepare("UPDATE alfred_agent_dispatches SET assigned_agent = ?, status = 'queued' WHERE id = ?")->execute([$best, $mid]);
                    $loadMap[$best]++;
                    asort($loadMap);
                    $assigned++;
                }
            }
            agent_panel_json(['ok' => true, 'assigned' => $assigned]);
        }
        break;

    /* ═══════ FLEET CEREMONY LOG ═══════ */
    case 'ceremony_log':
        $sub = $_GET['sub_action'] ?? $_POST['sub_action'] ?? 'list';
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_ceremony_log (
            id INT AUTO_INCREMENT PRIMARY KEY,
            agent_id VARCHAR(40) NOT NULL,
            ceremony_type ENUM('promotion','commendation','milestone','badge','reprimand','retirement','inauguration') DEFAULT 'commendation',
            title VARCHAR(200) NOT NULL,
            description TEXT,
            awarded_by VARCHAR(40) DEFAULT 'commander',
            ceremony_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            INDEX idx_agent (agent_id),
            INDEX idx_type (ceremony_type)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");
        if ($sub === 'list') {
            $agent = $_GET['agent_id'] ?? '';
            $where = '1=1'; $params = [];
            if ($agent) { $where .= ' AND agent_id = ?'; $params[] = $agent; }
            $st = $db->prepare("SELECT * FROM alfred_ceremony_log WHERE $where ORDER BY ceremony_date DESC LIMIT 50");
            $st->execute($params);
            agent_panel_json(['ok' => true, 'ceremonies' => $st->fetchAll(PDO::FETCH_ASSOC)]);
        } elseif ($sub === 'create') {
            $agent = trim($_POST['agent_id'] ?? '');
            $type = $_POST['ceremony_type'] ?? 'commendation';
            $title = trim($_POST['title'] ?? '');
            $desc = trim($_POST['description'] ?? '');
            if (!$agent || !$title) { agent_panel_json(['error' => 'Agent and title required']); break; }
            $st = $db->prepare("INSERT INTO alfred_ceremony_log (agent_id, ceremony_type, title, description) VALUES (?, ?, ?, ?)");
            $st->execute([$agent, $type, $title, $desc]);
            agent_panel_json(['ok' => true, 'id' => $db->lastInsertId()]);
        }
        break;

    /* ═══════ AGENT SANDBOX ═══════ */
    case 'agent_sandbox':
        $sub = $_GET['sub_action'] ?? $_POST['sub_action'] ?? 'list';
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_sandbox_runs (
            id INT AUTO_INCREMENT PRIMARY KEY,
            agent_id VARCHAR(40) NOT NULL,
            command TEXT NOT NULL,
            result TEXT,
            status ENUM('queued','running','success','failed','timeout') DEFAULT 'queued',
            execution_time_ms INT DEFAULT 0,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            completed_at TIMESTAMP NULL,
            INDEX idx_agent (agent_id)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");
        if ($sub === 'list') {
            $agent = $_GET['agent_id'] ?? '';
            $where = '1=1'; $params = [];
            if ($agent) { $where .= ' AND agent_id = ?'; $params[] = $agent; }
            $st = $db->prepare("SELECT * FROM alfred_sandbox_runs WHERE $where ORDER BY created_at DESC LIMIT 30");
            $st->execute($params);
            agent_panel_json(['ok' => true, 'runs' => $st->fetchAll(PDO::FETCH_ASSOC)]);
        } elseif ($sub === 'run') {
            $agent = trim($_POST['agent_id'] ?? '');
            $command = trim($_POST['command'] ?? '');
            if (!$agent || !$command) { agent_panel_json(['error' => 'Agent and command required']); break; }
            // Record the sandbox run (actual execution would be done by the agent harness)
            $st = $db->prepare("INSERT INTO alfred_sandbox_runs (agent_id, command, status) VALUES (?, ?, 'queued')");
            $st->execute([$agent, $command]);
            $runId = $db->lastInsertId();
            // Simulate sandbox execution by recording it
            $db->prepare("UPDATE alfred_sandbox_runs SET status = 'success', result = ?, execution_time_ms = ?, completed_at = NOW() WHERE id = ?")
                ->execute(['[Sandbox] Command queued for agent ' . $agent . ': ' . substr($command, 0, 100), rand(50, 500), $runId]);
            agent_panel_json(['ok' => true, 'run_id' => $runId]);
        } elseif ($sub === 'clear') {
            $agent = trim($_POST['agent_id'] ?? '');
            if ($agent) {
                $db->prepare("DELETE FROM alfred_sandbox_runs WHERE agent_id = ?")->execute([$agent]);
            } else {
                $db->exec("TRUNCATE TABLE alfred_sandbox_runs");
            }
            agent_panel_json(['ok' => true]);
        }
        break;

    /* ═══════ FLEET BROADCAST CONSOLE ═══════ */
    case 'broadcast_console':
        $sub = $_GET['sub_action'] ?? $_POST['sub_action'] ?? 'list';
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_fleet_broadcasts (
            id INT AUTO_INCREMENT PRIMARY KEY,
            title VARCHAR(200) NOT NULL,
            message TEXT NOT NULL,
            broadcast_type ENUM('general','alert','order','intel','ceremony') DEFAULT 'general',
            priority ENUM('critical','high','normal','low') DEFAULT 'normal',
            target_agents TEXT,
            broadcaster VARCHAR(40) DEFAULT 'commander',
            status ENUM('draft','sent','acknowledged') DEFAULT 'sent',
            ack_count INT DEFAULT 0,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");
        if ($sub === 'list') {
            $st = $db->query("SELECT * FROM alfred_fleet_broadcasts ORDER BY created_at DESC LIMIT 30");
            agent_panel_json(['ok' => true, 'broadcasts' => $st->fetchAll(PDO::FETCH_ASSOC)]);
        } elseif ($sub === 'send') {
            $title = trim($_POST['title'] ?? '');
            $message = trim($_POST['message'] ?? '');
            $type = $_POST['broadcast_type'] ?? 'general';
            $priority = $_POST['priority'] ?? 'normal';
            $targets = trim($_POST['target_agents'] ?? 'all');
            if (!$title || !$message) { agent_panel_json(['error' => 'Title and message required']); break; }
            $st = $db->prepare("INSERT INTO alfred_fleet_broadcasts (title, message, broadcast_type, priority, target_agents) VALUES (?, ?, ?, ?, ?)");
            $st->execute([$title, $message, $type, $priority, $targets]);
            // Also send as comms to targeted agents
            if ($targets === 'all') {
                $agents = $db->query("SELECT DISTINCT agent_name FROM alfred_heartbeat")->fetchAll(PDO::FETCH_COLUMN);
            } else {
                $agents = array_filter(array_map('trim', explode(',', $targets)));
            }
            foreach ($agents as $agent) {
                $db->prepare("INSERT INTO alfred_agent_comms (from_agent, to_agent, channel, message, priority) VALUES ('commander', ?, 'broadcast', ?, ?)")
                    ->execute([$agent, '[' . strtoupper($type) . '] ' . $title . ': ' . $message, $priority]);
            }
            agent_panel_json(['ok' => true, 'id' => $db->lastInsertId(), 'sent_to' => count($agents)]);
        }
        break;

    /* ═══════ AGENT EVOLUTION TREE ═══════ */
    case 'evolution_tree':
        $agent = $_GET['agent_id'] ?? '';
        // Gather evolution data from multiple sources
        $evolution = [];
        if ($agent) {
            // Version history
            $vSt = $db->prepare("SELECT version, status, changelog, deployed_at FROM alfred_agent_versions WHERE agent_id = ? ORDER BY deployed_at DESC LIMIT 20");
            $vSt->execute([$agent]);
            $versions = $vSt->fetchAll(PDO::FETCH_ASSOC);
            // Config snapshots
            $cSt = $db->prepare("SELECT snapshot_name, created_at FROM alfred_config_snapshots WHERE agent_id = ? ORDER BY created_at DESC LIMIT 10");
            $cSt->execute([$agent]);
            $configs = $cSt->fetchAll(PDO::FETCH_ASSOC);
            // Training records
            $tSt = $db->prepare("SELECT skill_name, xp_gained, completed_at FROM alfred_agent_training WHERE agent_id = ? AND status = 'completed' ORDER BY completed_at DESC LIMIT 15");
            $tSt->execute([$agent]);
            $training = $tSt->fetchAll(PDO::FETCH_ASSOC);
            // Changelog
            $chSt = $db->prepare("SELECT change_type, title, created_at FROM alfred_agent_changelog WHERE agent_id = ? ORDER BY created_at DESC LIMIT 15");
            $chSt->execute([$agent]);
            $changelog = $chSt->fetchAll(PDO::FETCH_ASSOC);
            agent_panel_json(['ok' => true, 'agent' => $agent, 'versions' => $versions, 'configs' => $configs, 'training' => $training, 'changelog' => $changelog]);
        } else {
            // Overview for all agents
            $agents = $db->query("SELECT DISTINCT agent_name FROM alfred_heartbeat ORDER BY agent_name")->fetchAll(PDO::FETCH_COLUMN);
            $overview = [];
            foreach ($agents as $a) {
                $vCnt = $db->prepare("SELECT COUNT(*) FROM alfred_agent_versions WHERE agent_id = ?"); $vCnt->execute([$a]);
                $tCnt = $db->prepare("SELECT COUNT(*) FROM alfred_agent_training WHERE agent_id = ? AND status = 'completed'"); $tCnt->execute([$a]);
                $chCnt = $db->prepare("SELECT COUNT(*) FROM alfred_agent_changelog WHERE agent_id = ?"); $chCnt->execute([$a]);
                $overview[] = ['agent' => $a, 'versions' => (int)$vCnt->fetchColumn(), 'training' => (int)$tCnt->fetchColumn(), 'changes' => (int)$chCnt->fetchColumn()];
            }
            agent_panel_json(['ok' => true, 'overview' => $overview]);
        }
        break;

    /* ═══════ MISSION WAR MAP ═══════ */
    case 'mission_warmap':
        // Strategic overview of missions grouped by agent zones
        $agents = $db->query("SELECT DISTINCT agent_name FROM alfred_heartbeat ORDER BY agent_name")->fetchAll(PDO::FETCH_COLUMN);
        $zones = [];
        foreach ($agents as $a) {
            $mSt = $db->prepare("SELECT status, COUNT(*) as cnt FROM alfred_agent_dispatches WHERE assigned_agent = ? GROUP BY status");
            $mSt->execute([$a]);
            $statuses = [];
            foreach ($mSt->fetchAll(PDO::FETCH_ASSOC) as $row) { $statuses[$row['status']] = (int)$row['cnt']; }
            $hSt = $db->prepare("SELECT status, cpu_percent, memory_bytes FROM alfred_heartbeat WHERE agent_name = ? ORDER BY checked_at DESC LIMIT 1");
            $hSt->execute([$a]);
            $health = $hSt->fetch(PDO::FETCH_ASSOC);
            $zones[] = [
                'agent' => $a,
                'missions' => $statuses,
                'total_missions' => array_sum($statuses),
                'active' => ($statuses['active'] ?? 0) + ($statuses['in_progress'] ?? 0),
                'completed' => $statuses['completed'] ?? 0,
                'failed' => $statuses['failed'] ?? 0,
                'health' => $health['status'] ?? 'unknown',
                'cpu' => round((float)($health['cpu_percent'] ?? 0), 1),
                'mem_mb' => round((float)($health['memory_bytes'] ?? 0) / 1048576, 1)
            ];
        }
        // Fleet totals
        $total = $db->query("SELECT status, COUNT(*) as cnt FROM alfred_agent_dispatches GROUP BY status")->fetchAll(PDO::FETCH_ASSOC);
        agent_panel_json(['ok' => true, 'zones' => $zones, 'fleet_totals' => $total]);
        break;

    /* ═══════ FLEET HEARTBEAT CHORUS ═══════ */
    case 'heartbeat_chorus':
        $agents = $db->query("SELECT DISTINCT agent_name FROM alfred_heartbeat ORDER BY agent_name")->fetchAll(PDO::FETCH_COLUMN);
        $chorus = [];
        foreach ($agents as $a) {
            $st = $db->prepare("SELECT checked_at, status, response_time_ms, cpu_percent, memory_bytes
                FROM alfred_heartbeat WHERE agent_name = ? ORDER BY checked_at DESC LIMIT 20");
            $st->execute([$a]);
            $beats = $st->fetchAll(PDO::FETCH_ASSOC);
            if (!empty($beats)) {
                $intervals = [];
                for ($i = 0; $i < count($beats) - 1; $i++) {
                    $diff = strtotime($beats[$i]['checked_at']) - strtotime($beats[$i+1]['checked_at']);
                    $intervals[] = $diff;
                }
                $avgInterval = count($intervals) > 0 ? round(array_sum($intervals) / count($intervals)) : 0;
                $chorus[] = [
                    'agent' => $a,
                    'last_beat' => $beats[0]['checked_at'],
                    'status' => $beats[0]['status'],
                    'response_ms' => (int)$beats[0]['response_time_ms'],
                    'avg_interval' => $avgInterval,
                    'beat_count' => count($beats),
                    'cpu' => round((float)$beats[0]['cpu_percent'], 1),
                    'mem_mb' => round((float)$beats[0]['memory_bytes'] / 1048576, 1),
                    'rhythm' => array_map(function($b) { return ['t' => $b['checked_at'], 's' => $b['status'], 'r' => (int)$b['response_time_ms']]; }, array_slice($beats, 0, 10))
                ];
            }
        }
        agent_panel_json(['ok' => true, 'chorus' => $chorus]);
        break;

    /* ═══════ AGENT LOYALTY INDEX ═══════ */
    case 'loyalty_index':
        $agents = $db->query("SELECT DISTINCT agent_name FROM alfred_heartbeat ORDER BY agent_name")->fetchAll(PDO::FETCH_COLUMN);
        $loyalty = [];
        foreach ($agents as $a) {
            // Mission completion rate
            $mSt = $db->prepare("SELECT
                COUNT(*) as total,
                SUM(CASE WHEN status IN ('completed','verified') THEN 1 ELSE 0 END) as completed,
                SUM(CASE WHEN status = 'failed' THEN 1 ELSE 0 END) as failed
                FROM alfred_agent_dispatches WHERE assigned_agent = ?");
            $mSt->execute([$a]);
            $m = $mSt->fetch(PDO::FETCH_ASSOC);
            $completionRate = $m['total'] > 0 ? round($m['completed'] / $m['total'] * 100, 1) : 100;
            // Uptime from heartbeat
            $hSt = $db->prepare("SELECT COUNT(*) as total, SUM(CASE WHEN status = 'healthy' THEN 1 ELSE 0 END) as healthy
                FROM alfred_heartbeat WHERE agent_name = ? AND checked_at >= NOW() - INTERVAL 7 DAY");
            $hSt->execute([$a]);
            $h = $hSt->fetch(PDO::FETCH_ASSOC);
            $uptimeRate = $h['total'] > 0 ? round($h['healthy'] / $h['total'] * 100, 1) : 100;
            // Error rate
            $eSt = $db->prepare("SELECT COUNT(*) FROM alfred_error_log WHERE agent_name = ? AND created_at >= NOW() - INTERVAL 7 DAY");
            $eSt->execute([$a]);
            $errorCount = (int)$eSt->fetchColumn();
            $errorPenalty = min(30, $errorCount * 2);
            // Comms responsiveness
            $cSt = $db->prepare("SELECT COUNT(*) as total, SUM(CASE WHEN is_read = 1 THEN 1 ELSE 0 END) as read_count
                FROM alfred_agent_comms WHERE to_agent = ? AND created_at >= NOW() - INTERVAL 7 DAY");
            $cSt->execute([$a]);
            $c = $cSt->fetch(PDO::FETCH_ASSOC);
            $commsRate = $c['total'] > 0 ? round($c['read_count'] / $c['total'] * 100, 1) : 100;
            // Composite loyalty score
            $loyaltyScore = round($completionRate * 0.35 + $uptimeRate * 0.30 + (100 - $errorPenalty) * 0.20 + $commsRate * 0.15, 1);
            $grade = $loyaltyScore >= 95 ? 'S' : ($loyaltyScore >= 90 ? 'A' : ($loyaltyScore >= 80 ? 'B' : ($loyaltyScore >= 70 ? 'C' : ($loyaltyScore >= 60 ? 'D' : 'F'))));
            $loyalty[] = [
                'agent' => $a,
                'loyalty_score' => $loyaltyScore,
                'grade' => $grade,
                'mission_rate' => $completionRate,
                'uptime_rate' => $uptimeRate,
                'error_count' => $errorCount,
                'error_penalty' => $errorPenalty,
                'comms_rate' => $commsRate,
                'missions_total' => (int)$m['total'],
                'missions_completed' => (int)$m['completed']
            ];
        }
        usort($loyalty, function($a, $b) { return $b['loyalty_score'] <=> $a['loyalty_score']; });
        agent_panel_json(['ok' => true, 'loyalty' => $loyalty]);
        break;

    // ─── FLEET RESOURCE POOL ───
    case 'resource_pool':
        $sub = $input['sub'] ?? $_GET['sub'] ?? 'list';
        if ($sub === 'allocate') {
            $agentName = $input['agent_name'] ?? '';
            $resource = $input['resource'] ?? '';
            $quota = (int)($input['quota'] ?? 0);
            if (!$agentName || !$resource || $quota <= 0) { agent_panel_json(['error'=>'agent_name, resource and quota>0 required']); break; }
            $stmt = $pdo->prepare("INSERT INTO alfred_resource_pool (agent_name, resource_type, quota, used, updated_at) VALUES (?, ?, ?, 0, NOW()) ON DUPLICATE KEY UPDATE quota = VALUES(quota), updated_at = NOW()");
            $stmt->execute([$agentName, $resource, $quota]);
            agent_panel_json(['ok'=>true,'msg'=>'Resource allocated']);
        } elseif ($sub === 'consume') {
            $agentName = $input['agent_name'] ?? '';
            $resource = $input['resource'] ?? '';
            $amount = (int)($input['amount'] ?? 1);
            if (!$agentName || !$resource) { agent_panel_json(['error'=>'agent_name and resource required']); break; }
            $stmt = $pdo->prepare("UPDATE alfred_resource_pool SET used = LEAST(used + ?, quota), updated_at = NOW() WHERE agent_name = ? AND resource_type = ?");
            $stmt->execute([$amount, $agentName, $resource]);
            agent_panel_json(['ok'=>true,'msg'=>'Resource consumed']);
        } else {
            $rows = $pdo->query("SELECT agent_name, resource_type, quota, used, updated_at FROM alfred_resource_pool ORDER BY agent_name, resource_type")->fetchAll(PDO::FETCH_ASSOC);
            $byAgent = [];
            foreach ($rows as $r) {
                $byAgent[$r['agent_name']][] = [
                    'resource' => $r['resource_type'],
                    'quota' => (int)$r['quota'],
                    'used' => (int)$r['used'],
                    'pct' => $r['quota'] > 0 ? round($r['used'] / $r['quota'] * 100, 1) : 0,
                    'updated' => $r['updated_at']
                ];
            }
            $pool = [];
            foreach ($byAgent as $name => $resources) {
                $pool[] = ['name' => $name, 'resources' => $resources];
            }
            agent_panel_json(['ok' => true, 'pool' => $pool]);
        }
        break;

    // ─── AGENT REPUTATION BOARD ───
    case 'reputation_board':
        $sub = $input['sub'] ?? $_GET['sub'] ?? 'list';
        if ($sub === 'endorse') {
            $fromAgent = $input['from_agent'] ?? '';
            $toAgent = $input['to_agent'] ?? '';
            $category = $input['category'] ?? 'general';
            $comment = $input['comment'] ?? '';
            if (!$fromAgent || !$toAgent) { agent_panel_json(['error'=>'from_agent and to_agent required']); break; }
            $stmt = $pdo->prepare("INSERT INTO alfred_reputation (from_agent, to_agent, category, comment, created_at) VALUES (?, ?, ?, ?, NOW())");
            $stmt->execute([$fromAgent, $toAgent, $category, $comment]);
            agent_panel_json(['ok'=>true,'msg'=>'Endorsement recorded']);
        } else {
            $agents = $pdo->query("SELECT DISTINCT name FROM alfred_agent_health ORDER BY name")->fetchAll(PDO::FETCH_COLUMN);
            $board = [];
            foreach ($agents as $name) {
                $st = $pdo->prepare("SELECT COUNT(*) as cnt, category FROM alfred_reputation WHERE to_agent = ? GROUP BY category");
                $st->execute([$name]);
                $endors = $st->fetchAll(PDO::FETCH_ASSOC);
                $total = 0;
                $cats = [];
                foreach ($endors as $e) { $total += (int)$e['cnt']; $cats[$e['category']] = (int)$e['cnt']; }
                $st2 = $pdo->prepare("SELECT from_agent, category, comment, created_at FROM alfred_reputation WHERE to_agent = ? ORDER BY created_at DESC LIMIT 5");
                $st2->execute([$name]);
                $recent = $st2->fetchAll(PDO::FETCH_ASSOC);
                $board[] = ['name' => $name, 'total_endorsements' => $total, 'categories' => $cats, 'recent' => $recent];
            }
            usort($board, function($a, $b) { return $b['total_endorsements'] <=> $a['total_endorsements']; });
            agent_panel_json(['ok' => true, 'board' => $board]);
        }
        break;

    // ─── MISSION REPLAY LOG ───
    case 'mission_replay':
        $missionId = $input['mission_id'] ?? $_GET['mission_id'] ?? null;
        if ($missionId) {
            $st = $pdo->prepare("SELECT id, mission, agent_name, status, priority, created_at FROM alfred_agent_dispatches WHERE id = ?");
            $st->execute([$missionId]);
            $mission = $st->fetch(PDO::FETCH_ASSOC);
            if (!$mission) { agent_panel_json(['error'=>'Mission not found']); break; }
            $st2 = $pdo->prepare("SELECT step_num, action, detail, result, duration_ms, created_at FROM alfred_mission_replay WHERE mission_id = ? ORDER BY step_num ASC");
            $st2->execute([$missionId]);
            $steps = $st2->fetchAll(PDO::FETCH_ASSOC);
            agent_panel_json(['ok'=>true, 'mission'=>$mission, 'steps'=>$steps]);
        } else {
            $missions = $pdo->query("SELECT d.id, d.mission, d.agent_name, d.status, d.priority, d.created_at, COUNT(r.id) as step_count FROM alfred_agent_dispatches d LEFT JOIN alfred_mission_replay r ON r.mission_id = d.id GROUP BY d.id ORDER BY d.created_at DESC LIMIT 50")->fetchAll(PDO::FETCH_ASSOC);
            agent_panel_json(['ok'=>true, 'missions'=>$missions]);
        }
        break;

    // ─── FLEET CHAIN OF COMMAND ───
    case 'chain_of_command':
        $agents = $pdo->query("SELECT DISTINCT h.name, h.status, h.last_heartbeat, COALESCE(c.reports_to, 'Commander') as reports_to, COALESCE(c.rank, 'Agent') as rank, COALESCE(c.tier, 1) as tier FROM alfred_agent_health h LEFT JOIN alfred_chain_of_command c ON c.agent_name = h.name ORDER BY c.tier ASC, h.name")->fetchAll(PDO::FETCH_ASSOC);
        $hierarchy = [];
        foreach ($agents as $a) {
            $subordinates = $pdo->prepare("SELECT agent_name FROM alfred_chain_of_command WHERE reports_to = ?");
            $subordinates->execute([$a['name']]);
            $subs = $subordinates->fetchAll(PDO::FETCH_COLUMN);
            $hierarchy[] = [
                'name' => $a['name'],
                'status' => $a['status'],
                'rank' => $a['rank'],
                'tier' => (int)$a['tier'],
                'reports_to' => $a['reports_to'],
                'subordinates' => $subs,
                'last_heartbeat' => $a['last_heartbeat']
            ];
        }
        agent_panel_json(['ok' => true, 'hierarchy' => $hierarchy]);
        break;

    // ─── AGENT CAPABILITY MATRIX ───
    case 'capability_matrix':
        $sub = $input['sub'] ?? $_GET['sub'] ?? 'list';
        if ($sub === 'set') {
            $agentName = $input['agent_name'] ?? '';
            $skill = $input['skill'] ?? '';
            $proficiency = max(0, min(100, (int)($input['proficiency'] ?? 50)));
            if (!$agentName || !$skill) { agent_panel_json(['error'=>'agent_name and skill required']); break; }
            $stmt = $pdo->prepare("INSERT INTO alfred_capabilities (agent_name, skill, proficiency, updated_at) VALUES (?, ?, ?, NOW()) ON DUPLICATE KEY UPDATE proficiency = VALUES(proficiency), updated_at = NOW()");
            $stmt->execute([$agentName, $skill, $proficiency]);
            agent_panel_json(['ok'=>true,'msg'=>'Capability set']);
        } else {
            $rows = $pdo->query("SELECT agent_name, skill, proficiency, updated_at FROM alfred_capabilities ORDER BY agent_name, skill")->fetchAll(PDO::FETCH_ASSOC);
            $byAgent = [];
            foreach ($rows as $r) {
                $byAgent[$r['agent_name']][] = [
                    'skill' => $r['skill'],
                    'proficiency' => (int)$r['proficiency'],
                    'updated' => $r['updated_at']
                ];
            }
            $matrix = [];
            $allSkills = array_unique(array_column($rows, 'skill'));
            foreach ($byAgent as $name => $skills) {
                $avgProf = count($skills) > 0 ? round(array_sum(array_column($skills, 'proficiency')) / count($skills), 1) : 0;
                $matrix[] = ['name' => $name, 'skills' => $skills, 'avg_proficiency' => $avgProf, 'skill_count' => count($skills)];
            }
            usort($matrix, function($a, $b) { return $b['avg_proficiency'] <=> $a['avg_proficiency']; });
            agent_panel_json(['ok' => true, 'matrix' => $matrix, 'all_skills' => array_values($allSkills)]);
        }
        break;

    // ─── FLEET MORALE PULSE ───
    case 'morale_pulse':
        $agents = $pdo->query("SELECT DISTINCT h.name FROM alfred_agent_health h ORDER BY h.name")->fetchAll(PDO::FETCH_COLUMN);
        $morale = [];
        foreach ($agents as $name) {
            $st = $pdo->prepare("SELECT morale_score, factor, note, recorded_at FROM alfred_agent_morale WHERE agent_name = ? ORDER BY recorded_at DESC LIMIT 10");
            $st->execute([$name]);
            $history = $st->fetchAll(PDO::FETCH_ASSOC);
            $current = !empty($history) ? (int)$history[0]['morale_score'] : 50;
            $trend = count($history) >= 2 ? (int)$history[0]['morale_score'] - (int)$history[1]['morale_score'] : 0;
            $level = $current >= 80 ? 'excellent' : ($current >= 60 ? 'good' : ($current >= 40 ? 'fair' : 'low'));
            $morale[] = [
                'name' => $name,
                'current' => $current,
                'level' => $level,
                'trend' => $trend,
                'factor' => $history[0]['factor'] ?? 'unknown',
                'history' => array_map(function($h) {
                    return ['score' => (int)$h['morale_score'], 'factor' => $h['factor'], 'time' => $h['recorded_at']];
                }, $history)
            ];
        }
        usort($morale, function($a, $b) { return $b['current'] <=> $a['current']; });
        agent_panel_json(['ok' => true, 'agents' => $morale]);
        break;

    // ─── AGENT DUTY ROSTER VIEW ───
    case 'duty_roster_view':
        $rows = $pdo->query("SELECT agent_name, shift, duty_type, start_time, end_time, status, notes FROM alfred_duty_roster ORDER BY start_time DESC LIMIT 100")->fetchAll(PDO::FETCH_ASSOC);
        $byAgent = [];
        foreach ($rows as $r) {
            $byAgent[$r['agent_name']][] = [
                'shift' => $r['shift'],
                'duty_type' => $r['duty_type'],
                'start' => $r['start_time'],
                'end' => $r['end_time'],
                'status' => $r['status'],
                'notes' => $r['notes']
            ];
        }
        $roster = [];
        foreach ($byAgent as $name => $duties) {
            $active = count(array_filter($duties, function($d) { return $d['status'] === 'active'; }));
            $roster[] = ['name' => $name, 'duties' => $duties, 'active_count' => $active, 'total' => count($duties)];
        }
        usort($roster, function($a, $b) { return $b['active_count'] <=> $a['active_count']; });
        agent_panel_json(['ok' => true, 'roster' => $roster]);
        break;

    // ─── MISSION PRIORITY QUEUE ───
    case 'priority_queue':
        $sub = $input['sub'] ?? $_GET['sub'] ?? 'list';
        if ($sub === 'promote') {
            $missionId = (int)($input['mission_id'] ?? 0);
            if (!$missionId) { agent_panel_json(['error'=>'mission_id required']); break; }
            $pdo->prepare("UPDATE alfred_agent_dispatches SET priority = CASE WHEN priority = 'low' THEN 'medium' WHEN priority = 'medium' THEN 'high' WHEN priority = 'high' THEN 'critical' ELSE priority END WHERE id = ?")->execute([$missionId]);
            agent_panel_json(['ok'=>true,'msg'=>'Mission promoted']);
        } elseif ($sub === 'demote') {
            $missionId = (int)($input['mission_id'] ?? 0);
            if (!$missionId) { agent_panel_json(['error'=>'mission_id required']); break; }
            $pdo->prepare("UPDATE alfred_agent_dispatches SET priority = CASE WHEN priority = 'critical' THEN 'high' WHEN priority = 'high' THEN 'medium' WHEN priority = 'medium' THEN 'low' ELSE priority END WHERE id = ?")->execute([$missionId]);
            agent_panel_json(['ok'=>true,'msg'=>'Mission demoted']);
        } else {
            $missions = $pdo->query("SELECT id, mission, agent_name, status, priority, created_at FROM alfred_agent_dispatches WHERE status IN ('pending','queued','active') ORDER BY FIELD(priority,'critical','high','medium','low'), created_at ASC LIMIT 50")->fetchAll(PDO::FETCH_ASSOC);
            $counts = ['critical'=>0,'high'=>0,'medium'=>0,'low'=>0];
            foreach ($missions as $m) { if (isset($counts[$m['priority']])) $counts[$m['priority']]++; }
            agent_panel_json(['ok'=>true, 'queue'=>$missions, 'counts'=>$counts, 'total'=>count($missions)]);
        }
        break;

    // ─── FLEET ANOMALY DETECTOR ───
    case 'anomaly_detector':
        $anomalies = [];
        // Check heartbeat gaps (agents not beating for >5min)
        $stale = $pdo->query("SELECT name, status, last_heartbeat, TIMESTAMPDIFF(MINUTE, last_heartbeat, NOW()) as minutes_ago FROM alfred_agent_health WHERE last_heartbeat < DATE_SUB(NOW(), INTERVAL 5 MINUTE) ORDER BY last_heartbeat ASC")->fetchAll(PDO::FETCH_ASSOC);
        foreach ($stale as $s) {
            $anomalies[] = ['type'=>'heartbeat_gap','severity'=>$s['minutes_ago'] > 30 ? 'critical' : ($s['minutes_ago'] > 15 ? 'high' : 'medium'), 'agent'=>$s['name'], 'detail'=>"No heartbeat for {$s['minutes_ago']} minutes", 'time'=>$s['last_heartbeat']];
        }
        // Check error spikes (>5 errors in last hour per agent)
        $errSpikes = $pdo->query("SELECT agent_name, COUNT(*) as cnt FROM alfred_error_log WHERE created_at > DATE_SUB(NOW(), INTERVAL 1 HOUR) GROUP BY agent_name HAVING cnt > 5 ORDER BY cnt DESC")->fetchAll(PDO::FETCH_ASSOC);
        foreach ($errSpikes as $e) {
            $anomalies[] = ['type'=>'error_spike','severity'=>$e['cnt'] > 20 ? 'critical' : 'high', 'agent'=>$e['agent_name'], 'detail'=>"{$e['cnt']} errors in last hour", 'time'=>date('Y-m-d H:i:s')];
        }
        // Check mission failure rate (>50% in last 24h)
        $failRates = $pdo->query("SELECT agent_name, COUNT(*) as total, SUM(status='failed') as failed FROM alfred_agent_dispatches WHERE created_at > DATE_SUB(NOW(), INTERVAL 24 HOUR) GROUP BY agent_name HAVING total > 3 AND (failed/total) > 0.5")->fetchAll(PDO::FETCH_ASSOC);
        foreach ($failRates as $f) {
            $pct = round($f['failed'] / $f['total'] * 100);
            $anomalies[] = ['type'=>'mission_failure_rate','severity'=>'high', 'agent'=>$f['agent_name'], 'detail'=>"{$pct}% failure rate ({$f['failed']}/{$f['total']} missions)", 'time'=>date('Y-m-d H:i:s')];
        }
        // Check morale drops (morale < 30)
        $lowMorale = $pdo->query("SELECT agent_name, morale_score, factor FROM alfred_agent_morale WHERE (agent_name, recorded_at) IN (SELECT agent_name, MAX(recorded_at) FROM alfred_agent_morale GROUP BY agent_name) AND morale_score < 30")->fetchAll(PDO::FETCH_ASSOC);
        foreach ($lowMorale as $m) {
            $anomalies[] = ['type'=>'low_morale','severity'=>'medium', 'agent'=>$m['agent_name'], 'detail'=>"Morale at {$m['morale_score']} ({$m['factor']})", 'time'=>date('Y-m-d H:i:s')];
        }
        usort($anomalies, function($a, $b) { $sev = ['critical'=>0,'high'=>1,'medium'=>2,'low'=>3]; return ($sev[$a['severity']]??9) <=> ($sev[$b['severity']]??9); });
        $summary = ['critical'=>0,'high'=>0,'medium'=>0,'low'=>0];
        foreach ($anomalies as $a) { if (isset($summary[$a['severity']])) $summary[$a['severity']]++; }
        agent_panel_json(['ok'=>true, 'anomalies'=>$anomalies, 'summary'=>$summary, 'total'=>count($anomalies)]);
        break;

    // ─── AGENT TRAINING ACADEMY ───
    case 'training_academy':
        $agents = $pdo->query("SELECT DISTINCT name FROM alfred_agent_health ORDER BY name")->fetchAll(PDO::FETCH_COLUMN);
        $academy = [];
        foreach ($agents as $name) {
            $st = $pdo->prepare("SELECT module, status, score, started_at, completed_at FROM alfred_agent_training WHERE agent_name = ? ORDER BY started_at DESC LIMIT 10");
            $st->execute([$name]);
            $courses = $st->fetchAll(PDO::FETCH_ASSOC);
            $completed = count(array_filter($courses, function($c) { return $c['status'] === 'completed'; }));
            $inProgress = count(array_filter($courses, function($c) { return $c['status'] === 'in_progress' || $c['status'] === 'active'; }));
            $avgScore = 0;
            $scored = array_filter($courses, function($c) { return $c['score'] > 0; });
            if (count($scored) > 0) $avgScore = round(array_sum(array_column($scored, 'score')) / count($scored), 1);
            $academy[] = [
                'name' => $name,
                'total_courses' => count($courses),
                'completed' => $completed,
                'in_progress' => $inProgress,
                'avg_score' => $avgScore,
                'courses' => $courses
            ];
        }
        usort($academy, function($a, $b) { return $b['avg_score'] <=> $a['avg_score']; });
        agent_panel_json(['ok' => true, 'academy' => $academy]);
        break;

    // ─── FLEET DEPLOYMENT HISTORY ───
    case 'deploy_history':
        $rows = $pdo->query("SELECT d.id, d.agent_name, d.version, d.status, d.deploy_type, d.notes, d.created_at FROM alfred_deployments d ORDER BY d.created_at DESC LIMIT 100")->fetchAll(PDO::FETCH_ASSOC);
        $byAgent = [];
        foreach ($rows as $r) {
            $byAgent[$r['agent_name']][] = [
                'id' => (int)$r['id'],
                'version' => $r['version'],
                'status' => $r['status'],
                'type' => $r['deploy_type'],
                'notes' => $r['notes'],
                'time' => $r['created_at']
            ];
        }
        $history = [];
        foreach ($byAgent as $name => $deploys) {
            $history[] = ['name' => $name, 'deploys' => $deploys, 'total' => count($deploys), 'latest' => $deploys[0] ?? null];
        }
        usort($history, function($a, $b) { return ($b['latest']['time'] ?? '') <=> ($a['latest']['time'] ?? ''); });
        agent_panel_json(['ok' => true, 'history' => $history, 'total' => count($rows)]);
        break;

    // ─── AGENT SOP LIBRARY ───
    case 'sop_library':
        $search = $input['search'] ?? $_GET['search'] ?? '';
        $query = "SELECT id, agent_name, title, category, content, version, status, created_at, updated_at FROM alfred_agent_sops";
        $params = [];
        if ($search) {
            $query .= " WHERE title LIKE ? OR content LIKE ? OR category LIKE ?";
            $params = ["%$search%", "%$search%", "%$search%"];
        }
        $query .= " ORDER BY updated_at DESC LIMIT 100";
        $st = $pdo->prepare($query);
        $st->execute($params);
        $sops = $st->fetchAll(PDO::FETCH_ASSOC);
        $categories = [];
        foreach ($sops as $s) {
            $cat = $s['category'] ?: 'uncategorized';
            if (!isset($categories[$cat])) $categories[$cat] = 0;
            $categories[$cat]++;
        }
        agent_panel_json(['ok' => true, 'sops' => $sops, 'categories' => $categories, 'total' => count($sops)]);
        break;

    // ─── MISSION SUCCESS PREDICTOR ───
    case 'success_predictor':
        $agents = $pdo->query("SELECT DISTINCT h.name, h.status FROM alfred_agent_health h ORDER BY h.name")->fetchAll(PDO::FETCH_ASSOC);
        $predictions = [];
        foreach ($agents as $a) {
            $name = $a['name'];
            // Mission success rate
            $ms = $pdo->prepare("SELECT COUNT(*) as total, SUM(status='completed') as completed, SUM(status='failed') as failed FROM alfred_agent_dispatches WHERE agent_name = ? AND created_at > DATE_SUB(NOW(), INTERVAL 30 DAY)");
            $ms->execute([$name]);
            $mr = $ms->fetch(PDO::FETCH_ASSOC);
            $successRate = $mr['total'] > 0 ? round($mr['completed'] / $mr['total'] * 100, 1) : 50;
            // Uptime
            $ut = $pdo->prepare("SELECT COUNT(*) as total, SUM(status='healthy') as healthy FROM alfred_heartbeat WHERE agent_name = ? AND created_at > DATE_SUB(NOW(), INTERVAL 24 HOUR)");
            $ut->execute([$name]);
            $ur = $ut->fetch(PDO::FETCH_ASSOC);
            $uptime = $ur['total'] > 0 ? round($ur['healthy'] / $ur['total'] * 100, 1) : 50;
            // Error rate
            $er = $pdo->prepare("SELECT COUNT(*) as cnt FROM alfred_error_log WHERE agent_name = ? AND created_at > DATE_SUB(NOW(), INTERVAL 24 HOUR)");
            $er->execute([$name]);
            $errCount = (int)$er->fetchColumn();
            $errPenalty = min(30, $errCount * 3);
            // Composite prediction
            $prediction = round(($successRate * 0.5) + ($uptime * 0.3) + ((100 - $errPenalty) * 0.2), 1);
            $confidence = $mr['total'] >= 10 ? 'high' : ($mr['total'] >= 3 ? 'medium' : 'low');
            $predictions[] = [
                'name' => $name,
                'prediction' => $prediction,
                'confidence' => $confidence,
                'success_rate' => $successRate,
                'uptime' => $uptime,
                'error_penalty' => $errPenalty,
                'missions_30d' => (int)$mr['total'],
                'status' => $a['status']
            ];
        }
        usort($predictions, function($a, $b) { return $b['prediction'] <=> $a['prediction']; });
        agent_panel_json(['ok' => true, 'predictions' => $predictions]);
        break;

    // ─── FLEET QUARANTINE WARD ───
    case 'quarantine_ward':
        $sub = $input['sub'] ?? $_GET['sub'] ?? 'list';
        if ($sub === 'release') {
            $agentName = $input['agent_name'] ?? '';
            if (!$agentName) { agent_panel_json(['error'=>'agent_name required']); break; }
            $pdo->prepare("UPDATE alfred_quarantine SET status = 'released', released_at = NOW() WHERE agent_name = ? AND status = 'quarantined'")->execute([$agentName]);
            agent_panel_json(['ok'=>true,'msg'=>'Agent released from quarantine']);
        } else {
            $rows = $pdo->query("SELECT agent_name, reason, severity, status, quarantined_at, released_at, quarantined_by FROM alfred_quarantine ORDER BY quarantined_at DESC LIMIT 50")->fetchAll(PDO::FETCH_ASSOC);
            $active = count(array_filter($rows, function($r) { return $r['status'] === 'quarantined'; }));
            agent_panel_json(['ok'=>true, 'quarantined'=>$rows, 'active_count'=>$active, 'total'=>count($rows)]);
        }
        break;

    // ─── AGENT NOTEPAD ───
    case 'notepad_view':
        $sub = $input['sub'] ?? $_GET['sub'] ?? 'list';
        if ($sub === 'save') {
            $agentName = $input['agent_name'] ?? '';
            $title = $input['title'] ?? 'Untitled';
            $content = $input['content'] ?? '';
            if (!$agentName || !$content) { agent_panel_json(['error'=>'agent_name and content required']); break; }
            $stmt = $pdo->prepare("INSERT INTO alfred_notepad (agent_name, title, content, created_at, updated_at) VALUES (?, ?, ?, NOW(), NOW())");
            $stmt->execute([$agentName, $title, $content]);
            agent_panel_json(['ok'=>true,'msg'=>'Note saved','id'=>$pdo->lastInsertId()]);
        } elseif ($sub === 'delete') {
            $noteId = (int)($input['note_id'] ?? 0);
            if (!$noteId) { agent_panel_json(['error'=>'note_id required']); break; }
            $pdo->prepare("DELETE FROM alfred_notepad WHERE id = ?")->execute([$noteId]);
            agent_panel_json(['ok'=>true,'msg'=>'Note deleted']);
        } else {
            $agentFilter = $input['agent_name'] ?? $_GET['agent_name'] ?? '';
            if ($agentFilter) {
                $st = $pdo->prepare("SELECT id, agent_name, title, content, created_at, updated_at FROM alfred_notepad WHERE agent_name = ? ORDER BY updated_at DESC LIMIT 50");
                $st->execute([$agentFilter]);
            } else {
                $st = $pdo->query("SELECT id, agent_name, title, content, created_at, updated_at FROM alfred_notepad ORDER BY updated_at DESC LIMIT 100");
            }
            $notes = $st->fetchAll(PDO::FETCH_ASSOC);
            agent_panel_json(['ok'=>true, 'notes'=>$notes, 'total'=>count($notes)]);
        }
        break;

    // ─── FLEET SIGNAL INTELLIGENCE ───
    case 'signal_intel':
        // Comms volume by channel
        $channels = $pdo->query("SELECT channel, COUNT(*) as cnt, MAX(created_at) as last_msg FROM alfred_agent_comms GROUP BY channel ORDER BY cnt DESC")->fetchAll(PDO::FETCH_ASSOC);
        // Top communicators
        $top = $pdo->query("SELECT from_agent as agent, COUNT(*) as sent FROM alfred_agent_comms GROUP BY from_agent ORDER BY sent DESC LIMIT 10")->fetchAll(PDO::FETCH_ASSOC);
        // Recent volume (last 24h vs previous 24h)
        $recent = (int)$pdo->query("SELECT COUNT(*) FROM alfred_agent_comms WHERE created_at > DATE_SUB(NOW(), INTERVAL 24 HOUR)")->fetchColumn();
        $previous = (int)$pdo->query("SELECT COUNT(*) FROM alfred_agent_comms WHERE created_at BETWEEN DATE_SUB(NOW(), INTERVAL 48 HOUR) AND DATE_SUB(NOW(), INTERVAL 24 HOUR)")->fetchColumn();
        $trend = $previous > 0 ? round(($recent - $previous) / $previous * 100, 1) : 0;
        // Hourly distribution
        $hourly = $pdo->query("SELECT HOUR(created_at) as hr, COUNT(*) as cnt FROM alfred_agent_comms WHERE created_at > DATE_SUB(NOW(), INTERVAL 24 HOUR) GROUP BY hr ORDER BY hr")->fetchAll(PDO::FETCH_ASSOC);
        agent_panel_json(['ok'=>true, 'channels'=>$channels, 'top_senders'=>$top, 'volume_24h'=>$recent, 'volume_prev'=>$previous, 'trend'=>$trend, 'hourly'=>$hourly]);
        break;

    // ─── AGENT FITNESS REPORT ───
    case 'fitness_report':
        $agents = $pdo->query("SELECT DISTINCT name, status FROM alfred_agent_health ORDER BY name")->fetchAll(PDO::FETCH_ASSOC);
        $reports = [];
        foreach ($agents as $a) {
            $name = $a['name'];
            // Health score from heartbeats
            $hb = $pdo->prepare("SELECT COUNT(*) as total, SUM(status='healthy') as ok FROM alfred_heartbeat WHERE agent_name = ? AND created_at > DATE_SUB(NOW(), INTERVAL 24 HOUR)");
            $hb->execute([$name]);
            $hr = $hb->fetch(PDO::FETCH_ASSOC);
            $healthScore = $hr['total'] > 0 ? round($hr['ok'] / $hr['total'] * 100, 1) : 0;
            // Mission score
            $ms = $pdo->prepare("SELECT COUNT(*) as total, SUM(status='completed') as ok FROM alfred_agent_dispatches WHERE agent_name = ? AND created_at > DATE_SUB(NOW(), INTERVAL 7 DAY)");
            $ms->execute([$name]);
            $mr = $ms->fetch(PDO::FETCH_ASSOC);
            $missionScore = $mr['total'] > 0 ? round($mr['ok'] / $mr['total'] * 100, 1) : 50;
            // Error count
            $ec = $pdo->prepare("SELECT COUNT(*) FROM alfred_error_log WHERE agent_name = ? AND created_at > DATE_SUB(NOW(), INTERVAL 24 HOUR)");
            $ec->execute([$name]);
            $errors = (int)$ec->fetchColumn();
            // Training level
            $tr = $pdo->prepare("SELECT COUNT(*) FROM alfred_agent_training WHERE agent_name = ? AND status = 'completed'");
            $tr->execute([$name]);
            $training = (int)$tr->fetchColumn();
            // Composite fitness
            $fitness = round(($healthScore * 0.35) + ($missionScore * 0.35) + (max(0, 100 - $errors * 5) * 0.2) + (min(100, $training * 10) * 0.1), 1);
            $grade = $fitness >= 90 ? 'A' : ($fitness >= 75 ? 'B' : ($fitness >= 60 ? 'C' : ($fitness >= 40 ? 'D' : 'F')));
            $reports[] = ['name'=>$name, 'fitness'=>$fitness, 'grade'=>$grade, 'health'=>$healthScore, 'missions'=>$missionScore, 'errors_24h'=>$errors, 'training_completed'=>$training, 'status'=>$a['status']];
        }
        usort($reports, function($a, $b) { return $b['fitness'] <=> $a['fitness']; });
        agent_panel_json(['ok'=>true, 'reports'=>$reports]);
        break;

    // ─── MISSION AFTER-ACTION REVIEW ───
    case 'after_action_review':
        $rows = $pdo->query("SELECT id, mission_name, agent_name, outcome, summary, lessons_learned, recommendations, reviewed_by, created_at FROM alfred_after_action ORDER BY created_at DESC LIMIT 50")->fetchAll(PDO::FETCH_ASSOC);
        $outcomes = ['success'=>0,'partial'=>0,'failure'=>0];
        foreach ($rows as $r) {
            $o = strtolower($r['outcome'] ?? 'unknown');
            if (isset($outcomes[$o])) $outcomes[$o]++;
        }
        agent_panel_json(['ok'=>true, 'reviews'=>$rows, 'outcomes'=>$outcomes, 'total'=>count($rows)]);
        break;

    // ─── FLEET INVENTORY MANIFEST ───
    case 'inventory_manifest':
        // Agents by status
        $agentsByStatus = $pdo->query("SELECT status, COUNT(*) as cnt FROM alfred_agent_health GROUP BY status")->fetchAll(PDO::FETCH_ASSOC);
        // Total agents
        $totalAgents = (int)$pdo->query("SELECT COUNT(DISTINCT name) FROM alfred_agent_health")->fetchColumn();
        // Tools count
        $totalTools = (int)$pdo->query("SELECT COUNT(*) FROM alfred_capabilities")->fetchColumn();
        // SOPs
        $totalSops = (int)$pdo->query("SELECT COUNT(*) FROM alfred_agent_sops")->fetchColumn();
        // Formations
        $totalFormations = (int)$pdo->query("SELECT COUNT(*) FROM alfred_fleet_formations")->fetchColumn();
        // Active missions
        $activeMissions = (int)$pdo->query("SELECT COUNT(*) FROM alfred_agent_dispatches WHERE status IN ('pending','in_progress','active')")->fetchColumn();
        // Deployments
        $totalDeploys = (int)$pdo->query("SELECT COUNT(*) FROM alfred_deployments")->fetchColumn();
        // Resource pools
        $resources = $pdo->query("SELECT resource_type, SUM(quantity) as total FROM alfred_resource_pool GROUP BY resource_type")->fetchAll(PDO::FETCH_ASSOC);
        agent_panel_json(['ok'=>true, 'total_agents'=>$totalAgents, 'agents_by_status'=>$agentsByStatus, 'total_tools'=>$totalTools, 'total_sops'=>$totalSops, 'total_formations'=>$totalFormations, 'active_missions'=>$activeMissions, 'total_deployments'=>$totalDeploys, 'resources'=>$resources]);
        break;

    // ─── AGENT WATCHLIST ───
    case 'agent_watchlist':
        $sub = $input['sub'] ?? $_GET['sub'] ?? 'list';
        if ($sub === 'add') {
            $agentName = $input['agent_name'] ?? '';
            $reason = $input['reason'] ?? '';
            $severity = $input['severity'] ?? 'medium';
            if (!$agentName) { agent_panel_json(['error'=>'agent_name required']); break; }
            $pdo->prepare("INSERT INTO alfred_watchlist (agent_name, reason, severity, status, added_by, created_at) VALUES (?, ?, ?, 'active', 'commander', NOW())")->execute([$agentName, $reason, $severity]);
            agent_panel_json(['ok'=>true,'msg'=>'Agent added to watchlist']);
        } elseif ($sub === 'remove') {
            $agentName = $input['agent_name'] ?? '';
            if (!$agentName) { agent_panel_json(['error'=>'agent_name required']); break; }
            $pdo->prepare("UPDATE alfred_watchlist SET status = 'cleared', cleared_at = NOW() WHERE agent_name = ? AND status = 'active'")->execute([$agentName]);
            agent_panel_json(['ok'=>true,'msg'=>'Agent cleared from watchlist']);
        } else {
            $rows = $pdo->query("SELECT agent_name, reason, severity, status, added_by, created_at, cleared_at FROM alfred_watchlist ORDER BY FIELD(status,'active','cleared'), created_at DESC LIMIT 50")->fetchAll(PDO::FETCH_ASSOC);
            $active = count(array_filter($rows, function($r) { return $r['status'] === 'active'; }));
            agent_panel_json(['ok'=>true, 'watchlist'=>$rows, 'active_count'=>$active, 'total'=>count($rows)]);
        }
        break;

    // ─── FLEET COMPLIANCE TRACKER ───
    case 'compliance_tracker':
        $rows = $pdo->query("SELECT id, agent_name, check_type, status, details, score, checked_at FROM alfred_compliance_checks ORDER BY checked_at DESC LIMIT 100")->fetchAll(PDO::FETCH_ASSOC);
        $summary = ['pass'=>0,'fail'=>0,'warning'=>0];
        foreach ($rows as $r) {
            $s = strtolower($r['status'] ?? 'unknown');
            if (isset($summary[$s])) $summary[$s]++;
        }
        $byAgent = [];
        foreach ($rows as $r) {
            $byAgent[$r['agent_name']][] = $r;
        }
        $agents = [];
        foreach ($byAgent as $name => $checks) {
            $avgScore = count($checks) > 0 ? round(array_sum(array_column($checks,'score')) / count($checks), 1) : 0;
            $agents[] = ['name'=>$name, 'checks'=>count($checks), 'avg_score'=>$avgScore, 'latest'=>$checks[0]];
        }
        usort($agents, function($a,$b) { return $a['avg_score'] <=> $b['avg_score']; });
        agent_panel_json(['ok'=>true, 'checks'=>$rows, 'summary'=>$summary, 'agents'=>$agents, 'total'=>count($rows)]);
        break;

    // ─── AGENT VERSION REGISTRY ───
    case 'version_registry':
        $rows = $pdo->query("SELECT id, agent_name, version, previous_version, changelog, deployed_by, status, created_at FROM alfred_agent_versions ORDER BY created_at DESC LIMIT 100")->fetchAll(PDO::FETCH_ASSOC);
        $byAgent = [];
        foreach ($rows as $r) {
            $byAgent[$r['agent_name']][] = $r;
        }
        $registry = [];
        foreach ($byAgent as $name => $versions) {
            $registry[] = ['name'=>$name, 'current'=>$versions[0]['version']??'—', 'total_versions'=>count($versions), 'versions'=>array_slice($versions,0,10)];
        }
        usort($registry, function($a,$b) { return ($b['versions'][0]['created_at']??'') <=> ($a['versions'][0]['created_at']??''); });
        agent_panel_json(['ok'=>true, 'registry'=>$registry, 'total'=>count($rows)]);
        break;

    // ─── MISSION DEPENDENCY RESOLVER ───
    case 'dep_resolver':
        $chains = $pdo->query("SELECT mc.id as chain_id, mc.name as chain_name, mc.status as chain_status, cl.id as link_id, cl.mission_name, cl.agent_name, cl.status as link_status, cl.depends_on, cl.sort_order FROM alfred_mission_chains mc LEFT JOIN alfred_chain_links cl ON mc.id = cl.chain_id ORDER BY mc.id, cl.sort_order LIMIT 200")->fetchAll(PDO::FETCH_ASSOC);
        $grouped = [];
        foreach ($chains as $r) {
            $cid = $r['chain_id'];
            if (!isset($grouped[$cid])) $grouped[$cid] = ['id'=>$cid, 'name'=>$r['chain_name'], 'status'=>$r['chain_status'], 'links'=>[]];
            if ($r['link_id']) $grouped[$cid]['links'][] = ['id'=>(int)$r['link_id'], 'mission'=>$r['mission_name'], 'agent'=>$r['agent_name'], 'status'=>$r['link_status'], 'depends_on'=>$r['depends_on'], 'order'=>(int)$r['sort_order']];
        }
        $resolved = [];
        foreach ($grouped as $chain) {
            $total = count($chain['links']);
            $done = count(array_filter($chain['links'], function($l) { return $l['status']==='completed'; }));
            $blocked = count(array_filter($chain['links'], function($l) { return $l['status']==='blocked'; }));
            $chain['progress'] = $total > 0 ? round($done/$total*100,1) : 0;
            $chain['blocked_count'] = $blocked;
            $resolved[] = $chain;
        }
        agent_panel_json(['ok'=>true, 'chains'=>array_values($resolved), 'total_chains'=>count($resolved)]);
        break;

    // ─── FLEET ALERT DASHBOARD ───
    case 'alert_dashboard':
        // Active alerts from rules
        $rules = $pdo->query("SELECT id, name, condition_type, threshold, severity, status, agent_filter, action_type, created_at FROM alfred_alert_rules ORDER BY FIELD(severity,'critical','high','medium','low'), created_at DESC LIMIT 50")->fetchAll(PDO::FETCH_ASSOC);
        // Alert channels
        $channels = $pdo->query("SELECT id, name, channel_type, config, status, created_at FROM alfred_alert_channels ORDER BY name LIMIT 20")->fetchAll(PDO::FETCH_ASSOC);
        // Recent incidents triggered
        $recent = $pdo->query("SELECT agent_name, incident_type, severity, status, created_at, resolved_at FROM alfred_incident_response WHERE created_at > DATE_SUB(NOW(), INTERVAL 48 HOUR) ORDER BY created_at DESC LIMIT 20")->fetchAll(PDO::FETCH_ASSOC);
        $bySeverity = ['critical'=>0,'high'=>0,'medium'=>0,'low'=>0];
        foreach ($rules as $r) {
            $s = strtolower($r['severity']??'medium');
            if (isset($bySeverity[$s])) $bySeverity[$s]++;
        }
        agent_panel_json(['ok'=>true, 'rules'=>$rules, 'channels'=>$channels, 'recent_incidents'=>$recent, 'by_severity'=>$bySeverity, 'total_rules'=>count($rules)]);
        break;

    // ─── AGENT INCIDENT TIMELINE ───
    case 'incident_timeline':
        $rows = $pdo->query("SELECT id, agent_name, incident_type, severity, status, description, assigned_to, created_at, resolved_at, resolution_notes FROM alfred_incident_response ORDER BY created_at DESC LIMIT 100")->fetchAll(PDO::FETCH_ASSOC);
        $bySeverity = ['critical'=>0,'high'=>0,'medium'=>0,'low'=>0];
        $byStatus = ['open'=>0,'investigating'=>0,'resolved'=>0,'closed'=>0];
        foreach ($rows as $r) {
            $sev = strtolower($r['severity']??'medium');
            $st = strtolower($r['status']??'open');
            if (isset($bySeverity[$sev])) $bySeverity[$sev]++;
            if (isset($byStatus[$st])) $byStatus[$st]++;
        }
        // Average resolution time
        $resolved = array_filter($rows, function($r) { return $r['resolved_at'] && $r['created_at']; });
        $avgRes = 0;
        if (count($resolved) > 0) {
            $totalSec = 0;
            foreach ($resolved as $r) { $totalSec += strtotime($r['resolved_at']) - strtotime($r['created_at']); }
            $avgRes = round($totalSec / count($resolved) / 60, 1); // minutes
        }
        agent_panel_json(['ok'=>true, 'incidents'=>$rows, 'by_severity'=>$bySeverity, 'by_status'=>$byStatus, 'avg_resolution_min'=>$avgRes, 'total'=>count($rows)]);
        break;

    // ─── FLEET MISSION SCOREBOARD ───
    case 'mission_scoreboard':
        $agents = $pdo->query("SELECT DISTINCT agent_name FROM alfred_agent_dispatches ORDER BY agent_name")->fetchAll(PDO::FETCH_COLUMN);
        $scoreboard = [];
        foreach ($agents as $name) {
            $st = $pdo->prepare("SELECT COUNT(*) as total, SUM(status='completed') as wins, SUM(status='failed') as losses, AVG(TIMESTAMPDIFF(SECOND, created_at, COALESCE(completed_at, NOW()))) as avg_time FROM alfred_agent_dispatches WHERE agent_name = ?");
            $st->execute([$name]);
            $r = $st->fetch(PDO::FETCH_ASSOC);
            $total = (int)$r['total'];
            $wins = (int)$r['wins'];
            $losses = (int)$r['losses'];
            $winRate = $total > 0 ? round($wins / $total * 100, 1) : 0;
            $avgTime = round($r['avg_time'] ?? 0);
            // Reliability score: weighted formula
            $reliability = round(($winRate * 0.6) + (min(100, max(0, 100 - $losses * 10)) * 0.2) + (min(100, max(0, 100 - $avgTime / 60)) * 0.2), 1);
            $scoreboard[] = ['name'=>$name, 'total'=>$total, 'wins'=>$wins, 'losses'=>$losses, 'win_rate'=>$winRate, 'avg_time_sec'=>$avgTime, 'reliability'=>$reliability];
        }
        usort($scoreboard, function($a,$b) { return $b['reliability'] <=> $a['reliability']; });
        // Rank them
        foreach ($scoreboard as $i => &$s) { $s['rank'] = $i + 1; }
        agent_panel_json(['ok'=>true, 'scoreboard'=>$scoreboard, 'total_agents'=>count($scoreboard)]);
        break;

    // ─── AGENT COMMUNICATION HEATMAP ───
    case 'comm_heatmap_detail':
        $hourDay = $pdo->query("SELECT DAYOFWEEK(created_at) as dow, HOUR(created_at) as hr, COUNT(*) as cnt FROM alfred_agent_comms WHERE created_at > DATE_SUB(NOW(), INTERVAL 7 DAY) GROUP BY dow, hr ORDER BY dow, hr")->fetchAll(PDO::FETCH_ASSOC);
        // Build 7x24 matrix
        $matrix = [];
        for ($d = 1; $d <= 7; $d++) { for ($h = 0; $h < 24; $h++) { $matrix[$d][$h] = 0; } }
        $maxVal = 1;
        foreach ($hourDay as $r) { $matrix[(int)$r['dow']][(int)$r['hr']] = (int)$r['cnt']; if ((int)$r['cnt'] > $maxVal) $maxVal = (int)$r['cnt']; }
        // Top pairs
        $pairs = $pdo->query("SELECT from_agent, to_agent, COUNT(*) as cnt FROM alfred_agent_comms WHERE created_at > DATE_SUB(NOW(), INTERVAL 7 DAY) GROUP BY from_agent, to_agent ORDER BY cnt DESC LIMIT 10")->fetchAll(PDO::FETCH_ASSOC);
        $total = (int)$pdo->query("SELECT COUNT(*) FROM alfred_agent_comms WHERE created_at > DATE_SUB(NOW(), INTERVAL 7 DAY)")->fetchColumn();
        agent_panel_json(['ok'=>true, 'matrix'=>$matrix, 'max_val'=>$maxVal, 'top_pairs'=>$pairs, 'total_7d'=>$total]);
        break;

    // ─── FLEET EMERGENCY BEACON ───
    case 'emergency_beacon':
        $sub = $input['sub'] ?? $_GET['sub'] ?? 'list';
        if ($sub === 'send') {
            $message = $input['message'] ?? '';
            $severity = $input['severity'] ?? 'critical';
            $sender = $input['sender'] ?? 'commander';
            if (!$message) { agent_panel_json(['error'=>'Message required']); break; }
            $pdo->prepare("INSERT INTO alfred_emergency_beacons (message, severity, sender, status, created_at) VALUES (?, ?, ?, 'active', NOW())")->execute([$message, $severity, $sender]);
            agent_panel_json(['ok'=>true, 'msg'=>'EMERGENCY BEACON ACTIVATED', 'id'=>$pdo->lastInsertId()]);
        } elseif ($sub === 'acknowledge') {
            $beaconId = (int)($input['beacon_id'] ?? 0);
            if (!$beaconId) { agent_panel_json(['error'=>'beacon_id required']); break; }
            $pdo->prepare("UPDATE alfred_emergency_beacons SET status = 'acknowledged', acknowledged_at = NOW() WHERE id = ?")->execute([$beaconId]);
            agent_panel_json(['ok'=>true, 'msg'=>'Beacon acknowledged']);
        } elseif ($sub === 'resolve') {
            $beaconId = (int)($input['beacon_id'] ?? 0);
            if (!$beaconId) { agent_panel_json(['error'=>'beacon_id required']); break; }
            $pdo->prepare("UPDATE alfred_emergency_beacons SET status = 'resolved', resolved_at = NOW() WHERE id = ?")->execute([$beaconId]);
            agent_panel_json(['ok'=>true, 'msg'=>'Beacon resolved']);
        } else {
            $rows = $pdo->query("SELECT id, message, severity, sender, status, created_at, acknowledged_at, resolved_at FROM alfred_emergency_beacons ORDER BY FIELD(status,'active','acknowledged','resolved'), created_at DESC LIMIT 50")->fetchAll(PDO::FETCH_ASSOC);
            $active = count(array_filter($rows, function($r) { return $r['status'] === 'active'; }));
            agent_panel_json(['ok'=>true, 'beacons'=>$rows, 'active_count'=>$active, 'total'=>count($rows)]);
        }
        break;

    // ─── AGENT KNOWLEDGE GRAPH ───
    case 'knowledge_graph':
        // Knowledge entries per agent
        $entries = $pdo->query("SELECT agent_name, category, COUNT(*) as cnt FROM alfred_agent_knowledge GROUP BY agent_name, category ORDER BY cnt DESC LIMIT 100")->fetchAll(PDO::FETCH_ASSOC);
        // Build graph: nodes = agents, edges = shared categories
        $agentCats = [];
        foreach ($entries as $e) {
            $agentCats[$e['agent_name']][] = $e['category'];
        }
        $nodes = [];
        foreach ($agentCats as $name => $cats) {
            $nodes[] = ['name'=>$name, 'categories'=>array_unique($cats), 'count'=>count($cats)];
        }
        // Find connections (agents sharing categories)
        $edges = [];
        $names = array_keys($agentCats);
        for ($i = 0; $i < count($names); $i++) {
            for ($j = $i + 1; $j < count($names); $j++) {
                $shared = array_intersect($agentCats[$names[$i]], $agentCats[$names[$j]]);
                if (count($shared) > 0) {
                    $edges[] = ['from'=>$names[$i], 'to'=>$names[$j], 'shared'=>array_values($shared), 'weight'=>count($shared)];
                }
            }
        }
        // Top categories
        $topCats = $pdo->query("SELECT category, COUNT(*) as cnt FROM alfred_agent_knowledge GROUP BY category ORDER BY cnt DESC LIMIT 15")->fetchAll(PDO::FETCH_ASSOC);
        agent_panel_json(['ok'=>true, 'nodes'=>$nodes, 'edges'=>$edges, 'top_categories'=>$topCats, 'total_entries'=>array_sum(array_column($entries,'cnt'))]);
        break;

    // ─── MISSION OPERATIONS LOG ───
    case 'ops_log':
        $limit = min(200, (int)($input['limit'] ?? $_GET['limit'] ?? 50));
        // Aggregate recent activity from multiple tables
        $logs = [];
        // Dispatches
        $st = $pdo->query("SELECT 'mission' as type, agent_name, status, mission_type as detail, created_at FROM alfred_agent_dispatches ORDER BY created_at DESC LIMIT " . (int)$limit);
        foreach ($st as $r) $logs[] = $r;
        // Comms
        $st = $pdo->query("SELECT 'comm' as type, from_agent as agent_name, 'sent' as status, channel as detail, created_at FROM alfred_agent_comms ORDER BY created_at DESC LIMIT " . (int)($limit / 2));
        foreach ($st as $r) $logs[] = $r;
        // Deployments
        $st = $pdo->query("SELECT 'deploy' as type, agent_name, status, version as detail, created_at FROM alfred_deployments ORDER BY created_at DESC LIMIT " . (int)($limit / 2));
        foreach ($st as $r) $logs[] = $r;
        // Incidents
        $st = $pdo->query("SELECT 'incident' as type, agent_name, status, incident_type as detail, created_at FROM alfred_incident_response ORDER BY created_at DESC LIMIT " . (int)($limit / 2));
        foreach ($st as $r) $logs[] = $r;
        // Errors
        $st = $pdo->query("SELECT 'error' as type, agent_name, 'error' as status, error_type as detail, created_at FROM alfred_error_log ORDER BY created_at DESC LIMIT " . (int)($limit / 2));
        foreach ($st as $r) $logs[] = $r;
        // Sort all by time descending
        usort($logs, function($a,$b) { return ($b['created_at']??'') <=> ($a['created_at']??''); });
        $logs = array_slice($logs, 0, $limit);
        agent_panel_json(['ok'=>true, 'logs'=>$logs, 'total'=>count($logs)]);
        break;

    // ═══════════════════════════════════════════════════════════
    // BATCH 16 — Systems 76-80
    // ═══════════════════════════════════════════════════════════

    case 'resource_monitor':
        // Fleet Resource Monitor — aggregate heartbeat metrics per agent
        $rows = $pdo->query("SELECT agent_name,
            ROUND(AVG(CAST(JSON_EXTRACT(metrics,'$.cpu') AS DECIMAL(5,2))),1) AS avg_cpu,
            ROUND(AVG(CAST(JSON_EXTRACT(metrics,'$.memory') AS DECIMAL(5,2))),1) AS avg_mem,
            ROUND(AVG(CAST(JSON_EXTRACT(metrics,'$.disk') AS DECIMAL(5,2))),1) AS avg_disk,
            MAX(CAST(JSON_EXTRACT(metrics,'$.cpu') AS DECIMAL(5,2))) AS peak_cpu,
            MAX(CAST(JSON_EXTRACT(metrics,'$.memory') AS DECIMAL(5,2))) AS peak_mem,
            COUNT(*) AS samples,
            MAX(created_at) AS last_seen
            FROM alfred_heartbeat
            WHERE created_at >= DATE_SUB(NOW(), INTERVAL 24 HOUR)
            GROUP BY agent_name ORDER BY avg_cpu DESC")->fetchAll();
        agent_panel_json(['success'=>true,'data'=>$rows]);
        break;

    case 'collab_score':
        // Agent Collaboration Score — measures inter-agent cooperation
        $pairs = $pdo->query("SELECT from_agent, to_agent, COUNT(*) AS msgs
            FROM alfred_agent_comms
            WHERE created_at >= DATE_SUB(NOW(), INTERVAL 30 DAY)
            GROUP BY from_agent, to_agent ORDER BY msgs DESC LIMIT 30")->fetchAll();
        // Calculate per-agent collab score based on unique partners + message volume
        $agents = [];
        foreach ($pairs as $p) {
            $f = $p['from_agent']; $t = $p['to_agent'];
            if (!isset($agents[$f])) $agents[$f] = ['partners'=>[],'total'=>0];
            if (!isset($agents[$t])) $agents[$t] = ['partners'=>[],'total'=>0];
            $agents[$f]['partners'][$t] = ($agents[$f]['partners'][$t] ?? 0) + (int)$p['msgs'];
            $agents[$f]['total'] += (int)$p['msgs'];
            $agents[$t]['partners'][$f] = ($agents[$t]['partners'][$f] ?? 0) + (int)$p['msgs'];
            $agents[$t]['total'] += (int)$p['msgs'];
        }
        $scores = [];
        foreach ($agents as $name => $info) {
            $partnerCount = count($info['partners']);
            $score = min(100, ($partnerCount * 15) + min(50, $info['total'] / 2));
            $scores[] = ['agent'=>$name, 'partners'=>$partnerCount, 'messages'=>$info['total'], 'score'=>round($score,1)];
        }
        usort($scores, fn($a,$b) => $b['score'] <=> $a['score']);
        agent_panel_json(['success'=>true,'data'=>['scores'=>$scores,'pairs'=>$pairs]]);
        break;

    case 'priority_viz':
        // Mission Priority Queue Visualizer — ordered by priority then created_at
        $rows = $pdo->query("SELECT id, title, description, agent_assigned AS agent, priority, status, created_at
            FROM alfred_agent_tasks
            WHERE status IN ('pending','in_progress','queued')
            ORDER BY
                CASE priority WHEN 'critical' THEN 0 WHEN 'high' THEN 1 WHEN 'medium' THEN 2 WHEN 'low' THEN 3 ELSE 4 END,
                created_at ASC
            LIMIT 50")->fetchAll();
        $counts = $pdo->query("SELECT priority, COUNT(*) AS cnt FROM alfred_agent_tasks
            WHERE status IN ('pending','in_progress','queued') GROUP BY priority")->fetchAll();
        agent_panel_json(['success'=>true,'data'=>['queue'=>$rows,'counts'=>$counts]]);
        break;

    case 'geo_distribution':
        // Fleet Geo Distribution — agent locations
        $rows = $pdo->query("SELECT agent_name, location, region, status, last_updated
            FROM alfred_agent_locations
            ORDER BY region, agent_name")->fetchAll();
        // Group by region
        $regions = [];
        foreach ($rows as $r) {
            $reg = $r['region'] ?: 'Unknown';
            if (!isset($regions[$reg])) $regions[$reg] = [];
            $regions[$reg][] = $r;
        }
        agent_panel_json(['success'=>true,'data'=>['agents'=>$rows,'regions'=>$regions,'total'=>count($rows)]]);
        break;

    case 'skill_matrix':
        // Agent Skill Matrix — skill coverage heatmap
        $rows = $pdo->query("SELECT agent_name, skill_name, level, xp
            FROM alfred_skill_tree
            ORDER BY agent_name, skill_name")->fetchAll();
        $agents = []; $allSkills = [];
        foreach ($rows as $r) {
            $a = $r['agent_name']; $s = $r['skill_name'];
            if (!isset($agents[$a])) $agents[$a] = [];
            $agents[$a][$s] = ['level'=>(int)$r['level'],'xp'=>(int)$r['xp']];
            $allSkills[$s] = true;
        }
        $allSkills = array_keys($allSkills);
        sort($allSkills);
        $matrix = [];
        foreach ($agents as $name => $skills) {
            $row = ['agent'=>$name,'skills'=>[]];
            foreach ($allSkills as $sk) {
                $row['skills'][$sk] = $skills[$sk] ?? ['level'=>0,'xp'=>0];
            }
            $matrix[] = $row;
        }
        agent_panel_json(['success'=>true,'data'=>['matrix'=>$matrix,'skills'=>$allSkills,'agent_count'=>count($agents)]]);
        break;

    // ═══════════════════════════════════════════════════════════
    // BATCH 17 — Systems 81-85
    // ═══════════════════════════════════════════════════════════

    case 'audit_trail':
        // Fleet Audit Trail — comprehensive audit log with filters
        $filter = $_GET['filter'] ?? '';
        $agent = $_GET['agent'] ?? '';
        $limit = min((int)($_GET['limit'] ?? 100), 500);
        $where = '1=1';
        $params = [];
        if ($agent) { $where .= ' AND agent_name = ?'; $params[] = $agent; }
        if ($filter) { $where .= ' AND (action LIKE ? OR details LIKE ?)'; $params[] = "%$filter%"; $params[] = "%$filter%"; }
        $stmt = $pdo->prepare("SELECT id, agent_name, action, details, ip_address, created_at
            FROM alfred_audit_log WHERE $where ORDER BY created_at DESC LIMIT $limit");
        $stmt->execute($params);
        $rows = $stmt->fetchAll();
        $stats = $pdo->query("SELECT COUNT(*) AS total, COUNT(DISTINCT agent_name) AS agents,
            DATE(MIN(created_at)) AS earliest, DATE(MAX(created_at)) AS latest
            FROM alfred_audit_log")->fetch();
        agent_panel_json(['success'=>true,'data'=>['entries'=>$rows,'stats'=>$stats]]);
        break;

    case 'emotion_engine':
        // Agent Emotion Engine — sentiment from journal entries
        $rows = $pdo->query("SELECT agent_name,
            SUM(CASE WHEN mood IN ('happy','excited','confident','proud') THEN 1 ELSE 0 END) AS positive,
            SUM(CASE WHEN mood IN ('neutral','calm','focused') THEN 1 ELSE 0 END) AS neutral_mood,
            SUM(CASE WHEN mood IN ('frustrated','angry','sad','anxious','confused') THEN 1 ELSE 0 END) AS negative,
            COUNT(*) AS total,
            MAX(created_at) AS last_entry
            FROM alfred_agent_journal
            WHERE created_at >= DATE_SUB(NOW(), INTERVAL 30 DAY)
            GROUP BY agent_name ORDER BY positive DESC")->fetchAll();
        $result = [];
        foreach ($rows as $r) {
            $total = (int)$r['total'] ?: 1;
            $sentiment = round(((int)$r['positive'] - (int)$r['negative']) / $total * 100, 1);
            $result[] = [
                'agent' => $r['agent_name'],
                'positive' => (int)$r['positive'],
                'neutral' => (int)$r['neutral_mood'],
                'negative' => (int)$r['negative'],
                'total' => $total,
                'sentiment' => $sentiment,
                'last_entry' => $r['last_entry']
            ];
        }
        agent_panel_json(['success'=>true,'data'=>$result]);
        break;

    case 'chain_viz':
        // Mission Chain Visualizer — chain link progression
        $chains = $pdo->query("SELECT c.id, c.name, c.description, c.status, c.created_at,
            COUNT(l.id) AS link_count,
            SUM(CASE WHEN l.status='completed' THEN 1 ELSE 0 END) AS completed_links
            FROM alfred_mission_chains c
            LEFT JOIN alfred_chain_links l ON l.chain_id = c.id
            GROUP BY c.id ORDER BY c.created_at DESC LIMIT 20")->fetchAll();
        // Get links for each chain
        $chainIds = array_column($chains, 'id');
        $links = [];
        if ($chainIds) {
            $placeholders = implode(',', array_fill(0, count($chainIds), '?'));
            $stmt = $pdo->prepare("SELECT id, chain_id, title, status, seq_order, agent_assigned
                FROM alfred_chain_links WHERE chain_id IN ($placeholders) ORDER BY chain_id, seq_order");
            $stmt->execute($chainIds);
            foreach ($stmt->fetchAll() as $lk) {
                $links[$lk['chain_id']][] = $lk;
            }
        }
        foreach ($chains as &$ch) { $ch['links'] = $links[$ch['id']] ?? []; }
        agent_panel_json(['success'=>true,'data'=>$chains]);
        break;

    case 'bandwidth_history':
        // Fleet Bandwidth History — usage trends grouped by day
        $rows = $pdo->query("SELECT DATE(recorded_at) AS day,
            SUM(bytes_in) AS total_in, SUM(bytes_out) AS total_out,
            COUNT(DISTINCT agent_name) AS agents
            FROM alfred_bandwidth_log
            WHERE recorded_at >= DATE_SUB(NOW(), INTERVAL 30 DAY)
            GROUP BY DATE(recorded_at) ORDER BY day DESC")->fetchAll();
        // Top consumers
        $top = $pdo->query("SELECT agent_name,
            SUM(bytes_in) AS total_in, SUM(bytes_out) AS total_out,
            SUM(bytes_in + bytes_out) AS combined
            FROM alfred_bandwidth_log
            WHERE recorded_at >= DATE_SUB(NOW(), INTERVAL 7 DAY)
            GROUP BY agent_name ORDER BY combined DESC LIMIT 10")->fetchAll();
        agent_panel_json(['success'=>true,'data'=>['daily'=>$rows,'top_consumers'=>$top]]);
        break;

    case 'reputation_board':
        // Agent Reputation Leaderboard — rankings with history
        $rows = $pdo->query("SELECT r.agent_name, r.score, r.level, r.updated_at,
            (SELECT COUNT(*) FROM alfred_reputation r2 WHERE r2.score > r.score) + 1 AS ranking
            FROM alfred_reputation r ORDER BY r.score DESC LIMIT 30")->fetchAll();
        // Recent changes
        $changes = $pdo->query("SELECT agent_name,
            JSON_EXTRACT(metadata,'$.reason') AS reason,
            JSON_EXTRACT(metadata,'$.delta') AS delta,
            updated_at
            FROM alfred_reputation
            WHERE updated_at >= DATE_SUB(NOW(), INTERVAL 7 DAY)
            ORDER BY updated_at DESC LIMIT 20")->fetchAll();
        agent_panel_json(['success'=>true,'data'=>['rankings'=>$rows,'changes'=>$changes]]);
        break;

    // ═══════════════════════════════════════════════════════════
    // BATCH 18 — Systems 86-90
    // ═══════════════════════════════════════════════════════════

    case 'heartbeat_timeline':
        // Fleet Heartbeat Timeline — recent heartbeats as timeline
        $limit = min((int)($_GET['limit'] ?? 100), 500);
        $rows = $pdo->query("SELECT agent_name, status, latency_ms,
            JSON_EXTRACT(metrics,'$.cpu') AS cpu,
            JSON_EXTRACT(metrics,'$.memory') AS memory,
            created_at
            FROM alfred_heartbeat
            ORDER BY created_at DESC LIMIT $limit")->fetchAll();
        // Group by 10-minute intervals
        $intervals = [];
        foreach ($rows as $r) {
            $key = substr($r['created_at'], 0, 15) . '0'; // round to 10min
            if (!isset($intervals[$key])) $intervals[$key] = ['time'=>$key,'count'=>0,'agents'=>[],'avg_latency'=>0];
            $intervals[$key]['count']++;
            $intervals[$key]['agents'][] = $r['agent_name'];
            $intervals[$key]['avg_latency'] += (float)($r['latency_ms'] ?? 0);
        }
        foreach ($intervals as &$iv) {
            $iv['avg_latency'] = $iv['count'] > 0 ? round($iv['avg_latency'] / $iv['count'], 1) : 0;
            $iv['unique_agents'] = count(array_unique($iv['agents']));
            unset($iv['agents']);
        }
        agent_panel_json(['success'=>true,'data'=>['events'=>$rows,'intervals'=>array_values($intervals)]]);
        break;

    case 'permission_matrix':
        // Agent Permission Matrix — permissions per agent
        $rows = $pdo->query("SELECT agent_name, permission, granted, granted_by, created_at
            FROM alfred_permissions ORDER BY agent_name, permission")->fetchAll();
        $agents = [];
        $allPerms = [];
        foreach ($rows as $r) {
            $a = $r['agent_name']; $p = $r['permission'];
            if (!isset($agents[$a])) $agents[$a] = [];
            $agents[$a][$p] = (bool)$r['granted'];
            $allPerms[$p] = true;
        }
        $allPerms = array_keys($allPerms);
        sort($allPerms);
        $matrix = [];
        foreach ($agents as $name => $perms) {
            $row = ['agent'=>$name,'permissions'=>[]];
            foreach ($allPerms as $p) $row['permissions'][$p] = $perms[$p] ?? false;
            $matrix[] = $row;
        }
        agent_panel_json(['success'=>true,'data'=>['matrix'=>$matrix,'permissions'=>$allPerms,'agent_count'=>count($agents)]]);
        break;

    case 'template_gallery':
        // Mission Template Gallery — browse templates
        $rows = $pdo->query("SELECT id, name, description, category, parameters, created_by, created_at,
            (SELECT COUNT(*) FROM alfred_agent_dispatches WHERE JSON_EXTRACT(parameters,'$.template_id') = alfred_mission_templates.id) AS usage_count
            FROM alfred_mission_templates ORDER BY created_at DESC LIMIT 50")->fetchAll();
        $cats = $pdo->query("SELECT DISTINCT category FROM alfred_mission_templates ORDER BY category")->fetchAll(PDO::FETCH_COLUMN);
        agent_panel_json(['success'=>true,'data'=>['templates'=>$rows,'categories'=>$cats]]);
        break;

    case 'config_drift':
        // Fleet Config Drift Detector — compare config snapshots
        $latest = $pdo->query("SELECT cs1.agent_name, cs1.config_data AS current_config, cs1.created_at AS current_time,
            (SELECT cs2.config_data FROM alfred_config_snapshots cs2
             WHERE cs2.agent_name = cs1.agent_name AND cs2.id < cs1.id
             ORDER BY cs2.id DESC LIMIT 1) AS prev_config
            FROM alfred_config_snapshots cs1
            INNER JOIN (SELECT agent_name, MAX(id) AS max_id FROM alfred_config_snapshots GROUP BY agent_name) latest
            ON cs1.agent_name = latest.agent_name AND cs1.id = latest.max_id
            ORDER BY cs1.agent_name")->fetchAll();
        $drifts = [];
        foreach ($latest as $row) {
            $current = json_decode($row['current_config'] ?? '{}', true) ?: [];
            $prev = json_decode($row['prev_config'] ?? '{}', true) ?: [];
            $changes = [];
            foreach ($current as $k => $v) {
                if (!isset($prev[$k])) $changes[] = ['key'=>$k,'type'=>'added','new'=>$v];
                elseif ($prev[$k] !== $v) $changes[] = ['key'=>$k,'type'=>'changed','old'=>$prev[$k],'new'=>$v];
            }
            foreach ($prev as $k => $v) {
                if (!isset($current[$k])) $changes[] = ['key'=>$k,'type'=>'removed','old'=>$v];
            }
            if ($changes) $drifts[] = ['agent'=>$row['agent_name'],'changes'=>$changes,'snapshot_time'=>$row['current_time']];
        }
        agent_panel_json(['success'=>true,'data'=>['drifts'=>$drifts,'total_agents'=>count($latest),'drifted'=>count($drifts)]]);
        break;

    case 'relationship_web':
        // Agent Relationship Web — relationship mapping
        $rows = $pdo->query("SELECT agent_a, agent_b, relation_type, strength, notes, created_at
            FROM alfred_agent_relations ORDER BY strength DESC LIMIT 100")->fetchAll();
        // Build node list
        $nodes = [];
        foreach ($rows as $r) {
            $nodes[$r['agent_a']] = true;
            $nodes[$r['agent_b']] = true;
        }
        $nodeList = array_keys($nodes);
        // Type distribution
        $types = $pdo->query("SELECT relation_type, COUNT(*) AS cnt FROM alfred_agent_relations GROUP BY relation_type ORDER BY cnt DESC")->fetchAll();
        agent_panel_json(['success'=>true,'data'=>['relationships'=>$rows,'nodes'=>$nodeList,'types'=>$types]]);
        break;

    // ═══════════════════════════════════════════════════════════
    // BATCH 19 — Systems 91-95
    // ═══════════════════════════════════════════════════════════

    case 'uptime_calendar':
        // Fleet Uptime Calendar — daily uptime percentages for last 30 days
        $rows = $pdo->query("SELECT DATE(created_at) AS day,
            COUNT(DISTINCT agent_name) AS agents_seen,
            SUM(CASE WHEN status='healthy' THEN 1 ELSE 0 END) AS healthy,
            COUNT(*) AS total
            FROM alfred_heartbeat
            WHERE created_at >= DATE_SUB(NOW(), INTERVAL 30 DAY)
            GROUP BY DATE(created_at) ORDER BY day DESC")->fetchAll();
        $calendar = [];
        foreach ($rows as $r) {
            $pct = $r['total'] > 0 ? round($r['healthy'] / $r['total'] * 100, 1) : 0;
            $calendar[] = ['day'=>$r['day'],'uptime'=>$pct,'agents'=>(int)$r['agents_seen'],'checks'=>(int)$r['total']];
        }
        agent_panel_json(['success'=>true,'data'=>$calendar]);
        break;

    case 'training_progress':
        // Agent Training Progress — completion status
        $rows = $pdo->query("SELECT agent_name, module, status, score, completed_at, created_at
            FROM alfred_agent_training
            ORDER BY created_at DESC LIMIT 100")->fetchAll();
        $summary = $pdo->query("SELECT agent_name,
            COUNT(*) AS total_modules,
            SUM(CASE WHEN status='completed' THEN 1 ELSE 0 END) AS completed,
            ROUND(AVG(CASE WHEN score IS NOT NULL THEN score END),1) AS avg_score
            FROM alfred_agent_training GROUP BY agent_name ORDER BY completed DESC")->fetchAll();
        agent_panel_json(['success'=>true,'data'=>['entries'=>$rows,'summary'=>$summary]]);
        break;

    case 'risk_heatmap':
        // Mission Risk Heatmap — risk per active mission
        $rows = $pdo->query("SELECT d.id, d.mission_type, d.agent_name, d.status, d.priority, d.created_at,
            CASE d.priority WHEN 'critical' THEN 90 WHEN 'high' THEN 70 WHEN 'medium' THEN 40 ELSE 20 END AS base_risk,
            TIMESTAMPDIFF(HOUR, d.created_at, NOW()) AS age_hours
            FROM alfred_agent_dispatches d
            WHERE d.status IN ('active','in_progress','dispatched')
            ORDER BY base_risk DESC LIMIT 50")->fetchAll();
        foreach ($rows as &$r) {
            $ageBonus = min(30, floor((int)$r['age_hours'] / 6) * 5);
            $r['risk_score'] = min(100, (int)$r['base_risk'] + $ageBonus);
        }
        agent_panel_json(['success'=>true,'data'=>$rows]);
        break;

    case 'command_history':
        // Fleet Command History — decision trail
        $limit = min((int)($_GET['limit'] ?? 50), 200);
        $rows = $pdo->query("SELECT id, decision_type, description, made_by, context, outcome, created_at
            FROM alfred_decisions ORDER BY created_at DESC LIMIT $limit")->fetchAll();
        $stats = $pdo->query("SELECT COUNT(*) AS total, COUNT(DISTINCT made_by) AS commanders,
            COUNT(DISTINCT decision_type) AS types FROM alfred_decisions")->fetch();
        agent_panel_json(['success'=>true,'data'=>['decisions'=>$rows,'stats'=>$stats]]);
        break;

    case 'capability_radar':
        // Agent Capability Radar — capability dimensions per agent
        $agent = $_GET['agent'] ?? '';
        if ($agent) {
            $stmt = $pdo->prepare("SELECT capability, level FROM alfred_capabilities WHERE agent_name = ? ORDER BY capability");
            $stmt->execute([$agent]);
            $caps = $stmt->fetchAll();
        } else {
            $caps = $pdo->query("SELECT agent_name, capability, level FROM alfred_capabilities ORDER BY agent_name, capability")->fetchAll();
        }
        $agents = [];
        foreach ($caps as $c) {
            $a = $c['agent_name'] ?? $agent;
            if (!isset($agents[$a])) $agents[$a] = [];
            $agents[$a][$c['capability']] = (int)$c['level'];
        }
        agent_panel_json(['success'=>true,'data'=>$agents]);
