    case 'alert_digest':
        // Fleet Alert Digest — grouped alerts summary
        $rows = $pdo->query("SELECT severity, channel, alert_type, COUNT(*) AS cnt,
            MAX(created_at) AS latest, MIN(created_at) AS earliest
            FROM alfred_alert_channels
            GROUP BY severity, channel, alert_type
            ORDER BY FIELD(severity,'critical','high','medium','low','info'), cnt DESC")->fetchAll();
        $recent = $pdo->query("SELECT id, severity, channel, alert_type, message, acknowledged, created_at
            FROM alfred_alert_channels ORDER BY created_at DESC LIMIT 30")->fetchAll();
        $stats = $pdo->query("SELECT COUNT(*) AS total,
            SUM(CASE WHEN severity='critical' THEN 1 ELSE 0 END) AS critical,
            SUM(CASE WHEN severity='high' THEN 1 ELSE 0 END) AS high,
            SUM(CASE WHEN acknowledged=0 THEN 1 ELSE 0 END) AS unacked
            FROM alfred_alert_channels")->fetch();
        agent_panel_json(['success'=>true,'data'=>['groups'=>$rows,'recent'=>$recent,'stats'=>$stats]]);
        break;

    case 'workflow_engine':
        // Agent Workflow Engine — pipeline status
        $rows = $pdo->query("SELECT id, pipeline_name, agent_name, status, stage, total_stages,
            started_at, completed_at, created_at
            FROM alfred_deploy_pipelines ORDER BY created_at DESC LIMIT 50")->fetchAll();
        foreach ($rows as &$r) {
            $r['progress'] = $r['total_stages'] > 0 ? round($r['stage'] / $r['total_stages'] * 100) : 0;
        }
        $byStatus = $pdo->query("SELECT status, COUNT(*) AS cnt FROM alfred_deploy_pipelines GROUP BY status ORDER BY cnt DESC")->fetchAll();
        agent_panel_json(['success'=>true,'data'=>['pipelines'=>$rows,'by_status'=>$byStatus]]);
