        }
        $latest = $pdo->query("SELECT agent_name, version, created_at FROM alfred_agent_versions
            WHERE (agent_name, created_at) IN (SELECT agent_name, MAX(created_at) FROM alfred_agent_versions GROUP BY agent_name)
            ORDER BY agent_name")->fetchAll();
