    case 'service_mesh':
        // Fleet Service Mesh — inter-service connections
        $comms = $pdo->query("SELECT from_agent, to_agent, channel, COUNT(*) AS msg_count,
            MAX(created_at) AS last_msg
            FROM alfred_agent_comms
            WHERE created_at >= DATE_SUB(NOW(), INTERVAL 24 HOUR)
            GROUP BY from_agent, to_agent, channel
            ORDER BY msg_count DESC LIMIT 100")->fetchAll();
        $nodes = [];
        foreach ($comms as $c) {
            $nodes[$c['from_agent']] = true;
            $nodes[$c['to_agent']] = true;
        }
        $health = $pdo->query("SELECT agent_name, status, MAX(created_at) AS last_hb
            FROM alfred_heartbeat
            WHERE created_at >= DATE_SUB(NOW(), INTERVAL 1 HOUR)
