    case 'loyalty_index':
        // Agent Loyalty Index — uptime + reliability scoring
        $rows = $pdo->query("SELECT agent_name,
            COUNT(*) AS total_beats,
            SUM(CASE WHEN status='healthy' THEN 1 ELSE 0 END) AS healthy_beats,
            ROUND(SUM(CASE WHEN status='healthy' THEN 1 ELSE 0 END) / COUNT(*) * 100, 1) AS reliability,
            DATEDIFF(NOW(), MIN(created_at)) AS days_active,
            MAX(created_at) AS last_seen
            FROM alfred_heartbeat
            GROUP BY agent_name
            ORDER BY reliability DESC, total_beats DESC")->fetchAll();
        foreach ($rows as &$r) {
