            SUM(CASE WHEN status='completed' THEN 1 ELSE 0 END) AS completed,
            SUM(CASE WHEN status='failed' THEN 1 ELSE 0 END) AS failed
            FROM alfred_agent_dispatches
            GROUP BY mission_type ORDER BY missions DESC LIMIT 30")->fetchAll();
        foreach ($rows as &$r) {
            $r['success_rate'] = $r['missions'] > 0 ? round($r['completed'] / $r['missions'] * 100, 1) : 0;
            $r['cost_index'] = round($r['avg_duration_min'] * (1 + ($r['failed'] * 0.5)), 1);
        }
        agent_panel_json(['success'=>true,'data'=>$rows]);
