    case 'compliance_dash':
        // Fleet Compliance Dashboard — compliance check results
        $rows = $pdo->query("SELECT agent_name, check_type, status, details, checked_at
            FROM alfred_compliance_checks
            ORDER BY checked_at DESC LIMIT 100")->fetchAll();
        $summary = $pdo->query("SELECT agent_name,
            COUNT(*) AS total_checks,
            SUM(CASE WHEN status='pass' THEN 1 ELSE 0 END) AS passed,
            SUM(CASE WHEN status='fail' THEN 1 ELSE 0 END) AS failed
            FROM alfred_compliance_checks GROUP BY agent_name ORDER BY failed DESC")->fetchAll();
        agent_panel_json(['success'=>true,'data'=>['checks'=>$rows,'summary'=>$summary]]);
