    case 'heartbeat_anomaly':
        // Agent Heartbeat Anomaly Detector — detect unusual patterns
        $rows = $pdo->query("SELECT agent_name,
            ROUND(AVG(cpu_percent),1) AS avg_cpu,
            ROUND(STDDEV(cpu_percent),1) AS std_cpu,
            ROUND(AVG(mem_percent),1) AS avg_mem,
            ROUND(STDDEV(mem_percent),1) AS std_mem,
            COUNT(*) AS samples,
            MAX(created_at) AS last_seen
            FROM alfred_heartbeat
            WHERE created_at >= DATE_SUB(NOW(), INTERVAL 24 HOUR)
            GROUP BY agent_name HAVING samples >= 3
            ORDER BY std_cpu DESC")->fetchAll();
        foreach ($rows as &$r) {
            $anomalies = [];
            if ($r['std_cpu'] > 20) $anomalies[] = 'CPU volatile';
            if ($r['std_mem'] > 15) $anomalies[] = 'MEM volatile';
            if ($r['avg_cpu'] > 85) $anomalies[] = 'CPU high';
            if ($r['avg_mem'] > 90) $anomalies[] = 'MEM high';
            $r['anomalies'] = $anomalies;
            $r['health'] = empty($anomalies) ? 'stable' : (count($anomalies) >= 2 ? 'critical' : 'warning');
        }
        agent_panel_json(['success'=>true,'data'=>$rows]);
        break;

    /* ─── FLEET CHANGELOG FEED ─── */
    case 'changelog_feed':
        $rows = $pdo->query("
            SELECT c.id, c.agent_id, a.name AS agent_name, c.field_changed, c.old_value, c.new_value, c.changed_at
            FROM alfred_agent_changelog c
            JOIN alfred_agents a ON a.id = c.agent_id
            ORDER BY c.changed_at DESC
            LIMIT 50
        ")->fetchAll(PDO::FETCH_ASSOC);
        agent_panel_json(['success'=>true,'data'=>$rows]);
        break;

    /* ─── AGENT SESSION TRACKER ─── */
    case 'session_tracker':
        $rows = $pdo->query("
            SELECT t.id, t.agent_id, a.name AS agent_name, t.title, t.status, t.priority, t.created_at, t.updated_at
            FROM alfred_agent_tasks t
            JOIN alfred_agents a ON a.id = t.agent_id
            WHERE t.status IN ('in_progress','active','running')
            ORDER BY t.updated_at DESC
            LIMIT 60
        ")->fetchAll(PDO::FETCH_ASSOC);
        // Group by agent
        $byAgent = [];
        foreach ($rows as $r) {
            $n = $r['agent_name'];
            if (!isset($byAgent[$n])) $byAgent[$n] = ['agent_name'=>$n, 'sessions'=>[]];
            $byAgent[$n]['sessions'][] = $r;
        }
        agent_panel_json(['success'=>true,'data'=>array_values($byAgent)]);
        break;

    /* ─── MISSION DEPENDENCY GRAPH ─── */
    case 'mission_deps':
        $chains = $pdo->query("
            SELECT mc.id AS chain_id, mc.name AS chain_name, mc.status AS chain_status,
                   cl.step_order, cl.dispatch_id, d.mission_type, d.status AS step_status, d.agent_id, a.name AS agent_name
            FROM alfred_mission_chains mc
            JOIN alfred_chain_links cl ON cl.chain_id = mc.id
            LEFT JOIN alfred_agent_dispatches d ON d.id = cl.dispatch_id
            LEFT JOIN alfred_agents a ON a.id = d.agent_id
            ORDER BY mc.id DESC, cl.step_order ASC
            LIMIT 100
        ")->fetchAll(PDO::FETCH_ASSOC);
        $grouped = [];
        foreach ($chains as $c) {
            $cid = $c['chain_id'];
            if (!isset($grouped[$cid])) $grouped[$cid] = ['chain_id'=>$cid,'chain_name'=>$c['chain_name'],'chain_status'=>$c['chain_status'],'steps'=>[]];
            $grouped[$cid]['steps'][] = ['step'=>$c['step_order'],'dispatch_id'=>$c['dispatch_id'],'mission_type'=>$c['mission_type'],'step_status'=>$c['step_status'],'agent_name'=>$c['agent_name']];
        }
        agent_panel_json(['success'=>true,'data'=>array_values($grouped)]);
        break;

    /* ─── FLEET CERTIFICATE MONITOR ─── */
    case 'cert_monitor':
        $rows = $pdo->query("
            SELECT id, agent_id, category, title, content, confidence, created_at
            FROM alfred_agent_knowledge
            WHERE category = 'cert_monitor'
            ORDER BY created_at DESC
            LIMIT 30
        ")->fetchAll(PDO::FETCH_ASSOC);
        if (empty($rows)) {
            // Fallback: generate from domains we know
            $rows = [];
            $domains = ['gositeme.com','gocodeme.com','meta-dome.com','alfredlinux.com','alfred-mobile.com'];
            foreach ($domains as $d) {
                $rows[] = ['domain'=>$d,'status'=>'unknown','days_left'=>null,'issuer'=>'—','checked_at'=>date('Y-m-d H:i:s')];
            }
        }
        agent_panel_json(['success'=>true,'data'=>$rows]);
        break;

    /* ─── AGENT FEEDBACK LOOP ─── */
    case 'feedback_loop':
        $rows = $pdo->query("
            SELECT f.id, f.agent_id, a.name AS agent_name, f.feedback_type, f.rating, f.comment, f.source, f.created_at
            FROM alfred_agent_feedback f
            JOIN alfred_agents a ON a.id = f.agent_id
            ORDER BY f.created_at DESC
            LIMIT 50
        ")->fetchAll(PDO::FETCH_ASSOC);
        // Summary per agent
        $summary = [];
        foreach ($rows as $r) {
            $n = $r['agent_name'];
            if (!isset($summary[$n])) $summary[$n] = ['agent_name'=>$n,'count'=>0,'total_rating'=>0,'positive'=>0,'negative'=>0,'neutral'=>0];
            $summary[$n]['count']++;
            $summary[$n]['total_rating'] += (float)$r['rating'];
            $type = strtolower($r['feedback_type'] ?? 'neutral');
            if (strpos($type,'pos') !== false || (float)$r['rating'] >= 4) $summary[$n]['positive']++;
            elseif (strpos($type,'neg') !== false || (float)$r['rating'] <= 2) $summary[$n]['negative']++;
            else $summary[$n]['neutral']++;
        }
        foreach ($summary as &$s) {
            $s['avg_rating'] = $s['count'] ? round($s['total_rating'] / $s['count'], 2) : 0;
        }
        agent_panel_json(['success'=>true,'data'=>['entries'=>$rows,'summary'=>array_values($summary)]]);
        break;

    /* ─── FLEET LATENCY MAP ─── */
    case 'latency_map':
        $rows = $pdo->query("
            SELECT c.from_agent_id, a1.name AS from_name, c.to_agent_id, a2.name AS to_name,
                   c.channel, COUNT(*) AS msg_count,
                   AVG(TIMESTAMPDIFF(SECOND, c.created_at, IFNULL(c.read_at, NOW()))) AS avg_latency_sec
            FROM alfred_agent_comms c
            JOIN alfred_agents a1 ON a1.id = c.from_agent_id
            JOIN alfred_agents a2 ON a2.id = c.to_agent_id
            WHERE c.created_at > DATE_SUB(NOW(), INTERVAL 24 HOUR)
            GROUP BY c.from_agent_id, c.to_agent_id, c.channel
            ORDER BY avg_latency_sec DESC
            LIMIT 50
        ")->fetchAll(PDO::FETCH_ASSOC);
        agent_panel_json(['success'=>true,'data'=>$rows]);
        break;

    /* ─── AGENT WORKLOAD BALANCER ─── */
    case 'workload_balance':
        $rows = $pdo->query("
            SELECT a.id, a.name AS agent_name, a.status,
                   (SELECT COUNT(*) FROM alfred_agent_tasks t WHERE t.agent_id = a.id AND t.status IN ('pending','in_progress','queued')) AS active_tasks,
                   (SELECT COUNT(*) FROM alfred_agent_dispatches d WHERE d.agent_id = a.id AND d.status IN ('pending','in_progress','dispatched')) AS active_dispatches
            FROM alfred_agents a
            WHERE a.status != 'decommissioned'
            ORDER BY (active_tasks + active_dispatches) DESC
        ")->fetchAll(PDO::FETCH_ASSOC);
        $total = array_sum(array_column($rows, 'active_tasks')) + array_sum(array_column($rows, 'active_dispatches'));
        $avg = count($rows) ? round($total / count($rows), 1) : 0;
        agent_panel_json(['success'=>true,'data'=>['agents'=>$rows,'fleet_total'=>$total,'fleet_avg'=>$avg]]);
        break;

    /* ─── MISSION SUCCESS FUNNEL ─── */
    case 'success_funnel':
        $row = $pdo->query("
            SELECT
                COUNT(*) AS total,
                SUM(status IN ('in_progress','active','running')) AS in_progress,
                SUM(status = 'completed') AS completed,
                SUM(status = 'failed') AS failed,
                SUM(status IN ('pending','dispatched','queued')) AS pending
            FROM alfred_agent_dispatches
            WHERE created_at > DATE_SUB(NOW(), INTERVAL 7 DAY)
        ")->fetch(PDO::FETCH_ASSOC);
        $row['success_rate'] = $row['total'] > 0 ? round(($row['completed'] / $row['total']) * 100, 1) : 0;
        agent_panel_json(['success'=>true,'data'=>$row]);
        break;

