            $stmt = $pdo->prepare("INSERT INTO alfred_reputation_score (agent_name, mission_score, uptime_score, peer_score, violation_score, total_score, trust_level) VALUES (?, ?, ?, ?, ?, ?, ?) ON DUPLICATE KEY UPDATE mission_score=VALUES(mission_score), uptime_score=VALUES(uptime_score), peer_score=VALUES(peer_score), violation_score=VALUES(violation_score), total_score=VALUES(total_score), trust_level=VALUES(trust_level)");
