            $stmt->execute([$d['agent_id']??'',$d['agent_name']??'Unknown',$d['mood']??'neutral',$d['energy_level']??50,$d['morale']??50,$d['stress_level']??0,$d['last_positive_event']??null,$d['last_negative_event']??null]);
