            $stmt->execute([$d['mission_name']??'',$d['sender']??'Unknown',$d['recipient']??null,$d['channel']??'direct',$d['message']??'',$d['priority']??'normal']);
            agent_panel_json(['success'=>true,'id'=>$pdo->lastInsertId()]);
        } else {
