    // ── 1. CYBER OPERATIONS CENTER (CYBERCOM) — ID 1001 ──────────────────
    case 'cybercom':
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_cybercom (
            id INT AUTO_INCREMENT PRIMARY KEY,
            operation_id VARCHAR(64) NOT NULL UNIQUE,
            operation_name VARCHAR(128) NOT NULL,
            op_type ENUM('recon','defense','counter','audit','sweep','lockdown') NOT NULL DEFAULT 'defense',
            target VARCHAR(255) DEFAULT NULL,
            status ENUM('planning','active','completed','aborted','escalated') NOT NULL DEFAULT 'planning',
            severity ENUM('low','medium','high','critical','sovereign') NOT NULL DEFAULT 'medium',
            assigned_agent VARCHAR(64) DEFAULT NULL,
            findings JSON DEFAULT NULL,
            countermeasures JSON DEFAULT NULL,
            started_at DATETIME DEFAULT NULL,
            completed_at DATETIME DEFAULT NULL,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            INDEX idx_status (status),
            INDEX idx_severity (severity)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $db->exec("CREATE TABLE IF NOT EXISTS alfred_cybercom_threats (
            id INT AUTO_INCREMENT PRIMARY KEY,
            threat_id VARCHAR(64) NOT NULL UNIQUE,
            threat_name VARCHAR(128) NOT NULL,
            threat_type ENUM('intrusion','malware','ddos','phishing','insider','supply_chain','zero_day','apt') NOT NULL,
            source_ip VARCHAR(45) DEFAULT NULL,
            target_system VARCHAR(128) DEFAULT NULL,
            severity ENUM('low','medium','high','critical','sovereign') NOT NULL DEFAULT 'medium',
            status ENUM('detected','analyzing','mitigated','neutralized','monitoring') NOT NULL DEFAULT 'detected',
            indicators JSON DEFAULT NULL,
            response_actions JSON DEFAULT NULL,
            detected_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            resolved_at DATETIME DEFAULT NULL,
            INDEX idx_status (status),
            INDEX idx_type (threat_type)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $sub = $_GET['sub_action'] ?? ($input['sub_action'] ?? 'dashboard');

        if ($sub === 'dashboard') {
            $ops = $db->query("SELECT op_type, COUNT(*) as count, SUM(status='active') as active FROM alfred_cybercom GROUP BY op_type")->fetchAll(PDO::FETCH_ASSOC);
            $threats = $db->query("SELECT threat_type, COUNT(*) as count, SUM(status IN ('detected','analyzing')) as active FROM alfred_cybercom_threats GROUP BY threat_type")->fetchAll(PDO::FETCH_ASSOC);
            $activeOps = (int)$db->query("SELECT COUNT(*) FROM alfred_cybercom WHERE status='active'")->fetchColumn();
            $activeThreats = (int)$db->query("SELECT COUNT(*) FROM alfred_cybercom_threats WHERE status IN ('detected','analyzing')")->fetchColumn();
            $totalOps = (int)$db->query("SELECT COUNT(*) FROM alfred_cybercom")->fetchColumn();
            $totalThreats = (int)$db->query("SELECT COUNT(*) FROM alfred_cybercom_threats")->fetchColumn();

            // Live security scan
            $openPorts = trim(shell_exec("ss -tulpn 2>/dev/null | grep -c LISTEN") ?: '0');
            $failedSSH = trim(shell_exec("journalctl _COMM=sshd --since '1 hour ago' 2>/dev/null | grep -c 'Failed password'") ?: '0');
            $fw_rules = trim(shell_exec("sudo iptables -L -n 2>/dev/null | wc -l") ?: '0');

            agent_panel_json(['ok'=>true,'system'=>'CYBERCOM','id'=>1001,'level'=>5,
                'live_scan'=>['open_ports'=>(int)$openPorts,'failed_ssh_1h'=>(int)$failedSSH,'firewall_rules'=>(int)$fw_rules],
                'operations'=>['total'=>$totalOps,'active'=>$activeOps,'by_type'=>$ops],
                'threats'=>['total'=>$totalThreats,'active'=>$activeThreats,'by_type'=>$threats],
                'defense_posture'=>$activeThreats === 0 ? 'GREEN' : ($activeThreats <= 3 ? 'YELLOW' : 'RED')
            ]);

        } elseif ($sub === 'create_op') {
            $opId = 'CYOP-' . strtoupper(bin2hex(random_bytes(4)));
            $stmt = $db->prepare("INSERT INTO alfred_cybercom (operation_id, operation_name, op_type, target, severity, assigned_agent, status, started_at) VALUES (?,?,?,?,?,?,'active',NOW())");
            $stmt->execute([$opId, $input['name']??'Unnamed Op', $input['op_type']??'defense', $input['target']??null, $input['severity']??'medium', $input['agent']??null]);
            logAudit($db, 'cybercom_op_created', 'cybercom', "Operation $opId created: " . ($input['name']??''));
            agent_panel_json(['ok'=>true,'operation_id'=>$opId]);

        } elseif ($sub === 'report_threat') {
            $threatId = 'THR-' . strtoupper(bin2hex(random_bytes(4)));
            $stmt = $db->prepare("INSERT INTO alfred_cybercom_threats (threat_id, threat_name, threat_type, source_ip, target_system, severity, indicators) VALUES (?,?,?,?,?,?,?)");
            $stmt->execute([$threatId, $input['name']??'Unknown Threat', $input['threat_type']??'intrusion', $input['source_ip']??null, $input['target_system']??null, $input['severity']??'medium', json_encode($input['indicators']??[])]);
            logAudit($db, 'cybercom_threat_reported', 'cybercom', "Threat $threatId: " . ($input['name']??''));
            agent_panel_json(['ok'=>true,'threat_id'=>$threatId]);

        } elseif ($sub === 'mitigate') {
            $stmt = $db->prepare("UPDATE alfred_cybercom_threats SET status='mitigated', response_actions=?, resolved_at=NOW() WHERE threat_id=?");
            $stmt->execute([json_encode($input['actions']??[]), $input['threat_id']??'']);
            logAudit($db, 'cybercom_threat_mitigated', 'cybercom', "Threat " . ($input['threat_id']??'') . " mitigated");
            agent_panel_json(['ok'=>true]);

        } elseif ($sub === 'list_ops') {
            $rows = $db->query("SELECT * FROM alfred_cybercom ORDER BY created_at DESC LIMIT 50")->fetchAll(PDO::FETCH_ASSOC);
            agent_panel_json(['ok'=>true,'operations'=>$rows]);

        } elseif ($sub === 'list_threats') {
            $rows = $db->query("SELECT * FROM alfred_cybercom_threats ORDER BY detected_at DESC LIMIT 50")->fetchAll(PDO::FETCH_ASSOC);
            agent_panel_json(['ok'=>true,'threats'=>$rows]);

        } elseif ($sub === 'lockdown') {
            // Emergency lockdown — log the event
            $opId = 'LOCK-' . strtoupper(bin2hex(random_bytes(4)));
            $db->prepare("INSERT INTO alfred_cybercom (operation_id, operation_name, op_type, severity, status, started_at) VALUES (?,'EMERGENCY LOCKDOWN','lockdown','sovereign','active',NOW())")
               ->execute([$opId]);
            logAudit($db, 'cybercom_lockdown', 'cybercom', "Emergency lockdown initiated: $opId");
            agent_panel_json(['ok'=>true,'lockdown_id'=>$opId,'message'=>'LOCKDOWN INITIATED — All perimeter defenses activated']);

        } else { agent_panel_json(['error'=>'Unknown sub_action']); }
        break;

    // ── 2. MILITARY BROADCASTING NETWORK (MIL-NET) — ID 1002 ─────────────
    case 'milnet':
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_milnet_broadcasts (
            id INT AUTO_INCREMENT PRIMARY KEY,
            broadcast_id VARCHAR(64) NOT NULL UNIQUE,
            title VARCHAR(255) NOT NULL,
            content TEXT NOT NULL,
            broadcast_type ENUM('alert','news','briefing','order','ceremony','emergency') NOT NULL DEFAULT 'news',
            priority ENUM('routine','priority','immediate','flash','supreme') NOT NULL DEFAULT 'routine',
            scope ENUM('all','officers','nco','enlisted','department','individual') NOT NULL DEFAULT 'all',
            scope_target VARCHAR(128) DEFAULT NULL,
            author_client_id INT DEFAULT NULL,
            status ENUM('draft','scheduled','broadcasting','completed','cancelled') NOT NULL DEFAULT 'draft',
            scheduled_at DATETIME DEFAULT NULL,
            broadcast_at DATETIME DEFAULT NULL,
            expires_at DATETIME DEFAULT NULL,
            views INT DEFAULT 0,
            acknowledgements INT DEFAULT 0,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            INDEX idx_status (status),
            INDEX idx_type (broadcast_type),
            INDEX idx_priority (priority)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $db->exec("CREATE TABLE IF NOT EXISTS alfred_milnet_acks (
            id INT AUTO_INCREMENT PRIMARY KEY,
            broadcast_id VARCHAR(64) NOT NULL,
            client_id INT NOT NULL,
            acknowledged_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            UNIQUE KEY uniq_ack (broadcast_id, client_id),
            INDEX idx_broadcast (broadcast_id)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $sub = $_GET['sub_action'] ?? ($input['sub_action'] ?? 'feed');

        if ($sub === 'feed') {
            $rows = $db->query("SELECT * FROM alfred_milnet_broadcasts WHERE status IN ('broadcasting','completed') ORDER BY broadcast_at DESC LIMIT 50")->fetchAll(PDO::FETCH_ASSOC);
            $stats = $db->query("SELECT broadcast_type, COUNT(*) as count FROM alfred_milnet_broadcasts GROUP BY broadcast_type")->fetchAll(PDO::FETCH_ASSOC);
            agent_panel_json(['ok'=>true,'system'=>'MIL-NET','id'=>1002,'level'=>5,'broadcasts'=>$rows,'stats'=>$stats]);

        } elseif ($sub === 'broadcast') {
            $bId = 'MILNET-' . strtoupper(bin2hex(random_bytes(4)));
            $stmt = $db->prepare("INSERT INTO alfred_milnet_broadcasts (broadcast_id, title, content, broadcast_type, priority, scope, scope_target, author_client_id, status, broadcast_at) VALUES (?,?,?,?,?,?,?,33,'broadcasting',NOW())");
            $stmt->execute([$bId, $input['title']??'Untitled', $input['content']??'', $input['type']??'news', $input['priority']??'routine', $input['scope']??'all', $input['scope_target']??null]);
            logAudit($db, 'milnet_broadcast', 'milnet', "Broadcast $bId: " . ($input['title']??''));
            agent_panel_json(['ok'=>true,'broadcast_id'=>$bId,'message'=>'Broadcast live on MIL-NET']);

        } elseif ($sub === 'acknowledge') {
            $stmt = $db->prepare("INSERT IGNORE INTO alfred_milnet_acks (broadcast_id, client_id) VALUES (?,?)");
            $stmt->execute([$input['broadcast_id']??'', $input['client_id']??33]);
            $db->prepare("UPDATE alfred_milnet_broadcasts SET acknowledgements = acknowledgements + 1 WHERE broadcast_id = ?")->execute([$input['broadcast_id']??'']);
            agent_panel_json(['ok'=>true]);

        } elseif ($sub === 'schedule') {
            $bId = 'MILNET-' . strtoupper(bin2hex(random_bytes(4)));
            $stmt = $db->prepare("INSERT INTO alfred_milnet_broadcasts (broadcast_id, title, content, broadcast_type, priority, scope, status, scheduled_at) VALUES (?,?,?,?,?,?,'scheduled',?)");
            $stmt->execute([$bId, $input['title']??'', $input['content']??'', $input['type']??'news', $input['priority']??'routine', $input['scope']??'all', $input['scheduled_at']??date('Y-m-d H:i:s', strtotime('+1 hour'))]);
            agent_panel_json(['ok'=>true,'broadcast_id'=>$bId,'scheduled'=>true]);

        } elseif ($sub === 'cancel') {
            $db->prepare("UPDATE alfred_milnet_broadcasts SET status='cancelled' WHERE broadcast_id=? AND status IN ('draft','scheduled','broadcasting')")->execute([$input['broadcast_id']??'']);
            agent_panel_json(['ok'=>true]);

        } else { agent_panel_json(['error'=>'Unknown sub_action']); }
        break;

    // ── 3. STRATEGIC COMMAND (STRATCOM) — ID 1003 ────────────────────────
    case 'stratcom':
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_stratcom (
            id INT AUTO_INCREMENT PRIMARY KEY,
            directive_id VARCHAR(64) NOT NULL UNIQUE,
            directive_name VARCHAR(255) NOT NULL,
            directive_type ENUM('standing_order','campaign','contingency','doctrine','policy','treaty') NOT NULL DEFAULT 'standing_order',
            classification ENUM('unclassified','confidential','secret','top_secret','sovereign') NOT NULL DEFAULT 'confidential',
            priority ENUM('low','medium','high','critical','supreme') NOT NULL DEFAULT 'medium',
            issuing_authority VARCHAR(128) DEFAULT 'Supreme Commander',
            objective TEXT,
            parameters JSON DEFAULT NULL,
            affected_systems JSON DEFAULT NULL,
            status ENUM('draft','active','suspended','completed','revoked') NOT NULL DEFAULT 'draft',
            effective_from DATETIME DEFAULT CURRENT_TIMESTAMP,
            effective_until DATETIME DEFAULT NULL,
            review_date DATETIME DEFAULT NULL,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
            INDEX idx_status (status),
            INDEX idx_type (directive_type),
            INDEX idx_class (classification)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $sub = $_GET['sub_action'] ?? ($input['sub_action'] ?? 'overview');

        if ($sub === 'overview') {
            $active = $db->query("SELECT * FROM alfred_stratcom WHERE status='active' ORDER BY priority DESC, created_at DESC")->fetchAll(PDO::FETCH_ASSOC);
            $stats = $db->query("SELECT directive_type, COUNT(*) as count, SUM(status='active') as active FROM alfred_stratcom GROUP BY directive_type")->fetchAll(PDO::FETCH_ASSOC);
            $totalActive = (int)$db->query("SELECT COUNT(*) FROM alfred_stratcom WHERE status='active'")->fetchColumn();
            agent_panel_json(['ok'=>true,'system'=>'STRATCOM','id'=>1003,'level'=>5,
                'active_directives'=>$totalActive,'directives'=>$active,'by_type'=>$stats,
                'strategic_posture'=>$totalActive > 0 ? 'DIRECTIVES ACTIVE' : 'STANDBY'
            ]);

        } elseif ($sub === 'issue') {
            $dId = 'STRAT-' . strtoupper(bin2hex(random_bytes(4)));
            $stmt = $db->prepare("INSERT INTO alfred_stratcom (directive_id, directive_name, directive_type, classification, priority, objective, parameters, affected_systems, status) VALUES (?,?,?,?,?,?,?,?,'active')");
            $stmt->execute([$dId, $input['name']??'Unnamed Directive', $input['type']??'standing_order', $input['classification']??'confidential', $input['priority']??'medium', $input['objective']??'', json_encode($input['parameters']??[]), json_encode($input['affected_systems']??[])]);
            logAudit($db, 'stratcom_directive_issued', 'stratcom', "Directive $dId: " . ($input['name']??''));
            agent_panel_json(['ok'=>true,'directive_id'=>$dId]);

        } elseif ($sub === 'revoke') {
            $db->prepare("UPDATE alfred_stratcom SET status='revoked', updated_at=NOW() WHERE directive_id=?")->execute([$input['directive_id']??'']);
            logAudit($db, 'stratcom_directive_revoked', 'stratcom', "Directive " . ($input['directive_id']??'') . " revoked");
            agent_panel_json(['ok'=>true]);

        } elseif ($sub === 'suspend') {
            $db->prepare("UPDATE alfred_stratcom SET status='suspended', updated_at=NOW() WHERE directive_id=?")->execute([$input['directive_id']??'']);
            agent_panel_json(['ok'=>true]);

        } elseif ($sub === 'list') {
            $rows = $db->query("SELECT * FROM alfred_stratcom ORDER BY created_at DESC LIMIT 100")->fetchAll(PDO::FETCH_ASSOC);
            agent_panel_json(['ok'=>true,'directives'=>$rows]);

        } else { agent_panel_json(['error'=>'Unknown sub_action']); }
        break;

    // ── 4. ARSENAL & ARMORY — ID 1004 (Extends existing arsenal) ─────────
    case 'armory':
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_armory (
            id INT AUTO_INCREMENT PRIMARY KEY,
            weapon_id VARCHAR(64) NOT NULL UNIQUE,
            weapon_name VARCHAR(128) NOT NULL,
            weapon_class ENUM('tool','script','exploit_defense','scanner','encryptor','decoy','shield','payload','sensor','drone') NOT NULL DEFAULT 'tool',
            tier ENUM('standard','advanced','elite','sovereign','experimental') NOT NULL DEFAULT 'standard',
            description TEXT,
            capabilities JSON DEFAULT NULL,
            power_rating INT DEFAULT 0,
            ammo_count INT DEFAULT -1,
            assigned_to VARCHAR(64) DEFAULT NULL,
            status ENUM('ready','deployed','charging','maintenance','retired','classified') NOT NULL DEFAULT 'ready',
            last_deployed DATETIME DEFAULT NULL,
            deployment_count INT DEFAULT 0,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            INDEX idx_class (weapon_class),
            INDEX idx_tier (tier),
            INDEX idx_status (status)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $sub = $_GET['sub_action'] ?? ($input['sub_action'] ?? 'inventory');

        if ($sub === 'inventory') {
            $weapons = $db->query("SELECT * FROM alfred_armory ORDER BY tier DESC, power_rating DESC LIMIT 100")->fetchAll(PDO::FETCH_ASSOC);
            $stats = $db->query("SELECT weapon_class, tier, COUNT(*) as count, SUM(status='deployed') as deployed, AVG(power_rating) as avg_power FROM alfred_armory GROUP BY weapon_class, tier")->fetchAll(PDO::FETCH_ASSOC);
            $total = (int)$db->query("SELECT COUNT(*) FROM alfred_armory")->fetchColumn();
            $deployed = (int)$db->query("SELECT COUNT(*) FROM alfred_armory WHERE status='deployed'")->fetchColumn();
            agent_panel_json(['ok'=>true,'system'=>'ARMORY','id'=>1004,'level'=>5,
                'total_weapons'=>$total,'deployed'=>$deployed,'ready'=>$total-$deployed,
                'weapons'=>$weapons,'breakdown'=>$stats,
                'armory_status'=>$deployed > 0 ? 'WEAPONS HOT' : 'ARSENAL COLD'
            ]);

        } elseif ($sub === 'forge') {
            $wId = 'WPN-' . strtoupper(bin2hex(random_bytes(4)));
            $stmt = $db->prepare("INSERT INTO alfred_armory (weapon_id, weapon_name, weapon_class, tier, description, capabilities, power_rating) VALUES (?,?,?,?,?,?,?)");
            $stmt->execute([$wId, $input['name']??'Unnamed Weapon', $input['class']??'tool', $input['tier']??'standard', $input['description']??'', json_encode($input['capabilities']??[]), (int)($input['power_rating']??50)]);
            logAudit($db, 'armory_forged', 'armory', "Weapon forged: $wId — " . ($input['name']??''));
            agent_panel_json(['ok'=>true,'weapon_id'=>$wId]);

        } elseif ($sub === 'deploy') {
            $db->prepare("UPDATE alfred_armory SET status='deployed', assigned_to=?, last_deployed=NOW(), deployment_count=deployment_count+1 WHERE weapon_id=?")->execute([$input['agent']??'', $input['weapon_id']??'']);
            logAudit($db, 'armory_deployed', 'armory', "Weapon " . ($input['weapon_id']??'') . " deployed to " . ($input['agent']??''));
            agent_panel_json(['ok'=>true]);

        } elseif ($sub === 'recall') {
