            $db->prepare("INSERT INTO alfred_service_events (client_id, event_type, event_title) VALUES (?,'enlistment','Enlisted in GoSiteMe Defense Force')")->execute([(int)($input['client_id']??0)]);
            logAudit($db, 'veteran_enlisted', 'veterans', "Client " . ($input['client_id']??0) . " enlisted as $svcNum");
            agent_panel_json(['ok'=>true,'service_number'=>$svcNum]);

