                FROM alfred_veterans v
                LEFT JOIN tblclients tc ON tc.id = v.client_id
                LEFT JOIN user_ranks ur ON ur.client_id = v.client_id AND ur.is_active=1
                LEFT JOIN military_ranks mr ON mr.rank_code = ur.rank_code
                WHERE v.client_id = ?");
            $record->execute([$cid]);
            $rec = $record->fetch(PDO::FETCH_ASSOC);
            $events = $db->prepare("SELECT * FROM alfred_service_events WHERE client_id = ? ORDER BY event_date DESC LIMIT 100");
            $events->execute([$cid]);
            agent_panel_json(['ok'=>true,'record'=>$rec,'events'=>$events->fetchAll(PDO::FETCH_ASSOC)]);

        } elseif ($sub === 'commend') {
            $db->prepare("UPDATE alfred_veterans SET commendations = commendations + 1 WHERE client_id = ?")->execute([(int)($input['client_id']??0)]);
            $db->prepare("INSERT INTO alfred_service_events (client_id, event_type, event_title, event_description) VALUES (?,'commendation',?,?)")
               ->execute([(int)($input['client_id']??0), $input['title']??'Commendation', $input['reason']??'']);
