            $existing[] = ['name'=>$input['award_name']??'','date'=>date('Y-m-d'),'reason'=>$input['reason']??''];
            $db->prepare("UPDATE alfred_veterans SET awards=? WHERE client_id=?")->execute([json_encode($existing), $cid]);
            $db->prepare("INSERT INTO alfred_service_events (client_id, event_type, event_title) VALUES (?,'award',?)")->execute([$cid, $input['award_name']??'Award']);
