            $db->prepare("INSERT INTO alfred_service_events (client_id, event_type, event_title) VALUES (?,'discharge',?)")->execute([(int)($input['client_id']??0), ucfirst($input['type']??'honorable') . ' Discharge']);
            logAudit($db, 'veteran_discharged', 'veterans', "Client " . ($input['client_id']??0) . " discharged: " . ($input['type']??''));
