    // ── 7. OFFICER CANDIDATE SCHOOL (OCS) — ID 1007 ─────────────────────
    case 'ocs':
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_ocs (
            id INT AUTO_INCREMENT PRIMARY KEY,
            candidate_id VARCHAR(64) NOT NULL UNIQUE,
            client_id INT NOT NULL,
            current_phase ENUM('application','assessment','training','practicum','evaluation','graduated','failed','withdrawn') NOT NULL DEFAULT 'application',
