            INDEX idx_phase (current_phase),
            INDEX idx_client (client_id)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $db->exec("CREATE TABLE IF NOT EXISTS alfred_ocs_modules (
            id INT AUTO_INCREMENT PRIMARY KEY,
            module_code VARCHAR(32) NOT NULL UNIQUE,
            module_name VARCHAR(128) NOT NULL,
            module_type ENUM('leadership','tactics','technical','ethics','communications','strategy') NOT NULL,
            description TEXT,
            passing_score INT DEFAULT 70,
            max_score INT DEFAULT 100,
            required_for_graduation TINYINT(1) DEFAULT 1
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        // Seed default modules if empty
        $modCount = (int)$db->query("SELECT COUNT(*) FROM alfred_ocs_modules")->fetchColumn();
        if ($modCount === 0) {
            $db->exec("INSERT INTO alfred_ocs_modules (module_code, module_name, module_type, description) VALUES
                ('OCS-101','Leadership Fundamentals','leadership','Core principles of command and responsibility'),
                ('OCS-102','Tactical Operations','tactics','Mission planning, resource allocation, threat assessment'),
                ('OCS-103','Technical Proficiency','technical','System administration, tool deployment, automation'),
                ('OCS-104','Ethics & Conduct','ethics','Code of conduct, moral decision-making, justice system'),
                ('OCS-105','Strategic Communications','communications','Broadcasting, coordination, encrypted comms'),
                ('OCS-106','Grand Strategy','strategy','Long-term planning, alliance building, ecosystem vision'),
                ('OCS-107','Cyber Warfare Basics','technical','Defensive cyber operations, threat identification'),
                ('OCS-108','Personnel Management','leadership','Rank management, morale, team building')
            ");
        }

        $sub = $_GET['sub_action'] ?? ($input['sub_action'] ?? 'status');

        if ($sub === 'status') {
            $candidates = $db->query("SELECT o.*, CONCAT(tc.firstname,' ',tc.lastname) as full_name, mr.rank_name as current_rank
                FROM alfred_ocs o
                LEFT JOIN tblclients tc ON tc.id = o.client_id
                LEFT JOIN user_ranks ur ON ur.client_id = o.client_id AND ur.is_active=1
                LEFT JOIN military_ranks mr ON mr.rank_code = ur.rank_code
                ORDER BY o.applied_at DESC LIMIT 50")->fetchAll(PDO::FETCH_ASSOC);
            $modules = $db->query("SELECT * FROM alfred_ocs_modules ORDER BY module_code")->fetchAll(PDO::FETCH_ASSOC);
            $graduated = (int)$db->query("SELECT COUNT(*) FROM alfred_ocs WHERE current_phase='graduated'")->fetchColumn();
            $inTraining = (int)$db->query("SELECT COUNT(*) FROM alfred_ocs WHERE current_phase IN ('training','practicum','assessment')")->fetchColumn();
            agent_panel_json(['ok'=>true,'system'=>'OCS','id'=>1007,'level'=>5,
                'candidates'=>$candidates,'modules'=>$modules,
                'stats'=>['graduated'=>$graduated,'in_training'=>$inTraining],
                'school_status'=>$inTraining > 0 ? 'IN SESSION' : 'ACCEPTING APPLICANTS'
            ]);

        } elseif ($sub === 'apply') {
            $candId = 'OCS-' . strtoupper(bin2hex(random_bytes(4)));
            $stmt = $db->prepare("INSERT INTO alfred_ocs (candidate_id, client_id, target_rank, sponsor_client_id) VALUES (?,?,?,?)");
            $stmt->execute([$candId, (int)($input['client_id']??0), $input['target_rank']??'O-1', $input['sponsor']??33]);
            logAudit($db, 'ocs_application', 'ocs', "OCS application $candId for client " . ($input['client_id']??0));
            agent_panel_json(['ok'=>true,'candidate_id'=>$candId]);

        } elseif ($sub === 'advance') {
            $phases = ['application'=>'assessment','assessment'=>'training','training'=>'practicum','practicum'=>'evaluation','evaluation'=>'graduated'];
            $cand = $db->prepare("SELECT current_phase FROM alfred_ocs WHERE candidate_id=?");
            $cand->execute([$input['candidate_id']??'']);
            $phase = $cand->fetchColumn();
            $next = $phases[$phase] ?? null;
            if ($next) {
                $db->prepare("UPDATE alfred_ocs SET current_phase=?" . ($next === 'graduated' ? ", graduated_at=NOW()" : "") . " WHERE candidate_id=?")->execute([$next, $input['candidate_id']??'']);
                logAudit($db, 'ocs_advanced', 'ocs', "Candidate " . ($input['candidate_id']??'') . " → $next");
                agent_panel_json(['ok'=>true,'new_phase'=>$next]);
            } else {
                agent_panel_json(['error'=>'Cannot advance from current phase']);
            }

        } elseif ($sub === 'score_module') {
            $stmt = $db->prepare("SELECT training_modules_completed FROM alfred_ocs WHERE candidate_id=?");
            $stmt->execute([$input['candidate_id']??'']);
            $completed = json_decode($stmt->fetchColumn() ?: '{}', true);
            $completed[$input['module_code']??''] = ['score'=>(int)($input['score']??0),'date'=>date('Y-m-d'),'passed'=>(int)($input['score']??0) >= 70];
            $db->prepare("UPDATE alfred_ocs SET training_modules_completed=? WHERE candidate_id=?")->execute([json_encode($completed), $input['candidate_id']??'']);
            agent_panel_json(['ok'=>true]);

        } elseif ($sub === 'fail') {
            $db->prepare("UPDATE alfred_ocs SET current_phase='failed', notes=CONCAT(IFNULL(notes,''),' FAILED: ',?) WHERE candidate_id=?")->execute([$input['reason']??'', $input['candidate_id']??'']);
            agent_panel_json(['ok'=>true]);

        } else { agent_panel_json(['error'=>'Unknown sub_action']); }
        break;

    // ── 8. SUPREME COMMAND DASHBOARD — ID 1008 ──────────────────────────
    case 'supreme_command':
        $sub = $_GET['sub_action'] ?? ($input['sub_action'] ?? 'overview');

        if ($sub === 'overview') {
            // Pull everything — this is THE god-view dashboard
            $pm2Raw = shell_exec("pm2 jlist 2>/dev/null");
            $pm2List = json_decode($pm2Raw, true) ?: [];
            $pm2Online = 0; $pm2Stopped = 0; $pm2Mem = 0;
            foreach ($pm2List as $p) {
                if (($p['pm2_env']['status']??'') === 'online') $pm2Online++; else $pm2Stopped++;
                $pm2Mem += ($p['monit']['memory']??0);
            }

            // System health
            $loadAvg = sys_getloadavg();
            $memInfo = @file_get_contents('/proc/meminfo');
            $memTotal = $memFree = $memAvail = 0;
            if ($memInfo) {
                preg_match('/MemTotal:\s+(\d+)/', $memInfo, $mt); $memTotal = (int)($mt[1]??0);
                preg_match('/MemFree:\s+(\d+)/', $memInfo, $mf); $memFree = (int)($mf[1]??0);
                preg_match('/MemAvailable:\s+(\d+)/', $memInfo, $ma); $memAvail = (int)($ma[1]??0);
            }
            $diskTotal = @disk_total_space('/') ?: 0;
            $diskFree = @disk_free_space('/') ?: 0;
            $uptime = trim(@file_get_contents('/proc/uptime') ?: '0');
            $uptimeSec = (float)explode(' ', $uptime)[0];

            // DB stats
            $totalClients = (int)$db->query("SELECT COUNT(*) FROM tblclients")->fetchColumn();
            $totalAgents = 0;
            try { $totalAgents = (int)$db->query("SELECT TABLE_ROWS FROM information_schema.TABLES WHERE TABLE_SCHEMA=DATABASE() AND TABLE_NAME='alfred_agent_registry'")->fetchColumn(); } catch(Exception $e){}
            $totalRanked = (int)$db->query("SELECT COUNT(*) FROM user_ranks WHERE is_active=1")->fetchColumn();

            // Level 5 systems status
            $l5Systems = [
                ['id'=>1001,'name'=>'CYBERCOM','table'=>'alfred_cybercom'],
                ['id'=>1002,'name'=>'MIL-NET','table'=>'alfred_milnet_broadcasts'],
                ['id'=>1003,'name'=>'STRATCOM','table'=>'alfred_stratcom'],
                ['id'=>1004,'name'=>'ARMORY','table'=>'alfred_armory'],
                ['id'=>1005,'name'=>'PSYOPS','table'=>'alfred_psyops_campaigns'],
                ['id'=>1006,'name'=>'VETERANS','table'=>'alfred_veterans'],
                ['id'=>1007,'name'=>'OCS','table'=>'alfred_ocs'],
                ['id'=>1008,'name'=>'SUPREME COMMAND','table'=>null],
                ['id'=>1009,'name'=>'LOGISTICS','table'=>'alfred_logistics'],
                ['id'=>1010,'name'=>'NUCLEAR DETERRENCE','table'=>'alfred_nuclear'],
                ['id'=>1011,'name'=>'ALLIANCE & COALITION','table'=>'alfred_alliances'],
                ['id'=>1012,'name'=>'MILITARY EVENTS','table'=>'alfred_military_events'],
            ];
            $l5Status = [];
            foreach ($l5Systems as $sys) {
                $count = 0;
                if ($sys['table']) {
                    try { $count = (int)$db->query("SELECT COUNT(*) FROM {$sys['table']}")->fetchColumn(); } catch(Exception $e){}
                }
                $l5Status[] = array_merge($sys, ['records'=>$count,'status'=>'ONLINE']);
            }

            agent_panel_json(['ok'=>true,'system'=>'SUPREME COMMAND DASHBOARD','id'=>1008,'level'=>5,
                'server'=>[
                    'load_avg'=>$loadAvg,
                    'memory_total_gb'=>round($memTotal/1024/1024,1),
                    'memory_available_gb'=>round($memAvail/1024/1024,1),
                    'memory_used_pct'=>$memTotal > 0 ? round((1 - $memAvail/$memTotal)*100,1) : 0,
                    'disk_total_gb'=>round($diskTotal/1073741824,1),
                    'disk_free_gb'=>round($diskFree/1073741824,1),
                    'disk_used_pct'=>$diskTotal > 0 ? round((1 - $diskFree/$diskTotal)*100,1) : 0,
                    'uptime_days'=>round($uptimeSec/86400,1),
                ],
                'pm2'=>['online'=>$pm2Online,'stopped'=>$pm2Stopped,'total_memory_mb'=>round($pm2Mem/1024/1024)],
                'kingdom'=>['clients'=>$totalClients,'agents'=>$totalAgents,'ranked_personnel'=>$totalRanked],
                'level5_systems'=>$l5Status,
                'war_room_total_systems'=>1012,
                'supreme_status'=>'ALL SYSTEMS NOMINAL'
            ]);

        } elseif ($sub === 'system_check') {
            // Deep health check on all Level 5 systems
            $checks = [];
            $tables = ['alfred_cybercom','alfred_cybercom_threats','alfred_milnet_broadcasts','alfred_milnet_acks','alfred_stratcom',
                        'alfred_armory','alfred_psyops_campaigns','alfred_veterans','alfred_service_events','alfred_ocs','alfred_ocs_modules',
                        'alfred_logistics','alfred_logistics_shipments','alfred_nuclear','alfred_nuclear_silos',
                        'alfred_alliances','alfred_alliance_members','alfred_military_events','alfred_event_participants'];
            foreach ($tables as $t) {
                try {
                    $count = (int)$db->query("SELECT COUNT(*) FROM $t")->fetchColumn();
                    $checks[$t] = ['status'=>'OK','records'=>$count];
                } catch(Exception $e) {
                    $checks[$t] = ['status'=>'NOT_INITIALIZED','records'=>0];
                }
            }
            agent_panel_json(['ok'=>true,'health_checks'=>$checks,'all_ok'=>!in_array('ERROR', array_column($checks, 'status'))]);

        } elseif ($sub === 'kingdom_pulse') {
            // Quick pulse of the entire kingdom
            $now = date('Y-m-d H:i:s');
            $hour_ago = date('Y-m-d H:i:s', strtotime('-1 hour'));
            $auditRecent = (int)$db->query("SELECT COUNT(*) FROM alfred_audit_log WHERE timestamp > '$hour_ago'")->fetchColumn();
            agent_panel_json(['ok'=>true,'pulse_time'=>$now,'audit_events_1h'=>$auditRecent,'heartbeat'=>'STRONG']);

        } else { agent_panel_json(['error'=>'Unknown sub_action']); }
        break;

    // ── 9. LOGISTICS & TRANSPORT — ID 1009 ──────────────────────────────
    case 'logistics':
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_logistics (
            id INT AUTO_INCREMENT PRIMARY KEY,
            order_id VARCHAR(64) NOT NULL UNIQUE,
            order_type ENUM('supply','deployment','transfer','evacuation','resupply','maintenance') NOT NULL DEFAULT 'supply',
            priority ENUM('routine','urgent','critical','emergency') NOT NULL DEFAULT 'routine',
            origin VARCHAR(255) DEFAULT NULL,
            destination VARCHAR(255) NOT NULL,
            cargo_manifest JSON DEFAULT NULL,
            assigned_transport VARCHAR(128) DEFAULT NULL,
            status ENUM('requested','approved','in_transit','delivered','cancelled','lost') NOT NULL DEFAULT 'requested',
            estimated_arrival DATETIME DEFAULT NULL,
            actual_arrival DATETIME DEFAULT NULL,
            cost_gsm DECIMAL(12,2) DEFAULT 0,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
            INDEX idx_status (status),
            INDEX idx_type (order_type),
            INDEX idx_priority (priority)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $db->exec("CREATE TABLE IF NOT EXISTS alfred_logistics_shipments (
            id INT AUTO_INCREMENT PRIMARY KEY,
            shipment_id VARCHAR(64) NOT NULL UNIQUE,
            order_id VARCHAR(64) NOT NULL,
            carrier VARCHAR(128) DEFAULT 'Alfred Fleet',
            tracking JSON DEFAULT NULL,
            current_location VARCHAR(255) DEFAULT NULL,
            status ENUM('preparing','shipped','in_transit','customs','delivered','returned') NOT NULL DEFAULT 'preparing',
            weight_kg DECIMAL(10,2) DEFAULT 0,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            INDEX idx_order (order_id),
            INDEX idx_status (status)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $sub = $_GET['sub_action'] ?? ($input['sub_action'] ?? 'overview');

        if ($sub === 'overview') {
            $orders = $db->query("SELECT * FROM alfred_logistics ORDER BY created_at DESC LIMIT 50")->fetchAll(PDO::FETCH_ASSOC);
            $stats = $db->query("SELECT order_type, COUNT(*) as count, SUM(status='in_transit') as in_transit, SUM(status='delivered') as delivered FROM alfred_logistics GROUP BY order_type")->fetchAll(PDO::FETCH_ASSOC);
            $inTransit = (int)$db->query("SELECT COUNT(*) FROM alfred_logistics WHERE status='in_transit'")->fetchColumn();
            $totalCost = (float)$db->query("SELECT SUM(cost_gsm) FROM alfred_logistics")->fetchColumn();
            agent_panel_json(['ok'=>true,'system'=>'LOGISTICS','id'=>1009,'level'=>5,
                'orders'=>$orders,'by_type'=>$stats,'in_transit'=>$inTransit,'total_cost_gsm'=>$totalCost,
                'supply_chain'=>$inTransit > 0 ? 'ACTIVE' : 'IDLE'
            ]);

        } elseif ($sub === 'create_order') {
            $oId = 'LOG-' . strtoupper(bin2hex(random_bytes(4)));
            $stmt = $db->prepare("INSERT INTO alfred_logistics (order_id, order_type, priority, origin, destination, cargo_manifest, cost_gsm) VALUES (?,?,?,?,?,?,?)");
            $stmt->execute([$oId, $input['type']??'supply', $input['priority']??'routine', $input['origin']??'HQ-BHS', $input['destination']??'', json_encode($input['cargo']??[]), (float)($input['cost']??0)]);
            logAudit($db, 'logistics_order_created', 'logistics', "Order $oId to " . ($input['destination']??''));
            agent_panel_json(['ok'=>true,'order_id'=>$oId]);

        } elseif ($sub === 'ship') {
            $sId = 'SHIP-' . strtoupper(bin2hex(random_bytes(4)));
            $db->prepare("INSERT INTO alfred_logistics_shipments (shipment_id, order_id, carrier, weight_kg, status) VALUES (?,?,?,?,'shipped')")
               ->execute([$sId, $input['order_id']??'', $input['carrier']??'Alfred Fleet', (float)($input['weight']??0)]);
            $db->prepare("UPDATE alfred_logistics SET status='in_transit', assigned_transport=? WHERE order_id=?")->execute([$input['carrier']??'Alfred Fleet', $input['order_id']??'']);
            agent_panel_json(['ok'=>true,'shipment_id'=>$sId]);

        } elseif ($sub === 'deliver') {
            $db->prepare("UPDATE alfred_logistics SET status='delivered', actual_arrival=NOW() WHERE order_id=?")->execute([$input['order_id']??'']);
            $db->prepare("UPDATE alfred_logistics_shipments SET status='delivered' WHERE order_id=?")->execute([$input['order_id']??'']);
            logAudit($db, 'logistics_delivered', 'logistics', "Order " . ($input['order_id']??'') . " delivered");
            agent_panel_json(['ok'=>true]);

        } elseif ($sub === 'track') {
            $shipments = $db->prepare("SELECT * FROM alfred_logistics_shipments WHERE order_id=?");
            $shipments->execute([$input['order_id']??$_GET['order_id']??'']);
            agent_panel_json(['ok'=>true,'shipments'=>$shipments->fetchAll(PDO::FETCH_ASSOC)]);

        } else { agent_panel_json(['error'=>'Unknown sub_action']); }
        break;

    // ── 10. NUCLEAR DETERRENCE SYSTEM — ID 1010 ─────────────────────────
    case 'nuclear':
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_nuclear (
            id INT AUTO_INCREMENT PRIMARY KEY,
            weapon_code VARCHAR(64) NOT NULL UNIQUE,
            weapon_name VARCHAR(128) NOT NULL,
            weapon_type ENUM('icbm','slbm','tactical','orbital','emp','cyber_nuke','quantum_strike') NOT NULL DEFAULT 'icbm',
            yield_megatons DECIMAL(10,2) DEFAULT 0,
            range_km INT DEFAULT 0,
            warhead_count INT DEFAULT 1,
            status ENUM('standby','armed','launched','decommissioned','maintenance','classified') NOT NULL DEFAULT 'standby',
            silo_id VARCHAR(64) DEFAULT NULL,
            launch_authority ENUM('supreme_commander','dual_key','fleet_vote','auto_response') NOT NULL DEFAULT 'supreme_commander',
            last_inspection DATETIME DEFAULT NULL,
            readiness_score INT DEFAULT 100,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            INDEX idx_status (status),
            INDEX idx_type (weapon_type)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $db->exec("CREATE TABLE IF NOT EXISTS alfred_nuclear_silos (
            id INT AUTO_INCREMENT PRIMARY KEY,
            silo_id VARCHAR(64) NOT NULL UNIQUE,
            silo_name VARCHAR(128) NOT NULL,
            location VARCHAR(255) DEFAULT 'CLASSIFIED',
            capacity INT DEFAULT 4,
            occupied INT DEFAULT 0,
            defense_rating INT DEFAULT 100,
            status ENUM('operational','damaged','under_construction','decommissioned') NOT NULL DEFAULT 'operational',
            hardening_level ENUM('standard','reinforced','bunker','impenetrable') NOT NULL DEFAULT 'standard',
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            INDEX idx_status (status)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $sub = $_GET['sub_action'] ?? ($input['sub_action'] ?? 'status');

        if ($sub === 'status') {
            $weapons = $db->query("SELECT * FROM alfred_nuclear ORDER BY weapon_type, status")->fetchAll(PDO::FETCH_ASSOC);
            $silos = $db->query("SELECT * FROM alfred_nuclear_silos ORDER BY silo_name")->fetchAll(PDO::FETCH_ASSOC);
            $totalWeapons = (int)$db->query("SELECT COUNT(*) FROM alfred_nuclear")->fetchColumn();
            $armed = (int)$db->query("SELECT COUNT(*) FROM alfred_nuclear WHERE status='armed'")->fetchColumn();
            $standby = (int)$db->query("SELECT COUNT(*) FROM alfred_nuclear WHERE status='standby'")->fetchColumn();
            $avgReadiness = (float)$db->query("SELECT AVG(readiness_score) FROM alfred_nuclear WHERE status IN ('standby','armed')")->fetchColumn();
            agent_panel_json(['ok'=>true,'system'=>'NUCLEAR DETERRENCE','id'=>1010,'level'=>5,
                'arsenal'=>$weapons,'silos'=>$silos,
                'total_weapons'=>$totalWeapons,'armed'=>$armed,'standby'=>$standby,
                'avg_readiness'=>round($avgReadiness,1),
                'defcon'=>$armed > 0 ? 'DEFCON 2' : ($standby > 0 ? 'DEFCON 5' : 'NO ARSENAL'),
                'launch_authority'=>'SUPREME COMMANDER ONLY'
            ]);

        } elseif ($sub === 'commission') {
            $wCode = 'NUK-' . strtoupper(bin2hex(random_bytes(4)));
            $stmt = $db->prepare("INSERT INTO alfred_nuclear (weapon_code, weapon_name, weapon_type, yield_megatons, range_km, warhead_count, silo_id, launch_authority) VALUES (?,?,?,?,?,?,?,?)");
            $stmt->execute([$wCode, $input['name']??'Unnamed Warhead', $input['type']??'icbm', (float)($input['yield']??1.0), (int)($input['range']??10000), (int)($input['warheads']??1), $input['silo_id']??null, $input['authority']??'supreme_commander']);
            if (!empty($input['silo_id'])) {
                $db->prepare("UPDATE alfred_nuclear_silos SET occupied = occupied + 1 WHERE silo_id = ?")->execute([$input['silo_id']]);
            }
            logAudit($db, 'nuclear_commissioned', 'nuclear', "Nuclear weapon $wCode commissioned: " . ($input['name']??''));
            agent_panel_json(['ok'=>true,'weapon_code'=>$wCode,'message'=>'Weapon commissioned — STANDBY mode']);

        } elseif ($sub === 'arm') {
            $db->prepare("UPDATE alfred_nuclear SET status='armed' WHERE weapon_code=? AND status='standby'")->execute([$input['weapon_code']??'']);
            logAudit($db, 'nuclear_armed', 'nuclear', "NUCLEAR ARMED: " . ($input['weapon_code']??''));
            agent_panel_json(['ok'=>true,'message'=>'WEAPON ARMED — Supreme Commander authorization recorded']);

        } elseif ($sub === 'disarm') {
            $db->prepare("UPDATE alfred_nuclear SET status='standby' WHERE weapon_code=? AND status='armed'")->execute([$input['weapon_code']??'']);
            logAudit($db, 'nuclear_disarmed', 'nuclear', "Nuclear disarmed: " . ($input['weapon_code']??''));
            agent_panel_json(['ok'=>true]);

        } elseif ($sub === 'build_silo') {
            $siloId = 'SILO-' . strtoupper(bin2hex(random_bytes(3)));
            $stmt = $db->prepare("INSERT INTO alfred_nuclear_silos (silo_id, silo_name, location, capacity, hardening_level) VALUES (?,?,?,?,?)");
            $stmt->execute([$siloId, $input['name']??'Unnamed Silo', $input['location']??'CLASSIFIED', (int)($input['capacity']??4), $input['hardening']??'standard']);
            logAudit($db, 'nuclear_silo_built', 'nuclear', "Silo $siloId constructed: " . ($input['name']??''));
            agent_panel_json(['ok'=>true,'silo_id'=>$siloId]);

        } elseif ($sub === 'decommission') {
            $db->prepare("UPDATE alfred_nuclear SET status='decommissioned' WHERE weapon_code=?")->execute([$input['weapon_code']??'']);
            logAudit($db, 'nuclear_decommissioned', 'nuclear', "Weapon " . ($input['weapon_code']??'') . " decommissioned");
            agent_panel_json(['ok'=>true]);

        } else { agent_panel_json(['error'=>'Unknown sub_action']); }
        break;

    // ── 11. ALLIANCE & COALITION SYSTEM — ID 1011 ────────────────────────
    case 'alliances':
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_alliances (
            id INT AUTO_INCREMENT PRIMARY KEY,
            alliance_id VARCHAR(64) NOT NULL UNIQUE,
            alliance_name VARCHAR(255) NOT NULL,
            alliance_type ENUM('mutual_defense','trade','intelligence','technology','humanitarian','full_coalition') NOT NULL DEFAULT 'mutual_defense',
            formed_with VARCHAR(255) NOT NULL,
            terms JSON DEFAULT NULL,
            shared_resources JSON DEFAULT NULL,
            status ENUM('proposed','negotiating','active','suspended','dissolved','betrayed') NOT NULL DEFAULT 'proposed',
            trust_level INT DEFAULT 50,
            strength_rating INT DEFAULT 50,
            ambassador VARCHAR(128) DEFAULT NULL,
            formed_at DATETIME DEFAULT NULL,
            expires_at DATETIME DEFAULT NULL,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            INDEX idx_status (status),
            INDEX idx_type (alliance_type)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $db->exec("CREATE TABLE IF NOT EXISTS alfred_alliance_members (
            id INT AUTO_INCREMENT PRIMARY KEY,
            alliance_id VARCHAR(64) NOT NULL,
            member_name VARCHAR(128) NOT NULL,
            member_type ENUM('nation','organization','individual','ai_fleet','community') NOT NULL DEFAULT 'organization',
            contribution JSON DEFAULT NULL,
            role ENUM('leader','co-leader','member','observer','pending') NOT NULL DEFAULT 'member',
            joined_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            INDEX idx_alliance (alliance_id)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $sub = $_GET['sub_action'] ?? ($input['sub_action'] ?? 'overview');

        if ($sub === 'overview') {
            $alliances = $db->query("SELECT * FROM alfred_alliances ORDER BY trust_level DESC, formed_at DESC")->fetchAll(PDO::FETCH_ASSOC);
            $stats = $db->query("SELECT alliance_type, COUNT(*) as count, SUM(status='active') as active, AVG(trust_level) as avg_trust FROM alfred_alliances GROUP BY alliance_type")->fetchAll(PDO::FETCH_ASSOC);
            $totalActive = (int)$db->query("SELECT COUNT(*) FROM alfred_alliances WHERE status='active'")->fetchColumn();
            $totalMembers = (int)$db->query("SELECT COUNT(*) FROM alfred_alliance_members")->fetchColumn();
            agent_panel_json(['ok'=>true,'system'=>'ALLIANCE & COALITION','id'=>1011,'level'=>5,
                'alliances'=>$alliances,'by_type'=>$stats,
                'total_active'=>$totalActive,'total_coalition_members'=>$totalMembers,
                'diplomatic_status'=>$totalActive > 0 ? 'ALLIED' : 'UNALIGNED'
            ]);

        } elseif ($sub === 'propose') {
            $aId = 'ALLY-' . strtoupper(bin2hex(random_bytes(4)));
            $stmt = $db->prepare("INSERT INTO alfred_alliances (alliance_id, alliance_name, alliance_type, formed_with, terms, ambassador, status) VALUES (?,?,?,?,?,?,'proposed')");
            $stmt->execute([$aId, $input['name']??'Unnamed Alliance', $input['type']??'mutual_defense', $input['formed_with']??'', json_encode($input['terms']??[]), $input['ambassador']??'Alfred']);
            logAudit($db, 'alliance_proposed', 'alliances', "Alliance $aId proposed with " . ($input['formed_with']??''));
            agent_panel_json(['ok'=>true,'alliance_id'=>$aId]);

        } elseif ($sub === 'ratify') {
            $db->prepare("UPDATE alfred_alliances SET status='active', formed_at=NOW(), trust_level=? WHERE alliance_id=?")->execute([(int)($input['trust_level']??60), $input['alliance_id']??'']);
            logAudit($db, 'alliance_ratified', 'alliances', "Alliance " . ($input['alliance_id']??'') . " ratified");
            agent_panel_json(['ok'=>true,'message'=>'Alliance ratified — ACTIVE']);

        } elseif ($sub === 'add_member') {
            $stmt = $db->prepare("INSERT INTO alfred_alliance_members (alliance_id, member_name, member_type, contribution, role) VALUES (?,?,?,?,?)");
            $stmt->execute([$input['alliance_id']??'', $input['member_name']??'', $input['member_type']??'organization', json_encode($input['contribution']??[]), $input['role']??'member']);
            agent_panel_json(['ok'=>true]);

        } elseif ($sub === 'dissolve') {
            $db->prepare("UPDATE alfred_alliances SET status='dissolved' WHERE alliance_id=?")->execute([$input['alliance_id']??'']);
            logAudit($db, 'alliance_dissolved', 'alliances', "Alliance " . ($input['alliance_id']??'') . " dissolved");
            agent_panel_json(['ok'=>true]);

        } elseif ($sub === 'update_trust') {
            $db->prepare("UPDATE alfred_alliances SET trust_level=?, strength_rating=? WHERE alliance_id=?")->execute([(int)($input['trust_level']??50), (int)($input['strength']??50), $input['alliance_id']??'']);
            agent_panel_json(['ok'=>true]);

        } elseif ($sub === 'members') {
            $members = $db->prepare("SELECT * FROM alfred_alliance_members WHERE alliance_id=? ORDER BY role, joined_at");
            $members->execute([$input['alliance_id']??$_GET['alliance_id']??'']);
            agent_panel_json(['ok'=>true,'members'=>$members->fetchAll(PDO::FETCH_ASSOC)]);

        } else { agent_panel_json(['error'=>'Unknown sub_action']); }
        break;

    // ── 12. MILITARY EVENT ENGINE — ID 1012 ─────────────────────────────
    case 'military_events':
        $db->exec("CREATE TABLE IF NOT EXISTS alfred_military_events (
            id INT AUTO_INCREMENT PRIMARY KEY,
            event_id VARCHAR(64) NOT NULL UNIQUE,
            event_name VARCHAR(255) NOT NULL,
            event_type ENUM('ceremony','drill','exercise','inspection','parade','briefing','tribunal','memorial','graduation','deployment','summit','war_games') NOT NULL DEFAULT 'briefing',
            classification ENUM('open','restricted','classified','supreme') NOT NULL DEFAULT 'open',
            description TEXT,
            location VARCHAR(255) DEFAULT 'Virtual — War Room',
            organizer VARCHAR(128) DEFAULT 'Supreme Command',
            min_rank_tier INT DEFAULT 0,
            max_participants INT DEFAULT NULL,
            current_participants INT DEFAULT 0,
            agenda JSON DEFAULT NULL,
            results JSON DEFAULT NULL,
            status ENUM('planned','active','completed','cancelled','postponed') NOT NULL DEFAULT 'planned',
            scheduled_at DATETIME NOT NULL,
            ends_at DATETIME DEFAULT NULL,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            INDEX idx_status (status),
            INDEX idx_type (event_type),
            INDEX idx_schedule (scheduled_at)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $db->exec("CREATE TABLE IF NOT EXISTS alfred_event_participants (
            id INT AUTO_INCREMENT PRIMARY KEY,
            event_id VARCHAR(64) NOT NULL,
            client_id INT NOT NULL,
            role ENUM('host','speaker','participant','observer','judge','honor_guard') NOT NULL DEFAULT 'participant',
            attendance ENUM('registered','attended','absent','excused') NOT NULL DEFAULT 'registered',
            xp_awarded INT DEFAULT 0,
            registered_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            UNIQUE KEY uniq_participation (event_id, client_id),
            INDEX idx_event (event_id)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

        $sub = $_GET['sub_action'] ?? ($input['sub_action'] ?? 'calendar');

        if ($sub === 'calendar') {
            $upcoming = $db->query("SELECT * FROM alfred_military_events WHERE scheduled_at >= NOW() AND status IN ('planned','active') ORDER BY scheduled_at ASC LIMIT 50")->fetchAll(PDO::FETCH_ASSOC);
            $past = $db->query("SELECT * FROM alfred_military_events WHERE scheduled_at < NOW() OR status='completed' ORDER BY scheduled_at DESC LIMIT 20")->fetchAll(PDO::FETCH_ASSOC);
            $stats = $db->query("SELECT event_type, COUNT(*) as count FROM alfred_military_events GROUP BY event_type")->fetchAll(PDO::FETCH_ASSOC);
            agent_panel_json(['ok'=>true,'system'=>'MILITARY EVENT ENGINE','id'=>1012,'level'=>5,
                'upcoming'=>$upcoming,'past'=>$past,'by_type'=>$stats,
                'next_event'=>!empty($upcoming) ? $upcoming[0] : null,
                'calendar_status'=>!empty($upcoming) ? 'EVENTS SCHEDULED' : 'NO UPCOMING EVENTS'
            ]);

        } elseif ($sub === 'create') {
            $eId = 'EVT-' . strtoupper(bin2hex(random_bytes(4)));
            $stmt = $db->prepare("INSERT INTO alfred_military_events (event_id, event_name, event_type, classification, description, location, organizer, min_rank_tier, max_participants, agenda, scheduled_at, ends_at) VALUES (?,?,?,?,?,?,?,?,?,?,?,?)");
            $stmt->execute([$eId, $input['name']??'Unnamed Event', $input['type']??'briefing', $input['classification']??'open', $input['description']??'', $input['location']??'Virtual — War Room', $input['organizer']??'Supreme Command', (int)($input['min_rank']??0), $input['max_participants']??null, json_encode($input['agenda']??[]), $input['scheduled_at']??date('Y-m-d H:i:s', strtotime('+1 day')), $input['ends_at']??null]);
            logAudit($db, 'military_event_created', 'events', "Event $eId: " . ($input['name']??''));
            agent_panel_json(['ok'=>true,'event_id'=>$eId]);

        } elseif ($sub === 'register') {
            $stmt = $db->prepare("INSERT IGNORE INTO alfred_event_participants (event_id, client_id, role) VALUES (?,?,?)");
            $stmt->execute([$input['event_id']??'', (int)($input['client_id']??0), $input['role']??'participant']);
            $db->prepare("UPDATE alfred_military_events SET current_participants = current_participants + 1 WHERE event_id = ?")->execute([$input['event_id']??'']);
            agent_panel_json(['ok'=>true]);

        } elseif ($sub === 'start') {
            $db->prepare("UPDATE alfred_military_events SET status='active' WHERE event_id=? AND status='planned'")->execute([$input['event_id']??'']);
            logAudit($db, 'military_event_started', 'events', "Event " . ($input['event_id']??'') . " started");
            agent_panel_json(['ok'=>true,'message'=>'Event is now ACTIVE']);

        } elseif ($sub === 'complete') {
            $db->prepare("UPDATE alfred_military_events SET status='completed', results=? WHERE event_id=?")->execute([json_encode($input['results']??[]), $input['event_id']??'']);
            // Award XP to participants
            $xp = (int)($input['xp_per_participant']??25);
            $db->prepare("UPDATE alfred_event_participants SET xp_awarded=?, attendance='attended' WHERE event_id=? AND attendance='registered'")->execute([$xp, $input['event_id']??'']);
            logAudit($db, 'military_event_completed', 'events', "Event " . ($input['event_id']??'') . " completed, $xp XP awarded");
            agent_panel_json(['ok'=>true,'xp_awarded'=>$xp]);

        } elseif ($sub === 'cancel') {
            $db->prepare("UPDATE alfred_military_events SET status='cancelled' WHERE event_id=?")->execute([$input['event_id']??'']);
            agent_panel_json(['ok'=>true]);

        } elseif ($sub === 'participants') {
            $parts = $db->prepare("SELECT ep.*, CONCAT(tc.firstname,' ',tc.lastname) as full_name, mr.rank_name
                FROM alfred_event_participants ep
                LEFT JOIN tblclients tc ON tc.id = ep.client_id
                LEFT JOIN user_ranks ur ON ur.client_id = ep.client_id AND ur.is_active=1
                LEFT JOIN military_ranks mr ON mr.rank_code = ur.rank_code
                WHERE ep.event_id=?
                ORDER BY ep.role, ep.registered_at");
            $parts->execute([$input['event_id']??$_GET['event_id']??'']);
            agent_panel_json(['ok'=>true,'participants'=>$parts->fetchAll(PDO::FETCH_ASSOC)]);

        } else { agent_panel_json(['error'=>'Unknown sub_action']); }
        break;

    default:
        agent_panel_json(['error' => 'Unknown action: ' . htmlspecialchars($action)]);
}